        private void RefreshMapTransferWindow()
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.MapTransfer) is not MapTransferUI mapTransferWindow)
            {
                return;
            }


            mapTransferWindow.RegisterCurrentMapRequested = RegisterCurrentMapTransferDestination;
            mapTransferWindow.DeleteDestinationRequested = DeleteMapTransferDestination;
            mapTransferWindow.MoveDestinationRequested = MoveToMapTransferDestination;
            mapTransferWindow.WorldMapRequested = HandleMapTransferWorldMapRequested;
            mapTransferWindow.ManualMapMoveRequested = MoveToManualMapTransferDestination;
            mapTransferWindow.PromptMapLabelResolver = ResolveMapTransferPromptLabel;
            mapTransferWindow.SetRegisterPromptMapId(_mapTransferManualDestination?.MapId ?? (_mapBoard?.MapInfo?.id ?? 0));
            mapTransferWindow.SetCurrentMapName(GetCurrentMapTransferDisplayName());
            mapTransferWindow.SetStatusMessage(GetMapTransferStatusMessage());
            mapTransferWindow.SetDestinations(BuildMapTransferDestinations());
        }


        private void HandleMapTransferWorldMapRequested(MapTransferUI.DestinationEntry destination)
        {
            _worldMapRequestMode = WorldMapRequestMode.MapTransferTargetSelection;
            _mapTransferEditDestination = destination?.IsSavedSlot == true ? destination : null;


            int focusedMapId = _mapTransferEditDestination?.MapId
                ?? _mapTransferManualDestination?.MapId
                ?? destination?.MapId
                ?? (_mapBoard?.MapInfo?.id ?? 0);
            RefreshWorldMapWindow(focusedMapId);
            uiWindowManager?.ShowWindow(MapSimulatorWindowNames.WorldMap);
        }


        private void RefreshWorldMapWindow(int? focusedMapId = null)
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.WorldMap) is not WorldMapUI worldMapWindow)
            {
                return;
            }


            worldMapWindow.MapRequested -= HandleWorldMapRequested;
            worldMapWindow.MapRequested += HandleWorldMapRequested;
            worldMapWindow.OnImeCandidateSelected = TrySelectWorldMapImeCandidate;
            worldMapWindow.ResolveImeWindowHandle = () => Window?.Handle ?? IntPtr.Zero;
            worldMapWindow.SetEntries(BuildWorldMapEntries(), _mapBoard?.MapInfo?.id ?? 0, focusedMapId);
            worldMapWindow.SetSearchResults(BuildWorldMapSearchResults(focusedMapId));
            worldMapWindow.SetQuestOverlays(BuildWorldMapQuestOverlays(focusedMapId));
        }


        private List<WorldMapUI.MapEntry> BuildWorldMapEntries()
        {
            List<WorldMapUI.MapEntry> entries = new();
            if (Program.InfoManager?.MapsNameCache == null)
            {
                return entries;
            }


            foreach (KeyValuePair<string, Tuple<string, string, string>> pair in Program.InfoManager.MapsNameCache)
            {
                if (!int.TryParse(pair.Key, out int mapId) || mapId <= 0 || mapId == MapConstants.MaxMap)
                {
                    continue;
                }


                Tuple<string, string, string> info = pair.Value;
                entries.Add(new WorldMapUI.MapEntry
                {
                    MapId = mapId,
                    StreetName = info?.Item1 ?? string.Empty,
                    MapName = info?.Item2 ?? string.Empty,
                    CategoryName = info?.Item3 ?? string.Empty,
                    RegionCode = WorldMapUI.GetRegionCodeForMapId(mapId)
                });
            }


            return entries;

        }

        private IReadOnlyList<int> ResolveQuestMobMapIds(int mobId)
        {
            EnsureQuestWorldMapEntityIndex();
            return mobId > 0 && _questMobMapIdsByMobId.TryGetValue(mobId, out IReadOnlyList<int> mapIds)
                ? mapIds
                : Array.Empty<int>();
        }

        private IReadOnlyList<int> ResolveQuestNpcMapIds(int npcId)
        {
            EnsureQuestWorldMapEntityIndex();
            return npcId > 0 && _questNpcMapIdsByNpcId.TryGetValue(npcId, out IReadOnlyList<int> mapIds)
                ? mapIds
                : Array.Empty<int>();
        }

        private int ResolveCurrentMorphTemplateIdForQuestDemand()
        {
            return Math.Max(0, _playerManager?.Player?.GetActiveMorphTemplateIdForQuestDemand() ?? 0);
        }

        private bool HasActiveBuffForQuestDemand(int buffSkillId)
        {
            return buffSkillId != 0 && _playerManager?.Skills?.HasBuff(buffSkillId) == true;
        }

        private int ResolveMonsterBookOwnedCardTypeCountForQuestDemand()
        {
            MonsterBookSnapshot snapshot = _monsterBookManager.GetSnapshot(_playerManager?.Player?.Build);
            return Math.Max(0, snapshot?.OwnedCardTypes ?? 0);
        }

        private int ResolveMonsterBookCardCountByMobIdForQuestDemand(int mobId)
        {
            if (mobId <= 0)
            {
                return 0;
            }

            MonsterBookSnapshot snapshot = _monsterBookManager.GetSnapshot(_playerManager?.Player?.Build);
            MonsterBookCardSnapshot matchedCard = snapshot?.Grades?
                .SelectMany(grade => grade?.Pages ?? Array.Empty<MonsterBookPageSnapshot>())
                .SelectMany(page => page?.Cards ?? Array.Empty<MonsterBookCardSnapshot>())
                .FirstOrDefault(card => card?.MobId == mobId);
            return Math.Max(0, matchedCard?.OwnedCopies ?? 0);
        }

        private bool IsSuccessDailyPlayQuestForQuestDemand(int questId)
        {
            if (questId <= 0 ||
                !_questRuntime.TryGetQuestRecordValue(questId, out string recordValue) ||
                string.IsNullOrWhiteSpace(recordValue))
            {
                return false;
            }

            if (TryResolveQuestRecordIntToken(recordValue, "count", out int successDays) &&
                TryResolveQuestRecordIntToken(recordValue, "daylimit", out int targetDays) &&
                targetDays > 0)
            {
                return successDays >= targetDays;
            }

            if (TryResolveQuestRecordIntToken(recordValue, "hour", out int todayHours) &&
                TryResolveQuestRecordIntToken(recordValue, "minhour", out int requiredHours) &&
                requiredHours > 0)
            {
                return todayHours >= requiredHours;
            }

            return false;
        }

        private int? ResolvePartyQuestRankCountForQuestDemand(int questId, string rankKey)
        {
            if (questId <= 0 ||
                string.IsNullOrWhiteSpace(rankKey) ||
                !_questRuntime.TryGetQuestRecordValue(questId, out string recordValue) ||
                string.IsNullOrWhiteSpace(recordValue))
            {
                return null;
            }

            string normalizedRankKey = rankKey.Trim();
            if (TryResolveQuestRecordIntToken(recordValue, normalizedRankKey, out int rankCount))
            {
                return Math.Max(0, rankCount);
            }

            return string.Equals(normalizedRankKey, "S", StringComparison.OrdinalIgnoreCase) &&
                   TryResolveQuestRecordIntToken(recordValue, "rank", out rankCount)
                ? Math.Max(0, rankCount)
                : null;
        }

        private static bool TryResolveQuestRecordIntToken(string recordValue, string token, out int value)
        {
            value = 0;
            return !string.IsNullOrWhiteSpace(recordValue) &&
                   !string.IsNullOrWhiteSpace(token) &&
                   QuestRuntimeManager.TryResolveQuestDetailRecordTokenValue(recordValue, token, out string textValue) &&
                   int.TryParse(textValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out value);
        }

        private void EnsureQuestWorldMapEntityIndex()
        {
            if (_questWorldMapEntityIndexBuilt)
            {
                return;
            }

            _questMobMapIdsByMobId.Clear();
            _questNpcMapIdsByNpcId.Clear();

            if (Program.InfoManager?.MapsCache != null)
            {
                foreach ((string mapIdText, Tuple<WzImage, string, string, string, MapInfo> mapEntry) in Program.InfoManager.MapsCache)
                {
                    if (!int.TryParse(mapIdText, out int mapId) || mapId <= 0)
                    {
                        continue;
                    }

                    WzImage mapImage = mapEntry?.Item1;
                    if (mapImage == null)
                    {
                        continue;
                    }

                    try
                    {
                        if (!mapImage.Parsed)
                        {
                            mapImage.ParseImage();
                        }
                    }
                    catch
                    {
                        continue;
                    }

                    if (mapImage["life"] is not WzSubProperty lifeProperty)
                    {
                        continue;
                    }

                    foreach (WzImageProperty lifeNode in lifeProperty.WzProperties)
                    {
                        if (lifeNode is not WzSubProperty lifeEntry)
                        {
                            continue;
                        }

                        string type = lifeEntry["type"]?.GetString();
                        int entityId = lifeEntry["id"]?.GetInt() ?? 0;
                        if (entityId <= 0)
                        {
                            continue;
                        }

                        if (string.Equals(type, "m", StringComparison.OrdinalIgnoreCase))
                        {
                            AddQuestWorldMapEntityIndexEntry(_questMobMapIdsByMobId, entityId, mapId);
                        }
                        else if (string.Equals(type, "n", StringComparison.OrdinalIgnoreCase))
                        {
                            AddQuestWorldMapEntityIndexEntry(_questNpcMapIdsByNpcId, entityId, mapId);
                        }
                    }
                }
            }

            _questWorldMapEntityIndexBuilt = true;
        }

        private static void AddQuestWorldMapEntityIndexEntry(Dictionary<int, IReadOnlyList<int>> index, int entityId, int mapId)
        {
            if (index == null || entityId <= 0 || mapId <= 0)
            {
                return;
            }

            if (index.TryGetValue(entityId, out IReadOnlyList<int> existing))
            {
                if (existing.Contains(mapId))
                {
                    return;
                }

                index[entityId] = existing.Concat(new[] { mapId }).OrderBy(id => id).ToArray();
                return;
            }

            index[entityId] = new[] { mapId };
        }



        private List<WorldMapUI.SearchResultEntry> BuildWorldMapSearchResults(int? focusedMapId)
        {
            List<WorldMapUI.SearchResultEntry> results = new();
            HashSet<string> seen = new(StringComparer.OrdinalIgnoreCase);
            int currentMapId = _mapBoard?.MapInfo?.id ?? 0;
            int selectedMapId = focusedMapId.GetValueOrDefault(currentMapId);


            AddWorldMapSearchFieldResult(results, seen, selectedMapId, "Selected field");
            if (currentMapId > 0 && currentMapId != selectedMapId)
            {
                AddWorldMapSearchFieldResult(results, seen, currentMapId, "Current field");
            }


            if (_npcsArray != null)
            {
                foreach (NpcItem npc in _npcsArray)
                {
                    string npcName = npc?.NpcInstance?.NpcInfo?.StringName;
                    if (string.IsNullOrWhiteSpace(npcName))
                    {
                        continue;
                    }


                    if (!seen.Add($"npc:{npcName.Trim()}"))
                    {
                        continue;
                    }


                    results.Add(new WorldMapUI.SearchResultEntry
                    {
                        Kind = WorldMapUI.SearchResultKind.Npc,
                        MapId = currentMapId,
                        Label = npcName.Trim(),
                        Description = "NPC in the currently loaded field"
                    });
                }
            }


            if (_mobsArray != null)
            {
                foreach (MobItem mob in _mobsArray)
                {
                    string mobName = mob?.MobInstance?.MobInfo?.Name;
                    if (string.IsNullOrWhiteSpace(mobName))
                    {
                        continue;
                    }


                    if (!seen.Add($"mob:{mobName.Trim()}"))
                    {
                        continue;
                    }


                    results.Add(new WorldMapUI.SearchResultEntry
                    {
                        Kind = WorldMapUI.SearchResultKind.Mob,
                        MapId = currentMapId,
                        Label = mobName.Trim(),
                        Description = "Mob in the currently loaded field"
                    });
                }
            }


            AppendPacketQuestGuideSearchResults(results, seen);
            AppendQuestDetailInlineReferenceSearchResult(results, seen);
            AppendQuestDemandItemSearchResults(results, seen);



            return results;

        }



        private void AddWorldMapSearchFieldResult(List<WorldMapUI.SearchResultEntry> results, HashSet<string> seen, int mapId, string prefix)
        {
            if (mapId <= 0 || !seen.Add($"field:{mapId}"))
            {
                return;
            }


            string displayName = ResolveMapTransferDisplayName(mapId, null);
            results.Add(new WorldMapUI.SearchResultEntry
            {
                Kind = WorldMapUI.SearchResultKind.Field,
                MapId = mapId,
                Label = string.IsNullOrWhiteSpace(prefix) ? displayName : $"{prefix}: {displayName}",
                Description = "Field result"
            });
        }
        private IReadOnlyList<WorldMapUI.QuestOverlayEntry> BuildWorldMapQuestOverlays(int? focusedMapId)
        {
            List<WorldMapUI.QuestOverlayEntry> overlays = new();
            HashSet<string> seen = new(StringComparer.OrdinalIgnoreCase);
            int currentMapId = _mapBoard?.MapInfo?.id ?? 0;
            int fallbackMapId = focusedMapId.GetValueOrDefault(currentMapId);
            int overlayOrder = 0;
            WorldMapUI.QuestOverlayMarkerStyle activeMarkerStyle = ResolveActiveQuestWorldMapOverlayMarkerStyle();


            if (_activeQuestDetailQuestId > 0 &&
                _questRuntime.TryGetQuestWorldMapTarget(_activeQuestDetailQuestId, _playerManager?.Player?.Build, out QuestWorldMapTarget activeTarget) &&
                activeTarget != null)
            {
                switch (activeTarget.Kind)
                {
                    case QuestWorldMapTargetKind.Mob:
                        if (activeTarget.EntityId is int targetMobId &&
                            TryGetPacketQuestGuideMapIds(targetMobId, out IReadOnlyList<int> packetMapIds))
                        {
                            IReadOnlyList<int> packetOverlayMapIds = ResolveQuestOverlayMapIds(activeTarget, packetMapIds, fallbackMapId);
                            for (int i = 0; i < packetOverlayMapIds.Count; i++)
                            {
                                AddWorldMapQuestOverlay(
                                    overlays,
                                    seen,
                                    WorldMapUI.SearchResultKind.Mob,
                                    packetOverlayMapIds[i],
                                    activeTarget.Label,
                                    $"Active quest #{_activeQuestDetailQuestId} mob target",
                                    ref overlayOrder,
                                    isPriorityTarget: true,
                                    markerStyle: activeMarkerStyle);
                            }
                        }
                        else
                        {
                            IReadOnlyList<int> fallbackOverlayMapIds = ResolveQuestOverlayMapIds(activeTarget, preferredMapIds: null, fallbackMapId);
                            for (int i = 0; i < fallbackOverlayMapIds.Count; i++)
                            {
                                AddWorldMapQuestOverlay(
                                    overlays,
                                    seen,
                                    WorldMapUI.SearchResultKind.Mob,
                                    fallbackOverlayMapIds[i],
                                    activeTarget.Label,
                                    $"Active quest #{_activeQuestDetailQuestId} mob target",
                                    ref overlayOrder,
                                    isPriorityTarget: true,
                                    markerStyle: activeMarkerStyle);
                            }
                        }


                        break;
                    case QuestWorldMapTargetKind.Item:
                        int activeItemId = activeTarget.EntityId ?? 0;
                        bool preferDemandQueryMaps = activeItemId > 0 &&
                                                     _lastQuestDemandQueryVisibleItemIds.Contains(activeItemId);
                        IReadOnlyList<int> itemPreferredMapIds = preferDemandQueryMaps
                            ? ResolveQuestDemandQueryMapIds(activeItemId, fallbackMapId)
                            : null;
                        IReadOnlyList<int> itemMapIds = ResolveQuestOverlayMapIds(activeTarget, itemPreferredMapIds, fallbackMapId);
                        string itemOverlaySourceSuffix = preferDemandQueryMaps
                            ? $" via {FormatQuestDemandQueryMapSource(ResolveQuestDemandQueryMapSource(activeItemId))}"
                            : string.Empty;
                        for (int i = 0; i < itemMapIds.Count; i++)
                        {
                            AddWorldMapQuestOverlay(
                                overlays,
                                seen,
                                WorldMapUI.SearchResultKind.Item,
                                itemMapIds[i],
                                activeTarget.Label,
                                $"Active quest #{_activeQuestDetailQuestId} delivery item{itemOverlaySourceSuffix}",
                                ref overlayOrder,
                                isPriorityTarget: true,
                                markerStyle: activeMarkerStyle);
                        }
                        break;
                    default:
                        IReadOnlyList<int> overlayMapIds = ResolveQuestOverlayMapIds(activeTarget, preferredMapIds: null, fallbackMapId);
                        for (int i = 0; i < overlayMapIds.Count; i++)
                        {
                            AddWorldMapQuestOverlay(
                                overlays,
                                seen,
                                WorldMapUI.SearchResultKind.Npc,
                                overlayMapIds[i],
                                activeTarget.Label,
                                activeTarget.Description,
                                ref overlayOrder,
                                isPriorityTarget: true,
                                markerStyle: activeMarkerStyle);
                        }
                        break;
                }
            }


            foreach ((int mobId, HashSet<int> mapIds) in _packetQuestGuideTargetsByMobId.OrderBy(entry => entry.Key))
            {
                string mobName = ResolvePacketGuideMobName(mobId);
                foreach (int mapId in mapIds.OrderBy(value => value))
                {
                    AddWorldMapQuestOverlay(
                        overlays,
                        seen,
                        WorldMapUI.SearchResultKind.Mob,
                        mapId,
                        mobName,
                        $"Packet guide quest #{_packetQuestGuideQuestId}",
                        ref overlayOrder);
                }
            }


            for (int i = 0; i < _lastQuestDemandQueryVisibleItemIds.Count; i++)
            {
                int itemId = _lastQuestDemandQueryVisibleItemIds[i];
                if (itemId <= 0)
                {
                    continue;
                }


                string itemName = InventoryItemMetadataResolver.TryResolveItemName(itemId, out string resolvedItemName)
                    ? resolvedItemName
                    : $"Item {itemId}";
                IReadOnlyList<int> mapIds = ResolveQuestDemandQueryMapIds(itemId, fallbackMapId);
                for (int mapIndex = 0; mapIndex < mapIds.Count; mapIndex++)
                {
                    AddWorldMapQuestOverlay(
                        overlays,
                        seen,
                        WorldMapUI.SearchResultKind.Item,
                        mapIds[mapIndex],
                        itemName,
                        $"Demand item query for quest #{_lastQuestDemandItemQueryQuestId}",
                        ref overlayOrder);
                }
            }


            return overlays;
        }

        private WorldMapUI.QuestOverlayMarkerStyle ResolveActiveQuestWorldMapOverlayMarkerStyle()
        {
            if (_activeQuestDetailQuestId <= 0)
            {
                return WorldMapUI.QuestOverlayMarkerStyle.Default;
            }

            bool lowLevelQuest = _questRuntime?.IsQuestWorthlessForWorldMapOverlay(
                _activeQuestDetailQuestId,
                _playerManager?.Player?.Build) == true;
            return ResolveQuestWorldMapOverlayMarkerStyle(lowLevelQuest);
        }

        private static WorldMapUI.QuestOverlayMarkerStyle ResolveQuestWorldMapOverlayMarkerStyle(bool lowLevelQuest)
        {
            return lowLevelQuest
                ? WorldMapUI.QuestOverlayMarkerStyle.LowLevelQuest
                : WorldMapUI.QuestOverlayMarkerStyle.HighLevelQuest;
        }

        internal static WorldMapUI.QuestOverlayMarkerStyle ResolveQuestWorldMapOverlayMarkerStyleForTesting(bool lowLevelQuest)
        {
            return ResolveQuestWorldMapOverlayMarkerStyle(lowLevelQuest);
        }

        private static IReadOnlyList<int> ResolveQuestOverlayMapIds(
            QuestWorldMapTarget target,
            IReadOnlyList<int> preferredMapIds,
            int fallbackMapId)
        {
            IReadOnlyList<int> sourceMapIds = preferredMapIds != null && preferredMapIds.Count > 0
                ? preferredMapIds
                : target?.MapIds;
            if (sourceMapIds != null && sourceMapIds.Count > 0)
            {
                int[] normalized = sourceMapIds
                    .Where(mapId => mapId > 0)
                    .Distinct()
                    .OrderBy(mapId => mapId)
                    .ToArray();
                if (normalized.Length > 0)
                {
                    return normalized;
                }
            }

            int fallback = target?.MapId > 0
                ? target.MapId
                : fallbackMapId;
            return fallback > 0
                ? new[] { fallback }
                : Array.Empty<int>();
        }

        internal static IReadOnlyList<int> ResolveQuestOverlayMapIdsForTesting(
            QuestWorldMapTarget target,
            IReadOnlyList<int> preferredMapIds,
            int fallbackMapId)
        {
            return ResolveQuestOverlayMapIds(target, preferredMapIds, fallbackMapId);
        }
        private static void AddWorldMapQuestOverlay(
            ICollection<WorldMapUI.QuestOverlayEntry> overlays,
            ISet<string> seen,
            WorldMapUI.SearchResultKind kind,
            int mapId,
            string label,
            string description,
            ref int overlayOrder,
            bool isPriorityTarget = false,
            WorldMapUI.QuestOverlayMarkerStyle markerStyle = WorldMapUI.QuestOverlayMarkerStyle.Default)
        {
            if (overlays == null || seen == null || mapId <= 0 || string.IsNullOrWhiteSpace(label))
            {
                return;
            }


            string trimmedLabel = label.Trim();
            string key = $"{kind}:{mapId}:{trimmedLabel}:{description}";
            if (!seen.Add(key))
            {
                return;
            }


            overlays.Add(new WorldMapUI.QuestOverlayEntry
            {
                Kind = kind,
                MapId = mapId,
                Label = trimmedLabel,
                Description = description ?? string.Empty,
                IsPriorityTarget = isPriorityTarget,
                StableOrder = overlayOrder++,
                MarkerStyle = markerStyle
            });
        }
        private bool TryGetPacketQuestGuideMapIds(int mobId, out IReadOnlyList<int> mapIds)
        {
            if (mobId > 0 &&
                _packetQuestGuideTargetsByMobId.TryGetValue(mobId, out HashSet<int> knownMapIds) &&
                knownMapIds != null &&
                knownMapIds.Count > 0)
            {
                mapIds = knownMapIds.OrderBy(value => value).ToArray();
                return true;
            }


            mapIds = Array.Empty<int>();

            return false;

        }



        private void HandleWorldMapRequested(WorldMapUI.MapEntry entry)
        {
            if (entry == null)
            {
                return;
            }

            MapleLib.WzLib.WzStructure.MapInfo targetMapInfo = ResolveMapTransferDestinationMapInfo(entry.MapId);
            string entryRestrictionMessage = GetMapTransferEntryRestrictionMessage(entry.MapId, targetMapInfo);


            if (_worldMapRequestMode == WorldMapRequestMode.MapTransferTargetSelection)
            {
                string selectedSlotLabel = _mapTransferEditDestination?.IsSavedSlot == true
                    ? $"saved slot {_mapTransferEditDestination.SavedSlotIndex + 1}"
                    : null;
                _mapTransferManualDestination = new MapTransferUI.DestinationEntry
                {
                    MapId = entry.MapId,
                    DisplayName = $"[Target] {entry.DisplayName}",
                    DetailText = BuildMapTransferDestinationDetailText(
                        !string.IsNullOrWhiteSpace(selectedSlotLabel)
                            ? $"{entry.MapId} selected for {selectedSlotLabel}"
                            : $"{entry.MapId} selected from world map",
                        entryRestrictionMessage),
                    RestrictionMessage = entryRestrictionMessage,
                    CanDelete = false
                };


                _worldMapRequestMode = WorldMapRequestMode.DirectTransfer;
                RefreshMapTransferWindow();
                if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.MapTransfer) is MapTransferUI mapTransferWindow)
                {
                    mapTransferWindow.SetSelectedMapId(entry.MapId);
                }
                if (TryOpenFieldRestrictedWindow(
                    MapSimulatorWindowNames.MapTransfer,
                    inheritDirectionModeOwner: true))
                {
                    uiWindowManager?.HideWindow(MapSimulatorWindowNames.WorldMap);
                }
                return;
            }


            string mapTransferRestrictionMessage = GetCurrentMapTransferRestrictionMessage();
            if (!string.IsNullOrWhiteSpace(mapTransferRestrictionMessage))
            {
                ShowFieldRestrictionMessage(mapTransferRestrictionMessage);
                return;
            }


            if (_loadMapCallback == null)
            {
                _chat.AddMessage("World map transfer is unavailable without a map loader.", new Color(255, 228, 151), Environment.TickCount);
                return;
            }

            if (!string.IsNullOrWhiteSpace(entryRestrictionMessage))
            {
                ShowFieldRestrictionMessage(entryRestrictionMessage);
                return;
            }


            if (QueueMapTransfer(entry.MapId, null))
            {
                uiWindowManager?.HideWindow(MapSimulatorWindowNames.WorldMap);
            }
        }


        private List<MapTransferUI.DestinationEntry> BuildMapTransferDestinations()
        {
            List<MapTransferUI.DestinationEntry> destinations = new();
            HashSet<string> seenKeys = new(StringComparer.OrdinalIgnoreCase);
            int savedCapacity = GetMapTransferSavedSlotCapacity();
            Dictionary<int, MapTransferDestinationRecord> savedBySlot = GetCurrentMapTransferDestinations()
                .Where(saved => saved != null && saved.SlotIndex >= 0 && saved.SlotIndex < savedCapacity)
                .GroupBy(saved => saved.SlotIndex)
                .ToDictionary(group => group.Key, group => group.First());


            for (int slotIndex = 0; slotIndex < savedCapacity; slotIndex++)
            {
                if (savedBySlot.TryGetValue(slotIndex, out MapTransferDestinationRecord saved))
                {
                    MapleLib.WzLib.WzStructure.MapInfo targetMapInfo = ResolveMapTransferDestinationMapInfo(saved.MapId);
                    string displayName = ResolveMapTransferDisplayName(saved.MapId, saved.DisplayName);
                    string restrictionMessage = GetMapTransferEntryRestrictionMessage(saved.MapId, targetMapInfo);
                    seenKeys.Add($"saved:{saved.MapId}");
                    destinations.Add(CreateMapTransferDestinationEntry(
                        saved.MapId,
                        displayName,
                        $"Saved slot {slotIndex + 1}    {saved.MapId}",
                        savedSlotIndex: slotIndex,
                        canDelete: true,
                        restrictionMessage: restrictionMessage));
                    continue;
                }


                destinations.Add(new MapTransferUI.DestinationEntry
                {
                    MapId = 0,
                    DisplayName = "Empty",
                    DetailText = $"Saved slot {slotIndex + 1} is empty. Press Register to save the current map or the selected world-map target here.",
                    SavedSlotIndex = slotIndex,
                    CanDelete = false
                });
            }


            if (_mapTransferManualDestination != null && seenKeys.Add($"manual:{_mapTransferManualDestination.MapId}"))
            {
                destinations.Add(_mapTransferManualDestination);
            }


            AddSystemMapTransferDestination(destinations, seenKeys, _mapBoard?.MapInfo?.returnMap, "Return");

            AddSystemMapTransferDestination(destinations, seenKeys, _mapBoard?.MapInfo?.forcedReturn, "Forced");



            if (_mapBoard?.BoardItems?.Portals != null)
            {
                foreach (PortalInstance portal in _mapBoard.BoardItems.Portals)
                {
                    if (portal == null || portal.tm <= 0 || portal.tm == MapConstants.MaxMap)
                    {
                        continue;
                    }


                    string key = $"portal:{portal.tm}:{portal.tn}";
                    if (!seenKeys.Add(key))
                    {
                        continue;
                    }


                    string displayName = ResolveMapTransferDisplayName(portal.tm);
                    string sourcePortal = string.IsNullOrWhiteSpace(portal.pn) ? "portal" : portal.pn;
                    MapleLib.WzLib.WzStructure.MapInfo targetMapInfo = ResolveMapTransferDestinationMapInfo(portal.tm);
                    string restrictionMessage = GetMapTransferEntryRestrictionMessage(portal.tm, targetMapInfo);
                    destinations.Add(CreateMapTransferDestinationEntry(
                        portal.tm,
                        $"[Portal] {displayName}",
                        $"{portal.tm} via {sourcePortal}",
                        targetPortalName: portal.tn,
                        restrictionMessage: restrictionMessage));
                }
            }


            return destinations;

        }



        private void AddSystemMapTransferDestination(
            ICollection<MapTransferUI.DestinationEntry> destinations,
            ISet<string> seenKeys,
            int? mapId,
            string label)
        {
            if (!mapId.HasValue || mapId.Value <= 0 || mapId.Value == MapConstants.MaxMap)
            {
                return;
            }


            string key = $"system:{label}:{mapId.Value}";
            if (!seenKeys.Add(key))
            {
                return;
            }


            string displayName = ResolveMapTransferDisplayName(mapId.Value);
            MapleLib.WzLib.WzStructure.MapInfo targetMapInfo = ResolveMapTransferDestinationMapInfo(mapId.Value);
            string restrictionMessage = GetMapTransferEntryRestrictionMessage(mapId.Value, targetMapInfo);
            destinations.Add(CreateMapTransferDestinationEntry(
                mapId.Value,
                $"[{label}] {displayName}",
                $"{mapId.Value}",
                restrictionMessage: restrictionMessage));
        }


        private void RegisterCurrentMapTransferDestination(MapTransferUI.DestinationEntry selectedEntry)
        {
            if (!TryResolveMapTransferRegisterTarget(out int targetMapId, out string targetDisplayName))
            {
                return;
            }

            CharacterBuild activeBuild = GetActiveMapTransferCharacterBuild();
            MapTransferDestinationBook destinationBook = GetCurrentMapTransferDestinationBook();
            IReadOnlyList<int> snapshotFieldList = _mapTransferRuntime.SnapshotFieldList(activeBuild, destinationBook);
            int targetSlotIndex = _mapTransferEditDestination?.SavedSlotIndex ?? selectedEntry?.SavedSlotIndex ?? -1;
            if (targetSlotIndex < 0 && !HasMapTransferEmptySlot(snapshotFieldList))
            {
                _chat.AddMessage(MapTransferClientParityText.ResolveRegisterListFullNotice(), new Color(255, 228, 151), Environment.TickCount);
                RefreshMapTransferWindow();
                return;
            }

            int currentMapId = _mapBoard?.MapInfo?.id ?? 0;
            if (targetMapId == currentMapId)
            {
                if (TryFindMapTransferSlot(snapshotFieldList, targetMapId, out int existingSlotIndex))
                {
                    _chat.AddMessage(MapTransferClientParityText.ResolveCurrentMapAlreadyRegisteredNotice(), new Color(255, 228, 151), Environment.TickCount);
                    RefreshMapTransferWindow();
                    if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.MapTransfer) is MapTransferUI focusWindow)
                    {
                        focusWindow.SetSelectedDestinationFocus(targetMapId, existingSlotIndex);
                    }

                    return;
                }
            }


            if (!string.IsNullOrWhiteSpace(targetDisplayName))
            {
                _mapTransferTitleCache[targetMapId] = targetDisplayName;
            }
            MapTransferRuntimeRequest request = new()
            {
                Type = MapTransferRuntimeRequestType.Register,
                Book = destinationBook,
                MapId = targetMapId,
                SlotIndex = targetSlotIndex
            };
            bool requestDispatched = TryDispatchMapTransferRequest(
                activeBuild,
                request,
                out MapTransferRuntimeResponse response,
                out string dispatchStatus);
            bool awaitingOfficialResult = _mapTransferOfficialSessionBridge.HasConnectedSession && requestDispatched;

            if (!_mapTransferOfficialSessionBridge.HasConnectedSession &&
                !requestDispatched &&
                !string.IsNullOrWhiteSpace(dispatchStatus))
            {
                response = new MapTransferRuntimeResponse
                {
                    Applied = false,
                    FailureMessage = dispatchStatus,
                    FocusMapId = response.FocusMapId,
                    FocusSlotIndex = response.FocusSlotIndex
                };
            }


            if (_mapTransferManualDestination?.MapId == targetMapId
                && (response.Applied || (!awaitingOfficialResult && response.FocusMapId == targetMapId)))
            {
                _mapTransferManualDestination = null;
            }


            if (response.Applied)
            {
                _mapTransferEditDestination = null;
            }


            RefreshMapTransferWindow();
            if (response.FocusMapId > 0
                && uiWindowManager?.GetWindow(MapSimulatorWindowNames.MapTransfer) is MapTransferUI mapTransferWindow)
            {
                mapTransferWindow.SetSelectedMapId(response.FocusMapId);
            }


            if (!response.Applied && !string.IsNullOrWhiteSpace(response.FailureMessage))
            {
                _chat.AddMessage(response.FailureMessage, new Color(255, 228, 151), Environment.TickCount);
            }

            if (_mapTransferOfficialSessionBridge.HasConnectedSession &&
                requestDispatched &&
                !string.IsNullOrWhiteSpace(dispatchStatus))
            {
                _chat.AddMessage(dispatchStatus, new Color(180, 220, 255), Environment.TickCount);
            }
        }

        private bool TryResolveMapTransferRegisterTarget(
            out int targetMapId,
            out string targetDisplayName)
        {
            targetMapId = 0;
            targetDisplayName = string.Empty;

            if (_mapTransferManualDestination?.MapId > 0 &&
                _mapTransferManualDestination.MapId != MapConstants.MaxMap)
            {
                targetMapId = _mapTransferManualDestination.MapId;
                targetDisplayName = ResolveMapTransferDisplayName(
                    targetMapId,
                    TrimMapTransferCategoryPrefix(_mapTransferManualDestination.DisplayName));
                return true;
            }

            if (_mapBoard?.MapInfo == null)
            {
                return false;
            }

            targetMapId = _mapBoard.MapInfo.id;
            targetDisplayName = ResolveMapTransferDisplayName(targetMapId, GetCurrentMapTransferDisplayName());
            return targetMapId > 0 && targetMapId != MapConstants.MaxMap;
        }

        internal static bool HasMapTransferEmptySlot(IReadOnlyList<int> snapshotFieldList)
        {
            if (snapshotFieldList == null || snapshotFieldList.Count == 0)
            {
                return true;
            }

            for (int i = 0; i < snapshotFieldList.Count; i++)
            {
                if (snapshotFieldList[i] == MapTransferRuntimeManager.EmptyDestinationMapId)
                {
                    return true;
                }
            }

            return false;
        }

        internal static bool TryFindMapTransferSlot(IReadOnlyList<int> snapshotFieldList, int mapId, out int slotIndex)
        {
            slotIndex = -1;
            if (snapshotFieldList == null || mapId <= 0)
            {
                return false;
            }

            for (int i = 0; i < snapshotFieldList.Count; i++)
            {
                if (snapshotFieldList[i] == mapId)
                {
                    slotIndex = i;
                    return true;
                }
            }

            return false;
        }


        private void DeleteMapTransferDestination(MapTransferUI.DestinationEntry destination)
        {
            if (destination == null || !destination.IsSavedSlot)
            {
                return;
            }


            MapTransferRuntimeRequest request = new()
            {
                Type = MapTransferRuntimeRequestType.Delete,
                Book = GetCurrentMapTransferDestinationBook(),
                MapId = destination.MapId,
                SlotIndex = destination.SavedSlotIndex
            };
            bool requestDispatched = TryDispatchMapTransferRequest(
                GetActiveMapTransferCharacterBuild(),
                request,
                out MapTransferRuntimeResponse response,
                out string dispatchStatus);
            if (_mapTransferOfficialSessionBridge.HasConnectedSession && requestDispatched)
            {
                if (!string.IsNullOrWhiteSpace(dispatchStatus))
                {
                    _chat.AddMessage(dispatchStatus, new Color(180, 220, 255), Environment.TickCount);
                }

                RefreshMapTransferWindow();
                return;
            }

            if (!response.Applied)
            {
                if (!string.IsNullOrWhiteSpace(response.FailureMessage))
                {
                    _chat.AddMessage(response.FailureMessage, new Color(255, 228, 151), Environment.TickCount);
                }

                return;
            }
            if (_mapTransferEditDestination?.SavedSlotIndex == destination.SavedSlotIndex)
            {
                _mapTransferEditDestination = null;
            }


            if (_mapTransferManualDestination != null && destination.MapId == _mapTransferManualDestination.MapId)
            {
                _mapTransferManualDestination = null;
            }


            RefreshMapTransferWindow();

        }



        private void MoveToMapTransferDestination(MapTransferUI.DestinationEntry destination)
        {
            if (destination == null)
            {
                return;
            }


            string mapTransferRestrictionMessage = GetCurrentMapTransferRestrictionMessage();
            if (!string.IsNullOrWhiteSpace(mapTransferRestrictionMessage))
            {
                ShowFieldRestrictionMessage(mapTransferRestrictionMessage);
                return;
            }


            if (_loadMapCallback == null)
            {
                _chat.AddMessage("Map transfer is unavailable without a map loader.", new Color(255, 228, 151), Environment.TickCount);
                return;
            }

            if (!string.IsNullOrWhiteSpace(destination.RestrictionMessage))
            {
                ShowFieldRestrictionMessage(destination.RestrictionMessage);
                return;
            }


            QueueMapTransfer(destination.MapId, destination.TargetPortalName);

        }



        private void MoveToManualMapTransferDestination(int targetMapId)
        {
            if (targetMapId <= 0)
            {
                return;
            }


            string mapTransferRestrictionMessage = GetCurrentMapTransferRestrictionMessage();
            if (!string.IsNullOrWhiteSpace(mapTransferRestrictionMessage))
            {
                ShowFieldRestrictionMessage(mapTransferRestrictionMessage);
                return;
            }


            if (_loadMapCallback == null)
            {
                _chat.AddMessage("Map transfer is unavailable without a map loader.", new Color(255, 228, 151), Environment.TickCount);
                return;
            }

            string entryRestrictionMessage = GetMapTransferEntryRestrictionMessage(targetMapId);
            if (!string.IsNullOrWhiteSpace(entryRestrictionMessage))
            {
                ShowFieldRestrictionMessage(entryRestrictionMessage);
                return;
            }


            QueueMapTransfer(targetMapId, null);

        }



        private bool QueueMapTransfer(
            int targetMapId,
            string targetPortalName,
            int targetPortalIndex = -1,
            string[] targetPortalNameCandidates = null)
        {
            if (targetMapId <= 0 || targetMapId == MapConstants.MaxMap || _gameState.PendingMapChange)
            {
                return false;
            }


            ConsumeCollisionScriptExclusiveRequestFromTransferLifecycle();
            ConsumePendingPortalSessionValueImpactsFromTransferLifecycle();
            if (ShouldConsumePassiveTransferRequestOnMapTransferAdmission(_passiveTransferRequestPending))
            {
                ConsumePassiveTransferRequestFromTransferLifecycle();
            }
            _playerManager?.ForceStand();
            _gameState.PendingMapChange = true;
            _gameState.PendingMapId = targetMapId;
            _gameState.PendingPortalName = targetPortalName;
            _gameState.PendingPortalNameCandidates = targetPortalNameCandidates ?? Array.Empty<string>();
            _gameState.PendingPortalIndex = targetPortalIndex;
            return true;
        }

        internal static bool ShouldConsumePassiveTransferRequestOnMapTransferAdmission(
            bool hasPendingPassiveTransferRequest)
        {
            // Transfer admission takes ownership from local passive retry replay:
            // once a map handoff is queued, native lifecycle clears this retry owner.
            return hasPendingPassiveTransferRequest;
        }

        private PortalInstance ResolvePortalByNameOrIndex(IEnumerable<PortalInstance> portals, string portalName, int portalIndex)
        {
            return ResolvePortalByNameCandidatesOrIndex(portals, portalName, null, portalIndex);
        }

        private PortalInstance ResolvePortalByNameCandidatesOrIndex(
            IEnumerable<PortalInstance> portals,
            string portalName,
            IEnumerable<string> portalNameCandidates,
            int portalIndex)
        {
            if (portals == null)
            {
                return null;
            }

            if (!string.IsNullOrWhiteSpace(portalName))
            {
                PortalInstance namedPortal = portals.FirstOrDefault(portal => string.Equals(portal?.pn, portalName, StringComparison.Ordinal));
                if (namedPortal != null)
                {
                    return namedPortal;
                }
            }

            if (portalNameCandidates != null)
            {
                PortalInstance uniqueCandidatePortal = ResolveUniquePortalByNameCandidates(portals, portalNameCandidates);
                if (uniqueCandidatePortal != null)
                {
                    return uniqueCandidatePortal;
                }
            }

            if (portalIndex < 0)
            {
                return null;
            }

            return portals
                .Where(portal => portal != null)
                .Skip(portalIndex)
                .FirstOrDefault();
        }

        internal static PortalInstance ResolveUniquePortalByNameCandidates(
            IEnumerable<PortalInstance> portals,
            IEnumerable<string> portalNameCandidates)
        {
            if (portals == null || portalNameCandidates == null)
            {
                return null;
            }

            PortalInstance resolvedPortal = null;
            foreach (string candidatePortalName in portalNameCandidates)
            {
                if (string.IsNullOrWhiteSpace(candidatePortalName))
                {
                    continue;
                }

                PortalInstance candidatePortal = portals.FirstOrDefault(
                    portal => string.Equals(portal?.pn, candidatePortalName, StringComparison.OrdinalIgnoreCase));
                if (candidatePortal == null)
                {
                    continue;
                }

                if (resolvedPortal == null)
                {
                    resolvedPortal = candidatePortal;
                    continue;
                }

                if (!string.Equals(resolvedPortal.pn, candidatePortal.pn, StringComparison.OrdinalIgnoreCase))
                {
                    return null;
                }
            }

            return resolvedPortal;
        }

