        private void WireMemoMailboxWindowData()
        {
            if (uiWindowManager == null)
            {
                return;
            }


            if (uiWindowManager.GetWindow(MapSimulatorWindowNames.MemoMailbox) is MemoMailboxWindow memoMailboxWindow)
            {
                _memoMailbox.SocialChatObserved = TryTriggerSpecialistPetSocialFeedback;
                memoMailboxWindow.SetSnapshotProvider(_memoMailbox.GetSnapshot, _memoMailbox.GetDraftSnapshot);
                memoMailboxWindow.SetActions(
                    tab => _memoMailbox.SetActiveTab(tab),
                    memoId => _memoMailbox.OpenMemo(memoId),
                    memoId => _memoMailbox.DeleteMemo(memoId),
                    OpenMemoAttachmentWindow,
                    () =>
                    {
                        _memoMailbox.TryDispatchActiveDraft(true, null, out string message);
                        ShowUtilityFeedbackMessage(message);
                        return message;
                    },
                    visible => _memoMailbox.SetTaxInfoVisible(visible),
                    tab =>
                    {
                        _memoMailbox.SetActiveTab(tab);
                        ShowUtilityFeedbackMessage(
                            tab == ParcelDialogTab.QuickSend
                                ? "Quick Send meso field focused in the parcel owner."
                                : "Send meso field focused in the parcel owner.");
                    },
                    HandleMemoDraftAttachmentOwnerRequest,
                    recipient => _memoMailbox.UpdateDraftRecipientFromUi(recipient),
                    body => _memoMailbox.UpdateDraftBodyFromUi(body),
                    meso => _memoMailbox.UpdateDraftMesoFromUi(meso));
                memoMailboxWindow.InventoryDropRequested = HandleMemoDraftAttachmentInventoryDrop;
                memoMailboxWindow.InventoryPickRequested = HandleMemoDraftAttachmentInventoryPick;
                memoMailboxWindow.OnImeCandidateSelected = TrySelectMemoMailboxImeCandidate;
                memoMailboxWindow.ResolveImeWindowHandle = () => Window?.Handle ?? IntPtr.Zero;
                memoMailboxWindow.SetFont(_fontChat);
            }


            if (uiWindowManager.GetWindow(MapSimulatorWindowNames.MemoSend) is MemoSendWindow memoSendWindow)
            {
                memoSendWindow.SetSnapshotProvider(_memoMailbox.GetDraftSnapshot);
                memoSendWindow.SetActions(
                    () =>
                    {
                        if (_memoMailbox.TrySendDraft(out string message))
                        {
                            ShowUtilityFeedbackMessage(message);
                            memoSendWindow.Hide();
                            TryOpenFieldRestrictedWindow(
                                MapSimulatorWindowNames.MemoMailbox,
                                inheritDirectionModeOwner: true,
                                beforeShow: () => _memoMailbox.SetActiveTab(ParcelDialogTab.Receive));
                        }
                        else
                        {
                            ShowUtilityFeedbackMessage(message);
                        }


                        return message;
                    },
                    () => ShowUtilityFeedbackMessage("Closed memo send dialog."));
                memoSendWindow.SetFont(_fontChat);
            }


            if (uiWindowManager.GetWindow(MapSimulatorWindowNames.MemoGet) is MemoGetWindow memoGetWindow)
            {
                memoGetWindow.SetSnapshotProvider(() => _memoMailbox.GetAttachmentSnapshot(_activeMemoAttachmentId));
                memoGetWindow.SetActions(
                    () =>
                    {
                        if (_memoMailbox.TryClaimAttachment(_activeMemoAttachmentId, out string message))
                        {
                            ShowUtilityFeedbackMessage(message);
                        }
                        else
                        {
                            ShowUtilityFeedbackMessage(message);
                        }


                        return message;
                    },
                    () => ShowUtilityFeedbackMessage("Closed memo package dialog."));
                memoGetWindow.SetFont(_fontChat);
            }
        }


        private void OpenMemoAttachmentWindow(int memoId)
        {
            if (!_memoMailbox.CanClaimAttachment(memoId))
            {
                if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.MemoMailbox) is MemoMailboxWindow)
                {
                    MemoMailboxAttachmentSnapshot snapshot = _memoMailbox.GetAttachmentSnapshot(memoId);
                    ShowUtilityFeedbackMessage(snapshot.IsExpired
                        ? "This parcel package expired before it could be claimed."
                        : "No claimable package is attached to this memo.");
                }


                return;

            }



            _activeMemoAttachmentId = memoId;
            if (!TryOpenFieldRestrictedWindow(
                    MapSimulatorWindowNames.MemoGet,
                    out string restrictionMessage,
                    inheritDirectionModeOwner: true))
            {
                ShowUtilityFeedbackMessage(restrictionMessage ?? "Parcel package windows cannot be opened in this map.");
            }

        }

        private void HandleMemoDraftAttachmentOwnerRequest(ParcelDialogTab activeTab)
        {
            if (activeTab == ParcelDialogTab.QuickSend)
            {
                if (_memoMailbox.GetDraftSnapshot().AttachmentKind == MemoDraftAttachmentKind.Item)
                {
                    _memoMailbox.ClearDraftAttachment();
                    ShowUtilityFeedbackMessage("Quick Send cleared the staged item package because this tab only supports meso attachments.");
                    return;
                }

                ShowUtilityFeedbackMessage("Quick Send does not allow item packages. Use the parcel-owner meso field instead.");
                return;
            }

            if (_memoMailbox.GetDraftSnapshot().AttachmentKind == MemoDraftAttachmentKind.Item)
            {
                _memoMailbox.ClearDraftAttachment();
                ShowUtilityFeedbackMessage("Cleared the staged parcel item package.");
                return;
            }

            if (TryResolveDraggedMemoDraftAttachmentSource(out InventoryType draggedInventoryType, out int draggedSlotIndex, out InventorySlotData draggedSlotData)
                && TryStageMemoDraftAttachment(draggedInventoryType, draggedSlotIndex, draggedSlotData, out string draggedMessage))
            {
                ShowUtilityFeedbackMessage(draggedMessage);
                return;
            }

            MemoMailboxDraftSnapshot draftSnapshot = _memoMailbox.GetDraftSnapshot();
            if (draftSnapshot.AwaitingItemSelection)
            {
                _memoMailbox.CancelDraftItemSelection();
                ShowUtilityFeedbackMessage("Cancelled parcel item picker.");
                return;
            }

            if (uiWindowManager?.InventoryWindow is not InventoryUI)
            {
                ShowUtilityFeedbackMessage("No inventory runtime is available for parcel item staging.");
                return;
            }

            _memoMailbox.BeginDraftItemSelection();
            ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.Inventory);
            ShowUtilityFeedbackMessage("Parcel item picker armed. Click an inventory slot or drag an item into the package lane.");
        }

        private bool HandleMemoDraftAttachmentInventoryDrop(InventoryType sourceInventoryType, int sourceSlotIndex, InventorySlotData draggedSlotData)
        {
            if (draggedSlotData == null)
            {
                return false;
            }

            MemoMailboxDraftSnapshot draftSnapshot = _memoMailbox.GetDraftSnapshot();
            if (draftSnapshot.ActiveTab == ParcelDialogTab.Receive)
            {
                return false;
            }

            ReleaseActiveKeydownSkillForClientCancelIngress(currTickCount);

            if (draftSnapshot.ActiveTab == ParcelDialogTab.QuickSend)
            {
                if (draftSnapshot.AttachmentKind == MemoDraftAttachmentKind.Item)
                {
                    _memoMailbox.ClearDraftAttachment();
                }

                ShowUtilityFeedbackMessage("Quick Send does not allow item packages. Use the parcel-owner meso field instead.");
                return true;
            }

            if (!TryStageMemoDraftAttachment(sourceInventoryType, sourceSlotIndex, draggedSlotData, out string message))
            {
                return false;
            }

            ShowUtilityFeedbackMessage(message);
            return true;
        }

        private bool HandleMemoDraftAttachmentInventoryPick(InventoryType sourceInventoryType, int sourceSlotIndex, InventorySlotData pickedSlotData)
        {
            if (pickedSlotData == null)
            {
                return false;
            }

            MemoMailboxDraftSnapshot draftSnapshot = _memoMailbox.GetDraftSnapshot();
            if (draftSnapshot.ActiveTab != ParcelDialogTab.Send || !draftSnapshot.AwaitingItemSelection)
            {
                return false;
            }

            ReleaseActiveKeydownSkillForClientCancelIngress(currTickCount);

            if (!TryStageMemoDraftAttachment(sourceInventoryType, sourceSlotIndex, pickedSlotData, out string message))
            {
                ShowUtilityFeedbackMessage(message);
                return true;
            }

            ShowUtilityFeedbackMessage(message);
            return true;
        }

        private bool TryResolveDraggedMemoDraftAttachmentSource(out InventoryType inventoryType, out int slotIndex, out InventorySlotData slotData)
        {
            inventoryType = InventoryType.NONE;
            slotIndex = -1;
            slotData = null;

            if (uiWindowManager?.InventoryWindow is not InventoryUI inventoryWindow
                || !inventoryWindow.IsDraggingItem
                || inventoryWindow.DraggedSlotData == null)
            {
                return false;
            }

            inventoryType = inventoryWindow.DraggedInventoryType;
            slotIndex = inventoryWindow.DraggedSlotIndex;
            slotData = inventoryWindow.DraggedSlotData;
            return slotData != null;
        }

        private bool TryStageMemoDraftAttachment(InventoryType inventoryType, int slotIndex, InventorySlotData slot, out string message)
        {
            if (slot == null
                || slot.IsDisabled
                || slot.ItemId <= 0
                || Math.Max(0, slot.Quantity) <= 0)
            {
                message = "Dragged inventory slot does not contain a valid parcel item.";
                return false;
            }

            int quantity = Math.Max(1, slot.Quantity);
            if (!_memoMailbox.SetDraftItemAttachment(slot.ItemId, quantity, out _))
            {
                message = "Parcel item staging rejected this inventory item.";
                return false;
            }

            string itemName = !string.IsNullOrWhiteSpace(slot.ItemName)
                ? slot.ItemName.Trim()
                : InventoryItemMetadataResolver.TryResolveItemName(slot.ItemId, out string resolvedName)
                    ? resolvedName
                    : $"Item {slot.ItemId}";
            string slotLabel = slotIndex >= 0 ? $" slot #{slotIndex + 1}" : string.Empty;
            message = $"Staged {itemName} x{quantity} from {inventoryType}{slotLabel} into the parcel owner.";
            return true;
        }



        private void ShowCharacterInfoWindow(string initialPage = null, UserInfoUI.UserInfoInspectionTarget inspectionTarget = null)



        {



            ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.CharacterInfo);



            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.CharacterInfo) is not UserInfoUI characterInfoWindow)



            {



                return;



            }







            uiWindowManager.BringToFront(characterInfoWindow);

            if (inspectionTarget?.Build != null)
            {
                characterInfoWindow.CharacterBuild = inspectionTarget.Build;
                characterInfoWindow.SetInspectionTarget(inspectionTarget);
            }
            else
            {
                characterInfoWindow.CharacterBuild = _playerManager?.Player?.Build;
                characterInfoWindow.ClearInspectionTarget();
                _familyChartRuntime.ClearRemotePreviewRequest();
            }



            if (!string.IsNullOrWhiteSpace(initialPage))



            {



                characterInfoWindow.ShowPage(initialPage);



            }



        }







        private void ShowWindowWithInheritedDirectionModeOwner(string windowName)
        {
            if (uiWindowManager == null || string.IsNullOrWhiteSpace(windowName))
            {
                return;
            }
            if (!TryShowFieldRestrictedWindow(windowName))
            {
                return;
            }



            if (ShouldTrackInheritedDirectionModeOwner())
            {
                TrackDirectionModeOwnerWindow(windowName, uiWindowManager.GetWindow(windowName));
            }

            PreparePacketOwnedAdminShopForUniqueModelessOwnerShow(windowName);

            uiWindowManager.ShowWindow(windowName);
        }
        private bool ShouldAllowWindowToggleOpen(string windowName)
        {
            return TryShowFieldRestrictedWindow(windowName);
        }

        private void HandleImplicitDirectionModeOwnerWindowShow(UIWindowBase window)
        {
            string windowName = window?.WindowName;
            if (!ShouldTrackInheritedDirectionModeOwner()
                || !DirectionModeWindowOwnerRegistry.IsImplicitOwnerEligibleWindow(windowName))
            {
                return;
            }

            TrackDirectionModeOwnerWindow(windowName, window);
        }

        private void TrackDirectionModeOwnerWindow(string windowName, UIWindowBase window)
        {
            if (string.IsNullOrWhiteSpace(windowName))
            {
                return;
            }

            if (window != null)
            {
                _scriptedDirectionModeWindows.TrackOwner(windowName, () => window.IsVisible);
                return;
            }

            _scriptedDirectionModeWindows.TrackWindow(windowName);
        }
        private bool ShouldTrackInheritedDirectionModeOwner()
        {
            bool trackedOwnerVisible = _scriptedDirectionModeWindows.HasVisibleOwnedWindow(IsWindowVisible);
            return _gameState.ShouldInheritDirectionModeOwner(
                _npcInteractionOverlay?.IsVisible == true,
                trackedOwnerVisible,
                _scriptedDirectionModeOwnerActive,
                _specialFieldRuntime.SpecialEffects.Wedding.HasActiveScriptedDialog,
                _specialFieldRuntime.SpecialEffects.CakePie.IsItemInfoVisible,
                _specialFieldRuntime.Minigames.MemoryGame.IsVisible,
                _specialFieldRuntime.Minigames.Tournament.MatchTableDialog.IsVisible,
                _specialFieldRuntime.Minigames.RockPaperScissors.IsVisible,
                _initialQuizTimerRuntime.IsActive(currTickCount),
                _speedQuizOwnerRuntime.IsActive(currTickCount),
                _packetScriptDedicatedOwnerRuntime.IsActive);
        }


        private void WireSocialListWindowData()
        {
            WireGuildRankWindowData();
            WireGuildMarkWindowData();
            WireGuildCreateAgreementWindowData();

            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.SocialList) is not SocialListWindow socialListWindow)
            {
                return;
            }


            _socialListRuntime.UpdateLocalContext(
                _playerManager?.Player?.Build,
                GetCurrentMapTransferDisplayName(),
                Math.Max(1, _simulatorChannelIndex + 1));
            _socialListRuntime.SocialChatObserved = TryTriggerSpecialistPetSocialFeedback;
            socialListWindow.SetSnapshotProvider(_socialListRuntime.BuildSnapshot);
            socialListWindow.SetHandlers(
                tab => _socialListRuntime.SelectTab(tab),
                visibleIndex => _socialListRuntime.SelectVisibleEntry(visibleIndex),
                delta => _socialListRuntime.MovePage(delta),
                delta => _socialListRuntime.MoveScroll(delta),
                ratio => _socialListRuntime.SetScrollPosition(ratio),
                onlineOnly => _socialListRuntime.SetFriendOnlineOnly(onlineOnly),
                actionKey =>
                {
                    if (string.Equals(actionKey, "Friend.AddGroup", StringComparison.Ordinal))
                    {
                        string message = _socialListRuntime.OpenFriendGroupPopup(FriendGroupPopupMode.AddFriend);
                        if (_socialListRuntime.HasOpenFriendGroupPopup)
                        {
                            WireFriendGroupWindowData();
                            ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.FriendGroup);
                        }

                        return message;
                    }

                    if (string.Equals(actionKey, "Friend.GroupWhisper", StringComparison.Ordinal))
                    {
                        string message = _socialListRuntime.OpenFriendGroupPopup(FriendGroupPopupMode.GroupWhisper);
                        if (_socialListRuntime.HasOpenFriendGroupPopup)
                        {
                            WireFriendGroupWindowData();
                            ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.FriendGroup);
                        }

                        return message;
                    }

                    if (string.Equals(actionKey, "Guild.Board", StringComparison.Ordinal))
                    {
                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.GuildBbs);
                        return "Opened Guild BBS from the guild member list.";
                    }


                    if (string.Equals(actionKey, "Party.Search", StringComparison.Ordinal))
                    {
                        _socialListRuntime.OpenSearchWindow(SocialSearchTab.Party);
                        WireSocialSearchWindowData();
                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.SocialSearch);
                        return "Opened the party and expedition search surface.";
                    }


                    if (string.Equals(actionKey, "Guild.Search", StringComparison.Ordinal))
                    {
                        _socialListRuntime.OpenGuildSearchWindow();
                        WireGuildSearchWindowData();
                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.GuildSearch);
                        return "Opened the dedicated guild search surface.";
                    }


                    if (string.Equals(actionKey, "Guild.Skill", StringComparison.Ordinal))

                    {
                        if (!_socialListRuntime.BuildGuildSkillUiContext(_playerManager?.Player?.Build).HasGuildMembership)
                        {
                            return "Join a guild before opening the dedicated guild skill surface.";
                        }
                        WireGuildSkillWindowData();
                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.GuildSkill);
                        return "Opened the dedicated guild skill surface.";
                    }


                    if (string.Equals(actionKey, "Guild.Manage", StringComparison.Ordinal))



                    {



                        _socialListRuntime.OpenGuildManageWindow(GuildManageTab.Position);



                        WireGuildManageWindowData();



                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.GuildManage);



                        return "Opened the dedicated guild-management surface.";



                    }







                    if (string.Equals(actionKey, "Guild.Change", StringComparison.Ordinal))



                    {



                        _socialListRuntime.OpenGuildManageWindow(GuildManageTab.Change);



                        WireGuildManageWindowData();



                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.GuildManage);



                        return "Opened the guild notice editor on the change tab.";



                    }







                    if (string.Equals(actionKey, "Alliance.Change", StringComparison.Ordinal))



                    {



                        _socialListRuntime.OpenAllianceEditor(AllianceEditorFocus.RankTitle);



                        WireAllianceEditorWindowData();



                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.AllianceEditor);



                        return "Opened the alliance editor for rank-title changes.";



                    }







                    if (string.Equals(actionKey, "Alliance.Notice", StringComparison.Ordinal))



                    {



                        _socialListRuntime.OpenAllianceEditor(AllianceEditorFocus.Notice);



                        WireAllianceEditorWindowData();



                        ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.AllianceEditor);



                        return "Opened the alliance editor for notice changes.";



                    }

                    if (string.Equals(actionKey, "Party.ChangeBoss", StringComparison.Ordinal))
                    {
                        string restrictionMessage = FieldInteractionRestrictionEvaluator.GetPartyBossRestrictionMessage(
                            _mapBoard?.MapInfo?.fieldLimit ?? 0,
                            _mapBoard?.MapInfo);
                        if (!string.IsNullOrWhiteSpace(restrictionMessage))
                        {
                            return restrictionMessage;
                        }
                    }


                    return _socialListRuntime.ExecuteAction(actionKey);
                },
                ShowUtilityFeedbackMessage);
            socialListWindow.SetFont(_fontChat);
        }

