        private UserInfoUI.UserInfoInspectionTarget ResolveCharacterInfoInspectionTarget(UserInfoUI.UserInfoInspectionTarget inspectionTarget)
        {
            if (inspectionTarget == null)
            {
                return null;
            }

            bool foundActor = (inspectionTarget.CharacterId > 0 && _remoteUserPool.TryGetActor(inspectionTarget.CharacterId, out RemoteUserActor actor))
                || _remoteUserPool.TryGetActorByName(inspectionTarget.Name, out actor);
            WeddingRemoteParticipantSnapshot? weddingSnapshot = TryGetCharacterInfoWeddingParticipantSnapshot(
                inspectionTarget.CharacterId,
                inspectionTarget.Name,
                out WeddingRemoteParticipantSnapshot resolvedWeddingSnapshot)
                ? resolvedWeddingSnapshot
                : null;
            CharacterBuild resolvedBuild = actor?.Build ?? weddingSnapshot?.Build ?? inspectionTarget.Build;
            int resolvedCharacterId = actor?.CharacterId ?? (weddingSnapshot?.CharacterId > 0 ? weddingSnapshot.Value.CharacterId : inspectionTarget.CharacterId);
            string resolvedName = !string.IsNullOrWhiteSpace(actor?.Name)
                ? actor.Name
                : !string.IsNullOrWhiteSpace(weddingSnapshot?.Name)
                    ? weddingSnapshot.Value.Name
                    : inspectionTarget.Name;
            TryResolveCharacterInfoPresence(
                resolvedCharacterId,
                resolvedName,
                actor,
                inspectionTarget.LocationSummary,
                inspectionTarget.Channel,
                out string locationSummary,
                out int channel);

            return new UserInfoUI.UserInfoInspectionTarget
            {
                Build = resolvedBuild,
                CharacterId = resolvedCharacterId,
                Name = resolvedName,
                LocationSummary = locationSummary,
                Channel = channel,
                IsLiveRemoteTarget = actor?.IsVisibleInWorld == true || weddingSnapshot.HasValue
            };
        }

        private string HandleCharacterInfoPartyRequest(UserInfoUI.UserInfoActionContext context)
        {
            WireSocialListWindowData();

            if (!context.IsRemoteTarget)
            {
                _socialListRuntime.SelectTab(SocialListTab.Party);
                ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.SocialList);
                return "Party list opened from the profile window.";
            }

            _socialListRuntime.SelectTab(SocialListTab.Party);
            if (!_socialListRuntime.HasLocalPartyLeader())
            {
                ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.SocialList);
                return "Party invite preview requires the local player to be party leader, matching CUIUserInfo::OnButtonClicked.";
            }

            if (!TryResolveRemoteCharacterInfoTargetPresence(
                    context,
                    out string locationSummary,
                    out int channel,
                    out string unavailableMessage))
            {
                ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.SocialList);
                return unavailableMessage;
            }

            string message = _socialListRuntime.InviteCharacterToParty(
                context.CharacterName,
                context.Build?.JobName,
                context.Build?.Level ?? 1,
                locationSummary,
                channel);
            ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.SocialList);
            return message;
        }

        private string HandleCharacterInfoSearchRequest(UserInfoUI.UserInfoActionContext context)
        {
            context = NormalizeCharacterInfoActionContext(context);
            string locationSummary = context.LocationSummary;
            int channel = context.Channel;
            string handoffStatus = null;
            bool remotePresenceResolved = true;
            if (context.IsRemoteTarget)
            {
                remotePresenceResolved = TryResolveRemoteCharacterInfoTargetPresence(
                    context,
                    out locationSummary,
                    out channel,
                    out string unavailableMessage);
                string channelLabel = channel > 0 ? $"CH {channel}" : "CH ?";
                handoffStatus = remotePresenceResolved
                    ? $"Character-info BtSearch handoff preserved {locationSummary} ({channelLabel})."
                    : unavailableMessage;
            }

            WireSocialSearchWindowData();
            int? launchOption = _socialListRuntime.ResolveCharacterInfoSearchLaunchOption(
                context.CharacterId,
                context.CharacterName,
                context.IsRemoteTarget);
            _socialListRuntime.OpenSearchWindowFromCharacterInfo(
                context.CharacterName,
                context.Build,
                locationSummary,
                channel,
                context.IsRemoteTarget,
                handoffStatus,
                launchOption);
            ShowWindowWithInheritedDirectionModeOwner(MapSimulatorWindowNames.SocialSearch);
            return context.IsRemoteTarget && !remotePresenceResolved
                ? $"Social search opened from the character-info target handoff for {context.CharacterName}. Target presence could not be proven from the active seams, so this remains preview-only."
                : context.IsRemoteTarget
                    ? $"Social search opened from the character-info target handoff for {context.CharacterName}."
                : "Social search opened from the profile window.";
        }

