        private bool TryShowRemoteCharacterInfoWindow(string characterSelector)
        {
            if (string.IsNullOrWhiteSpace(characterSelector))
            {
                return false;
            }

            string selector = characterSelector.Trim();
            bool selectorIsCharacterId = int.TryParse(selector, out int parsedCharacterId);
            RemoteUserActor actor = null;
            bool foundActor = selectorIsCharacterId
                ? _remoteUserPool.TryGetActor(parsedCharacterId, out actor)
                : _remoteUserPool.TryGetActorByName(selector, out actor);

            WeddingRemoteParticipantSnapshot? weddingSnapshot = TryGetCharacterInfoWeddingParticipantSnapshot(
                selectorIsCharacterId ? parsedCharacterId : actor?.CharacterId ?? 0,
                selectorIsCharacterId ? actor?.Name : selector,
                out WeddingRemoteParticipantSnapshot resolvedWeddingSnapshot)
                ? resolvedWeddingSnapshot
                : null;

            string resolvedName = !string.IsNullOrWhiteSpace(actor?.Name)
                ? actor.Name.Trim()
                : !string.IsNullOrWhiteSpace(weddingSnapshot?.Name)
                    ? weddingSnapshot.Value.Name.Trim()
                    : selectorIsCharacterId
                        ? string.Empty
                        : selector;
            int resolvedCharacterId = actor?.CharacterId
                ?? (weddingSnapshot?.CharacterId > 0
                    ? weddingSnapshot.Value.CharacterId
                    : (selectorIsCharacterId ? parsedCharacterId : 0));

            SocialTrackedEntrySnapshot trackedEntry = ResolveRemoteCharacterInfoTrackedEntry(resolvedName);
            MessengerRemoteParticipantSnapshot? messengerSnapshot = ResolveRemoteCharacterInfoMessengerSnapshot(resolvedName);
            bool presenceResolved = TryResolveCharacterInfoPresence(
                resolvedCharacterId,
                resolvedName,
                foundActor ? actor : null,
                "Location unknown",
                0,
                out string locationSummary,
                out int channel);
            CharacterBuild pendingProfileBuild = TryCreateRemoteCharacterInfoInspectionBuildFromPendingProfile(
                resolvedCharacterId,
                resolvedName,
                out CharacterBuild resolvedPendingProfileBuild)
                ? resolvedPendingProfileBuild
                : null;

            CharacterBuild inspectionBuild = actor?.Build?.Clone()
                ?? weddingSnapshot?.Build?.Clone()
                ?? pendingProfileBuild
                ?? CreateRemoteCharacterInfoInspectionFallbackBuild(
                    resolvedCharacterId,
                    resolvedName,
                    trackedEntry,
                    messengerSnapshot,
                    allowNameOnlyFallback: presenceResolved);
            if (inspectionBuild == null)
            {
                return false;
            }

            if (resolvedCharacterId > 0 && inspectionBuild.Id <= 0)
            {
                inspectionBuild.Id = resolvedCharacterId;
            }

            if (string.IsNullOrWhiteSpace(inspectionBuild.Name))
            {
                inspectionBuild.Name = string.IsNullOrWhiteSpace(resolvedName)
                    ? $"Remote Character {Math.Max(1, resolvedCharacterId)}"
                    : resolvedName;
            }

            ShowCharacterInfoWindow(
                inspectionTarget: new UserInfoUI.UserInfoInspectionTarget
                {
                    Build = inspectionBuild,
                    CharacterId = resolvedCharacterId > 0 ? resolvedCharacterId : inspectionBuild.Id,
                    Name = inspectionBuild.Name,
                    LocationSummary = locationSummary,
                    Channel = channel,
                    IsLiveRemoteTarget = actor?.IsVisibleInWorld == true
                });
            return true;
        }

        private SocialTrackedEntrySnapshot ResolveRemoteCharacterInfoTrackedEntry(string characterName)
        {
            if (string.IsNullOrWhiteSpace(characterName) || _socialListRuntime == null)
            {
                return null;
            }

            return _socialListRuntime.TryFindTrackedEntry(characterName.Trim(), out SocialTrackedEntrySnapshot trackedEntry) && trackedEntry.IsOnline
                ? trackedEntry
                : null;
        }

        private MessengerRemoteParticipantSnapshot? ResolveRemoteCharacterInfoMessengerSnapshot(string characterName)
        {
            if (string.IsNullOrWhiteSpace(characterName) || _messengerRuntime == null)
            {
                return null;
            }

            string resolvedName = characterName.Trim();
            IReadOnlyList<MessengerRemoteParticipantSnapshot> snapshots = _messengerRuntime.GetRemoteParticipantSnapshots();
            for (int i = 0; i < snapshots.Count; i++)
            {
                MessengerRemoteParticipantSnapshot snapshot = snapshots[i];
                if (!snapshot.IsOnline
                    || !string.Equals(snapshot.Name, resolvedName, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                return snapshot;
            }

            return null;
        }

        internal static CharacterBuild CreateRemoteCharacterInfoInspectionFallbackBuild(
            int characterId,
            string characterName,
            SocialTrackedEntrySnapshot trackedEntry,
            MessengerRemoteParticipantSnapshot? messengerSnapshot,
            bool allowNameOnlyFallback = false)
        {
            string resolvedName = !string.IsNullOrWhiteSpace(characterName)
                ? characterName.Trim()
                : !string.IsNullOrWhiteSpace(trackedEntry?.Name)
                    ? trackedEntry.Name.Trim()
                    : messengerSnapshot.HasValue && !string.IsNullOrWhiteSpace(messengerSnapshot.Value.Name)
                        ? messengerSnapshot.Value.Name.Trim()
                        : string.Empty;
            if (string.IsNullOrWhiteSpace(resolvedName))
            {
                return null;
            }

            bool hasLevelMetadata = false;
            bool hasJobMetadata = false;
            CharacterBuild build = new CharacterBuild
            {
                Id = Math.Max(0, characterId),
                Name = resolvedName,
                HasAuthoritativeProfileGuild = false,
                HasAuthoritativeProfileAlliance = false,
                HasAuthoritativeProfileFame = false,
                HasAuthoritativeProfileWorldRank = false,
                HasAuthoritativeProfileJobRank = false,
                HasAuthoritativeProfileRide = false,
                HasAuthoritativeProfileTraits = false,
                HasAuthoritativeProfilePendantSlot = false,
                HasAuthoritativeProfilePocketSlot = false,
                HasAuthoritativeProfileMedal = false,
                HasAuthoritativeProfileCollection = false,
                HasAuthoritativeProfileMarriage = false
            };

            if (trackedEntry != null)
            {
                if (TryResolveCharacterInfoTrackedLevel(trackedEntry.PrimaryText, trackedEntry.SecondaryText, out int trackedLevel))
                {
                    build.Level = trackedLevel;
                    hasLevelMetadata = true;
                }

                if (TryResolveCharacterInfoTrackedJobName(trackedEntry, out string trackedJobName))
                {
                    build.JobName = trackedJobName;
                    hasJobMetadata = true;
                }
            }

            if (messengerSnapshot.HasValue)
            {
                MessengerRemoteParticipantSnapshot snapshot = messengerSnapshot.Value;
                if (!hasLevelMetadata && snapshot.Level > 0)
                {
                    build.Level = snapshot.Level;
                    hasLevelMetadata = true;
                }

                if (!hasJobMetadata && !string.IsNullOrWhiteSpace(snapshot.JobName))
                {
                    build.JobName = snapshot.JobName.Trim();
                    hasJobMetadata = true;
                }
            }

            build.HasAuthoritativeProfileLevel = hasLevelMetadata;
            build.HasAuthoritativeProfileJob = hasJobMetadata;
            return hasLevelMetadata || hasJobMetadata || allowNameOnlyFallback
                ? build
                : null;
        }

        private bool TryCreateRemoteCharacterInfoInspectionBuildFromPendingProfile(
            int characterId,
            string characterName,
            out CharacterBuild build)
        {
            build = null;
            if (characterId <= 0
                || !_pendingRemoteUserProfilesByCharacterId.TryGetValue(characterId, out RemoteUserProfilePacket packet))
            {
                return false;
            }

            string fallbackName = !string.IsNullOrWhiteSpace(characterName)
                ? characterName.Trim()
                : $"Remote Character {characterId}";
            build = CreateRemoteCharacterInfoInspectionFallbackBuild(
                        characterId,
                        fallbackName,
                        trackedEntry: null,
                        messengerSnapshot: null,
                        allowNameOnlyFallback: true)
                    ?? new CharacterBuild
                    {
                        Id = Math.Max(0, characterId),
                        Name = fallbackName
                    };
            ApplyRemoteUserProfilePacketToCharacterInfoInspectionBuild(build, packet);
            return true;
        }

        internal static void ApplyRemoteUserProfilePacketToCharacterInfoInspectionBuild(
            CharacterBuild build,
            RemoteUserProfilePacket packet)
        {
            if (build == null)
            {
                return;
            }

            if (packet.Level.HasValue && packet.Level.Value > 0)
            {
                build.Level = Math.Max(1, packet.Level.Value);
                build.HasAuthoritativeProfileLevel = true;
            }

            if (packet.JobId.HasValue && packet.JobId.Value >= 0)
            {
                build.Job = packet.JobId.Value;
                build.JobName = SkillDataLoader.GetJobName(packet.JobId.Value);
                build.HasAuthoritativeProfileJob = true;
            }

            if (packet.GuildName != null)
            {
                build.GuildName = string.IsNullOrWhiteSpace(packet.GuildName) ? string.Empty : packet.GuildName.Trim();
                build.HasAuthoritativeProfileGuild = true;
            }

            if (packet.AllianceName != null)
            {
                build.AllianceName = string.IsNullOrWhiteSpace(packet.AllianceName) ? string.Empty : packet.AllianceName.Trim();
                build.HasAuthoritativeProfileAlliance = true;
            }

            if (packet.Fame.HasValue)
            {
                build.Fame = packet.Fame.Value;
                build.HasAuthoritativeProfileFame = true;
            }

            if (packet.WorldRank.HasValue)
            {
                build.WorldRank = Math.Max(0, packet.WorldRank.Value);
                build.HasAuthoritativeProfileWorldRank = true;
            }

            if (packet.JobRank.HasValue)
            {
                build.JobRank = Math.Max(0, packet.JobRank.Value);
                build.HasAuthoritativeProfileJobRank = true;
            }

            if (packet.HasRide.HasValue)
            {
                build.HasMonsterRiding = packet.HasRide.Value;
                build.HasAuthoritativeProfileRide = true;
            }

            if (packet.HasPendantSlot.HasValue)
            {
                build.HasPendantSlotExtension = packet.HasPendantSlot.Value;
                build.HasAuthoritativeProfilePendantSlot = true;
            }

            if (packet.HasPocketSlot.HasValue)
            {
                build.HasPocketSlot = packet.HasPocketSlot.Value;
                build.HasAuthoritativeProfilePocketSlot = true;
            }

            bool hasTraitUpdate = false;
            if (packet.TraitCharisma.HasValue)
            {
                build.TraitCharisma = Math.Max(0, packet.TraitCharisma.Value);
                hasTraitUpdate = true;
            }

            if (packet.TraitInsight.HasValue)
            {
                build.TraitInsight = Math.Max(0, packet.TraitInsight.Value);
                hasTraitUpdate = true;
            }

            if (packet.TraitWill.HasValue)
            {
                build.TraitWill = Math.Max(0, packet.TraitWill.Value);
                hasTraitUpdate = true;
            }

            if (packet.TraitCraft.HasValue)
            {
                build.TraitCraft = Math.Max(0, packet.TraitCraft.Value);
                hasTraitUpdate = true;
            }

            if (packet.TraitSense.HasValue)
            {
                build.TraitSense = Math.Max(0, packet.TraitSense.Value);
                hasTraitUpdate = true;
            }

            if (packet.TraitCharm.HasValue)
            {
                build.TraitCharm = Math.Max(0, packet.TraitCharm.Value);
                hasTraitUpdate = true;
            }

            if (hasTraitUpdate)
            {
                build.HasAuthoritativeProfileTraits = true;
            }

            if (packet.HasMedal.HasValue)
            {
                build.HasAuthoritativeProfileMedal = true;
            }

            if (packet.HasCollection.HasValue)
            {
                build.HasAuthoritativeProfileCollection = true;
            }
        }

        private bool TryResolveCharacterInfoPresence(
            int characterId,
            string characterName,
            RemoteUserActor actor,
            string fallbackLocationSummary,
            int fallbackChannel,
            out string locationSummary,
            out int channel)
        {
            locationSummary = string.IsNullOrWhiteSpace(fallbackLocationSummary)
                ? "Location unknown"
                : fallbackLocationSummary.Trim();
            channel = Math.Max(0, fallbackChannel);

            if (_socialListRuntime.TryFindTrackedEntry(characterName, out SocialTrackedEntrySnapshot trackedEntry) && trackedEntry.IsOnline)
            {
                ApplyCharacterInfoProfileAuthorityFromSocialTrackedEntry(actor?.Build, trackedEntry);
                if (!string.IsNullOrWhiteSpace(trackedEntry.LocationSummary))
                {
                    locationSummary = trackedEntry.LocationSummary.Trim();
                }

                channel = trackedEntry.Channel > 0
                    ? trackedEntry.Channel
                    : Math.Max(channel, 0);
                return true;
            }

            if (TryResolveCharacterInfoPresenceFromPacketWhisperFind(
                    characterName,
                    _socialListRuntime,
                    out string whisperLocation,
                    out int whisperChannel))
            {
                locationSummary = whisperLocation;
                channel = whisperChannel > 0
                    ? whisperChannel
                    : Math.Max(channel, 0);
                return true;
            }

            if (TryResolveCharacterInfoPresenceFromFallbackSnapshots(
                    characterName,
                    _messengerRuntime.GetRemoteParticipantSnapshots(),
                    _familyChartRuntime.BuildTrackedMembersSnapshot(),
                    _familyChartRuntime.TrackedMembersCount,
                    out string fallbackLocation,
                    out int fallbackResolvedChannel))
            {
                locationSummary = fallbackLocation;
                channel = fallbackResolvedChannel > 0
                    ? fallbackResolvedChannel
                    : Math.Max(channel, 0);
                return true;
            }

            if (TryResolveCharacterInfoPresenceFromSocialRoomSnapshots(
                    characterName,
                    BuildCharacterInfoActiveSocialRoomPresenceSnapshots(),
                    GetCurrentMapTransferDisplayName(),
                    Math.Max(1, _simulatorChannelIndex + 1),
                    out string socialRoomLocation,
                    out int socialRoomChannel))
            {
                locationSummary = socialRoomLocation;
                channel = socialRoomChannel > 0
                    ? socialRoomChannel
                    : Math.Max(channel, 0);
                return true;
            }

            if (TryResolveCharacterInfoPresenceFromWeddingSnapshots(
                    characterId,
                    characterName,
                    GetCharacterInfoWeddingParticipantSnapshots(),
                    GetCurrentMapTransferDisplayName(),
                    Math.Max(1, _simulatorChannelIndex + 1),
                    out string weddingLocation,
                    out int weddingChannel))
            {
                locationSummary = weddingLocation;
                channel = weddingChannel;
                return true;
            }

            if (actor?.IsVisibleInWorld == true)
            {
                locationSummary = GetCurrentMapTransferDisplayName();
                channel = Math.Max(1, _simulatorChannelIndex + 1);
                return true;
            }

            return false;
        }

        internal static bool TryResolveCharacterInfoPresenceFromPacketWhisperFind(
            string characterName,
            SocialListRuntime socialListRuntime,
            out string locationSummary,
            out int channel)
        {
            locationSummary = "Location unknown";
            channel = 0;
            if (socialListRuntime == null || string.IsNullOrWhiteSpace(characterName))
            {
                return false;
            }

            if (!socialListRuntime.TryResolvePacketWhisperFindPresence(characterName, out string resolvedLocation, out int resolvedChannel))
            {
                return false;
            }

            locationSummary = string.IsNullOrWhiteSpace(resolvedLocation)
                ? "Location unknown"
                : resolvedLocation.Trim();
            channel = Math.Max(0, resolvedChannel);
            return true;
        }

        internal static bool ApplyCharacterInfoProfileAuthorityFromSocialTrackedEntry(
            CharacterBuild build,
            SocialTrackedEntrySnapshot trackedEntry)
        {
            if (build == null || trackedEntry == null)
            {
                return false;
            }

            bool applied = false;
            if (TryResolveCharacterInfoTrackedLevel(trackedEntry.PrimaryText, trackedEntry.SecondaryText, out int level))
            {
                build.Level = Math.Max(1, level);
                build.HasAuthoritativeProfileLevel = true;
                applied = true;
            }

            if (TryResolveCharacterInfoTrackedJobName(trackedEntry, out string jobName))
            {
                build.JobName = jobName;
                build.HasAuthoritativeProfileJob = true;
                applied = true;
            }

            if (trackedEntry.Tab == SocialListTab.Guild &&
                !string.IsNullOrWhiteSpace(trackedEntry.SecondaryText) &&
                !LooksLikeCharacterInfoTrackedLevel(trackedEntry.SecondaryText))
            {
                build.GuildName = trackedEntry.SecondaryText.Trim();
                build.HasAuthoritativeProfileGuild = true;
                applied = true;
            }

            return applied;
        }

        private static bool TryResolveCharacterInfoTrackedLevel(string primaryText, string secondaryText, out int level)
        {
            return TryParseCharacterInfoTrackedLevel(primaryText, out level)
                   || TryParseCharacterInfoTrackedLevel(secondaryText, out level);
        }

        private static bool TryParseCharacterInfoTrackedLevel(string text, out int level)
        {
            level = 0;
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            string trimmed = text.Trim();
            int lvIndex = trimmed.IndexOf("Lv", StringComparison.OrdinalIgnoreCase);
            if (lvIndex < 0)
            {
                return false;
            }

            int digitStart = lvIndex + 2;
            while (digitStart < trimmed.Length && (trimmed[digitStart] == '.' || char.IsWhiteSpace(trimmed[digitStart])))
            {
                digitStart++;
            }

            int digitEnd = digitStart;
            while (digitEnd < trimmed.Length && char.IsDigit(trimmed[digitEnd]))
            {
                digitEnd++;
            }

            return digitEnd > digitStart
                   && int.TryParse(trimmed[digitStart..digitEnd], NumberStyles.Integer, CultureInfo.InvariantCulture, out level)
                   && level > 0;
        }

        private static bool LooksLikeCharacterInfoTrackedLevel(string text)
        {
            return TryParseCharacterInfoTrackedLevel(text, out _);
        }

        private static bool TryResolveCharacterInfoTrackedJobName(SocialTrackedEntrySnapshot trackedEntry, out string jobName)
        {
            jobName = null;
            if (trackedEntry == null)
            {
                return false;
            }

            string candidate = trackedEntry.PrimaryText?.Trim();
            if (string.IsNullOrWhiteSpace(candidate)
                || LooksLikeCharacterInfoTrackedLevel(candidate)
                || IsCharacterInfoTrackedNonJobLabel(candidate))
            {
                candidate = trackedEntry.SecondaryText?.Trim();
            }

            if (string.IsNullOrWhiteSpace(candidate)
                || LooksLikeCharacterInfoTrackedLevel(candidate)
                || IsCharacterInfoTrackedNonJobLabel(candidate))
            {
                return false;
            }

            jobName = candidate;
            return true;
        }

        private static bool IsCharacterInfoTrackedNonJobLabel(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return true;
            }

            string normalized = text.Trim();
            return normalized.Equals("Leader", StringComparison.OrdinalIgnoreCase)
                   || normalized.Equals("Support", StringComparison.OrdinalIgnoreCase)
                   || normalized.Equals("Scout", StringComparison.OrdinalIgnoreCase)
                   || normalized.Equals("Member", StringComparison.OrdinalIgnoreCase)
                   || normalized.Equals("Jr. Master", StringComparison.OrdinalIgnoreCase)
                   || normalized.Equals("Master", StringComparison.OrdinalIgnoreCase)
                   || normalized.Equals("Guild", StringComparison.OrdinalIgnoreCase)
                   || normalized.Equals("Representative", StringComparison.OrdinalIgnoreCase)
                   || normalized.Contains("online", StringComparison.OrdinalIgnoreCase);
        }

        internal static bool TryResolveCharacterInfoPresenceFromWeddingSnapshots(
            int characterId,
            string characterName,
            IReadOnlyList<WeddingRemoteParticipantSnapshot> weddingSnapshots,
            string currentMapDisplayName,
            int currentChannel,
            out string locationSummary,
            out int channel)
        {
            locationSummary = string.IsNullOrWhiteSpace(currentMapDisplayName)
                ? "Location unknown"
                : currentMapDisplayName.Trim();
            channel = currentChannel > 0 ? currentChannel : 1;

            if (!TryFindCharacterInfoWeddingParticipantSnapshot(characterId, characterName, weddingSnapshots, out _))
            {
                return false;
            }

            return true;
        }

        internal static bool TryFindCharacterInfoWeddingParticipantSnapshot(
            int characterId,
            string characterName,
            IReadOnlyList<WeddingRemoteParticipantSnapshot> weddingSnapshots,
            out WeddingRemoteParticipantSnapshot snapshot)
        {
            snapshot = default;
            if (weddingSnapshots == null || weddingSnapshots.Count == 0)
            {
                return false;
            }

            if (characterId > 0)
            {
                for (int i = 0; i < weddingSnapshots.Count; i++)
                {
                    WeddingRemoteParticipantSnapshot candidate = weddingSnapshots[i];
                    if (candidate.CharacterId != characterId)
                    {
                        continue;
                    }

                    snapshot = candidate;
                    return true;
                }
            }

            if (string.IsNullOrWhiteSpace(characterName))
            {
                return false;
            }

            string resolvedName = characterName.Trim();
            for (int i = 0; i < weddingSnapshots.Count; i++)
            {
                WeddingRemoteParticipantSnapshot candidate = weddingSnapshots[i];
                if (!string.Equals(candidate.Name, resolvedName, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                snapshot = candidate;
                return true;
            }

            return false;
        }

        internal static bool TryResolveCharacterInfoPresenceFromFallbackSnapshots(
            string characterName,
            IReadOnlyList<MessengerRemoteParticipantSnapshot> messengerSnapshots,
            IReadOnlyList<FamilyTrackedMemberSnapshot> familySnapshots,
            int familySnapshotCount,
            out string locationSummary,
            out int channel)
        {
            locationSummary = null;
            channel = 0;
            if (string.IsNullOrWhiteSpace(characterName))
            {
                return false;
            }

            string resolvedCharacterName = characterName.Trim();
            if (messengerSnapshots != null)
            {
                for (int i = 0; i < messengerSnapshots.Count; i++)
                {
                    MessengerRemoteParticipantSnapshot snapshot = messengerSnapshots[i];
                    if (!snapshot.IsOnline
                        || !string.Equals(snapshot.Name, resolvedCharacterName, StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    locationSummary = string.IsNullOrWhiteSpace(snapshot.LocationSummary)
                        ? "Location unknown"
                        : snapshot.LocationSummary.Trim();
                    channel = Math.Max(0, snapshot.Channel);
                    return true;
                }
            }

            if (familySnapshots == null || familySnapshotCount <= 0)
            {
                return false;
            }

            int availableFamilySnapshots = Math.Min(familySnapshotCount, familySnapshots.Count);
            for (int i = 0; i < availableFamilySnapshots; i++)
            {
                FamilyTrackedMemberSnapshot snapshot = familySnapshots[i];
                if (snapshot == null
                    || snapshot.IsLocalPlayer
                    || !snapshot.IsOnline
                    || !string.Equals(snapshot.Name, resolvedCharacterName, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (!TryParseCharacterInfoTrackedLocationSummary(snapshot.LocationSummary, out locationSummary, out channel))
                {
                    locationSummary = string.IsNullOrWhiteSpace(snapshot.LocationSummary)
                        ? "Location unknown"
                        : snapshot.LocationSummary.Trim();
                    channel = 0;
                }

                return true;
            }

            return false;
        }

        internal static bool TryParseCharacterInfoTrackedLocationSummary(
            string trackedLocationSummary,
            out string locationSummary,
            out int channel)
        {
            locationSummary = string.IsNullOrWhiteSpace(trackedLocationSummary)
                ? "Location unknown"
                : trackedLocationSummary.Trim();
            channel = 0;

            if (string.IsNullOrWhiteSpace(trackedLocationSummary))
            {
                return false;
            }

            string trimmed = trackedLocationSummary.Trim();
            if (!TryParseCharacterInfoTrackedLocationWithChannelSuffix(
                    trimmed,
                    out string parsedLocation,
                    out int resolvedChannel))
            {
                return false;
            }

            locationSummary = string.IsNullOrWhiteSpace(parsedLocation)
                ? "Location unknown"
                : parsedLocation;
            channel = resolvedChannel;
            return true;
        }

        private static bool TryParseCharacterInfoTrackedLocationWithChannelSuffix(
            string trackedLocationSummary,
            out string parsedLocation,
            out int resolvedChannel)
        {
            parsedLocation = trackedLocationSummary;
            resolvedChannel = 0;
            if (string.IsNullOrWhiteSpace(trackedLocationSummary))
            {
                return false;
            }

            if (TryParseCharacterInfoTrackedChannelAfterSeparator(
                    trackedLocationSummary,
                    " CH ",
                    out parsedLocation,
                    out resolvedChannel))
            {
                return true;
            }

            if (TryParseCharacterInfoTrackedChannelAfterSeparator(
                    trackedLocationSummary,
                    " CHANNEL ",
                    out parsedLocation,
                    out resolvedChannel))
            {
                return true;
            }

            // Some tracked seams preserve parenthesized channel hints such as:
            // "Henesys Market (CH 3)".
            int openParenIndex = trackedLocationSummary.LastIndexOf("(", StringComparison.Ordinal);
            if (openParenIndex < 0 || !trackedLocationSummary.EndsWith(")", StringComparison.Ordinal))
            {
                return false;
            }

            string suffixBody = trackedLocationSummary[(openParenIndex + 1)..^1].Trim();
            if (!TryParseCharacterInfoTrackedChannelToken(suffixBody, out resolvedChannel))
            {
                return false;
            }

            parsedLocation = trackedLocationSummary[..openParenIndex].TrimEnd();
            return true;
        }

        private static bool TryParseCharacterInfoTrackedChannelAfterSeparator(
            string trackedLocationSummary,
            string separator,
            out string parsedLocation,
            out int resolvedChannel)
        {
            parsedLocation = trackedLocationSummary;
            resolvedChannel = 0;
            int separatorIndex = trackedLocationSummary.LastIndexOf(separator, StringComparison.OrdinalIgnoreCase);
            if (separatorIndex < 0)
            {
                return false;
            }

            string locationSegment = trackedLocationSummary[..separatorIndex].TrimEnd();
            string suffixSegment = trackedLocationSummary[(separatorIndex + separator.Length)..].Trim();
            if (!TryParseCharacterInfoTrackedChannelToken(suffixSegment, out resolvedChannel))
            {
                return false;
            }

            parsedLocation = locationSegment;
            return true;
        }

        private static bool TryParseCharacterInfoTrackedChannelToken(string channelToken, out int channel)
        {
            channel = 0;
            if (string.IsNullOrWhiteSpace(channelToken))
            {
                return false;
            }

            string normalized = channelToken.Trim();
            if (normalized.StartsWith("CH", StringComparison.OrdinalIgnoreCase))
            {
                normalized = normalized[2..].Trim();
            }
            else if (normalized.StartsWith("CHANNEL", StringComparison.OrdinalIgnoreCase))
            {
                normalized = normalized["CHANNEL".Length..].Trim();
            }

            return int.TryParse(normalized, NumberStyles.Integer, CultureInfo.InvariantCulture, out channel)
                   && channel > 0;
        }

