        private bool TryUseInventoryItem(int itemId, InventoryType inventoryType)
        {
            return TryUseInventoryItem(itemId, inventoryType, currTickCount);
        }


        private bool TryUseInventoryItem(int itemId, InventoryType inventoryType, int currentTime)

        {
            if (itemId <= 0 || inventoryType == InventoryType.NONE)
            {
                return false;
            }

            ReleaseActiveKeydownSkillForClientCancelIngress(currentTime);

            if (TryRejectOnlyPickupInventoryUse(itemId, inventoryType, currentTime))
            {
                return false;
            }

            if (TryUseRandomMorphInventoryItem(itemId, inventoryType, currentTime))



            {



                return true;



            }



            if (TryUsePetFoodInventoryItem(itemId, inventoryType, currentTime))



            {



                return true;



            }



            bool used = inventoryType switch
            {
                InventoryType.SETUP => TryUseSetupInventoryItem(itemId, currentTime),
                InventoryType.USE => TryUseItemAuthoredNpcInteractionInventoryItem(itemId, inventoryType, currentTime)
                                     || TryUseConsumableInventoryItem(itemId, inventoryType, currentTime),
                InventoryType.ETC => TryUseItemAuthoredNpcInteractionInventoryItem(itemId, inventoryType, currentTime),
                InventoryType.CASH => TryUseItemAuthoredNpcInteractionInventoryItem(itemId, inventoryType, currentTime)
                                      || TryUseCashInventoryItem(itemId)
                                      || TryUseConsumableInventoryItem(itemId, inventoryType, currentTime),
                _ => false
            };


            if (TryTriggerItemReactorFromInventoryUse(itemId, inventoryType, currentTime, used))
            {
                return true;
            }

            if (!used && TryShowUnhandledFieldRestrictedItemUse(itemId, inventoryType))
            {
                return false;
            }


            return used;

        }

        private bool TryUseInventoryItemAtSlot(int itemId, InventoryType inventoryType, int slotIndex)
        {
            return TryUseInventoryItemAtSlot(itemId, inventoryType, slotIndex, currTickCount);
        }

        private bool TryUseInventoryItemAtSlot(int itemId, InventoryType inventoryType, int slotIndex, int currentTime)
        {
            if (itemId <= 0 ||
                slotIndex < 0 ||
                uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryWindow)
            {
                return false;
            }

            IReadOnlyList<UI.InventorySlotData> slots = inventoryWindow.GetSlots(inventoryType);
            if (slots == null || slotIndex >= slots.Count)
            {
                return false;
            }

            UI.InventorySlotData lockedSlot = slots[slotIndex];
            if (lockedSlot == null ||
                lockedSlot.IsDisabled ||
                lockedSlot.ItemId != itemId ||
                Math.Max(0, lockedSlot.Quantity) <= 0)
            {
                return false;
            }

            ReleaseActiveKeydownSkillForClientCancelIngress(currentTime);

            if (TryRejectOnlyPickupInventoryUse(itemId, inventoryType, currentTime))
            {
                return false;
            }

            if (TryUseRandomMorphInventoryItem(itemId, inventoryType, currentTime, slotIndex))
            {
                return true;
            }

            if (TryUsePetFoodInventoryItem(itemId, inventoryType, currentTime, slotIndex))
            {
                return true;
            }

            bool used = inventoryType switch
            {
                InventoryType.SETUP => TryUseSetupInventoryItem(itemId, currentTime, slotIndex),
                InventoryType.USE => TryUseItemAuthoredNpcInteractionInventoryItem(itemId, inventoryType, currentTime, slotIndex)
                                     || TryUseConsumableInventoryItem(itemId, inventoryType, currentTime, slotIndex),
                InventoryType.ETC => TryUseItemAuthoredNpcInteractionInventoryItem(itemId, inventoryType, currentTime, slotIndex),
                InventoryType.CASH => TryUseItemAuthoredNpcInteractionInventoryItem(itemId, inventoryType, currentTime, slotIndex)
                                      || TryUseCashInventoryItem(itemId)
                                      || TryUseConsumableInventoryItem(itemId, inventoryType, currentTime, slotIndex),
                _ => false
            };

            if (TryTriggerItemReactorFromInventoryUse(itemId, inventoryType, currentTime, used, slotIndex))
            {
                return true;
            }

            if (!used && TryShowUnhandledFieldRestrictedItemUse(itemId, inventoryType))
            {
                return false;
            }

            return used;
        }

        private void ReleaseActiveKeydownSkillForClientCancelIngress(int currentTime)
        {
            var skills = _playerManager?.Skills;
            if (skills == null)
            {
                return;
            }

            using var _ = skills.BeginClientCancelBatchScope();
            skills.ReleaseActiveKeydownSkill(currentTime);
        }

        private void RequestStatusBarBuffCancelForClientCancelIngress(int skillId, int currentTime)
        {
            var skills = _playerManager?.Skills;
            if (skills == null)
            {
                return;
            }

            TryExecuteStatusBarBuffCancelForClientCancelIngress(
                skillId,
                currentTime,
                () => skills.BeginClientCancelBatchScope(),
                tickCount => skills.ReleaseActiveKeydownSkill(tickCount),
                (cancelSkillId, tickCount) => skills.RequestClientSkillCancel(cancelSkillId, tickCount, enforceFieldCancelRestrictions: true));
        }

        private string ExecuteMapleTvClientCancelIngress(Func<string> action)
        {
            return ExecuteMapleTvClientCancelIngressForTests(
                currTickCount,
                ReleaseActiveKeydownSkillForClientCancelIngress,
                action);
        }

        internal static string ExecuteMapleTvClientCancelIngressForTests(
            int currentTime,
            Action<int> releaseActiveKeydownSkillForClientCancelIngress,
            Func<string> action)
        {
            releaseActiveKeydownSkillForClientCancelIngress?.Invoke(currentTime);
            return action?.Invoke() ?? string.Empty;
        }

        private static bool TryExecuteStatusBarBuffCancelForClientCancelIngress(
            int skillId,
            int currentTime,
            Func<IDisposable> beginClientCancelBatchScope,
            Action<int> releaseActiveKeydownSkill,
            Func<int, int, bool> requestClientSkillCancel)
        {
            if (skillId == 1311006)
            {
                return false;
            }

            if (beginClientCancelBatchScope == null
                || releaseActiveKeydownSkill == null
                || requestClientSkillCancel == null)
            {
                return false;
            }

            using var _ = beginClientCancelBatchScope();
            releaseActiveKeydownSkill(currentTime);
            return requestClientSkillCancel(skillId, currentTime);
        }

        internal static bool TryExecuteStatusBarBuffCancelForClientCancelIngressForTests(
            int skillId,
            int currentTime,
            Func<IDisposable> beginClientCancelBatchScope,
            Action<int> releaseActiveKeydownSkill,
            Func<int, int, bool> requestClientSkillCancel)
        {
            return TryExecuteStatusBarBuffCancelForClientCancelIngress(
                skillId,
                currentTime,
                beginClientCancelBatchScope,
                releaseActiveKeydownSkill,
                requestClientSkillCancel);
        }

        private bool TryRejectOnlyPickupInventoryUse(int itemId, InventoryType inventoryType, int currentTime)
        {
            if (itemId <= 0
                || !ShouldRejectOnlyPickupUseOutsidePickupRuntime(
                    inventoryType,
                    InventoryItemMetadataResolver.IsOnlyPickup(itemId)))
            {
                return false;
            }

            string itemName = ResolvePickupItemName(itemId);
            PushFieldRuleMessage(
                BuildOnlyPickupInventoryUseRejectedMessage(itemName),
                currentTime,
                false);
            return true;
        }

        internal static bool ShouldRejectOnlyPickupUseOutsidePickupRuntime(InventoryType inventoryType, bool isOnlyPickupItem)
        {
            return inventoryType != InventoryType.NONE && isOnlyPickupItem;
        }

        internal static string BuildOnlyPickupInventoryUseRejectedMessage(string itemName)
        {
            string normalizedItemName = string.IsNullOrWhiteSpace(itemName)
                ? string.Empty
                : itemName.Trim();
            return string.IsNullOrWhiteSpace(normalizedItemName)
                ? "That item can only be used when picked up."
                : $"{normalizedItemName} can only be used when picked up.";
        }



        private bool TryTriggerItemReactorFromInventoryUse(
            int itemId,
            InventoryType inventoryType,
            int currentTime,
            bool itemAlreadyConsumed,
            int? slotIndex = null)
        {
            if (itemId <= 0
                || inventoryType == InventoryType.NONE
                || _reactorPool == null
                || _playerManager?.Player == null)
            {
                return false;
            }


            string restrictionMessage = GetFieldItemUseRestrictionMessage(inventoryType, itemId, 1);
            if (!string.IsNullOrWhiteSpace(restrictionMessage))
            {
                return false;
            }


            float playerX = _playerManager.Player.X;
            float playerY = _playerManager.Player.Y;
            var matchingReactors = _reactorPool.FindItemReactorsAroundLocalUser(playerX, playerY, itemId, currentTick: currentTime);
            if (matchingReactors.Count == 0)
            {
                return false;
            }


            if (!itemAlreadyConsumed)
            {
                if (uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryRuntime
                    || !TryConsumeInventoryUseItem(inventoryRuntime, inventoryType, itemId, 1, slotIndex))
                {
                    return false;
                }
            }


            _reactorPool.TriggerItemReactorsAroundLocalUser(playerX, playerY, itemId, playerId: 0, currentTime);

            return true;

        }



        private bool TryUseCashInventoryItem(int itemId)
        {
            if (itemId <= 0 || uiWindowManager == null)
            {
                return false;
            }


            InventoryItemMetadataResolver.TryResolveItemName(itemId, out string itemName);
            InventoryItemMetadataResolver.TryResolveItemDescription(itemId, out string itemDescription);
            if (!TeleportItemUsageEvaluator.IsTeleportItem(itemId, InventoryType.CASH, itemName, itemDescription))
            {
                return false;
            }


            string restrictionMessage = FieldInteractionRestrictionEvaluator.GetTeleportItemRestrictionMessage(_mapBoard?.MapInfo?.fieldLimit ?? 0);
            if (!string.IsNullOrWhiteSpace(restrictionMessage))
            {
                ShowFieldRestrictionMessage(restrictionMessage);
                return false;
            }


            _worldMapRequestMode = WorldMapRequestMode.DirectTransfer;
            _mapTransferEditDestination = null;
            RefreshMapTransferWindow();

            string mapTransferWindowRestriction = FieldInteractionRestrictionEvaluator.GetWindowOpenRestrictionMessage(
                _mapBoard?.MapInfo?.fieldLimit ?? 0,
                _mapBoard?.MapInfo,
                MapSimulatorWindowNames.MapTransfer);
            if (!string.IsNullOrWhiteSpace(mapTransferWindowRestriction))
            {
                ShowFieldRestrictionMessage(mapTransferWindowRestriction);
                return false;
            }

            if (!TryOpenFieldRestrictedWindow(
                MapSimulatorWindowNames.MapTransfer,
                inheritDirectionModeOwner: true))
            {
                return false;
            }

            uiWindowManager.HideWindow(MapSimulatorWindowNames.WorldMap);
            return true;
        }

        private bool TryShowUnhandledFieldRestrictedItemUse(int itemId, InventoryType inventoryType)
        {
            if (inventoryType is not (InventoryType.USE or InventoryType.CASH or InventoryType.ETC)
                || itemId <= 0
                || !HasInventoryItem(itemId))
            {
                return false;
            }

            InventoryItemMetadataResolver.TryResolveItemName(itemId, out string itemName);
            InventoryItemMetadataResolver.TryResolveItemDescription(itemId, out string itemDescription);
            if (inventoryType == InventoryType.CASH
                && TeleportItemUsageEvaluator.IsTeleportItem(itemId, inventoryType, itemName, itemDescription))
            {
                return false;
            }

            if (ResolvePetFoodItemEffect(itemId).IsPetFood)
            {
                return false;
            }

            if (InventoryItemMetadataResolver.HasAuthoredNpcInteraction(itemId))
            {
                return false;
            }

            ConsumableItemEffect consumableEffect = ResolveConsumableItemEffect(itemId);
            if (consumableEffect.HasSupportedRecovery
                || consumableEffect.HasSupportedProgression
                || consumableEffect.HasSupportedMovement
                || consumableEffect.HasSupportedMorph
                || consumableEffect.HasSupportedTemporaryBuff
                || consumableEffect.HasSupportedCure
                || consumableEffect.HasSupportedFieldProtection)
            {
                return false;
            }

            string restrictionMessage = GetFieldItemUseRestrictionMessage(inventoryType, itemId, 1);
            if (string.IsNullOrWhiteSpace(restrictionMessage))
            {
                return false;
            }

            ShowFieldRestrictionMessage(restrictionMessage);
            return true;
        }


        private bool TryUsePetFoodInventoryItem(int itemId, InventoryType inventoryType, int currentTime, int? slotIndex = null)



        {



            if (itemId <= 0 ||



                (inventoryType != InventoryType.USE && inventoryType != InventoryType.CASH) ||



                uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryWindow ||



                _playerManager?.Pets == null)



            {



                return false;



            }







            PetFoodItemEffect effect = ResolvePetFoodItemEffect(itemId);



            if (!effect.IsPetFood)



            {



                return false;



            }







            string fieldItemRestrictionMessage = GetFieldItemUseRestrictionMessage(inventoryType, itemId, 1);



            if (!string.IsNullOrWhiteSpace(fieldItemRestrictionMessage))



            {



                ShowFieldRestrictionMessage(fieldItemRestrictionMessage);



                return false;



            }







            if (inventoryWindow.GetItemCount(inventoryType, itemId) <= 0)



            {



                return false;



            }







            if (!_playerManager.Pets.TryPlanFoodItemUse(
                    effect.SupportedPetItemIds,
                    effect.FullnessIncrease,
                    out PetController.PetFoodItemUsePlan foodPlan,
                    out PetController.PetFoodItemUseFailureReason failureReason))
            {
                PushFieldRuleMessage(BuildPetFoodFailureMessage(failureReason), currentTime, false);

                return false;

            }






            if (foodPlan.ConsumeItem && !TryConsumeInventoryUseItem(inventoryWindow, inventoryType, itemId, 1, slotIndex))



            {



                return false;



            }







            if (!_playerManager.Pets.TryExecuteFoodItemUse(foodPlan, currentTime, out _))



            {



                return false;



            }







            if (foodPlan.ConsumeItem)



            {



                _fieldRuleRuntime?.RegisterSuccessfulItemUse(
                    ShouldTrackFieldConsumeItemCooldown(inventoryType, effect, default),
                    currentTime);



            }







            return true;



        }



        private bool TryUseItemAuthoredNpcInteractionInventoryItem(
            int itemId,
            InventoryType inventoryType,
            int currentTime,
            int? slotIndex = null)
        {
            if (itemId <= 0 ||
                uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryWindow)
            {
                return false;
            }

            bool hasNpcReference = InventoryItemMetadataResolver.TryResolveNpcReference(itemId, out int npcId)
                                   && npcId > 0;
            bool hasScriptPublications = InventoryItemMetadataResolver.TryResolveSpecScriptPublications(
                itemId,
                out IReadOnlyList<FieldObjectScriptPublication> scriptPublications);
            bool hasScript = InventoryItemMetadataResolver.TryResolveSpecScripts(itemId, out IReadOnlyList<string> scriptNames);
            string scriptName = hasScript && scriptNames.Count > 0
                ? scriptNames[0]
                : null;
            if (!hasNpcReference && !hasScript && !hasScriptPublications)
            {
                return false;
            }

            string fieldItemRestrictionMessage = GetFieldItemUseRestrictionMessage(inventoryType, itemId, 1);
            if (!string.IsNullOrWhiteSpace(fieldItemRestrictionMessage))
            {
                ShowFieldRestrictionMessage(fieldItemRestrictionMessage);
                return false;
            }

            if (inventoryWindow.GetItemCount(inventoryType, itemId) <= 0)
            {
                return false;
            }

            if (!TryOpenItemAuthoredInventoryInteraction(
                    itemId,
                    npcId,
                    scriptName,
                    scriptNames,
                    scriptPublications))
            {
                return false;
            }

            bool consumeOnUse = !InventoryItemMetadataResolver.IsNotConsumedOnUse(itemId);
            if (consumeOnUse &&
                !TryConsumeInventoryUseItem(inventoryWindow, inventoryType, itemId, 1, slotIndex))
            {
                return false;
            }

            _fieldRuleRuntime?.RegisterSuccessfulItemUse(
                ShouldTrackFieldConsumeItemCooldown(inventoryType, default, default),
                currentTime);
            return true;
        }

        private bool TryOpenItemAuthoredInventoryInteraction(
            int itemId,
            int npcId,
            string scriptName,
            IReadOnlyList<string> publishedItemScriptNames = null,
            IReadOnlyList<FieldObjectScriptPublication> publishedItemScriptPublications = null)
        {
            IReadOnlyList<FieldObjectScriptPublication> publishedScriptPublications =
                BuildItemAuthoredInteractionPublishedScriptPublications(
                    npcId,
                    publishedItemScriptNames,
                    scriptName,
                    publishedItemScriptPublications);
            if (publishedScriptPublications.Count > 0)
            {
                PublishDynamicObjectTagStatesForScriptPublications(publishedScriptPublications, currTickCount);
            }

            NpcItem npcPreview = CreateNpcPreview(npcId, includeTooltips: false);
            if (npcPreview != null)
            {
                OpenNpcInteraction(npcPreview);
                return true;
            }

            if (_npcInteractionOverlay == null)
            {
                return false;
            }

            string itemName = ResolvePickupItemName(itemId);
            string npcName = ResolveItemAuthoredInteractionNpcName(npcId);
            NpcInteractionState interactionState = CreateItemAuthoredInventoryInteractionState(
                itemId,
                itemName,
                npcId,
                npcName,
                scriptName);
            if (interactionState == null)
            {
                return false;
            }

            _gameState.EnterDirectionMode();
            _scriptedDirectionModeOwnerActive = true;
            _activeNpcInteractionNpc = null;
            _activeNpcInteractionNpcId = npcId;

            _npcInteractionOverlay.Open(interactionState);
            return true;
        }

        internal static IReadOnlyList<string> BuildItemAuthoredInteractionPublishedScriptNames(
            int npcId,
            IEnumerable<string> scriptNames,
            string primaryScriptName = null,
            Func<int, IReadOnlyList<string>> npcScriptNameResolver = null)
        {
            IEnumerable<string> npcScriptNames = Array.Empty<string>();
            if (npcId > 0)
            {
                npcScriptNameResolver ??= FieldObjectNpcScriptNameResolver.ResolvePublishedScriptNames;
                npcScriptNames = npcScriptNameResolver(npcId) ?? Array.Empty<string>();
            }

            List<string> additionalRawScriptNames = scriptNames?
                .Where(script => !string.IsNullOrWhiteSpace(script))
                .Select(script => script.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList()
                ?? new List<string>();
            if (!string.IsNullOrWhiteSpace(primaryScriptName)
                && !additionalRawScriptNames.Contains(primaryScriptName, StringComparer.OrdinalIgnoreCase))
            {
                additionalRawScriptNames.Add(primaryScriptName.Trim());
            }

            return QuestRuntimeManager.BuildPublishedScriptNames(
                npcScriptNames,
                additionalRawScriptNames.ToArray());
        }

        internal static IReadOnlyList<FieldObjectScriptPublication> BuildItemAuthoredInteractionPublishedScriptPublications(
            int npcId,
            IEnumerable<string> scriptNames,
            string primaryScriptName = null,
            IEnumerable<FieldObjectScriptPublication> additionalScriptPublications = null,
            Func<int, IReadOnlyList<FieldObjectScriptPublication>> npcScriptPublicationResolver = null)
        {
            IEnumerable<FieldObjectScriptPublication> npcScriptPublications = Array.Empty<FieldObjectScriptPublication>();
            if (npcId > 0)
            {
                npcScriptPublicationResolver ??= FieldObjectNpcScriptNameResolver.ResolvePublishedScriptPublications;
                npcScriptPublications = npcScriptPublicationResolver(npcId) ?? Array.Empty<FieldObjectScriptPublication>();
            }

            List<FieldObjectScriptPublication> publicationCandidates = npcScriptPublications.ToList();
            if (additionalScriptPublications != null)
            {
                publicationCandidates.AddRange(additionalScriptPublications);
            }

            List<string> additionalRawScriptNames = scriptNames?
                .Where(script => !string.IsNullOrWhiteSpace(script))
                .Select(script => script.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList()
                ?? new List<string>();
            if (!string.IsNullOrWhiteSpace(primaryScriptName)
                && !additionalRawScriptNames.Contains(primaryScriptName, StringComparer.OrdinalIgnoreCase))
            {
                additionalRawScriptNames.Add(primaryScriptName.Trim());
            }

            return QuestRuntimeManager.BuildPublishedScriptPublications(
                publicationCandidates,
                additionalRawScriptNames.ToArray());
        }

        internal static IReadOnlyList<FieldObjectScriptPublication> BuildItemAuthoredInteractionPublishedScriptPublications(
            int npcId,
            string scriptName,
            IEnumerable<FieldObjectScriptPublication> additionalScriptPublications = null,
            Func<int, IReadOnlyList<FieldObjectScriptPublication>> npcScriptPublicationResolver = null)
        {
            return BuildItemAuthoredInteractionPublishedScriptPublications(
                npcId,
                string.IsNullOrWhiteSpace(scriptName)
                    ? Array.Empty<string>()
                    : new[] { scriptName },
                scriptName,
                additionalScriptPublications,
                npcScriptPublicationResolver);
        }

        internal static IReadOnlyList<string> BuildItemAuthoredInteractionPublishedScriptNames(
            int npcId,
            string scriptName,
            Func<int, IReadOnlyList<string>> npcScriptNameResolver = null)
        {
            return BuildItemAuthoredInteractionPublishedScriptNames(
                npcId,
                string.IsNullOrWhiteSpace(scriptName)
                    ? Array.Empty<string>()
                    : new[] { scriptName },
                scriptName,
                npcScriptNameResolver);
        }

        private string ResolveItemAuthoredInteractionNpcName(int npcId)
        {
            if (npcId <= 0)
            {
                return string.Empty;
            }

            if (Program.InfoManager?.NpcNameCache != null
                && Program.InfoManager.NpcNameCache.TryGetValue(npcId.ToString(CultureInfo.InvariantCulture), out Tuple<string, string> npcInfo)
                && !string.IsNullOrWhiteSpace(npcInfo?.Item1))
            {
                return npcInfo.Item1.Trim();
            }

            NpcInfo info = NpcInfo.Get(npcId.ToString(CultureInfo.InvariantCulture));
            return string.IsNullOrWhiteSpace(info?.StringName)
                ? string.Empty
                : info.StringName.Trim();
        }

        internal static NpcInteractionState CreateItemAuthoredInventoryInteractionState(
            int itemId,
            string itemName,
            int npcId,
            string npcName,
            string scriptName)
        {
            string trimmedItemName = string.IsNullOrWhiteSpace(itemName)
                ? $"Item {itemId}"
                : itemName.Trim();
            string trimmedNpcName = string.IsNullOrWhiteSpace(npcName)
                ? string.Empty
                : npcName.Trim();
            string trimmedScriptName = string.IsNullOrWhiteSpace(scriptName)
                ? string.Empty
                : scriptName.Trim();
            if (itemId <= 0
                && npcId <= 0
                && string.IsNullOrWhiteSpace(trimmedItemName)
                && string.IsNullOrWhiteSpace(trimmedNpcName)
                && string.IsNullOrWhiteSpace(trimmedScriptName))
            {
                return null;
            }

            string speakerName = !string.IsNullOrWhiteSpace(trimmedNpcName)
                ? trimmedNpcName
                : trimmedItemName;
            string subtitle = !string.IsNullOrWhiteSpace(trimmedScriptName)
                ? $"Item script: {trimmedScriptName}"
                : npcId > 0
                    ? $"Item-authored NPC service ({npcId})"
                    : "Item-authored interaction";

            List<string> pageLines = new()
            {
                "This inventory item opens an authored NPC or script interaction through the shared item-use seam."
            };

            if (itemId > 0)
            {
                pageLines.Add($"Item: {trimmedItemName} ({itemId})");
            }

            if (npcId > 0)
            {
                pageLines.Add(string.IsNullOrWhiteSpace(trimmedNpcName)
                    ? $"NPC template: {npcId}"
                    : $"NPC template: {trimmedNpcName} ({npcId})");
            }

            if (!string.IsNullOrWhiteSpace(trimmedScriptName))
            {
                pageLines.Add($"Script: {trimmedScriptName}");
            }

            pageLines.Add("The client owns the exact branch after launch; the simulator preserves the authored route instead of rejecting the item use.");
            string body = string.Join("\n", pageLines);

            return new NpcInteractionState
            {
                NpcName = speakerName,
                SpeakerTemplateId = npcId,
                SelectedEntryId = Math.Max(itemId, 1),
                Entries = new[]
                {
                    new NpcInteractionEntry
                    {
                        EntryId = Math.Max(itemId, 1),
                        Kind = NpcInteractionEntryKind.Utility,
                        Title = trimmedItemName,
                        Subtitle = subtitle,
                        Pages = new[]
                        {
                            new NpcInteractionPage
                            {
                                RawText = body,
                                Text = body
                            }
                        }
                    }
                }
            };
        }

