        private sealed class PendingRepairDurabilityRequest
        {
            public long SentTick { get; init; }
            public int NpcTemplateId { get; init; }
            public short OperationCode { get; init; }
            public bool RepairAll { get; init; }
            public int TotalCost { get; init; }
            public int PreferredItemId { get; init; }
            public int EncodedSlotPosition { get; init; }
            public RepairDurabilityWindow.RepairEntry Entry { get; init; }
            public IReadOnlyList<RepairDurabilityWindow.RepairEntry> Entries { get; init; }
            public int ResponseDelayMs { get; init; } = RepairDurabilityResponseDelayMs;
            public string RequestLabel { get; init; } = string.Empty;
        }

        private const int RepairDurabilityResponseDelayMs = 120;
        private const int RepairDurabilityExternalResultFallbackDelayMs = 750;
        private const short RepairDurabilityAllOpcode = 130;
        private const short RepairDurabilitySingleOpcode = 131;



        private void RefreshRepairDurabilityWindow(int npcTemplateId, int preferredItemId = 0)
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.RepairDurability) is not RepairDurabilityWindow repairWindow)
            {
                return;
            }


            int effectiveNpcTemplateId = npcTemplateId > 0 ? npcTemplateId : repairWindow.NpcTemplateId;
            int previousNpcTemplateId = repairWindow.NpcTemplateId;

            repairWindow.ConfigureNpc(effectiveNpcTemplateId, ResolveNpcDisplayName(effectiveNpcTemplateId));
            if (effectiveNpcTemplateId <= 0)
            {
                repairWindow.SetNpcPreview(null);
            }
            else if (effectiveNpcTemplateId != previousNpcTemplateId || !repairWindow.HasNpcPreview)
            {
                repairWindow.SetNpcPreview(CreateRepairDurabilityNpcPreview(effectiveNpcTemplateId));
            }

            repairWindow.SetEntries(BuildRepairDurabilityEntries(), preferredItemId);
            repairWindow.SetAwaitingRepairResponse(_pendingRepairDurabilityRequest != null);
            repairWindow.SetStatusMessage(_pendingRepairDurabilityRequest?.RequestLabel ?? GetRepairDurabilityStatusMessage());

        }



        private string GetRepairDurabilityStatusMessage()
        {
            if (_playerManager?.Player?.Build == null)
            {
                return "No player build is bound to the repair owner.";
            }


            int repairableCount = BuildRepairDurabilityEntries().Count;
            if (repairableCount <= 0)
            {
                return "No equip inventory or equipped item currently needs durability repair.";
            }


            long mesoCount = (uiWindowManager?.InventoryWindow as IInventoryRuntime)?.GetMesoCount() ?? 0;

            return $"Repairable items: {repairableCount}. Available meso: {mesoCount.ToString("N0", CultureInfo.InvariantCulture)}.";

        }



        private List<RepairDurabilityWindow.RepairEntry> BuildRepairDurabilityEntries()
        {
            var entries = new List<RepairDurabilityWindow.RepairEntry>();
            IInventoryRuntime inventory = uiWindowManager?.InventoryWindow as IInventoryRuntime;
            AppendRepairDurabilityInventoryEntries(entries, inventory);

            CharacterBuild build = _playerManager?.Player?.Build;
            if (build != null)
            {
                LoginAvatarLook avatarLook = LoginAvatarLookCodec.CreateLook(build);
                var equippedEntries = new List<RepairDurabilityWindow.RepairEntry>();
                AppendRepairDurabilityEquippedEntries(
                    equippedEntries,
                    build,
                    avatarLook?.VisibleEquipmentByBodyPart,
                    avatarLook?.HiddenEquipmentByBodyPart);

                IReadOnlyList<int> clientPositionOrder = RepairDurabilityClientParity.BuildClientEquippedPositionOrder(
                    equippedEntries.Select(static entry => entry.EncodedSlotPosition));
                foreach (int encodedPosition in clientPositionOrder)
                {
                    entries.AddRange(equippedEntries
                        .Where(entry => entry.EncodedSlotPosition == encodedPosition)
                        .OrderBy(entry => entry.Part?.ItemId ?? 0));
                }
            }

            // CRepairDurabilityDlg::SetItems appends damaged inventory entries first,
            // then appends damaged equipped entries in client nPOS order.
            return entries;
        }
        
        private void AppendRepairDurabilityInventoryEntries(
            ICollection<RepairDurabilityWindow.RepairEntry> entries,
            IInventoryRuntime inventory)
        {
            if (entries == null || inventory == null)
            {
                return;
            }

            IReadOnlyList<InventorySlotData> equipSlots = inventory.GetSlots(InventoryType.EQUIP);
            for (int i = 0; i < equipSlots.Count; i++)
            {
                InventorySlotData slot = equipSlots[i];
                CharacterPart part = ResolveRepairDurabilityInventoryPart(slot);
                if (!TryGetRepairDurabilityValues(part, out int currentDurability, out int maxDurability))
                {
                    continue;
                }

                entries.Add(new RepairDurabilityWindow.RepairEntry
                {
                    InventorySlot = slot,
                    EncodedSlotPosition = i + 1,
                    IsInventorySlot = true,
                    SlotLabel = $"Equip INV {i + 1}",
                    ItemName = ResolveRepairDurabilityItemName(part, slot?.ItemId ?? 0),
                    CurrentDurability = currentDurability,
                    MaxDurability = maxDurability,
                    RepairCost = CalculateRepairDurabilityCost(part, currentDurability, maxDurability),
                    IsCashItem = part?.IsCash == true,
                    AvailabilityText = currentDurability <= 0 ? "Broken" : "Repairable",
                    Icon = part?.IconRaw ?? part?.Icon
                });
            }
        }

        private static void AppendRepairDurabilityEquippedEntries(
            ICollection<RepairDurabilityWindow.RepairEntry> entries,
            CharacterBuild build,
            IReadOnlyDictionary<byte, int> visibleEquipmentByBodyPart,
            IReadOnlyDictionary<byte, int> hiddenEquipmentByBodyPart)
        {
            if (entries == null || build == null)
            {
                return;
            }

            HashSet<Character.EquipSlot> candidateSlots = new();
            if (build.Equipment != null)
            {
                foreach (Character.EquipSlot slot in build.Equipment.Keys)
                {
                    candidateSlots.Add(slot);
                }
            }

            if (build.HiddenEquipment != null)
            {
                foreach (Character.EquipSlot slot in build.HiddenEquipment.Keys)
                {
                    candidateSlots.Add(slot);
                }
            }

            foreach (Character.EquipSlot slot in candidateSlots)
            {
                CharacterPart part = ResolveRepairDurabilityEquippedPart(build, slot);
                if (!TryGetRepairDurabilityValues(part, out int currentDurability, out int maxDurability))
                {
                    continue;
                }

                bool preferHiddenLayer = build.HiddenEquipment?.TryGetValue(slot, out CharacterPart hiddenPart) == true
                    && ReferenceEquals(part, hiddenPart);
                int encodedPosition = EncodeRepairDurabilityEquippedPosition(
                    slot,
                    part?.ItemId ?? 0,
                    preferHiddenLayer,
                    visibleEquipmentByBodyPart,
                    hiddenEquipmentByBodyPart);
                if (encodedPosition == int.MinValue)
                {
                    continue;
                }


                entries.Add(new RepairDurabilityWindow.RepairEntry
                {
                    Part = part,
                    EncodedSlotPosition = encodedPosition,
                    Slot = slot,
                    IsInventorySlot = false,
                    IsHiddenSlot = preferHiddenLayer,
                    SlotLabel = BuildRepairDurabilitySlotLabel(slot),
                    ItemName = ResolveRepairDurabilityItemName(part, part.ItemId),
                    CurrentDurability = currentDurability,
                    MaxDurability = maxDurability,
                    RepairCost = CalculateRepairDurabilityCost(part, currentDurability, maxDurability),
                    IsCashItem = part.IsCash,
                    AvailabilityText = currentDurability <= 0 ? "Broken" : "Repairable",
                    Icon = part.IconRaw ?? part.Icon
                });
            }
        }

        private static CharacterPart ResolveRepairDurabilityEquippedPart(CharacterBuild build, Character.EquipSlot slot)
        {
            if (build == null)
            {
                return null;
            }

            CharacterPart visiblePart = EquipSlotStateResolver.GetEquippedPart(build, slot);
            CharacterPart underlyingPart = EquipSlotStateResolver.ResolveUnderlyingPart(build, slot);
            if (underlyingPart != null)
            {
                return underlyingPart;
            }

            return slot switch
            {
                Character.EquipSlot.Coat => EquipSlotStateResolver.ResolveDisplayedPart(build, Character.EquipSlot.Coat),
                Character.EquipSlot.Pants => EquipSlotStateResolver.ResolveDisplayedPart(build, Character.EquipSlot.Pants),
                _ => visiblePart ?? EquipSlotStateResolver.ResolveDisplayedPart(build, slot)
            };
        }


        private CharacterPart ResolveRepairDurabilityInventoryPart(InventorySlotData slot)
        {
            if (slot == null || slot.ItemId <= 0)
            {
                return null;
            }

            CharacterLoader loader = _playerManager?.Loader;
            if (slot.TooltipPart == null && loader != null)
            {
                slot.TooltipPart = loader.LoadEquipment(slot.ItemId);
            }

            return slot.TooltipPart;
        }

        private static bool TryGetRepairDurabilityValues(CharacterPart part, out int currentDurability, out int maxDurability)
        {
            currentDurability = 0;
            maxDurability = 0;
            if (part == null || !part.Durability.HasValue || !part.MaxDurability.HasValue)
            {
                return false;
            }

            maxDurability = Math.Max(0, part.MaxDurability.Value);
            currentDurability = Math.Clamp(part.Durability.Value, 0, maxDurability);
            return maxDurability > 0 && currentDurability < maxDurability;
        }

        private static string BuildRepairDurabilitySlotLabel(Character.EquipSlot slot)
        {
            return slot switch
            {
                Character.EquipSlot.FaceAccessory => "Face",
                Character.EquipSlot.EyeAccessory => "Eyes",
                Character.EquipSlot.Longcoat => "Overall",
                Character.EquipSlot.Pendant2 => "Pendant2",
                Character.EquipSlot.Ring1 => "Ring1",
                Character.EquipSlot.Ring2 => "Ring2",
                Character.EquipSlot.Ring3 => "Ring3",
                Character.EquipSlot.Ring4 => "Ring4",
                Character.EquipSlot.AndroidHeart => "Heart",
                Character.EquipSlot.TamingMob => "Mount",
                _ => slot.ToString()
            };
        }

        private static string ResolveRepairDurabilityItemName(CharacterPart part, int itemId)
        {
            return !string.IsNullOrWhiteSpace(part?.Name)
                ? part.Name
                : itemId > 0
                    ? $"Item {itemId}"
                    : "Unknown item";
        }


        private static int CalculateRepairDurabilityCost(CharacterPart part, int currentDurability, int maxDurability)
        {
            if (part == null || maxDurability <= 0 || currentDurability >= maxDurability)
            {
                return 0;
            }


            int level = Math.Max(1, part.RequiredLevel);
            double sellPrice = part.SellPrice > 0
                ? part.SellPrice
                : Math.Max(1d, level * level * 2d);
            double lostPercent = 100d - ((100d * currentDurability) / maxDurability);
            double durabilityScale = maxDurability / 100d;
            if (durabilityScale <= 0d)
            {
                return 0;
            }


            double epicMultiplier = part.IsEpic ? 1.25d : 1d;
            double cost = lostPercent * (((double)level * level) * (sellPrice / 50d) / durabilityScale) * epicMultiplier;
            if (double.IsNaN(cost) || double.IsInfinity(cost))
            {
                return 0;
            }


            return Math.Max(0, (int)Math.Round(cost));

        }



        private void HandleRepairDurabilityRequested(RepairDurabilityWindow.RepairEntry entry)
        {
            CharacterPart targetPart = ResolveRepairDurabilityTargetPart(entry);
            if (targetPart == null)
            {
                return;
            }


            IInventoryRuntime inventory = uiWindowManager?.InventoryWindow as IInventoryRuntime;
            if (inventory == null)
            {
                ShowUtilityFeedbackMessage("Durability repair is unavailable because the inventory runtime is not active.");
                return;
            }


            if (entry.RepairCost <= 0)
            {
                ShowUtilityFeedbackMessage($"{entry.ItemName} does not currently need durability repair.");
                return;
            }


            if (_pendingRepairDurabilityRequest != null)
            {
                ShowUtilityFeedbackMessage("A durability repair request is already awaiting a result.");
                RefreshRepairDurabilityWindow(0, targetPart.ItemId);
                return;
            }
            if (inventory.GetMesoCount() < entry.RepairCost)
            {
                ShowUtilityFeedbackMessage($"Not enough meso to repair {entry.ItemName}.");
                RefreshRepairDurabilityWindow(0, targetPart.ItemId);
                return;
            }


            int npcTemplateId = GetActiveRepairDurabilityNpcTemplateId();
            string npcName = ResolveNpcDisplayName(npcTemplateId);
            string requestLabel = BuildRepairDurabilityOutboundRequestLabel(
                RepairDurabilitySingleOpcode,
                entry.EncodedSlotPosition,
                $"Sent repair request for {entry.ItemName} to {npcName}.",
                out int responseDelayMs);
            _pendingRepairDurabilityRequest = new PendingRepairDurabilityRequest
            {
                SentTick = Environment.TickCount64,
                NpcTemplateId = npcTemplateId,
                OperationCode = RepairDurabilitySingleOpcode,
                RepairAll = false,
                TotalCost = entry.RepairCost,
                PreferredItemId = targetPart.ItemId,
                EncodedSlotPosition = entry.EncodedSlotPosition,
                Entry = entry,
                Entries = new[] { entry },
                ResponseDelayMs = responseDelayMs,
                RequestLabel = requestLabel
            };

            ShowUtilityFeedbackMessage(requestLabel);
            RefreshRepairDurabilityWindow(npcTemplateId, targetPart.ItemId);

        }



        private void HandleRepairDurabilityAllRequested(IReadOnlyList<RepairDurabilityWindow.RepairEntry> entries)
        {
            if (entries == null || entries.Count == 0)
            {
                ShowUtilityFeedbackMessage("No repairable equip inventory or equipped item is currently available.");
                return;
            }


            IInventoryRuntime inventory = uiWindowManager?.InventoryWindow as IInventoryRuntime;
            if (inventory == null)
            {
                ShowUtilityFeedbackMessage("Durability repair is unavailable because the inventory runtime is not active.");
                return;
            }


            int totalCost = entries.Sum(entry => Math.Max(0, entry?.RepairCost ?? 0));
            if (totalCost <= 0)
            {
                ShowUtilityFeedbackMessage("No repairable equip inventory or equipped item is currently available.");
                return;
            }


            if (_pendingRepairDurabilityRequest != null)
            {
                ShowUtilityFeedbackMessage("A durability repair request is already awaiting a result.");
                RefreshRepairDurabilityWindow(0);
                return;
            }
            if (inventory.GetMesoCount() < totalCost)
            {
                ShowUtilityFeedbackMessage("Not enough meso to repair every damaged repairable item.");
                RefreshRepairDurabilityWindow(0);
                return;
            }


            int npcTemplateId = GetActiveRepairDurabilityNpcTemplateId();
            string npcName = ResolveNpcDisplayName(npcTemplateId);
            string requestLabel = BuildRepairDurabilityOutboundRequestLabel(
                RepairDurabilityAllOpcode,
                int.MinValue,
                $"Sent repair-all request for {entries.Count} item(s) to {npcName}.",
                out int responseDelayMs);
            _pendingRepairDurabilityRequest = new PendingRepairDurabilityRequest
            {
                SentTick = Environment.TickCount64,
                NpcTemplateId = npcTemplateId,
                OperationCode = RepairDurabilityAllOpcode,
                RepairAll = true,
                TotalCost = totalCost,
                Entries = entries
                    .Where(candidate => ResolveRepairDurabilityTargetPart(candidate) != null)
                    .ToArray(),
                ResponseDelayMs = responseDelayMs,
                RequestLabel = requestLabel
            };

            ShowUtilityFeedbackMessage(requestLabel);
            RefreshRepairDurabilityWindow(npcTemplateId);

        }



        private int GetActiveRepairDurabilityNpcTemplateId()
        {
            return uiWindowManager?.GetWindow(MapSimulatorWindowNames.RepairDurability) is RepairDurabilityWindow repairWindow
                ? repairWindow.NpcTemplateId
                : 0;
        }

        private string BuildRepairDurabilityOutboundRequestLabel(
            short opcode,
            int encodedSlotPosition,
            string localMessage,
            out int responseDelayMs)
        {
            responseDelayMs = RepairDurabilityResponseDelayMs;
            byte[] payload = RepairDurabilityClientParity.BuildRepairRequestPayload(opcode, encodedSlotPosition);
            string payloadHex = payload.Length > 0 ? Convert.ToHexString(payload) : "<empty>";
            string dispatchStatus = "live bridge unavailable";
            string outboxStatus = "packet outbox unavailable";

            if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(opcode, payload, out dispatchStatus))
            {
                responseDelayMs = RepairDurabilityExternalResultFallbackDelayMs;
                return $"{localMessage} Mirrored opcode {opcode} [{payloadHex}] through the live local-utility bridge. {dispatchStatus}";
            }

            if (_localUtilityPacketOutbox.TrySendOutboundPacket(opcode, payload, out outboxStatus))
            {
                responseDelayMs = RepairDurabilityExternalResultFallbackDelayMs;
                return $"{localMessage} Mirrored opcode {opcode} [{payloadHex}] through the generic local-utility outbox after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
            }

            if (_localUtilityOfficialSessionBridge.IsRunning
                && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(opcode, payload, out string queuedBridgeStatus))
            {
                responseDelayMs = RepairDurabilityExternalResultFallbackDelayMs;
                return $"{localMessage} Queued opcode {opcode} [{payloadHex}] for deferred official-session injection after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred bridge: {queuedBridgeStatus}";
            }

            if (_localUtilityPacketOutbox.TryQueueOutboundPacket(opcode, payload, out string queuedOutboxStatus))
            {
                responseDelayMs = RepairDurabilityExternalResultFallbackDelayMs;
                return $"{localMessage} Queued opcode {opcode} [{payloadHex}] for deferred generic local-utility outbox delivery after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred outbox: {queuedOutboxStatus}";
            }

            return $"{localMessage} The repair owner will fall back to its local delayed response because neither the live bridge nor the packet outbox accepted opcode {opcode}. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
        }

        private NpcItem CreateNpcPreview(
            int npcTemplateId,
            bool includeTooltips = false,
            int requestedClientActionSetIndex = NpcClientActionSetLoader.AutomaticClientActionSetIndex)
        {
            if (npcTemplateId <= 0 || GraphicsDevice == null)
            {
                return null;
            }

            NpcInfo npcInfo = NpcInfo.Get(npcTemplateId.ToString(CultureInfo.InvariantCulture));
            if (npcInfo == null)
            {
                return null;
            }

            var npcInstance = new NpcInstance(
                npcInfo,
                null,
                0,
                0,
                0,
                0,
                0,
                null,
                0,
                false,
                false,
                null,
                null);
            var usedProps = new ConcurrentBag<WzObject>();
            NpcItem npcPreview = LifeLoader.CreateNpcFromProperty(
                _texturePool,
                npcInstance,
                UserScreenScaleFactor,
                GraphicsDevice,
                usedProps,
                includeTooltips,
                _playerManager?.Player?.Build?.Gender,
                _questRuntime.HasNpcClientActionSelectionContext(),
                _questRuntime.GetCurrentState,
                questId => _questRuntime.TryGetQuestRecordValue(questId, out string value) ? value : string.Empty,
                requestedClientActionSetIndex);
            if (npcPreview != null)
            {
                npcPreview.IdleActionCyclingEnabled = false;
                npcPreview.SetAction(AnimationKeys.Stand);
            }

            return npcPreview;
        }

        private NpcItem CreateRepairDurabilityNpcPreview(int npcTemplateId)
        {
            NpcInfo npcInfo = NpcInfo.Get(npcTemplateId.ToString(CultureInfo.InvariantCulture));
            WzImage source = NpcImgEntryResolver.Resolve(npcInfo);
            int? shopActionId = (source?["info"]?["shop"] as WzIntProperty)?.Value;
            List<NpcClientActionSetLoader.NpcClientActionSetDefinition> actionSets = NpcClientActionSetLoader.GetClientActionSets(source);
            List<string> preferredRepairActions = RepairDurabilityClientParity
                .EnumerateNpcActionCandidates(shopActionId, source)
                .Concat(RepairDurabilityClientParity.EnumerateNpcSpeakFallbackActions(source))
                .Where(static action => !string.IsNullOrWhiteSpace(action))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
            int automaticClientActionSetIndex = NpcClientActionSetLoader.ResolveClientActionSetIndex(
                actionSets,
                _playerManager?.Player?.Build?.Gender,
                _questRuntime.HasNpcClientActionSelectionContext(),
                _questRuntime.GetCurrentState,
                questId => _questRuntime.TryGetQuestRecordValue(questId, out string questRecordValue)
                    ? questRecordValue
                    : string.Empty,
                NpcClientActionSetLoader.AutomaticClientActionSetIndex);
            int selectedClientActionSetIndex = NpcClientActionSetLoader.ResolveClientActionSetIndexForPreferredActions(
                actionSets,
                preferredRepairActions,
                _playerManager?.Player?.Build?.Gender,
                _questRuntime.HasNpcClientActionSelectionContext(),
                _questRuntime.GetCurrentState,
                questId => _questRuntime.TryGetQuestRecordValue(questId, out string questRecordValue)
                    ? questRecordValue
                    : string.Empty,
                NpcClientActionSetLoader.AutomaticClientActionSetIndex);
            int resolvedClientActionSetIndex = RepairDurabilityClientParity.ResolveRepairNpcActionSetIndex(
                actionSets,
                shopActionId,
                automaticClientActionSetIndex,
                selectedClientActionSetIndex,
                preferredRepairActions);
            NpcItem npcPreview = CreateNpcPreview(
                npcTemplateId,
                includeTooltips: false,
                requestedClientActionSetIndex: resolvedClientActionSetIndex);
            if (npcPreview == null)
            {
                return null;
            }

            npcPreview.IdleActionCyclingEnabled = false;
            string repairAction = ResolveRepairDurabilityNpcAction(
                npcTemplateId,
                npcPreview,
                source,
                shopActionId,
                resolvedClientActionSetIndex);
            if (!string.IsNullOrWhiteSpace(repairAction))
            {
                npcPreview.SetAction(repairAction);
            }

            return npcPreview;
        }

        private string ResolveRepairDurabilityNpcAction(
            int npcTemplateId,
            NpcItem npcPreview,
            WzImage source = null,
            int? shopActionId = null,
            int selectedClientActionSetIndex = NpcClientActionSetLoader.RootClientActionSetIndex)
        {
            if (npcTemplateId <= 0 || npcPreview == null)
            {
                return AnimationKeys.Stand;
            }

            source ??= NpcImgEntryResolver.Resolve(NpcInfo.Get(npcTemplateId.ToString(CultureInfo.InvariantCulture)));
            shopActionId ??= (source?["info"]?["shop"] as WzIntProperty)?.Value;
            IReadOnlyList<string> authoredTemplateActionOrder = NpcClientActionSetLoader.BuildClientTemplateActionOrder(
                source,
                selectedClientActionSetIndex);
            return RepairDurabilityClientParity.ResolvePreferredNpcAction(
                shopActionId,
                npcPreview.GetAvailableActions(),
                RepairDurabilityClientParity.EnumerateNpcSpeakFallbackActions(source),
                source,
                authoredTemplateActionOrder);
        }

        private void ProcessPendingRepairDurabilityRequest()
        {
            PendingRepairDurabilityRequest request = _pendingRepairDurabilityRequest;
            if (request == null)
            {
                return;
            }

            if ((Environment.TickCount64 - request.SentTick) < request.ResponseDelayMs)
            {
                return;
            }

            _pendingRepairDurabilityRequest = null;
            string message = ApplyPendingRepairDurabilitySuccess(request);
            if (!string.IsNullOrWhiteSpace(message))
            {
                ShowUtilityFeedbackMessage(message);
            }
        }

        private bool TryApplyRepairDurabilityResultPayload(byte[] payload, out string message)
        {
            message = null;
            PendingRepairDurabilityRequest request = _pendingRepairDurabilityRequest;
            if (request == null)
            {
                message = "Repair-result payload was ignored because no durability repair request is pending.";
                return false;
            }

            if (!RepairDurabilityClientParity.TryDecodeSyntheticResultPayload(payload, out RepairDurabilityClientParity.ResultPayload result, out string error))
            {
                message = error;
                return false;
            }

            if (!RepairDurabilityClientParity.MatchesPendingResultOperation(request.OperationCode, result.OperationCode))
            {
                message = $"Repair-result payload for opcode {result.OperationCode.Value} was ignored because opcode {request.OperationCode} is still pending.";
                return false;
            }

            if (!RepairDurabilityClientParity.MatchesPendingResultTarget(request.RepairAll, request.EncodedSlotPosition, result.EncodedSlotPosition))
            {
                message = $"Repair-result payload for encoded position {result.EncodedSlotPosition.Value} was ignored because position {request.EncodedSlotPosition} is still pending.";
                return false;
            }

            _pendingRepairDurabilityRequest = null;
            message = result.Success
                ? AppendRepairDurabilityStatusText(ApplyPendingRepairDurabilitySuccess(request), result.StatusText)
                : ApplyPendingRepairDurabilityFailure(request, result.ReasonCode, result.StatusText);
            return true;
        }

        private string ApplyPendingRepairDurabilitySuccess(PendingRepairDurabilityRequest request)
        {
            IInventoryRuntime inventory = uiWindowManager?.InventoryWindow as IInventoryRuntime;
            if (inventory == null)
            {
                RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                return "Durability repair response failed because the inventory runtime is not active.";
            }

            if (request.TotalCost <= 0)
            {
                RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                return string.Empty;
            }

            if (!request.RepairAll)
            {
                RepairDurabilityWindow.RepairEntry liveEntry = FindLiveRepairDurabilityEntry(request.EncodedSlotPosition, request.PreferredItemId);
                CharacterPart livePart = ResolveRepairDurabilityTargetPart(liveEntry);
                if (livePart == null || liveEntry.MaxDurability <= 0)
                {
                    RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                    return "Durability repair response failed because the selected equipment is no longer available.";
                }

                int liveRepairCost = Math.Max(0, liveEntry.RepairCost);
                if (liveRepairCost <= 0)
                {
                    RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                    return $"{liveEntry.ItemName} no longer needs durability repair.";
                }

                if (!inventory.TryConsumeMeso(liveRepairCost))
                {
                    RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                    return $"Repair response for {liveEntry.ItemName} failed because you no longer have enough meso.";
                }

                livePart.Durability = liveEntry.MaxDurability;
                RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                return $"Repair response restored {liveEntry.ItemName} for {liveRepairCost.ToString("N0", CultureInfo.InvariantCulture)} meso.";
            }

            int repairedCount = 0;
            IReadOnlyList<RepairDurabilityWindow.RepairEntry> requestedEntries = request.Entries ?? Array.Empty<RepairDurabilityWindow.RepairEntry>();
            if (requestedEntries.Count <= 0)
            {
                RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                return "Repair-all response failed because none of the requested equipment entries are still available.";
            }

            List<RepairDurabilityWindow.RepairEntry> liveEntries = new();
            foreach (RepairDurabilityWindow.RepairEntry requestedEntry in requestedEntries)
            {
                RepairDurabilityWindow.RepairEntry liveEntry = FindLiveRepairDurabilityEntry(
                    requestedEntry?.EncodedSlotPosition ?? int.MinValue,
                    requestedEntry?.Part?.ItemId ?? requestedEntry?.InventorySlot?.ItemId ?? 0);
                if (liveEntry != null
                    && liveEntries.All(candidate => candidate.EncodedSlotPosition != liveEntry.EncodedSlotPosition))
                {
                    liveEntries.Add(liveEntry);
                }
            }

            if (liveEntries.Count <= 0)
            {
                RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                return "Repair-all response failed because none of the requested equipment entries are still available.";
            }

            int liveRepairAllCost = liveEntries.Sum(entry => Math.Max(0, entry?.RepairCost ?? 0));
            if (liveRepairAllCost <= 0)
            {
                RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                return "Repair-all response found no remaining damaged equipment.";
            }

            if (!inventory.TryConsumeMeso(liveRepairAllCost))
            {
                RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
                return "Repair-all response failed because you no longer have enough meso.";
            }

            for (int i = 0; i < liveEntries.Count; i++)
            {
                RepairDurabilityWindow.RepairEntry repairEntry = liveEntries[i];
                CharacterPart repairPart = ResolveRepairDurabilityTargetPart(repairEntry);
                if (repairPart == null || repairEntry.MaxDurability <= 0)
                {
                    continue;
                }

                repairPart.Durability = repairEntry.MaxDurability;
                repairedCount++;
            }

            RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
            return $"Repair-all response restored {repairedCount} item(s) for {liveRepairAllCost.ToString("N0", CultureInfo.InvariantCulture)} meso.";
        }

        private static string AppendRepairDurabilityStatusText(string message, string statusText)
        {
            if (string.IsNullOrWhiteSpace(statusText))
            {
                return message ?? string.Empty;
            }

            if (string.IsNullOrWhiteSpace(message))
            {
                return statusText.Trim();
            }

            return $"{message} Server text: {statusText.Trim()}";
        }

        private string ApplyPendingRepairDurabilityFailure(PendingRepairDurabilityRequest request, int? reasonCode, string statusText)
        {
            RefreshRepairDurabilityWindow(request.NpcTemplateId, request.PreferredItemId);
            string requestTarget = request.RepairAll
                ? "repair-all request"
                : $"repair request for {request.Entry?.ItemName ?? "the selected equipment"}";
            string message = reasonCode.HasValue
                ? $"Repair-result payload rejected the pending {requestTarget} with reason {reasonCode.Value}."
                : $"Repair-result payload rejected the pending {requestTarget}.";
            return AppendRepairDurabilityStatusText(message, statusText);
        }
        private static string ResolveNpcDisplayName(int npcTemplateId)
        {
            string key = npcTemplateId.ToString(CultureInfo.InvariantCulture);
            return npcTemplateId > 0
                   && Program.InfoManager?.NpcNameCache != null
                   && Program.InfoManager.NpcNameCache.TryGetValue(key, out Tuple<string, string> npcInfo)
                   && !string.IsNullOrWhiteSpace(npcInfo?.Item1)
                ? npcInfo.Item1
                : npcTemplateId > 0
                    ? $"NPC #{npcTemplateId}"
                    : "Repair NPC";
        }


