        private void ShowDirectionModeOwnedWindow(string windowName)
        {
            if (uiWindowManager == null || string.IsNullOrWhiteSpace(windowName))
            {
                return;
            }
            if (!TryShowFieldRestrictedWindow(windowName))
            {
                return;
            }


            TrackDirectionModeOwnerWindow(windowName, uiWindowManager.GetWindow(windowName));

            PreparePacketOwnedAdminShopForUniqueModelessOwnerShow(windowName);
            uiWindowManager.ShowWindow(windowName);

        }



        private void ShowWindow(string windowName, UIWindowBase window, bool trackDirectionModeOwner)
        {
            if (window == null || string.IsNullOrWhiteSpace(windowName))
            {
                return;
            }
            if (!TryShowFieldRestrictedWindow(windowName))
            {
                return;
            }



            if (trackDirectionModeOwner)
            {
                TrackDirectionModeOwnerWindow(windowName, window);
            }

            PreparePacketOwnedAdminShopForUniqueModelessOwnerShow(windowName);

            if (uiWindowManager != null)
            {
                uiWindowManager.ShowWindow(window);
                return;
            }


            window.Show();

        }

        private static CharacterPart ResolveRepairDurabilityTargetPart(RepairDurabilityWindow.RepairEntry entry)
        {
            return entry?.Part ?? entry?.InventorySlot?.TooltipPart;
        }

        private static int EncodeRepairDurabilityEquippedPosition(
            Character.EquipSlot slot,
            int itemId,
            bool preferHiddenLayer,
            IReadOnlyDictionary<byte, int> visibleEquipmentByBodyPart,
            IReadOnlyDictionary<byte, int> hiddenEquipmentByBodyPart)
        {
            return RepairDurabilityClientParity.TryEncodeEquippedPositionFromAvatarLook(
                slot,
                itemId,
                preferHiddenLayer,
                visibleEquipmentByBodyPart,
                hiddenEquipmentByBodyPart,
                out int encodedPosition)
                ? encodedPosition
                : int.MinValue;
        }

        private RepairDurabilityWindow.RepairEntry FindLiveRepairDurabilityEntry(int encodedSlotPosition, int preferredItemId)
        {
            List<RepairDurabilityWindow.RepairEntry> liveEntries = BuildRepairDurabilityEntries();
            RepairDurabilityWindow.RepairEntry positionMatch = liveEntries.FirstOrDefault(entry => entry.EncodedSlotPosition == encodedSlotPosition);
            if (positionMatch != null)
            {
                return positionMatch;
            }

            return preferredItemId > 0
                ? liveEntries.FirstOrDefault(entry => (entry.Part?.ItemId ?? entry.InventorySlot?.ItemId ?? 0) == preferredItemId)
                : null;
        }



