        private bool TryApplyMapleTvPacket(int packetType, byte[] payload, out string message)
        {
            bool applied = GetPacketOwnedSocialUtilityDialogDispatcher().TryApplyMapleTvPacket(
                packetType,
                payload,
                currTickCount,
                ResolveMapleTvBuildFromAvatarLook,
                out message);

            if (applied && packetType == MapleTvRuntime.PacketTypeSetMessage)
            {
                PublishMapleTvMegassengerMirror(currTickCount);
                ShowMapleTvWindow();
            }

            return applied;
        }



