        private bool TryUseSetupInventoryItem(int itemId, int currentTime, int? slotIndex = null)
        {
            if (itemId <= 0)
            {
                return false;
            }

            PortableChair activeChair = _playerManager?.Player?.Build?.ActivePortableChair;
            bool isActiveChair = activeChair?.ItemId == itemId;
            bool canResolveChair = _playerManager?.Loader?.LoadPortableChair(itemId) != null;
            if (isActiveChair || canResolveChair)
            {
                bool toggled = TryTogglePortableChair(itemId, out string toggleMessage);
                if (!toggled && !string.IsNullOrWhiteSpace(toggleMessage))
                {
                    PushFieldRuleMessage(toggleMessage, currentTime, false);
                }

                return toggled;
            }

            string fieldItemRestrictionMessage = GetFieldItemUseRestrictionMessage(InventoryType.SETUP, itemId, 1);
            if (!string.IsNullOrWhiteSpace(fieldItemRestrictionMessage))
            {
                ShowFieldRestrictionMessage(fieldItemRestrictionMessage);
                return false;
            }

            if (!HasInventoryItem(itemId))
            {
                return false;
            }

            if (TryRejectSetupUseLevelRequirement(itemId, currentTime))
            {
                return false;
            }

            if (TryUseItemAuthoredNpcInteractionInventoryItem(itemId, InventoryType.SETUP, currentTime, slotIndex))
            {
                return true;
            }

            if (TryUseSetupExperienceChairInventoryItem(itemId, currentTime))
            {
                return true;
            }

            if (TryUseSetupPersonalityInventoryItem(itemId, currentTime, slotIndex))
            {
                return true;
            }

            string itemName = ResolvePickupItemName(itemId);
            PushFieldRuleMessage(
                string.IsNullOrWhiteSpace(itemName)
                    ? "That setup item cannot be used right now."
                    : $"{itemName} cannot be used right now.",
                currentTime,
                false);
            return false;
        }

        private bool TryRejectSetupUseLevelRequirement(int itemId, int currentTime)
        {
            if (itemId <= 0)
            {
                return false;
            }

            int requiredLevel = InventoryItemMetadataResolver.ResolveSetupUseLevelRequirement(itemId);
            if (requiredLevel <= 0)
            {
                return false;
            }

            int currentLevel = Math.Max(1, _playerManager?.Player?.Level ?? _playerManager?.Player?.Build?.Level ?? 1);
            if (currentLevel >= requiredLevel)
            {
                return false;
            }

            string itemName = ResolvePickupItemName(itemId);
            string levelText = requiredLevel.ToString(CultureInfo.InvariantCulture);
            PushFieldRuleMessage(
                string.IsNullOrWhiteSpace(itemName)
                    ? $"This setup item requires Lv. {levelText} to use."
                    : $"{itemName} requires Lv. {levelText} to use.",
                currentTime,
                false);
            return true;
        }

        private bool TryUseSetupExperienceChairInventoryItem(int itemId, int currentTime)
        {
            if (itemId <= 0)
            {
                return false;
            }

            if (_activeSetupExperienceChairItemId > 0 && !HasInventoryItem(_activeSetupExperienceChairItemId))
            {
                _activeSetupExperienceChairItemId = 0;
            }

            if (!TryResolveSetupExperienceChairUseMetadata(
                    itemId,
                    out int expRatePercent,
                    out int maxAccumulatedExp,
                    out bool partyExpEnabled))
            {
                return false;
            }

            string itemName = ResolvePickupItemName(itemId);
            bool turningOn = _activeSetupExperienceChairItemId != itemId;
            _activeSetupExperienceChairItemId = turningOn ? itemId : 0;
            PushFieldRuleMessage(
                BuildSetupExperienceChairUseMessage(
                    itemName,
                    turningOn,
                    expRatePercent,
                    maxAccumulatedExp,
                    partyExpEnabled),
                currentTime,
                false);
            return true;
        }

        private bool TryResolveSetupExperienceChairUseMetadata(
            int itemId,
            out int expRatePercent,
            out int maxAccumulatedExp,
            out bool partyExpEnabled)
        {
            expRatePercent = 0;
            maxAccumulatedExp = 0;
            partyExpEnabled = false;
            if (itemId <= 0)
            {
                return false;
            }

            WzSubProperty infoProperty = LoadInventoryItemInfoProperty(itemId);
            if (infoProperty == null)
            {
                return false;
            }

            expRatePercent = Math.Max(0, GetWzIntValue(infoProperty["expRate"]));
            maxAccumulatedExp = Math.Max(0, GetWzIntValue(infoProperty["maxExp"]));
            bool cashExpTicketEnabled = GetWzIntValue(infoProperty["cashExpTicketOn"]) == 1;
            partyExpEnabled = GetWzIntValue(infoProperty["partyExpOn"]) == 1;
            return IsSetupExperienceChairUseSupported(
                expRatePercent,
                maxAccumulatedExp,
                cashExpTicketEnabled,
                partyExpEnabled);
        }

        private bool TryUseSetupPersonalityInventoryItem(int itemId, int currentTime, int? slotIndex = null)
        {
            if (itemId <= 0
                || _playerManager?.Player?.Build == null
                || uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryWindow)
            {
                return false;
            }

            WzSubProperty infoProperty = LoadInventoryItemInfoProperty(itemId);
            if (infoProperty == null)
            {
                return false;
            }

            int charismaExperience = Math.Max(0, GetWzIntValue(infoProperty["charismaEXP"]));
            int insightExperience = Math.Max(0, GetWzIntValue(infoProperty["insightEXP"]));
            int willExperience = Math.Max(0, GetWzIntValue(infoProperty["willEXP"]));
            int craftExperience = Math.Max(0, GetWzIntValue(infoProperty["craftEXP"]));
            int senseExperience = Math.Max(0, GetWzIntValue(infoProperty["senseEXP"]));
            int charmExperience = Math.Max(0, GetWzIntValue(infoProperty["charmEXP"]));
            if (!HasSetupPersonalityExperienceGain(
                    charismaExperience,
                    insightExperience,
                    willExperience,
                    craftExperience,
                    senseExperience,
                    charmExperience))
            {
                return false;
            }

            if (!TryConsumeInventoryUseItem(
                    inventoryWindow,
                    InventoryType.SETUP,
                    itemId,
                    1,
                    slotIndex))
            {
                return false;
            }

            ApplyConsumableProgressionToBuild(
                _playerManager.Player.Build,
                directExperience: 0,
                charismaExperience: charismaExperience,
                insightExperience: insightExperience,
                willExperience: willExperience,
                craftExperience: craftExperience,
                senseExperience: senseExperience,
                charmExperience: charmExperience,
                eventPoint: 0);

            _fieldRuleRuntime?.RegisterSuccessfulItemUse(
                ShouldTrackFieldConsumeItemCooldown(InventoryType.SETUP, default, default),
                currentTime);

            string itemName = ResolvePickupItemName(itemId);
            PushFieldRuleMessage(
                BuildSetupPersonalityUseMessage(
                    itemName,
                    charismaExperience,
                    insightExperience,
                    willExperience,
                    craftExperience,
                    senseExperience,
                    charmExperience),
                currentTime,
                false);
            return true;
        }

        internal static bool HasSetupPersonalityExperienceGain(
            int charismaExperience,
            int insightExperience,
            int willExperience,
            int craftExperience,
            int senseExperience,
            int charmExperience)
        {
            return charismaExperience > 0
                || insightExperience > 0
                || willExperience > 0
                || craftExperience > 0
                || senseExperience > 0
                || charmExperience > 0;
        }

        internal static string BuildSetupPersonalityUseMessage(
            string itemName,
            int charismaExperience,
            int insightExperience,
            int willExperience,
            int craftExperience,
            int senseExperience,
            int charmExperience)
        {
            List<string> gains = new();
            AppendSetupPersonalityGain(gains, "Charisma", charismaExperience);
            AppendSetupPersonalityGain(gains, "Insight", insightExperience);
            AppendSetupPersonalityGain(gains, "Will", willExperience);
            AppendSetupPersonalityGain(gains, "Craft", craftExperience);
            AppendSetupPersonalityGain(gains, "Sense", senseExperience);
            AppendSetupPersonalityGain(gains, "Charm", charmExperience);

            string resolvedName = string.IsNullOrWhiteSpace(itemName)
                ? "That setup item"
                : itemName;
            return gains.Count == 0
                ? $"{resolvedName} was consumed."
                : $"{resolvedName} granted {string.Join(", ", gains)}.";
        }

        private static void AppendSetupPersonalityGain(List<string> gains, string label, int value)
        {
            if (value <= 0)
            {
                return;
            }

            gains.Add($"{label} +{value.ToString(CultureInfo.InvariantCulture)}");
        }

        internal static bool IsSetupExperienceChairUseSupported(
            int expRatePercent,
            int maxAccumulatedExp,
            bool cashExpTicketEnabled,
            bool partyExpEnabled)
        {
            return expRatePercent > 0
                   && maxAccumulatedExp > 0
                   && (cashExpTicketEnabled || partyExpEnabled);
        }

        internal static string BuildSetupExperienceChairUseMessage(
            string itemName,
            bool turningOn,
            int expRatePercent,
            int maxAccumulatedExp,
            bool partyExpEnabled)
        {
            string resolvedName = string.IsNullOrWhiteSpace(itemName)
                ? "That setup EXP chair"
                : itemName;
            if (!turningOn)
            {
                return $"{resolvedName} is now OFF.";
            }

            string partyText = partyExpEnabled ? ", party EXP enabled" : string.Empty;
            return string.Format(
                CultureInfo.InvariantCulture,
                "{0} is now ON ({1}% hunting EXP, cap {2:N0}{3}).",
                resolvedName,
                expRatePercent,
                maxAccumulatedExp,
                partyText);
        }

        private static string BuildPetFoodFailureMessage(PetController.PetFoodItemUseFailureReason failureReason)
        {
            return failureReason switch
            {
                PetController.PetFoodItemUseFailureReason.NoActivePets => "Summon a pet before using that pet food.",
                PetController.PetFoodItemUseFailureReason.NoCompatiblePets => "None of the summoned pets can eat that pet food.",
                PetController.PetFoodItemUseFailureReason.NoHungryCompatiblePets => "None of the summoned pets want that pet food right now.",
                _ => "That pet food cannot be used right now.",
            };
        }

        private bool TryHandlePacketOwnedViewAllCharResult(out string summary, out bool continueRuntimeDispatch)
        {
            summary = null;
            continueRuntimeDispatch = false;

            LoginViewAllCharResultPacketProfile packetProfile = _loginPacketViewAllCharResultProfile;
            if (!IsLoginRuntimeSceneActive || packetProfile == null)
            {
                return false;
            }

            ApplyViewAllCharResultProfile();

            switch (packetProfile.Kind)
            {
                case LoginViewAllCharResultKind.Header:
                    if (_loginPacketViewAllCharExpectedCharacterCount <= 0 ||
                        packetProfile.RelatedServerCount <= 0)
                    {
                        summary = BuildViewAllCharEmptyRosterMessage(packetProfile);
                        _loginRuntime.SetCharacterSelectReady(false);
                        _loginRuntime.ForceStep(LoginStep.WorldSelect, "Packet-authored ViewAllCharResult returned to world selection.");
                        _loginCharacterStatusMessage = summary;
                        ShowLoginUtilityDialog(
                            "Login Utility",
                            ResolveViewAllCharNoticeDialogBody(packetProfile, isWorldSelectFallback: true),
                            LoginUtilityDialogButtonLayout.Ok,
                            LoginUtilityDialogAction.DismissOnly,
                            frameVariant: LoginUtilityDialogFrameVariant.LoginNotice,
                            returnWindowName: ResolveViewAllCharDialogReturnWindowName(packetProfile, isWorldSelectFallback: true));
                        return true;
                    }

                    summary = BuildViewAllCharHeaderMessage(packetProfile);
                    _loginRuntime.SetCharacterSelectReady(false);
                    _loginCharacterStatusMessage = summary;
                    HideLoginUtilityDialog();
                    return true;

                case LoginViewAllCharResultKind.Characters:
                    if (_loginPacketViewAllCharRosterProfile?.Entries?.Count > 0)
                    {
                        summary = BuildViewAllCharCompletedMessage(_loginPacketViewAllCharRosterProfile);
                        _loginRuntime.SetCharacterSelectReady(true);
                        _loginRuntime.ForceStep(LoginStep.ViewAllCharacters, "Packet-authored ViewAllCharResult completed VAC roster aggregation.");
                    }
                    else
                    {
                        summary = BuildViewAllCharChunkMessage(packetProfile);
                        _loginRuntime.SetCharacterSelectReady(false);
                    }

                    _loginCharacterStatusMessage = summary;
                    HideLoginUtilityDialog();
                    return true;

                case LoginViewAllCharResultKind.Completion:
                    if (_loginPacketViewAllCharRosterProfile?.Entries?.Count > 0)
                    {
                        summary = BuildViewAllCharCompletedMessage(_loginPacketViewAllCharRosterProfile);
                        _loginRuntime.SetCharacterSelectReady(true);
                        _loginRuntime.ForceStep(LoginStep.ViewAllCharacters, "Packet-authored ViewAllCharResult completed VAC roster aggregation.");
                        _loginCharacterStatusMessage = summary;
                        HideLoginUtilityDialog();
                        return true;
                    }

                    summary = BuildViewAllCharWorldSelectFallbackMessage();
                    _loginRuntime.SetCharacterSelectReady(false);
                    _loginRuntime.ForceStep(LoginStep.WorldSelect, "Packet-authored ViewAllCharResult fell back to world selection.");
                    _loginCharacterStatusMessage = summary;
                    ShowLoginUtilityDialog(
                        "Login Utility",
                        ResolveViewAllCharNoticeDialogBody(packetProfile, isWorldSelectFallback: true),
                        LoginUtilityDialogButtonLayout.Ok,
                        LoginUtilityDialogAction.DismissOnly,
                        frameVariant: LoginUtilityDialogFrameVariant.LoginNotice,
                        returnWindowName: ResolveViewAllCharDialogReturnWindowName(packetProfile, isWorldSelectFallback: true));
                    return true;

                case LoginViewAllCharResultKind.Error:
                    summary = BuildViewAllCharErrorMessage(packetProfile);
                    bool returnsToTitle = packetProfile.ResultCode is 2 or 3 or 6 or 7;
                    _loginRuntime.SetCharacterSelectReady(false);
                    _loginRuntime.ForceStep(
                        returnsToTitle ? LoginStep.Title : LoginStep.WorldSelect,
                        returnsToTitle
                            ? "Packet-authored ViewAllCharResult returned the login flow to title."
                            : "Packet-authored ViewAllCharResult kept the login flow on world selection.");
                    _loginCharacterStatusMessage = summary;
                    ShowLoginUtilityDialog(
                        "Login Utility",
                        ResolveViewAllCharNoticeDialogBody(packetProfile, isWorldSelectFallback: false),
                        LoginUtilityDialogButtonLayout.Ok,
                        LoginUtilityDialogAction.DismissOnly,
                        frameVariant: LoginUtilityDialogFrameVariant.LoginNotice,
                        returnWindowName: ResolveViewAllCharDialogReturnWindowName(packetProfile, isWorldSelectFallback: false));
                    return true;
            }

            return false;
        }

        private bool TryHandlePacketOwnedCheckPasswordResult(out string summary, out bool continueRuntimeDispatch)
        {
            summary = null;
            continueRuntimeDispatch = true;

            LoginCheckPasswordResultProfile packetProfile = _loginPacketCheckPasswordResultProfile;
            if (!IsLoginRuntimeSceneActive || packetProfile == null)
            {
                return false;
            }

            if (!packetProfile.IsSuccess && !packetProfile.IsLicenseResult)
            {
                summary = BuildCheckPasswordResultFailureMessage(packetProfile);
                _loginTitleStatusMessage = summary;
                _loginCharacterStatusMessage = summary;
                ShowCheckPasswordResultFailureDialog(packetProfile, summary);
                continueRuntimeDispatch = false;
                return true;
            }

            if (packetProfile.RequiresAccountRegistration)
            {
                summary = BuildCheckPasswordRegistrationSummary(packetProfile);
                _loginTitleStatusMessage = summary;
                _loginCharacterStatusMessage = summary;
                ShowLoginUtilityDialog(
                    "Login Utility",
                    summary,
                    LoginUtilityDialogButtonLayout.YesNo,
                    LoginUtilityDialogAction.WebsiteHandoffDecision,
                    noticeTextIndex: 31,
                    visualStyle: LoginUtilityDialogVisualStyle.SecurityYesNo,
                    frameVariant: LoginUtilityDialogFrameVariant.LoginNotice);
                PrepareLoginWebsiteHandoff(null, "CheckPasswordResult");
                continueRuntimeDispatch = false;
                return true;
            }

            if (packetProfile.IsLicenseResult)
            {
                summary = BuildCheckPasswordLicenseSummary(packetProfile);
                _loginTitleStatusMessage = summary;
                _loginCharacterStatusMessage = summary;
                ShowLoginLicenseAgreementDialog(LoginPacketType.CheckPasswordResult, summary);
                continueRuntimeDispatch = false;
                return true;
            }

            ApplyPacketOwnedAccountInfo(packetProfile);
            _loginAccountMigrationAccepted = true;
            _loginAccountAcceptedEula = true;
            summary = BuildCheckPasswordSuccessSummary(packetProfile);
            _loginTitleStatusMessage = summary;
            _loginCharacterStatusMessage = summary;
            HideLoginUtilityDialog();
            return true;
        }

        private bool TryHandlePacketOwnedGuestIdLoginResult(out string summary)
        {
            summary = null;

            LoginGuestIdLoginResultProfile packetProfile = _loginPacketGuestIdLoginResultProfile;
            if (!IsLoginRuntimeSceneActive || packetProfile == null)
            {
                return false;
            }

            if (!LoginGuestIdLoginResultCodec.IsSuccessCode(packetProfile.ResultCode))
            {
                summary = BuildGuestIdLoginFailureMessage(packetProfile);
                _loginTitleStatusMessage = summary;
                _loginCharacterStatusMessage = summary;
                ShowGuestIdLoginFailureDialog(packetProfile, summary);
                return true;
            }

            if (packetProfile.RegistrationStatusId is 2 or 3)
            {
                summary = BuildGuestIdLoginRegistrationSummary(packetProfile);
                _loginTitleStatusMessage = summary;
                _loginCharacterStatusMessage = summary;
                ShowLoginUtilityDialog(
                    "Login Utility",
                    summary,
                    LoginUtilityDialogButtonLayout.YesNo,
                    LoginUtilityDialogAction.WebsiteHandoffDecision,
                    noticeTextIndex: 31,
                    visualStyle: LoginUtilityDialogVisualStyle.SecurityYesNo,
                    frameVariant: LoginUtilityDialogFrameVariant.LoginNotice);
                PrepareLoginWebsiteHandoff(packetProfile.GuestRegistrationUrl, "Guest registration");
                return true;
            }

            ApplyPacketOwnedAccountInfo(packetProfile);
            _loginAccountMigrationAccepted = true;
            summary = BuildGuestIdLoginSuccessSummary(packetProfile);
            _loginTitleStatusMessage = summary;
            _loginCharacterStatusMessage = summary;
            ShowLoginLicenseAgreementDialog(LoginPacketType.GuestIdLoginResult, summary);
            return true;
        }

        private bool TryHandlePacketOwnedAccountInfoResult(out string summary, out bool continueRuntimeDispatch)
        {
            summary = null;
            continueRuntimeDispatch = true;

            if (!IsLoginRuntimeSceneActive ||
                !_loginPacketAccountDialogProfiles.TryGetValue(LoginPacketType.AccountInfoResult, out LoginAccountDialogPacketProfile packetProfile) ||
                packetProfile == null)
            {
                return false;
            }

            if (!IsSuccessfulAccountInfoResult(packetProfile))
            {
                summary = BuildAccountInfoResultFailureMessage(packetProfile);
                _loginTitleStatusMessage = summary;
                _loginCharacterStatusMessage = summary;
                ShowAccountInfoResultFailureDialog(packetProfile, summary);
                continueRuntimeDispatch = false;
                return true;
            }

            ApplyPacketOwnedAccountInfo(packetProfile);
            _loginAccountMigrationAccepted = true;
            _loginAccountAcceptedEula = true;
            bool scheduledWorldSelect = TrySchedulePacketOwnedLoginWorldSelectTransition("AccountInfoResult");
            summary = BuildAccountInfoResultSuccessSummary(packetProfile, scheduledWorldSelect);
            _loginTitleStatusMessage = summary;
            _loginCharacterStatusMessage = summary;
            HideLoginUtilityDialog();
            return true;
        }

        private bool TrySchedulePacketOwnedLoginWorldSelectTransition(string packetSource)
        {
            if (!IsLoginRuntimeSceneActive || _loginRuntime == null)
            {
                return false;
            }

            if (_loginRuntime.CurrentStep != LoginStep.Title)
            {
                return false;
            }

            if (_loginRuntime.PendingStep == LoginStep.WorldSelect)
            {
                return false;
            }

            _loginRuntime.ScheduleStepChange(
                LoginStep.WorldSelect,
                currTickCount,
                LoginRuntimeManager.DefaultStepChangeDelayMs,
                packetSource);
            return true;
        }

        private void ApplyPacketOwnedAccountInfo(LoginAccountDialogPacketProfile packetProfile)
        {
            if (packetProfile == null)
            {
                return;
            }

            if (packetProfile.AccountId.HasValue && packetProfile.AccountId.Value > 0)
            {
                _loginAccountId = packetProfile.AccountId.Value;
                _loginBackendSessionManager.SetAuthenticatedAccountId(packetProfile.AccountId.Value);
                if (!_loginCharacterAccountStore.BindAccountIdForAccount(
                        ResolveLoginRosterAccountName(),
                        packetProfile.AccountId.Value))
                {
                    _loginCharacterAccountStore.BindAccountId(
                        ResolveLoginRosterAccountName(),
                        ResolveLoginRosterWorldId(),
                        packetProfile.AccountId.Value);
                }

                ApplyPacketOwnedExtraCharacterEntitlement();
            }

            _loginPacketAccountDialogProfiles[LoginPacketType.AccountInfoResult] = new LoginAccountDialogPacketProfile
            {
                PacketType = LoginPacketType.AccountInfoResult,
                Source = packetProfile.Source,
                Payload = packetProfile.Payload,
                ResultCode = packetProfile.ResultCode,
                SecondaryCode = packetProfile.SecondaryCode,
                AccountId = packetProfile.AccountId,
                CharacterId = packetProfile.CharacterId,
                Gender = packetProfile.Gender,
                GradeCode = packetProfile.GradeCode,
                AccountFlags = packetProfile.AccountFlags,
                CountryId = packetProfile.CountryId,
                ClubId = packetProfile.ClubId,
                PurchaseExperience = packetProfile.PurchaseExperience,
                ChatBlockReason = packetProfile.ChatBlockReason,
                ChatUnblockFileTime = packetProfile.ChatUnblockFileTime,
                RegisterDateFileTime = packetProfile.RegisterDateFileTime,
                CharacterCount = packetProfile.CharacterCount,
                ClientKey = packetProfile.ClientKey,
                RequestedName = packetProfile.RequestedName,
                TextValue = packetProfile.TextValue,
            };
        }

        private void SyncPacketOwnedAccountCharacterCountFromRoster()
        {
            if (!_loginPacketAccountDialogProfiles.TryGetValue(LoginPacketType.AccountInfoResult, out LoginAccountDialogPacketProfile packetProfile) ||
                packetProfile == null ||
                !TryResolvePacketOwnedAccountCharacterCount(out int characterCount) ||
                packetProfile.CharacterCount == characterCount)
            {
                return;
            }

            _loginPacketAccountDialogProfiles[LoginPacketType.AccountInfoResult] = new LoginAccountDialogPacketProfile
            {
                PacketType = packetProfile.PacketType,
                Source = packetProfile.Source,
                Payload = packetProfile.Payload,
                ResultCode = packetProfile.ResultCode,
                SecondaryCode = packetProfile.SecondaryCode,
                AccountId = packetProfile.AccountId,
                CharacterId = packetProfile.CharacterId,
                Gender = packetProfile.Gender,
                GradeCode = packetProfile.GradeCode,
                AccountFlags = packetProfile.AccountFlags,
                CountryId = packetProfile.CountryId,
                ClubId = packetProfile.ClubId,
                PurchaseExperience = packetProfile.PurchaseExperience,
                ChatBlockReason = packetProfile.ChatBlockReason,
                ChatUnblockFileTime = packetProfile.ChatUnblockFileTime,
                RegisterDateFileTime = packetProfile.RegisterDateFileTime,
                CharacterCount = characterCount,
                ClientKey = packetProfile.ClientKey,
                RequestedName = packetProfile.RequestedName,
                TextValue = packetProfile.TextValue,
            };
        }

        private bool TryResolvePacketOwnedAccountCharacterCount(out int characterCount)
        {
            characterCount = 0;
            string accountName = ResolveLoginRosterAccountName();
            int? accountId = ResolveLoginRosterAccountId();
            IReadOnlyList<LoginCharacterAccountStore.LoginCharacterAccountState> storedStates =
                _loginCharacterAccountStore.SnapshotStatesForAccount(accountName, accountId);
            if (storedStates.Count > 0)
            {
                characterCount = storedStates.Sum(state => state?.Entries?.Count ?? 0);
                return true;
            }

            IReadOnlyList<LoginSelectWorldCharacterEntry> aggregatedEntries =
                _loginBackendSessionManager.SnapshotAggregatedViewAllEntries();
            if (aggregatedEntries.Count > 0)
            {
                characterCount = aggregatedEntries.Count;
                return true;
            }

            if (_loginCharacterRoster.Entries.Count > 0)
            {
                characterCount = _loginCharacterRoster.Entries.Count;
                return true;
            }

            return false;
        }

