        private static string BuildSelectCharacterResultFailureMessage(LoginSelectCharacterResultProfile packetProfile)
        {
            if (packetProfile == null)
            {
                return "SelectCharacterResult failed.";
            }

            string responseText = packetProfile.ResponseCode != 0
                ? $" Response {packetProfile.ResponseCode}."
                : string.Empty;

            if (packetProfile.RequiresWebsiteHandoff)
            {
                return packetProfile.ResultCode == 14
                    ? $"SelectCharacterResult requested the client security website handoff for result 14.{responseText}"
                    : $"SelectCharacterResult requested the client website handoff for result 15.{responseText}";
            }

            if (packetProfile.ResultCode == 12)
            {
                return packetProfile.ResponseCode switch
                {
                    1 => "SelectCharacterResult rejected the selected character and returned the login flow to title.",
                    2 => "SelectCharacterResult reported a blocked character and returned the login flow to title.",
                    3 => "SelectCharacterResult reported that the selected character could not enter the field and returned the login flow to title.",
                    19 => "SelectCharacterResult reported a blocked login and returned the login flow to title.",
                    25 => "SelectCharacterResult reported a migration-required account and returned the login flow to title.",
                    27 => "SelectCharacterResult reported an unsupported region response and returned the login flow to title.",
                    28 => "SelectCharacterResult reported a newer client requirement and returned the login flow to title.",
                    _ => $"SelectCharacterResult returned result {FormatSelectorPacketCode(packetProfile.ResultCode)} with response {packetProfile.ResponseCode}.",
                };
            }

            if (packetProfile.NoticeTextIndex.HasValue)
            {
                return $"SelectCharacterResult mapped the selector failure to login notice {packetProfile.NoticeTextIndex.Value}.{(packetProfile.ReturnsToTitle ? " The login flow returned to title." : string.Empty)}{responseText}";
            }

            return $"SelectCharacterResult returned result {FormatSelectorPacketCode(packetProfile.ResultCode)} with response {packetProfile.ResponseCode}.";
        }
        private static string BuildSelectCharacterByVacResultFailureMessage(LoginSelectCharacterByVacResultProfile packetProfile)
        {
            if (packetProfile == null)
            {
                return "SelectCharacterByVACResult failed.";
            }


            string secondaryText = packetProfile.SecondaryCode != 0
                ? $" Secondary code {packetProfile.SecondaryCode}."
                : string.Empty;

            if (packetProfile.RequiresWebsiteHandoff)
            {
                return packetProfile.ResultCode == 14
                    ? $"SelectCharacterByVACResult requested the client security website handoff for VAC result 14.{secondaryText}"
                    : $"SelectCharacterByVACResult requested the client website handoff for VAC result 15.{secondaryText}";
            }

            if (packetProfile.ResultCode == 12)
            {
                return packetProfile.SecondaryCode switch
                {
                    1 => "SelectCharacterByVACResult rejected alternate authenticated entry and returned the login flow to title.",
                    2 => "SelectCharacterByVACResult reported a blocked VAC character and returned the login flow to title.",
                    3 => "SelectCharacterByVACResult reported that the VAC character could not enter the field and returned the login flow to title.",
                    19 => "SelectCharacterByVACResult reported a blocked VAC login and returned the login flow to title.",
                    25 => "SelectCharacterByVACResult reported a migration-required VAC account and returned the login flow to title.",
                    27 => "SelectCharacterByVACResult reported an unsupported VAC region response and returned the login flow to title.",
                    28 => "SelectCharacterByVACResult reported a newer client requirement and returned the login flow to title.",
                    11 => "SelectCharacterByVACResult accepted alternate authenticated entry through secondary code 11.",
                    13 => "SelectCharacterByVACResult accepted alternate authenticated entry through secondary code 13.",
                    _ => $"SelectCharacterByVACResult rejected alternate authenticated entry for result 12 with secondary code {packetProfile.SecondaryCode}.{(packetProfile.ReturnsToTitle ? " The login flow returned to title." : string.Empty)}",
                };
            }

            if (packetProfile.NoticeTextIndex.HasValue)
            {
                return $"SelectCharacterByVACResult mapped the VAC entry failure to login notice {packetProfile.NoticeTextIndex.Value}.{(packetProfile.ReturnsToTitle ? " The login flow returned to title." : string.Empty)}{secondaryText}";
            }

            return $"SelectCharacterByVACResult returned result {FormatSelectorPacketCode(packetProfile.ResultCode)} with secondary code {packetProfile.SecondaryCode}.";

        }



