        private bool TryGetLoginDeleteCharacterPacketProfile(out LoginAccountDialogPacketProfile packetProfile)
        {
            return _loginPacketAccountDialogProfiles.TryGetValue(LoginPacketType.DeleteCharacterResult, out packetProfile) &&
                   packetProfile != null;
        }

        private void ShowDeleteCharacterFailureDialog(LoginAccountDialogPacketProfile packetProfile, string message)
        {
            if (packetProfile == null)
            {
                return;
            }

            ShowLoginUtilityDialog(
                "Login Utility",
                message,
                LoginUtilityDialogButtonLayout.Ok,
                LoginUtilityDialogAction.DismissOnly,
                noticeTextIndex: ResolveDeleteCharacterFailureNoticeTextIndex(packetProfile),
                frameVariant: ResolveDeleteCharacterFailureFrameVariant(packetProfile),
                returnWindowName: MapSimulatorWindowNames.CharacterSelect);
        }

        private static LoginUtilityDialogFrameVariant ResolveDeleteCharacterFailureFrameVariant(LoginAccountDialogPacketProfile packetProfile)
        {
            byte? resultCode = packetProfile?.ResultCode;
            if (resultCode is 6 or 9 or 20 or 22 or 24 or 29 or 35 or 36)
            {
                return LoginUtilityDialogFrameVariant.LoginNoticeCog;
            }

            if (resultCode == 26)
            {
                return LoginUtilityDialogFrameVariant.Default;
            }

            if (ResolveDeleteCharacterFailureNoticeTextIndex(packetProfile).HasValue)
            {
                return LoginUtilityDialogFrameVariant.LoginNotice;
            }

            return LoginUtilityDialogFrameVariant.Default;
        }

        private static int? ResolveDeleteCharacterFailureNoticeTextIndex(LoginAccountDialogPacketProfile packetProfile)
        {
            return packetProfile?.ResultCode switch
            {
                6 => 15,
                9 => 18,
                10 => 19,
                18 => 11,
                20 => 93,
                22 => 34,
                24 => 39,
                29 => 54,
                35 or 36 => 50,
                _ => null,
            };
        }

        private bool TryGetLoginCheckDuplicatedIdPacketProfile(out LoginAccountDialogPacketProfile packetProfile)
        {
            return _loginPacketAccountDialogProfiles.TryGetValue(LoginPacketType.CheckDuplicatedIdResult, out packetProfile) &&
                   packetProfile != null;
        }

        private static string BuildDeleteCharacterPacketFailureMessage(LoginAccountDialogPacketProfile packetProfile)
        {
            string packetText = packetProfile?.TextValue?.Trim();
            if (!string.IsNullOrWhiteSpace(packetText))
            {
                return packetText;
            }

            string targetText = packetProfile?.CharacterId.HasValue == true
                ? $" for character {packetProfile.CharacterId.Value}"
                : string.Empty;

            return packetProfile?.ResultCode switch
            {
                6 => $"DeleteCharacterResult rejected character deletion because the request could not continue{targetText}.",
                9 => $"DeleteCharacterResult reported that character deletion is not available{targetText}.",
                10 => $"DeleteCharacterResult blocked character deletion on the client security path{targetText}.",
                18 => $"DeleteCharacterResult reported that character deletion prerequisites are not satisfied{targetText}.",
                20 => $"DeleteCharacterResult hit the client security warning path{targetText}.",
                22 => $"DeleteCharacterResult returned the client warning 34{targetText}.",
                24 => $"DeleteCharacterResult returned the client warning 39{targetText}.",
                26 when LoginClientDirectNoticeText.TryResolve(LoginClientDirectNoticeText.DeleteCharacterTransferStringPoolId, out string directNoticeText)
                    => $"{directNoticeText}{targetText}",
                26 => $"DeleteCharacterResult returned the client direct-notice branch (StringPool 0x{LoginClientDirectNoticeText.DeleteCharacterTransferStringPoolId:X}){targetText}.",
                29 => $"DeleteCharacterResult returned the client warning 54{targetText}.",
                35 or 36 => $"DeleteCharacterResult returned the client warning 50{targetText}.",
                byte resultCode => packetProfile.CharacterId.HasValue
                    ? $"DeleteCharacterResult returned server code {FormatSelectorPacketCode(resultCode)} for character {packetProfile.CharacterId.Value}."
                    : $"DeleteCharacterResult returned server code {FormatSelectorPacketCode(resultCode)}.",
                _ => "DeleteCharacterResult did not include a result code.",
            };
        }

        private static string BuildCreateNewCharacterPacketFailureMessage(LoginCreateNewCharacterResultProfile packetProfile)
        {
            string packetText = packetProfile?.Payload?.Length > 0 &&
                                LoginAccountDialogPacketCodec.TryDecode(
                                    LoginPacketType.CreateNewCharacterResult,
                                    packetProfile.Payload,
                                    out LoginAccountDialogPacketProfile dialogProfile,
                                    out _)
                ? dialogProfile?.TextValue?.Trim()
                : null;
            if (!string.IsNullOrWhiteSpace(packetText))
            {
                return packetText;
            }

            return packetProfile?.ResultCode switch
            {
                10 => "CreateNewCharacterResult blocked character creation on the client security path.",
                26 when LoginClientDirectNoticeText.TryResolve(LoginClientDirectNoticeText.CreateCharacterTransferStringPoolId, out string directNoticeText)
                    => directNoticeText,
                26 => $"CreateNewCharacterResult returned the client direct-notice branch (StringPool 0x{LoginClientDirectNoticeText.CreateCharacterTransferStringPoolId:X}).",
                30 => "CreateNewCharacterResult reported that the selected starter name is not available.",
                byte resultCode => $"CreateNewCharacterResult returned server code {FormatSelectorPacketCode(resultCode)}.",
                _ => "CreateNewCharacterResult did not include a result code.",
            };
        }

        private static string BuildCheckDuplicatedIdPacketFailureMessage(LoginAccountDialogPacketProfile packetProfile)
        {
            string packetText = packetProfile?.TextValue?.Trim();
            if (!string.IsNullOrWhiteSpace(packetText))
            {
                return packetText;
            }

            string characterName = string.IsNullOrWhiteSpace(packetProfile?.RequestedName)
                ? "the requested name"
                : packetProfile.RequestedName.Trim();

            return packetProfile?.ResultCode switch
            {
                1 => $"{characterName} is already in use.",
                2 => $"{characterName} is not available.",
                byte resultCode => $"CheckDuplicatedIdResult returned server code {FormatSelectorPacketCode(resultCode)} for {characterName}.",
                _ => "CheckDuplicatedIdResult did not include a result code.",
            };
        }



        private static void ApplyLoginCharacterDetailDefaults(
            CharacterBuild build,
            int minimumLevel,
            string fallbackGuildName,
            int fallbackFame,
            int fallbackExpPercent,
            int fallbackWorldRank,
            int fallbackJobRank)
        {
            if (build == null)
            {
                return;
            }


            build.Level = Math.Max(build.Level, minimumLevel);
            build.GuildName = string.IsNullOrWhiteSpace(build.GuildName) ? fallbackGuildName : build.GuildName;
            if (build.Fame <= 0)
            {
                build.Fame = fallbackFame;
            }


            if (build.WorldRank <= 0)
            {
                build.WorldRank = fallbackWorldRank;
            }


            if (build.JobRank <= 0)
            {
                build.JobRank = fallbackJobRank;
            }


            if (build.ExpToNextLevel <= 0)
            {
                build.ExpToNextLevel = 100;
            }


            if (build.Exp <= 0)
            {
                int clampedPercent = Math.Clamp(fallbackExpPercent, 0, 100);
                build.Exp = (build.ExpToNextLevel * clampedPercent) / 100;
            }
        }


