        {



            return _loginAccountId.HasValue && _loginAccountId.Value > 0



                ? _loginAccountId.Value



                : null;



        }







        private int ResolveLoginRosterWorldId()



        {



            return Math.Max(0, _simulatorWorldId);



        }







        private LoginRosterSource GetActiveLoginRosterSource()



        {



            if (!TryGetActiveLoginRosterPacketProfile(out _, out string packetSource))



            {



                return _loginCharacterAccountStore.GetState(
                    ResolveLoginRosterAccountName(),
                    ResolveLoginRosterWorldId(),
                    ResolveLoginRosterAccountId()) != null



                    ? LoginRosterSource.AccountStore



                    : LoginRosterSource.None;



            }







            return string.Equals(packetSource, "ViewAllCharResult", StringComparison.Ordinal)



                ? LoginRosterSource.ViewAllCharResult



                : LoginRosterSource.SelectWorldResult;



        }




        private bool ShouldRouteLoginRosterMutationThroughLiveSession()



        {



            if (!IsLoginRuntimeSceneActive || !_loginOfficialSessionBridge.HasConnectedSession)



            {



                return false;



            }



            LoginRosterSource rosterSource = GetActiveLoginRosterSource();



            return rosterSource == LoginRosterSource.SelectWorldResult ||



                   rosterSource == LoginRosterSource.ViewAllCharResult;



        }







        private bool CanMutateAccountBackedLoginRoster(out string message)



        {



            LoginRosterSource rosterSource = GetActiveLoginRosterSource();



            if (rosterSource == LoginRosterSource.SelectWorldResult || rosterSource == LoginRosterSource.ViewAllCharResult)



            {
                if (ShouldRouteLoginRosterMutationThroughLiveSession())



                {



                    message = null;



                    return true;



                }



                message = rosterSource == LoginRosterSource.ViewAllCharResult



                    ? "Packet-authored VAC roster data is currently authoritative. Clear the ViewAllCharResult payload before mutating the local account roster."



                    : "Packet-authored SelectWorldResult data is currently authoritative. Clear the SelectWorldResult payload before mutating the local account roster.";



                return false;



            }







            message = null;



            return true;



        }




        private bool TrySendLiveOfficialCheckDuplicatedIdRequest(string characterName, out string status)



        {



            if (!ShouldRouteLoginRosterMutationThroughLiveSession())



            {



                status = "Login official-session roster mutation is unavailable.";



                return false;



            }



            return _loginOfficialSessionBridge.TrySendCheckDuplicateIdRequest(characterName, out status);



        }




        private bool TrySendLiveOfficialCreateCharacterRequest(string characterName, out string status)



        {



            if (!ShouldRouteLoginRosterMutationThroughLiveSession())



            {



                status = "Login official-session character creation is unavailable.";



                return false;



            }



            if (!TryBuildCreateCharacterPacketRequest(characterName, out _, out LoginNewCharacterRequest request, out _, out status))
            {
                return false;
            }

            return _loginOfficialSessionBridge.TrySendNewCharacterRequest(request, out status);



        }



        private bool TryBuildCreateCharacterPacketRequest(
            string characterName,
            out LoginCreateCharacterRequestProfile requestProfile,
            out LoginNewCharacterRequest packetRequest,
            out byte[] packetPayload,
            out string status)



        {
            requestProfile = null;
            packetRequest = default;
            packetPayload = Array.Empty<byte>();
            status = string.Empty;

            CharacterLoader loader = _playerManager?.Loader;
            LoginCreateCharacterFlowState flow = _loginCreateCharacterFlow;
            if (loader == null || flow == null)
            {
                status = "The login create-character flow is not ready for packet synthesis.";
                return false;
            }

            requestProfile = flow.BuildRequestProfile(loader);
            if (requestProfile == null)
            {
                status = "Starter avatar data could not be resolved from MakeCharInfo for packet synthesis.";
                return false;
            }

            LoginNewCharacterRequest request = requestProfile.ToPacketRequest(characterName);
            packetPayload = LoginOfficialSessionBridgeManager.BuildNewCharacterPacket(request);
            if (!LoginNewCharacterRequestCodec.TryDecode(packetPayload, out packetRequest, out string decodeError))
            {
                status = $"Unable to round-trip the new-character request payload: {decodeError}";
                return false;
            }

            status = requestProfile.IsCharSale
                ? "Built a packet-shaped extra-character create request from the active race, job, and avatar selections."
                : "Built a packet-shaped create-character request from the active race, job, and avatar selections.";
            return true;
        }




        private bool TrySendLiveOfficialDeleteCharacterRequest(LoginCharacterRosterEntry selectedEntry, out string status)



        {



            if (!ShouldRouteLoginRosterMutationThroughLiveSession())



            {



                status = "Login official-session character deletion is unavailable.";



                return false;



            }



            if (selectedEntry?.Build == null || selectedEntry.Build.Id <= 0)



            {



                status = "The selected character does not have a valid live-session character id.";



                return false;



            }



            if (!TryGetActiveLoginRosterPacketProfile(out LoginSelectWorldResultProfile rosterProfile, out _) ||
                !rosterProfile.LoginOpt)



            {



                status = "The attached login session does not currently expose the client delete-character security path.";



                return false;



            }



            if (string.IsNullOrWhiteSpace(_loginAccountSecondaryPassword))



            {



                status = "Live delete-character injection requires a stored secondary password from the login bootstrap flow.";



                return false;



            }



            return _loginOfficialSessionBridge.TrySendDeleteCharacterRequest(
                _loginAccountSecondaryPassword,
                selectedEntry.Build.Id,
                out status);



        }




        private static T PickLoginStarterValue<T>(IReadOnlyList<T> values, int index, T fallback)



        {



            return values != null && index >= 0 && index < values.Count



                ? values[index]



                : fallback;



        }







        private void ApplyStoredLoginAccountSecurity(LoginCharacterAccountStore.LoginCharacterAccountState storedState)



        {



            _loginAccountCashShopNxCredit = Math.Max(0L, storedState?.CashShopNxCredit ?? DefaultCashShopNxCredit);
            _loginAccountStorageExpansionHistory.Clear();
            foreach (LoginCharacterAccountStore.CashShopStorageExpansionRecordState record in storedState?.StorageExpansionHistory
                         ?? Array.Empty<LoginCharacterAccountStore.CashShopStorageExpansionRecordState>())
            {
                _loginAccountStorageExpansionHistory.Add(CloneStorageExpansionHistoryRecord(record));
            }

            _loginAccountId = storedState?.AccountId;

            if (_loginAccountId.HasValue && _loginAccountId.Value > 0)
            {
                _loginBackendSessionManager.SetAuthenticatedAccountId(_loginAccountId.Value);
                if (!_loginCharacterAccountStore.BindAccountIdForAccount(
                        ResolveLoginRosterAccountName(),
                        _loginAccountId.Value))
                {
                    _loginCharacterAccountStore.BindAccountId(
                        ResolveLoginRosterAccountName(),
                        ResolveLoginRosterWorldId(),
                        _loginAccountId.Value);
                }
            }

            ApplyStoredLoginRosterOwnership(storedState);

            _loginAccountPicCode = storedState?.PicCode?.Trim() ?? string.Empty;

            _loginAccountBirthDate = storedState?.BirthDate?.Trim() ?? string.Empty;



            _loginAccountSpwEnabled = storedState?.IsSecondaryPasswordEnabled ?? false;



            _loginAccountSecondaryPassword = storedState?.SecondaryPassword?.Trim() ?? string.Empty;



            SyncCashShopAccountCredit();
            SyncStorageAccessContext();

        }

        private void ApplyStoredLoginRosterOwnership(LoginCharacterAccountStore.LoginCharacterAccountState storedState)
        {
            if (storedState == null)
            {
                return;
            }

            LoginExtraCharInfoResultProfile resolvedExtraCharInfoResult =
                CloneLoginExtraCharInfoResultProfile(_loginPacketExtraCharInfoResultProfile) ??
                CloneLoginExtraCharInfoResultProfile(storedState.ExtraCharInfoResult);
            if (_loginPacketExtraCharInfoResultProfile == null && resolvedExtraCharInfoResult != null)
            {
                _loginPacketExtraCharInfoResultProfile = CloneLoginExtraCharInfoResultProfile(resolvedExtraCharInfoResult);
            }

            _loginBackendSessionManager.ApplyExtraCharInfoResult(resolvedExtraCharInfoResult);
            _loginCanHaveExtraCharacter = _loginBackendSessionManager.CanHaveExtraCharacter;

            IReadOnlyDictionary<int, LoginSelectWorldResultProfile> persistedRosters =
                BuildPersistedLoginRosterProfilesForAccount();
            if (persistedRosters.Count > 0)
            {
                _loginBackendSessionManager.ImportPersistedRosters(
                    persistedRosters,
                    ResolveLoginRosterWorldId());
            }
        }

        private IReadOnlyDictionary<int, LoginSelectWorldResultProfile> BuildPersistedLoginRosterProfilesForAccount()
        {
            Dictionary<int, LoginSelectWorldResultProfile> rostersByWorld = new();
            foreach (LoginCharacterAccountStore.LoginCharacterAccountState storedState in
                     _loginCharacterAccountStore.SnapshotStatesForAccount(
                         ResolveLoginRosterAccountName(),
                         ResolveLoginRosterAccountId()))
            {
                if (storedState == null)
                {
                    continue;
                }

                int worldId = Math.Max(0, storedState.WorldId);
                LoginSelectWorldCharacterEntry[] entries = storedState.Entries?
                    .Where(entry => entry != null)
                    .Select(entry => CreateLoginPacketCharacterEntry(entry, worldId))
                    .Where(entry => entry != null)
                    .ToArray()
                    ?? Array.Empty<LoginSelectWorldCharacterEntry>();
                rostersByWorld[worldId] = new LoginSelectWorldResultProfile
                {
                    ResultCode = 0,
                    Entries = entries,
                    LoginOpt = false,
                    SlotCount = Math.Max(0, storedState.SlotCount),
                    BuyCharacterCount = Math.Max(0, storedState.BuyCharacterCount)
                };
            }

            return rostersByWorld;
        }

        private static LoginExtraCharInfoResultProfile CloneLoginExtraCharInfoResultProfile(
            LoginExtraCharInfoResultProfile profile)
        {
            if (profile == null)
            {
                return null;
            }

            return new LoginExtraCharInfoResultProfile
            {
                AccountId = profile.AccountId,
                ResultFlag = profile.ResultFlag,
                CanHaveExtraCharacter = profile.CanHaveExtraCharacter
            };
        }

        private LoginExtraCharInfoResultProfile ResolvePersistedLoginExtraCharInfoResult()
        {
            LoginExtraCharInfoResultProfile resolvedProfile =
                _loginBackendSessionManager.SnapshotExtraCharInfoResult() ??
                CloneLoginExtraCharInfoResultProfile(_loginPacketExtraCharInfoResultProfile);
            if (resolvedProfile == null)
            {
                return null;
            }

            int? accountId = ResolveLoginRosterAccountId();
            return new LoginExtraCharInfoResultProfile
            {
                AccountId = accountId.HasValue && accountId.Value > 0
                    ? accountId.Value
                    : resolvedProfile.AccountId,
                ResultFlag = resolvedProfile.ResultFlag,
                CanHaveExtraCharacter = resolvedProfile.CanHaveExtraCharacter
            };
        }



        private void PersistLoginAccountSecurityState()



        {



            PersistLoginCharacterRosterToAccountStore(



                _loginCharacterRoster.Entries,



                _loginCharacterRoster.SlotCount,



                _loginCharacterRoster.BuyCharacterCount);



            SyncStorageAccessContext();

        }



        private void PersistLoginCharacterRosterToAccountStore(



            IEnumerable<LoginCharacterRosterEntry> entries,



            int slotCount,



            int buyCharacterCount)



        {



            List<LoginCharacterAccountStore.LoginCharacterAccountEntryState> storedEntries = entries?



                .Where(entry => entry != null)



                .Select(CreateLoginCharacterAccountEntryState)



                .ToList()



                ?? new List<LoginCharacterAccountStore.LoginCharacterAccountEntryState>();



            int nextCharacterId = CalculateNextLoginCharacterId(storedEntries);



            _loginCharacterAccountStore.SaveState(



                ResolveLoginRosterAccountName(),



                ResolveLoginRosterWorldId(),



                slotCount,



                buyCharacterCount,



                nextCharacterId,



                storedEntries,



                _loginAccountCashShopNxCredit,

                _loginAccountPicCode,

                _loginAccountBirthDate,



                _loginAccountSpwEnabled,



                _loginAccountSecondaryPassword,

                ResolveLoginRosterAccountId(),

                null,

                _loginAccountStorageExpansionHistory);
            SyncPacketOwnedAccountCharacterCountFromRoster();



        }

        private void PersistLoginBackendSessionRostersToAccountStore(bool pruneMissingWorlds = false)
        {
            IReadOnlyDictionary<int, LoginSelectWorldResultProfile> cachedRosters =
                _loginBackendSessionManager.SnapshotCachedWorldRosters(
                    preferViewAllRoster: _loginRuntime.CurrentStep == LoginStep.ViewAllCharacters);
            IReadOnlyCollection<int> cachedWorldIds = cachedRosters?.Keys?.ToArray() ?? Array.Empty<int>();

            if (pruneMissingWorlds)
            {
                _loginCharacterAccountStore.PruneStatesForAccount(
                    ResolveLoginRosterAccountName(),
                    cachedWorldIds,
                    ResolveLoginRosterAccountId());
            }

            if (cachedRosters == null || cachedRosters.Count == 0)
            {
                return;
            }

            foreach ((int worldId, LoginSelectWorldResultProfile rosterProfile) in cachedRosters.OrderBy(entry => entry.Key))
            {
                PersistLoginCharacterRosterProfileToAccountStore(rosterProfile, worldId);
            }

            SyncPacketOwnedAccountCharacterCountFromRoster();
        }

        private void PersistLoginCharacterRosterProfileToAccountStore(
            LoginSelectWorldResultProfile rosterProfile,
            int worldId)
        {
            if (rosterProfile == null)
            {
                return;
            }

            List<LoginCharacterAccountStore.LoginCharacterAccountEntryState> storedEntries = rosterProfile.Entries?
                .Where(entry => entry != null)
                .Select(CreateLoginCharacterAccountEntryState)
                .Where(entry => entry != null)
                .ToList()
                ?? new List<LoginCharacterAccountStore.LoginCharacterAccountEntryState>();

            _loginCharacterAccountStore.SaveState(
                ResolveLoginRosterAccountName(),
                Math.Max(0, worldId),
                Math.Max(0, rosterProfile.SlotCount),
                Math.Max(0, rosterProfile.BuyCharacterCount),
                CalculateNextLoginCharacterId(storedEntries),
                storedEntries,
                _loginAccountCashShopNxCredit,
                _loginAccountPicCode,
                _loginAccountBirthDate,
                _loginAccountSpwEnabled,
                _loginAccountSecondaryPassword,
                ResolveLoginRosterAccountId(),
                null,
                _loginAccountStorageExpansionHistory);
        }



        private void SyncCashShopAccountCredit()
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.CashShop) is AdminShopDialogUI cashShopWindow)
            {
                cashShopWindow.SetCashBalances(_loginAccountCashShopNxCredit);
                cashShopWindow.TryConsumeCashBalance = TryConsumeLoginAccountCashShopNxCredit;
                cashShopWindow.ResolveStorageExpansionCommoditySerialNumber = ResolveStorageExpansionCommoditySerialNumber;
                cashShopWindow.GetStorageExpansionStatusSummary = GetStorageExpansionStatusSummary;
                cashShopWindow.StorageExpansionResolved = HandleStorageExpansionResolved;
            }
        }


        private int ResolveStorageExpansionCommoditySerialNumber()
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.CashShopStage) is CashServiceStageWindow cashServiceStageWindow
                && cashServiceStageWindow.TryGetPendingCommoditySerialNumber(out int pendingCommoditySerialNumber))
            {
                return pendingCommoditySerialNumber;
            }

            return _lastPacketOwnedCommoditySerialNumber > 0
                ? _lastPacketOwnedCommoditySerialNumber
                : 0;
        }


        private string GetStorageExpansionStatusSummary()
        {
            LoginCharacterAccountStore.CashShopStorageExpansionRecordState lastRecord = _loginAccountStorageExpansionHistory.Count > 0
                ? _loginAccountStorageExpansionHistory[_loginAccountStorageExpansionHistory.Count - 1]
                : null;
            if (lastRecord == null)
            {
                return $"Account NX {_loginAccountCashShopNxCredit.ToString("N0", CultureInfo.InvariantCulture)}; no stored trunk-expansion result yet.";
            }

            string outcome = lastRecord.ResultSubtype == 1 ? "Last result: success" : "Last result: rejected";
            string subtypeText = lastRecord.CashItemResultSubtype > 0
                ? $" subtype {lastRecord.CashItemResultSubtype.ToString(CultureInfo.InvariantCulture)}"
                : string.Empty;
            string originText = lastRecord.IsPacketOwned
                ? lastRecord.PacketType > 0
                    ? $"packet {lastRecord.PacketType.ToString(CultureInfo.InvariantCulture)}"
                    : "packet-owned Cash Shop seam"
                : "local cash seam";
            string commodityText = lastRecord.CommoditySerialNumber > 0
                ? $"SN {lastRecord.CommoditySerialNumber.ToString(CultureInfo.InvariantCulture)} via {originText}"
                : originText;
            string reasonText = lastRecord.FailureReason > 0
                ? $", reason {lastRecord.FailureReason.ToString(CultureInfo.InvariantCulture)}"
                : string.Empty;
            string settlementText = lastRecord.CashAlreadySettled
                ? ", cash already settled"
                : ", cash billed locally";
            string messageText = string.IsNullOrWhiteSpace(lastRecord.Message)
                ? string.Empty
                : $" {lastRecord.Message.Trim()}";
            return $"{outcome}{subtypeText} via {commodityText}, slot limit {lastRecord.SlotLimitAfterResult.ToString(CultureInfo.InvariantCulture)}, price {lastRecord.NxPrice.ToString("N0", CultureInfo.InvariantCulture)} NX{reasonText}{settlementText}.{messageText}".Trim();
        }


        private void HandleStorageExpansionResolved(AdminShopDialogUI.StorageExpansionResolution resolution)
        {
            if (resolution == null)
            {
                return;
            }

            _loginAccountStorageExpansionHistory.Add(new LoginCharacterAccountStore.CashShopStorageExpansionRecordState
            {
                CashItemResultSubtype = Math.Max(0, resolution.CashItemResultSubtype),
                CommoditySerialNumber = Math.Max(0, resolution.CommoditySerialNumber),
                ResultSubtype = resolution.ResultSubtype,
                FailureReason = Math.Max(0, resolution.FailureReason),
                NxPrice = Math.Max(0L, resolution.NxPrice),
                SlotLimitAfterResult = Math.Max(0, resolution.SlotLimitAfterResult),
                IsPacketOwned = resolution.IsPacketOwned,
                PacketType = Math.Max(0, resolution.PacketType),
                CashAlreadySettled = resolution.CashAlreadySettled,
                Message = resolution.Message ?? string.Empty,
                AppliedAtUtc = DateTime.UtcNow
            });

            while (_loginAccountStorageExpansionHistory.Count > MaxStorageExpansionHistoryEntries)
            {
                _loginAccountStorageExpansionHistory.RemoveAt(0);
            }

            PersistLoginCharacterRosterToAccountStore(
                _loginCharacterRoster.Entries,
                _loginCharacterRoster.SlotCount,
                _loginCharacterRoster.BuyCharacterCount);
        }


        private static LoginCharacterAccountStore.CashShopStorageExpansionRecordState CloneStorageExpansionHistoryRecord(
            LoginCharacterAccountStore.CashShopStorageExpansionRecordState record)
        {
            if (record == null)
            {
                return null;
            }

            return new LoginCharacterAccountStore.CashShopStorageExpansionRecordState
            {
                CashItemResultSubtype = Math.Max(0, record.CashItemResultSubtype),
                CommoditySerialNumber = Math.Max(0, record.CommoditySerialNumber),
                ResultSubtype = record.ResultSubtype,
                FailureReason = Math.Max(0, record.FailureReason),
                NxPrice = Math.Max(0L, record.NxPrice),
                SlotLimitAfterResult = Math.Max(0, record.SlotLimitAfterResult),
                IsPacketOwned = record.IsPacketOwned,
                PacketType = Math.Max(0, record.PacketType),
                CashAlreadySettled = record.CashAlreadySettled,
                Message = record.Message ?? string.Empty,
                AppliedAtUtc = record.AppliedAtUtc == default ? DateTime.UtcNow : record.AppliedAtUtc
            };
        }


        private bool TryConsumeLoginAccountCashShopNxCredit(long amount)
        {
            long normalizedAmount = Math.Max(0L, amount);
            if (normalizedAmount <= 0)
            {
                return true;
            }


            if (_loginAccountCashShopNxCredit < normalizedAmount)
            {
                return false;
            }


            _loginAccountCashShopNxCredit -= normalizedAmount;
            PersistLoginCharacterRosterToAccountStore(
                _loginCharacterRoster.Entries,
                _loginCharacterRoster.SlotCount,
                _loginCharacterRoster.BuyCharacterCount);
            SyncCashShopAccountCredit();
            return true;
        }


        private LoginCharacterAccountStore.LoginCharacterAccountEntryState CreateLoginCharacterAccountEntryState(LoginCharacterRosterEntry entry)



        {



            CharacterBuild build = entry?.Build;



            LoginAvatarLook avatarLook = entry?.AvatarLook;
            byte[] avatarLookPacket = entry?.AvatarLookPacket != null



                ? (byte[])entry.AvatarLookPacket.Clone()



                : (avatarLook != null
                    ? LoginAvatarLookCodec.Encode(avatarLook)
                    : (build != null ? LoginAvatarLookCodec.Encode(build) : Array.Empty<byte>()));



            return new LoginCharacterAccountStore.LoginCharacterAccountEntryState



            {



                CharacterId = build?.Id ?? 0,



                Name = build?.Name ?? string.Empty,



                Gender = build?.Gender ?? CharacterGender.Male,



                Skin = build?.Skin ?? SkinColor.Light,



                Level = build?.Level ?? 1,



                Job = build?.Job ?? 0,



                SubJob = build?.SubJob ?? 0,



                JobName = build?.JobName ?? string.Empty,



                GuildName = build?.GuildName ?? string.Empty,



                AllianceName = build?.AllianceName ?? string.Empty,



                Fame = build?.Fame ?? 0,



                WorldRank = build?.WorldRank ?? 0,



                JobRank = build?.JobRank ?? 0,



                Exp = build?.Exp ?? 0,



                ExpToNextLevel = build?.ExpToNextLevel ?? 0,



                HP = build?.HP ?? 0,



                MaxHP = build?.MaxHP ?? 1,



                MP = build?.MP ?? 0,



                MaxMP = build?.MaxMP ?? 0,



                Strength = build?.STR ?? 0,



                Dexterity = build?.DEX ?? 0,



                Intelligence = build?.INT ?? 0,



                Luck = build?.LUK ?? 0,



                AbilityPoints = build?.AP ?? 0,



                FieldMapId = entry?.FieldMapId ?? 0,



                FieldDisplayName = entry?.FieldDisplayName ?? string.Empty,



                CanDelete = entry?.CanDelete ?? true,



                PreviousWorldRank = entry?.PreviousWorldRank,



                PreviousJobRank = entry?.PreviousJobRank,



                AvatarLookPacket = avatarLookPacket,



                Portal = entry?.Portal ?? 0



            };



        }







        private LoginCharacterAccountStore.LoginCharacterAccountEntryState CreateLoginCharacterAccountEntryState(
            LoginSelectWorldCharacterEntry packetEntry)
        {
            if (packetEntry == null)
            {
                return null;
            }

            CharacterBuild build = CreateLoginCharacterBuildFromPacket(packetEntry);
            int targetMapId = packetEntry.FieldMapId > 0 ? packetEntry.FieldMapId : ResolveLoginCharacterTargetMapId();

            return new LoginCharacterAccountStore.LoginCharacterAccountEntryState
            {
                CharacterId = build.Id,
                Name = build.Name ?? string.Empty,
                Gender = build.Gender,
                Skin = build.Skin,
                Level = build.Level,
                Job = build.Job,
                SubJob = build.SubJob,
                JobName = string.IsNullOrWhiteSpace(build.JobName) ? SkillDataLoader.GetJobName(build.Job) : build.JobName,
                GuildName = build.GuildName ?? string.Empty,
                AllianceName = build.AllianceName ?? string.Empty,
                Fame = build.Fame,
                WorldRank = build.WorldRank,
                JobRank = build.JobRank,
                Exp = build.Exp,
                ExpToNextLevel = build.ExpToNextLevel,
                HP = build.HP,
                MaxHP = build.MaxHP,
                MP = build.MP,
                MaxMP = build.MaxMP,
                Strength = build.STR,
                Dexterity = build.DEX,
                Intelligence = build.INT,
                Luck = build.LUK,
                AbilityPoints = build.AP,
                FieldMapId = targetMapId,
                FieldDisplayName = ResolveMapTransferDisplayName(targetMapId),
                CanDelete = true,
                PreviousWorldRank = packetEntry.PreviousWorldRank,
                PreviousJobRank = packetEntry.PreviousJobRank,
                AvatarLookPacket = packetEntry.AvatarLookPacket != null
                    ? (byte[])packetEntry.AvatarLookPacket.Clone()
                    : Array.Empty<byte>(),
                Portal = packetEntry.Portal
            };
        }

        private static int CalculateNextLoginCharacterId(IEnumerable<LoginCharacterAccountStore.LoginCharacterAccountEntryState> entries)



        {



            int maxCharacterId = 0;



            foreach (LoginCharacterAccountStore.LoginCharacterAccountEntryState entry in entries ?? Array.Empty<LoginCharacterAccountStore.LoginCharacterAccountEntryState>())



            {



                maxCharacterId = Math.Max(maxCharacterId, entry?.CharacterId ?? 0);



            }







            return maxCharacterId + 1;



        }







        private string BuildSuggestedLoginCharacterName()



        {



            int suffix = _loginCharacterRoster.Entries.Count + 1;



            while (_loginCharacterRoster.Entries.Any(entry =>



                       string.Equals(entry?.Build?.Name, $"Explorer{suffix}", StringComparison.OrdinalIgnoreCase)))



            {



                suffix++;



            }







            return $"Explorer{suffix}";



        }







        private CharacterBuild CreateAccountBackedLoginCharacterBuild(int characterId, string name, int rosterCount)



        {



            CharacterBuild build = null;



            int templateIndex = Math.Abs(rosterCount % 3);



            switch (templateIndex)



            {



                case 0:



                    build = _playerManager?.Loader?.LoadDefaultMale() ?? _playerManager?.Loader?.LoadRandom();



                    if (build != null)



                    {



                        ApplyLoginCharacterDetailDefaults(build, 15, "Henesys", 0, 14, 0, 0);



                    }



                    break;



                case 1:



                    build = _playerManager?.Loader?.LoadDefaultFemale() ?? _playerManager?.Loader?.LoadRandom();



                    if (build != null)



                    {



                        ApplyLoginCharacterDetailDefaults(build, 15, "Ellinia", 0, 18, 0, 0);



                    }



                    break;



                default:



                    build = _playerManager?.Loader?.LoadRandom()



                        ?? _playerManager?.Loader?.LoadDefaultMale()



                        ?? _playerManager?.Loader?.LoadDefaultFemale();



                    if (build != null)



                    {



                        ApplyLoginCharacterDetailDefaults(build, 15, "Lith Harbor", 0, 22, 0, 0);



                    }



                    break;



            }







            build ??= new CharacterBuild();



            build.Id = characterId;



            build.Name = name;



            build.ExpToNextLevel = Math.Max(100, build.ExpToNextLevel);



            return build;



        }







        private void SelectLoginCharacterById(int characterId)



        {



            if (characterId <= 0)



            {



                return;



            }







            for (int index = 0; index < _loginCharacterRoster.Entries.Count; index++)



            {



                if (_loginCharacterRoster.Entries[index]?.Build?.Id == characterId)



                {



                    _loginCharacterRoster.Select(index);



                    return;



                }



            }



        }







        private int ResolveLoginCharacterTargetMapId()
        {
            if (_mapBoard?.MapInfo?.returnMap is int returnMapId &&
                returnMapId > 0 &&
                returnMapId != MapConstants.MaxMap)
            {
                return returnMapId;
            }


            if (_mapBoard?.MapInfo?.forcedReturn is int forcedReturnId &&
                forcedReturnId > 0 &&
                forcedReturnId != MapConstants.MaxMap)
            {
                return forcedReturnId;
            }


            return DefaultLoginCharacterFieldMapId;

        }



        private void SyncLoginCharacterSelectWindow()

        {

            WireAvatarPreviewCarouselWindow();



            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.CharacterSelect) is not CharacterSelectWindow characterSelectWindow)
            {
                SyncAvatarPreviewCarouselWindow();
                SyncLoginCharacterDetailWindow();
                return;
            }


            bool shouldShow = IsLoginRuntimeSceneActive &&
                              (_loginRuntime.CurrentStep == LoginStep.CharacterSelect ||
                               _loginRuntime.CurrentStep == LoginStep.ViewAllCharacters);
            if (!shouldShow)
            {
                characterSelectWindow.Hide();
                SyncAvatarPreviewCarouselWindow();
                SyncLoginCharacterDetailWindow();
                return;
            }


            bool canEnter = _loginCharacterRoster.CanRequestSelection(_loginRuntime, out string validationMessage);
            bool canDelete = _loginCharacterRoster.SelectedEntry?.CanDelete == true &&
                             (_loginRuntime.CurrentStep == LoginStep.CharacterSelect ||
                              _loginRuntime.CurrentStep == LoginStep.ViewAllCharacters);
            characterSelectWindow.SetRoster(
                _loginCharacterRoster.Entries,
                _loginCharacterRoster.SelectedIndex,
                string.IsNullOrWhiteSpace(_loginCharacterStatusMessage) ? validationMessage : _loginCharacterStatusMessage,
                _loginCharacterRoster.SlotCount,
                _loginCharacterRoster.BuyCharacterCount,
                _loginCharacterRoster.PageIndex,
                _loginCharacterRoster.PageCount,
                canEnter,
                canDelete);
            characterSelectWindow.Show();
            uiWindowManager.BringToFront(characterSelectWindow);
            SyncAvatarPreviewCarouselWindow();
            SyncLoginCharacterDetailWindow();
        }
        private void SyncLoginCreateCharacterWindow()
        {
            WireLoginCreateCharacterWindow();


            bool shouldShow = IsLoginRuntimeSceneActive &&
                              _loginCreateCharacterFlow != null &&
                              (_loginRuntime.CurrentStep == LoginStep.NewCharacter ||
                               _loginRuntime.CurrentStep == LoginStep.NewCharacterAvatar);
            if (!shouldShow)
            {
                foreach (LoginCreateCharacterWindowBase window in EnumerateLoginCreateCharacterWindows())
                {
                    window.Hide();
                }
                return;
            }


            CharacterBuild previewBuild = _loginCreateCharacterFlow.CreatePreviewBuild(_playerManager?.Loader);
            LoginCreateCharacterWindowBase createCharacterWindow = GetLoginCreateCharacterWindow(_loginCreateCharacterFlow.Stage);
            foreach (LoginCreateCharacterWindowBase window in EnumerateLoginCreateCharacterWindows())
            {
                if (ReferenceEquals(window, createCharacterWindow))
                {
                    window.Configure(_loginCreateCharacterFlow, previewBuild);
                    window.Show();
                    uiWindowManager.BringToFront(window);
                }
                else
                {
                    window.Hide();
                }
            }
        }


        private void SyncAvatarPreviewCarouselWindow()
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.AvatarPreviewCarousel) is not AvatarPreviewCarouselWindow previewWindow)
            {
                return;
            }


            bool shouldShow = IsLoginRuntimeSceneActive &&
                              (_loginRuntime.CurrentStep == LoginStep.CharacterSelect ||
                               _loginRuntime.CurrentStep == LoginStep.ViewAllCharacters);
            if (!shouldShow)
            {
                previewWindow.Hide();
                return;
            }


            previewWindow.SetRoster(
                _loginCharacterRoster.Entries,
                _loginCharacterRoster.SelectedIndex,
                _loginCharacterRoster.SlotCount,
                _loginCharacterRoster.BuyCharacterCount,
                _loginCharacterRoster.PageIndex);
            previewWindow.Show();
            uiWindowManager.BringToFront(previewWindow);
        }


        private void SyncLoginEntryDialogs()
        {
            if (uiWindowManager == null)
            {
                return;
            }


            WireLoginEntryDialogWindows();



            if (!IsLoginRuntimeSceneActive)
            {
                uiWindowManager.HideWindow(MapSimulatorWindowNames.ConnectionNotice);
                if (!_loginUtilityDialogAllowedOutsideLogin)
                {
                    uiWindowManager.HideWindow(MapSimulatorWindowNames.LoginUtilityDialog);
                    _loginUtilityDialogReturnWindowName = string.Empty;
                }
                else
                {
                    SyncLoginUtilityDialogWindow();
                }
                return;
            }


            SyncConnectionNoticeWindow();

            SyncLoginUtilityDialogWindow();

        }



        private void SyncConnectionNoticeWindow()
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.ConnectionNotice) is not ConnectionNoticeWindow noticeWindow)
            {
                return;
            }


            if (_activeConnectionNoticeExpiresAt != int.MinValue &&
                unchecked(currTickCount - _activeConnectionNoticeExpiresAt) >= 0)
            {
                ClearActiveConnectionNotice();
            }


            bool shouldShow = false;
            string body = string.Empty;
            bool showProgress = false;
            float progress = 0f;
            ConnectionNoticeWindowVariant variant = ConnectionNoticeWindowVariant.Notice;
            string title = "Connection Notice";
            int? noticeTextIndex = null;


            if (_activeConnectionNoticeExpiresAt != int.MinValue)
            {
                shouldShow = true;
                title = _activeConnectionNoticeTitle;
                body = _activeConnectionNoticeBody;
                showProgress = _activeConnectionNoticeShowProgress;
                progress = _activeConnectionNoticeProgress;
                variant = _activeConnectionNoticeVariant;
                noticeTextIndex = _activeConnectionNoticeTextIndex;
            }
            else if (_selectorRequestKind != SelectorRequestKind.None)
            {
                shouldShow = true;
                body = _selectorRequestStatusMessage ?? "Waiting for the login bootstrap reply.";
                showProgress = true;
                variant = ConnectionNoticeWindowVariant.LoadingSingleGauge;
                if (_selectorRequestDurationMs > 0 && _selectorRequestStartedAt != int.MinValue)
                {
                    progress = MathHelper.Clamp(
                        (currTickCount - _selectorRequestStartedAt) / (float)_selectorRequestDurationMs,
                        0f,
                        1f);
                }
            }
            else if (_loginRuntime.CurrentStep == LoginStep.EnteringField)
            {
                shouldShow = true;
                body = string.IsNullOrWhiteSpace(_loginCharacterStatusMessage)
                    ? "Requesting field entry from the selected character."
                    : _loginCharacterStatusMessage;
            }
            else if (_loginRuntime.CurrentStep == LoginStep.Title &&
                     _loginRuntime.PendingStep == LoginStep.WorldSelect)
            {
                shouldShow = true;
                body = string.IsNullOrWhiteSpace(_loginTitleStatusMessage)
                    ? "Checking account credentials for the login bootstrap flow."
                    : _loginTitleStatusMessage;
                showProgress = true;
                variant = ConnectionNoticeWindowVariant.Loading;
                if (_loginRuntime.PendingStepDelayMs > 0 && _loginRuntime.StepChangeRequestedAt != int.MinValue)
                {
                    progress = MathHelper.Clamp(
                        (currTickCount - _loginRuntime.StepChangeRequestedAt) / (float)_loginRuntime.PendingStepDelayMs,
                        0f,
                        1f);
                }
            }


            if (!shouldShow)
            {
                noticeWindow.Hide();
                return;
            }


            noticeWindow.Configure(title, body, showProgress, progress, variant, noticeTextIndex);
            if (_activeConnectionNoticeTracksDirectionModeOwner)
            {
                ShowWindow(
                    MapSimulatorWindowNames.ConnectionNotice,
                    noticeWindow,
                    trackDirectionModeOwner: true);
                return;
            }

            uiWindowManager.ShowWindow(noticeWindow);
        }


        private void SyncLoginUtilityDialogWindow()
        {
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.LoginUtilityDialog) is not LoginUtilityDialogWindow utilityDialogWindow)
            {
                return;
            }


            if (_loginUtilityDialogAction == LoginUtilityDialogAction.None)
            {
                utilityDialogWindow.Hide();
                return;
            }


            if (utilityDialogWindow.IsVisible)
            {
                _loginUtilityDialogInputValue = utilityDialogWindow.InputValue ?? string.Empty;
            }


            utilityDialogWindow.Configure(
                _loginUtilityDialogTitle,
                _loginUtilityDialogBody,
                _loginUtilityDialogPrimaryLabel,
                _loginUtilityDialogSecondaryLabel,
                _loginUtilityDialogButtonLayout,
                _loginUtilityDialogNoticeTextIndex,
                _loginUtilityDialogInputLabel,
                _loginUtilityDialogInputPlaceholder,
                _loginUtilityDialogInputMasked,
                _loginUtilityDialogInputMaxLength,
                _loginUtilityDialogInputValue,
                _loginUtilityDialogSoftKeyboardType,
                _loginUtilityDialogVisualStyle,
                _loginUtilityDialogFrameVariant,
                _loginUtilityDialogInputBoundsOverride);
            if (_loginUtilityDialogTracksDirectionModeOwner)
            {
                ShowWindow(
                    MapSimulatorWindowNames.LoginUtilityDialog,
                    utilityDialogWindow,
                    trackDirectionModeOwner: true);
                return;
            }

            uiWindowManager.ShowWindow(utilityDialogWindow);
        }


        private void ShowLoginUtilityDialog(
            string title,
            string body,
            LoginUtilityDialogButtonLayout buttonLayout,
            LoginUtilityDialogAction action,
            int targetIndex = -1,
            int? noticeTextIndex = null,
            string primaryLabel = null,
            string secondaryLabel = null,
            string inputLabel = null,
            string inputPlaceholder = null,
            bool inputMasked = false,
            int inputMaxLength = 0,
            string inputValue = null,
            SoftKeyboardKeyboardType softKeyboardType = SoftKeyboardKeyboardType.AlphaNumeric,
            LoginUtilityDialogVisualStyle visualStyle = LoginUtilityDialogVisualStyle.Default,
            LoginUtilityDialogFrameVariant frameVariant = LoginUtilityDialogFrameVariant.Default,
            Rectangle? inputBoundsOverride = null,
            string returnWindowName = null,
            bool trackDirectionModeOwner = false,
            bool hasExplicitTrackDirectionModeOwner = false)
        {
            if (!string.IsNullOrWhiteSpace(returnWindowName))
            {
                _loginUtilityDialogReturnWindowName = returnWindowName;
            }
            else if (_loginUtilityDialogAction == LoginUtilityDialogAction.None ||
                     string.IsNullOrWhiteSpace(_loginUtilityDialogReturnWindowName))
            {
                _loginUtilityDialogReturnWindowName = ResolveLoginUtilityDialogReturnWindowName();
            }

            _loginUtilityDialogTitle = string.IsNullOrWhiteSpace(title) ? "Login Utility" : title;
            _loginUtilityDialogBody = body ?? string.Empty;
            _loginUtilityDialogButtonLayout = buttonLayout;
            _loginUtilityDialogPrimaryLabel = primaryLabel ?? string.Empty;
            _loginUtilityDialogSecondaryLabel = secondaryLabel ?? string.Empty;
            _loginUtilityDialogAction = action;
            _loginUtilityDialogTargetIndex = targetIndex;
            _loginUtilityDialogNoticeTextIndex = noticeTextIndex;
            _loginUtilityDialogInputLabel = inputLabel ?? string.Empty;
            _loginUtilityDialogInputPlaceholder = inputPlaceholder ?? string.Empty;
            _loginUtilityDialogInputMasked = inputMasked;
            _loginUtilityDialogInputMaxLength = Math.Max(0, inputMaxLength);
            _loginUtilityDialogInputValue = inputValue ?? string.Empty;
            _loginUtilityDialogSoftKeyboardType = softKeyboardType;
            _loginUtilityDialogVisualStyle = visualStyle;
            _loginUtilityDialogFrameVariant = ResolveLoginUtilityDialogFrameVariant(
                frameVariant,
                action,
                noticeTextIndex,
                inputLabel,
                visualStyle);
            _loginUtilityDialogTracksDirectionModeOwner = ResolveSharedHostDirectionModeOwnerTracking(
                trackDirectionModeOwner,
                hasExplicitTrackDirectionModeOwner,
                ShouldTrackInheritedDirectionModeOwner());
            _loginUtilityDialogInputBoundsOverride = inputBoundsOverride;
            _loginUtilityDialogAllowedOutsideLogin = IsLoginUtilityDialogActionAllowedOutsideLogin(action);
            ClearActiveConnectionNotice();
            SyncLoginEntryDialogs();
        }

        private static bool ResolveSharedHostDirectionModeOwnerTracking(
            bool trackDirectionModeOwner,
            bool hasExplicitTrackDirectionModeOwner,
            bool inheritedDirectionModeOwner)
        {
            if (hasExplicitTrackDirectionModeOwner)
            {
                return trackDirectionModeOwner;
            }

            return trackDirectionModeOwner || inheritedDirectionModeOwner;
        }

