        private static bool IsLoginUtilityDialogActionAllowedOutsideLogin(LoginUtilityDialogAction action)
        {
            return action is LoginUtilityDialogAction.ConfirmApspEvent
                or LoginUtilityDialogAction.ConfirmFollowCharacterRequest
                or LoginUtilityDialogAction.ConfirmUtilityQuit
                or LoginUtilityDialogAction.DismissOnly
                or LoginUtilityDialogAction.VerifyTrunkPic
                or LoginUtilityDialogAction.VerifyTrunkSpw
                or LoginUtilityDialogAction.RetryTrunkPic
                or LoginUtilityDialogAction.RetryTrunkSpw
                or LoginUtilityDialogAction.LogoutGiftCompletion
                or LoginUtilityDialogAction.SetFamilyPrecept
                or LoginUtilityDialogAction.EntrustedShopBlacklistAdd
                or LoginUtilityDialogAction.EntrustedShopBlacklistNotice;
        }

        private LoginUtilityDialogFrameVariant ResolveLoginUtilityDialogFrameVariant(
            LoginUtilityDialogFrameVariant frameVariant,
            LoginUtilityDialogAction action,
            int? noticeTextIndex,
            string inputLabel,
            LoginUtilityDialogVisualStyle visualStyle)
        {
            if (frameVariant != LoginUtilityDialogFrameVariant.Default)
            {
                return frameVariant;
            }

            if (!IsLoginRuntimeSceneActive)
            {
                return frameVariant;
            }

            if (noticeTextIndex.HasValue ||
                !string.IsNullOrWhiteSpace(inputLabel) ||
                visualStyle != LoginUtilityDialogVisualStyle.Default ||
                action is LoginUtilityDialogAction.AccountMigrationDecision
                    or LoginUtilityDialogAction.EulaDecision
                    or LoginUtilityDialogAction.VerifyBirthDate
                    or LoginUtilityDialogAction.VerifyPic
                    or LoginUtilityDialogAction.SetPic
                    or LoginUtilityDialogAction.SecondaryPasswordDecision
                    or LoginUtilityDialogAction.SetSpw
                    or LoginUtilityDialogAction.VerifySpw
                    or LoginUtilityDialogAction.WebsiteHandoffDecision
                    or LoginUtilityDialogAction.WebsiteHandoff)
            {
                return LoginUtilityDialogFrameVariant.LoginNotice;
            }

            return frameVariant;
        }


        private void HideLoginUtilityDialog()
        {
            _loginUtilityDialogAction = LoginUtilityDialogAction.None;
            _loginUtilityDialogBody = string.Empty;
            _loginUtilityDialogButtonLayout = LoginUtilityDialogButtonLayout.Ok;
            _loginUtilityDialogTargetIndex = -1;
            _loginUtilityDialogNoticeTextIndex = null;
            _loginUtilityDialogInputLabel = string.Empty;
            _loginUtilityDialogInputPlaceholder = string.Empty;
            _loginUtilityDialogInputMasked = false;
            _loginUtilityDialogInputMaxLength = 0;
            _loginUtilityDialogSoftKeyboardType = SoftKeyboardKeyboardType.AlphaNumeric;
            _loginUtilityDialogVisualStyle = LoginUtilityDialogVisualStyle.Default;
            _loginUtilityDialogFrameVariant = LoginUtilityDialogFrameVariant.Default;
            _loginUtilityDialogTracksDirectionModeOwner = false;
            _loginUtilityDialogInputValue = string.Empty;
            _loginUtilityDialogInputBoundsOverride = null;
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.LoginUtilityDialog) is LoginUtilityDialogWindow utilityDialogWindow)
            {
                utilityDialogWindow.Hide();
            }

            if (!TryBringLoginUtilityDialogReturnWindowToFront())
            {
                BringLoginTitleWindowToFront();
            }

            _loginUtilityDialogReturnWindowName = string.Empty;
        }

        private string ResolveLoginUtilityDialogReturnWindowName()
        {
            if (uiWindowManager == null)
            {
                return string.Empty;
            }

            static bool IsLoginUtilityOverlay(UIWindowBase window)
            {
                if (window == null)
                {
                    return false;
                }

                return string.Equals(window.WindowName, MapSimulatorWindowNames.LoginUtilityDialog, StringComparison.Ordinal) ||
                       string.Equals(window.WindowName, MapSimulatorWindowNames.ConnectionNotice, StringComparison.Ordinal);
            }

            UIWindowBase focusedWindow = uiWindowManager.FocusedWindow;
            if (focusedWindow?.IsVisible == true && !IsLoginUtilityOverlay(focusedWindow))
            {
                return focusedWindow.WindowName;
            }

            string[] fallbackWindowNames =
            {
                MapSimulatorWindowNames.LoginCreateCharacterNameSelect,
                MapSimulatorWindowNames.LoginCreateCharacterAvatarSelect,
                MapSimulatorWindowNames.LoginCreateCharacterJobSelect,
                MapSimulatorWindowNames.LoginCreateCharacterRaceSelect,
                MapSimulatorWindowNames.WorldSelect,
                MapSimulatorWindowNames.CharacterSelect,
                MapSimulatorWindowNames.LoginTitle,
                MapSimulatorWindowNames.MapTransfer,
                MapSimulatorWindowNames.AntiMacro,
                MapSimulatorWindowNames.AdminAntiMacro,
            };

            for (int i = 0; i < fallbackWindowNames.Length; i++)
            {
                string windowName = fallbackWindowNames[i];
                if (uiWindowManager.GetWindow(windowName) is UIWindowBase window &&
                    window.IsVisible &&
                    !IsLoginUtilityOverlay(window))
                {
                    return windowName;
                }
            }

            return string.Empty;
        }

        private bool TryBringLoginUtilityDialogReturnWindowToFront()
        {
            if (string.IsNullOrWhiteSpace(_loginUtilityDialogReturnWindowName) ||
                uiWindowManager?.GetWindow(_loginUtilityDialogReturnWindowName) is not UIWindowBase returnWindow ||
                !returnWindow.IsVisible)
            {
                return false;
            }

            uiWindowManager.BringToFront(returnWindow);
            return true;
        }

