        private bool ShouldAutoConsumePickedUpItem(int itemId)
        {
            if (itemId <= 0 || !InventoryItemMetadataResolver.IsConsumedOnPickup(itemId))
            {
                return false;
            }

            if (_monsterBookManager.IsConsumeOnPickupCardItem(itemId))
            {
                return true;
            }

            ConsumableItemEffect effect = ResolveConsumableItemEffect(itemId);
            return effect.HasSupportedRecovery
                   || effect.HasSupportedProgression
                   || effect.HasSupportedMovement
                   || effect.HasSupportedMorph
                   || effect.HasSupportedTemporaryBuff
                   || effect.HasSupportedCure
                   || effect.HasSupportedFieldProtection
                   || effect.HasSupportedMobSkill;
        }

        private bool ShouldAutoApplyRunOnPickupConsumableItem(int itemId)
        {
            if (itemId <= 0)
            {
                return false;
            }

            bool isRunOnPickup = InventoryItemMetadataResolver.IsRunOnPickup(itemId);
            bool hasAuthoredNpcInteraction = InventoryItemMetadataResolver.HasAuthoredNpcInteraction(itemId);
            ConsumableItemEffect effect = ResolveConsumableItemEffect(itemId);
            return ShouldAutoApplyRunOnPickupConsumableInteraction(
                isRunOnPickup,
                hasAuthoredNpcInteraction,
                HasSupportedPickupConsumableOutcome(effect));
        }

        internal static bool ShouldAutoApplyRunOnPickupConsumableInteraction(
            bool isRunOnPickup,
            bool hasAuthoredNpcInteraction,
            bool hasSupportedConsumableOutcome)
        {
            return isRunOnPickup
                   && !hasAuthoredNpcInteraction
                   && hasSupportedConsumableOutcome;
        }

        private static bool HasSupportedPickupConsumableOutcome(ConsumableItemEffect effect)
        {
            return effect.HasSupportedRecovery
                   || effect.HasSupportedProgression
                   || effect.HasSupportedMovement
                   || effect.HasSupportedMorph
                   || effect.HasSupportedTemporaryBuff
                   || effect.HasSupportedCure
                   || effect.HasSupportedFieldProtection
                   || effect.HasSupportedMobSkill;
        }

        private bool ShouldAutoHandlePickedUpItem(int itemId)
        {
            if (itemId <= 0)
            {
                return false;
            }

            if (_monsterBookManager.IsConsumeOnPickupCardItem(itemId))
            {
                return true;
            }

            return InventoryItemMetadataResolver.IsConsumedOnPickup(itemId)
                   || ShouldAutoConsumePickedUpItem(itemId)
                   || ShouldAutoApplyRunOnPickupConsumableItem(itemId)
                   || InventoryItemMetadataResolver.ShouldAutoRunOnPickupInteraction(itemId);
        }

        private bool TryApplyQuestBuffItemReward(int itemId)
        {
            if (itemId <= 0 || _playerManager?.Player == null)
            {
                return false;
            }


            ConsumableItemEffect effect = ResolveConsumableItemEffect(itemId);
            bool supportsRecovery = effect.HasSupportedRecovery;
            bool supportsProgression = effect.HasSupportedProgression;
            bool supportsMovement = effect.HasSupportedMovement;
            bool supportsMorph = effect.HasSupportedMorph;
            bool supportsTemporaryBuff = effect.HasSupportedTemporaryBuff;
            bool supportsCure = effect.HasSupportedCure;
            bool supportsFieldProtection = effect.HasSupportedFieldProtection;
            bool supportsMobSkill = effect.HasSupportedMobSkill;
            if (!supportsRecovery && !supportsProgression && !supportsMovement && !supportsMorph && !supportsTemporaryBuff && !supportsCure && !supportsFieldProtection && !supportsMobSkill)
            {
                return false;
            }

            if (IsConsumableUseBlockedByMobStatus(effect))
            {
                return false;
            }


            PlayerCharacter player = _playerManager.Player;
            int hpGain = supportsRecovery
                ? ResolveConsumableRecoveryAmount(player.HP, player.MaxHP, effect.FlatHp, effect.PercentHp)
                : 0;
            int mpGain = supportsRecovery
                ? ResolveConsumableRecoveryAmount(player.MP, player.MaxMP, effect.FlatMp, effect.PercentMp)
                : 0;
            bool canApplyProgression = supportsProgression && player.Build != null;
            int targetMapId = supportsMovement
                ? ResolveConsumableMoveTargetMapId(effect.MoveToMapId)
                : 0;
            int morphTemplateId = supportsMorph
                ? ResolveConsumableMorphTemplateId(effect)
                : 0;


            bool canApplyTemporaryBuff = supportsTemporaryBuff && _playerManager?.Skills != null;
            bool canApplyFieldProtection = supportsFieldProtection;
            bool canQueueMovement = TryCanQueueConsumableMapTransfer(targetMapId, showFailureMessage: true);
            bool canApplyMorph = supportsMorph
                && morphTemplateId > 0
                && player.CanApplyExternalAvatarTransform(itemId, actionName: null, morphTemplateId);
            bool canCureStatus = supportsCure && HasCurablePlayerMobStatus(effect);
            bool canApplyMobSkill = supportsMobSkill && _playerManager != null;
            bool hasAnySupportedOutcome = hpGain > 0 || mpGain > 0 || canApplyProgression || canQueueMovement || canApplyMorph || canApplyTemporaryBuff || canCureStatus || canApplyFieldProtection || canApplyMobSkill;
            if (!hasAnySupportedOutcome)
            {
                return false;
            }


            ApplyConsumableRecovery(player, hpGain, mpGain);
            if (canApplyProgression)
            {
                ApplyConsumableProgressionToBuild(
                    player.Build,
                    effect.DirectExperience,
                    effect.CharismaExperience,
                    effect.InsightExperience,
                    effect.WillExperience,
                    effect.CraftExperience,
                    effect.SenseExperience,
                    effect.CharmExperience,
                    effect.EventPoint);
            }


            if (supportsCure)
            {
                ClearCurablePlayerMobStatuses(effect);
            }

            if (canApplyMorph)
            {
                player.ApplyExternalAvatarTransform(itemId, actionName: null, morphTemplateId, currTickCount + effect.DurationMs);
            }


            if (canApplyTemporaryBuff)
            {
                SkillLevelData consumableBuffData = CreateConsumableBuffLevelData(effect);
                _playerManager.Skills.TryApplyConsumableBuff(
                    itemId,
                    ResolvePickupItemName(itemId),
                    ResolvePickupItemDescription(itemId),
                    consumableBuffData,
                    currTickCount);
            }

            if (canApplyFieldProtection)
            {
                ApplyConsumableEnvironmentalDamageProtection(effect, currTickCount);
            }

            if (canApplyMobSkill)
            {
                ApplyConsumableMobSkillEffects(effect.MobSkillEffects, currTickCount);
            }


            if (!supportsMovement)
            {
                return true;
            }

            return canQueueMovement && TryQueueConsumableMapTransfer(targetMapId);

        }

        private bool TryApplyPickedUpItemRuntime(int itemId, int currentTime)
        {
            if (itemId <= 0)
            {
                return false;
            }

            bool preferAuthoredRunOnPickupInteraction = InventoryItemMetadataResolver.ShouldAutoRunOnPickupInteraction(itemId);
            if (ShouldTryPickupConsumableRuntimeBeforeAuthoredInteraction(preferAuthoredRunOnPickupInteraction)
                && TryApplyPickedUpConsumableRuntime(itemId))
            {
                return true;
            }

            if (!InventoryItemMetadataResolver.ShouldAutoRunOnPickupInteraction(itemId))
            {
                return false;
            }

            bool hasNpcReference = InventoryItemMetadataResolver.TryResolveNpcReference(itemId, out int npcId)
                                   && npcId > 0;
            bool hasScriptPublications = InventoryItemMetadataResolver.TryResolveSpecScriptPublications(
                itemId,
                out IReadOnlyList<FieldObjectScriptPublication> scriptPublications);
            bool hasScript = InventoryItemMetadataResolver.TryResolveSpecScripts(itemId, out IReadOnlyList<string> scriptNames);
            string scriptName = hasScript && scriptNames.Count > 0
                ? scriptNames[0]
                : null;
            if (!hasNpcReference && !hasScript && !hasScriptPublications)
            {
                return false;
            }

            InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(itemId);
            string fieldItemRestrictionMessage = GetFieldItemUseRestrictionMessage(inventoryType, itemId, 1);
            if (!string.IsNullOrWhiteSpace(fieldItemRestrictionMessage))
            {
                ShowFieldRestrictionMessage(fieldItemRestrictionMessage);
                return false;
            }

            if (!TryOpenItemAuthoredInventoryInteraction(
                    itemId,
                    npcId,
                    scriptName,
                    scriptNames,
                    scriptPublications))
            {
                return false;
            }

            _fieldRuleRuntime?.RegisterSuccessfulItemUse(
                ShouldTrackFieldConsumeItemCooldown(inventoryType, default, default),
                currentTime);
            return true;
        }

        internal static bool ShouldTryPickupConsumableRuntimeBeforeAuthoredInteraction(bool preferAuthoredRunOnPickupInteraction)
        {
            return !preferAuthoredRunOnPickupInteraction;
        }

        private bool TryApplyPickedUpConsumableRuntime(int itemId)
        {
            if (itemId <= 0 || !InventoryItemMetadataResolver.IsConsumedOnPickup(itemId))
            {
                return false;
            }

            return TryApplyPickedUpConsumableRuntime(itemId, allowConsumedOnPickupFallback: true);
        }

        private bool TryApplyRunOnPickupConsumableRuntime(int itemId)
        {
            if (itemId <= 0
                || !InventoryItemMetadataResolver.IsRunOnPickup(itemId)
                || InventoryItemMetadataResolver.HasAuthoredNpcInteraction(itemId))
            {
                return false;
            }

            return TryApplyPickedUpConsumableRuntime(itemId, allowConsumedOnPickupFallback: false);
        }

        private bool TryApplyPickedUpConsumableRuntime(int itemId, bool allowConsumedOnPickupFallback)
        {
            if (itemId <= 0)
            {
                return false;
            }

            if (TryApplyQuestBuffItemReward(itemId))
            {
                return true;
            }

            if (!allowConsumedOnPickupFallback)
            {
                return false;
            }

            ConsumableItemEffect effect = ResolveConsumableItemEffect(itemId);
            if (!ShouldBurnConsumedOnPickupDeathMarkFallback(
                    consumedOnPickup: true,
                    curesDeathMark: effect.CuresDeathMark))
            {
                return false;
            }

            // WZ carries deathmark-only consumeOnPickup rows such as 2002058.
            // Those drops are authored to disappear on pickup instead of becoming bag items.
            ClearCurablePlayerMobStatuses(effect);
            return true;
        }

        internal static bool ShouldBurnConsumedOnPickupDeathMarkFallback(bool consumedOnPickup, bool curesDeathMark)
        {
            return consumedOnPickup && curesDeathMark;
        }

        internal static int ResolvePickupRunOnPickupInventoryRemainder(
            int pickedQuantity,
            bool interactionOpened,
            bool consumeOnUse)
        {
            int normalizedQuantity = Math.Max(0, pickedQuantity);
            if (normalizedQuantity == 0)
            {
                return 0;
            }

            if (!interactionOpened)
            {
                return normalizedQuantity;
            }

            return consumeOnUse
                ? Math.Max(0, normalizedQuantity - 1)
                : normalizedQuantity;
        }

        internal static int ResolvePickupAutoUseRemainder(
            int pickedQuantity,
            int successfulUseCount,
            bool consumeOnUse)
        {
            int normalizedQuantity = Math.Max(0, pickedQuantity);
            if (normalizedQuantity == 0)
            {
                return 0;
            }

            int normalizedUseCount = Math.Clamp(successfulUseCount, 0, normalizedQuantity);
            if (normalizedUseCount <= 0)
            {
                return normalizedQuantity;
            }

            return consumeOnUse
                ? Math.Max(0, normalizedQuantity - normalizedUseCount)
                : normalizedQuantity;
        }

        internal static bool ShouldBurnUnsupportedConsumeOnPickupRemainder(
            bool consumedOnPickup,
            bool autoConsumeHandled,
            bool autoRunHandled)
        {
            return consumedOnPickup && !autoConsumeHandled && !autoRunHandled;
        }

        internal static bool ShouldBurnUnsupportedRunOnPickupRemainder(
            bool runOnPickup,
            bool autoRunConsumableHandled,
            bool autoRunInteractionHandled)
        {
            return runOnPickup && !autoRunConsumableHandled && !autoRunInteractionHandled;
        }



