        private bool TryHandleSkillBookInventoryItem(
            int itemId,
            InventoryType inventoryType,
            UI.IInventoryRuntime inventoryWindow,
            int currentTime,
            int? slotIndex,
            out bool used)
        {
            used = false;
            if (!InventoryItemMetadataResolver.TryResolveSkillBookUseMetadata(itemId, out SkillBookUseMetadata metadata)
                || !metadata.IsValid)
            {
                return false;
            }

            if (_playerManager?.Skills == null)
            {
                ShowUtilityFeedbackMessage("Skill runtime is unavailable for this mastery book.");
                return true;
            }

            int selectedSkillId = 0;
            int selectedSkillLevel = 0;
            int selectedMasterLevel = 0;
            for (int i = 0; i < metadata.SkillIds.Count; i++)
            {
                int skillId = metadata.SkillIds[i];
                int skillLevel = _playerManager.Skills.GetSkillLevel(skillId);
                if (skillLevel <= 0)
                {
                    continue;
                }

                selectedSkillId = skillId;
                selectedSkillLevel = skillLevel;
                selectedMasterLevel = _playerManager.Skills.GetSkillMasterLevel(skillId);
                break;
            }

            if (selectedSkillId <= 0)
            {
                ShowUtilityFeedbackMessage($"{ResolvePickupItemName(itemId)} does not match any learned skill on this character.");
                return true;
            }

            string skillName = ResolveSkillBookTargetName(selectedSkillId);
            if (selectedSkillLevel <= metadata.RequiredSkillLevel)
            {
                ShowUtilityFeedbackMessage($"{skillName} must be above Lv. {metadata.RequiredSkillLevel} before using {ResolvePickupItemName(itemId)}.");
                return true;
            }

            if (selectedMasterLevel >= metadata.MasterLevel)
            {
                ShowUtilityFeedbackMessage($"{skillName} is already at Master Lv. {selectedMasterLevel}.");
                return true;
            }

            if (!TryConsumeConsumableInventoryItem(inventoryWindow, inventoryType, itemId, slotIndex))
            {
                return true;
            }

            bool success = Random.Shared.Next(100) < metadata.SuccessRatePercent;
            if (success)
            {
                ApplyQuestSkillMasterLevelReward(selectedSkillId, metadata.MasterLevel);
            }

            uiWindowManager?.ProductionEnhancementAnimationDisplayer?.PlaySkillBookResult(success, currentTime);
            ShowUtilityFeedbackMessage(success
                ? $"{ResolvePickupItemName(itemId)} succeeded. {skillName} reached Master Lv. {metadata.MasterLevel}."
                : $"{ResolvePickupItemName(itemId)} failed to raise {skillName} to Master Lv. {metadata.MasterLevel}.");
            used = true;
            return true;
        }

        private string ResolveSkillBookTargetName(int skillId)
        {
            SkillData skill = _playerManager?.SkillLoader?.LoadSkill(skillId);
            return string.IsNullOrWhiteSpace(skill?.Name)
                ? $"Skill #{skillId}"
                : skill.Name;
        }



        private void AddQuestGrantedSkillPoints(int amount)
        {
            if (amount <= 0)
            {
                return;
            }


            int tab = SkillDataLoader.GetJobAdvancementLevel(_playerManager?.Player?.Build?.Job ?? 0);
            _questGrantedSkillPointsByTab[tab] = (_questGrantedSkillPointsByTab.TryGetValue(tab, out int currentPoints) ? currentPoints : 0) + amount;
            AddQuestGrantedSkillPointsToUi(tab, amount);
        }


        private void ApplyQuestGrantedSkillPointBonuses()
        {
            foreach ((int tab, int bonus) in _questGrantedSkillPointsByTab)
            {
                AddQuestGrantedSkillPointsToUi(tab, bonus);
            }
        }


        private void AddQuestGrantedSkillPointsToUi(int tab, int amount)
        {
            if (amount == 0)
            {
                return;
            }


            if (uiWindowManager?.SkillWindow is SkillUIBigBang bigBangSkillWindow)
            {
                bigBangSkillWindow.AddSkillPoints(tab, amount);
            }


            if (uiWindowManager?.SkillWindow is SkillUI classicSkillWindow)
            {
                classicSkillWindow.AddSkillPoints(tab, amount);
            }
        }


        private void AddItemToInventoryWindow(string itemIdText, int quantity)
        {
            if (string.IsNullOrWhiteSpace(itemIdText) ||
                quantity <= 0 ||
                uiWindowManager?.InventoryWindow == null ||
                !int.TryParse(itemIdText, out int itemId))
            {
                return;
            }


            InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(itemId);
            if (inventoryType == InventoryType.NONE)
            {
                return;
            }


            Texture2D itemTexture = LoadInventoryItemIcon(itemId);
            InventorySlotData slotData = new InventorySlotData
            {
                ItemId = itemId,
                ItemTexture = itemTexture,
                Quantity = Math.Max(1, quantity),
                GradeFrameIndex = inventoryType == InventoryType.EQUIP ? 0 : null,
                MaxStackSize = ResolveInventoryItemMaxStack(itemId, inventoryType)
            };


            if (uiWindowManager.InventoryWindow is InventoryUI inventoryWindow)
            {
                inventoryWindow.AddItem(inventoryType, slotData);
            }
        }


        private bool CanAcceptPickedUpItem(DropItem drop)
        {
            if (drop == null || drop.Type == Pools.DropType.Meso)
            {
                return true;
            }


            if (uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventory
                || string.IsNullOrWhiteSpace(drop.ItemId)
                || !int.TryParse(drop.ItemId, out int itemId))
            {
                return true;
            }

            if (_monsterBookManager.IsConsumeOnPickupCardItem(itemId))
            {
                return true;
            }

            if (ShouldAutoHandlePickedUpItem(itemId))
            {
                return true;
            }


            InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(itemId);
            if (inventoryType == InventoryType.NONE)
            {
                return true;
            }


            return inventory.CanAcceptItem(
                inventoryType,
                itemId,
                Math.Max(1, drop.Quantity),
                ResolveInventoryItemMaxStack(itemId, inventoryType));
        }


        private Pools.DropPickupFailureReason EvaluatePickupAvailability(DropItem drop)
        {
            if (drop == null)
            {
                return Pools.DropPickupFailureReason.Unavailable;
            }

            long fieldLimit = _mapBoard?.MapInfo?.fieldLimit ?? 0;
            if (!FieldInteractionRestrictionEvaluator.CanPickupDrops(fieldLimit))
            {
                return Pools.DropPickupFailureReason.FieldRestricted;
            }

            return CanAcceptPickedUpItem(drop)
                ? Pools.DropPickupFailureReason.None
                : Pools.DropPickupFailureReason.InventoryFull;
        }


        private Pools.DropPickupFailureReason EvaluatePetPickupAvailability(DropItem drop)
        {
            Pools.DropPickupFailureReason baseReason = EvaluatePickupAvailability(drop);
            if (baseReason != Pools.DropPickupFailureReason.None)
            {
                return baseReason;
            }


            return IsPetPickupBlocked(drop)
                ? Pools.DropPickupFailureReason.PetPickupBlocked
                : Pools.DropPickupFailureReason.None;
        }
        private Pools.DropPickupFailureReason EvaluateRemotePetPickupAvailability(DropItem drop)
        {
            return IsPetPickupBlocked(drop)
                ? Pools.DropPickupFailureReason.PetPickupBlocked
                : Pools.DropPickupFailureReason.None;
        }


        private string ResolvePickupSourceName(int pickerId, bool pickedByPet)
        {
            if (!pickedByPet || pickerId <= 0)
            {
                return null;
            }


            IReadOnlyList<PetRuntime> activePets = _playerManager?.Pets?.ActivePets;
            if (activePets == null)
            {
                return null;
            }


            for (int i = 0; i < activePets.Count; i++)
            {
                PetRuntime pet = activePets[i];
                if (pet?.RuntimeId == pickerId)
                {
                    return string.IsNullOrWhiteSpace(pet.Name)
                        ? $"Pet {i + 1}"
                        : pet.Name;
                }
            }


            return null;
        }

        private bool TryGetSocialRoomEmployeeBridgeRuntime(
            SocialRoomEmployeePacketInboxMessage message,
            out SocialRoomRuntime runtime,
            out SocialRoomKind kind)
        {
            if (TryResolveSocialRoomEmployeeBridgeRuntimeFromPacket(message, out runtime, out kind))
            {
                return true;
            }

            if (_socialRoomEmployeeOfficialSessionBridge.PreferredKind is SocialRoomKind preferredKind
                && TryGetSocialRoomRuntime(preferredKind, out SocialRoomRuntime preferredRuntime))
            {
                runtime = preferredRuntime;
                kind = preferredKind;
                return true;
            }

            SocialRoomKind[] searchOrder =
            {
                SocialRoomKind.EntrustedShop,
                SocialRoomKind.PersonalShop
            };

            foreach (SocialRoomKind candidateKind in searchOrder)
            {
                if (!TryGetSocialRoomRuntime(candidateKind, out SocialRoomRuntime visibleRuntime))
                {
                    continue;
                }

                string windowName = GetSocialRoomWindowName(candidateKind);
                if (uiWindowManager?.GetWindow(windowName)?.IsVisible == true)
                {
                    runtime = visibleRuntime;
                    kind = candidateKind;
                    return true;
                }
            }

            foreach (SocialRoomKind candidateKind in searchOrder)
            {
                if (TryGetSocialRoomRuntime(candidateKind, out SocialRoomRuntime candidateRuntime))
                {
                    runtime = candidateRuntime;
                    kind = candidateKind;
                    return true;
                }
            }

            runtime = null;
            kind = SocialRoomKind.PersonalShop;
            return false;
        }

        private bool TryResolveSocialRoomEmployeeBridgeRuntimeFromPacket(
            SocialRoomEmployeePacketInboxMessage message,
            out SocialRoomRuntime runtime,
            out SocialRoomKind kind)
        {
            runtime = null;
            kind = SocialRoomKind.PersonalShop;
            if (message == null
                || !SocialRoomEmployeePoolCodec.TryDecodeRoutingHint(message.Opcode, message.Payload, out SocialRoomEmployeePoolCodec.RoutingHint hint, out _))
            {
                return false;
            }

            if (TryResolveSocialRoomEmployeeBridgeRuntimeByEmployer(hint.EmployerId, out runtime, out kind))
            {
                return true;
            }

            if (TryResolveSocialRoomKindFromMiniRoomType(hint.MiniRoomType, out SocialRoomKind hintedKind)
                && TryGetSocialRoomRuntime(hintedKind, out SocialRoomRuntime hintedRuntime))
            {
                runtime = hintedRuntime;
                kind = hintedKind;
                return true;
            }

            if (TryResolveSocialRoomEmployeeBridgeRuntimeByHintScore(hint, out runtime, out kind))
            {
                return true;
            }

            return false;
        }

        private bool TryResolveSocialRoomEmployeeBridgeRuntimeByEmployer(
            int employerId,
            out SocialRoomRuntime runtime,
            out SocialRoomKind kind)
        {
            runtime = null;
            kind = SocialRoomKind.PersonalShop;
            if (employerId <= 0)
            {
                return false;
            }

            SocialRoomKind? hintedKind = _packetOwnedEmployeePoolDispatcher.TryResolveKindHintForEmployer(employerId, out SocialRoomKind resolvedHintedKind)
                ? resolvedHintedKind
                : null;
            SocialRoomKind? preferredKind = _socialRoomEmployeeOfficialSessionBridge.PreferredKind;
            foreach (SocialRoomKind candidateKind in BuildEmployeeBridgeKindSearchOrderForTesting(hintedKind, preferredKind))
            {
                if (TryGetSocialRoomRuntime(candidateKind, out SocialRoomRuntime candidateRuntime)
                    && candidateRuntime.MatchesEmployeeEmployerId(employerId))
                {
                    runtime = candidateRuntime;
                    kind = candidateKind;
                    return true;
                }
            }

            return false;
        }

        internal static IReadOnlyList<SocialRoomKind> BuildEmployeeBridgeKindSearchOrderForTesting(
            SocialRoomKind? hintedKind,
            SocialRoomKind? preferredKind)
        {
            List<SocialRoomKind> order = new(2);
            TryAppendEmployeeBridgeMerchantKind(order, hintedKind);
            TryAppendEmployeeBridgeMerchantKind(order, preferredKind);
            TryAppendEmployeeBridgeMerchantKind(order, SocialRoomKind.EntrustedShop);
            TryAppendEmployeeBridgeMerchantKind(order, SocialRoomKind.PersonalShop);
            return order;
        }

        private static void TryAppendEmployeeBridgeMerchantKind(List<SocialRoomKind> order, SocialRoomKind? kind)
        {
            if (!kind.HasValue || !IsMerchantSocialRoomKind(kind.Value) || order.Contains(kind.Value))
            {
                return;
            }

            order.Add(kind.Value);
        }

        private static bool IsMerchantSocialRoomKind(SocialRoomKind kind)
        {
            return kind == SocialRoomKind.EntrustedShop || kind == SocialRoomKind.PersonalShop;
        }

        private bool TryResolveSocialRoomEmployeeBridgeRuntimeByHintScore(
            SocialRoomEmployeePoolCodec.RoutingHint hint,
            out SocialRoomRuntime runtime,
            out SocialRoomKind kind)
        {
            runtime = null;
            kind = SocialRoomKind.PersonalShop;
            SocialRoomKind? preferredKind = ResolveEmployeeBridgeHintPreferredKind(hint);

            SocialRoomEmployeeBridgeHintCandidate? bestCandidate = null;
            foreach (SocialRoomKind candidateKind in new[] { SocialRoomKind.EntrustedShop, SocialRoomKind.PersonalShop })
            {
                if (!TryGetSocialRoomRuntime(candidateKind, out SocialRoomRuntime candidateRuntime))
                {
                    continue;
                }

                int score = candidateRuntime.ScoreEmployeeRoutingHint(hint);
                if (score <= 0)
                {
                    continue;
                }

                bool isVisible = uiWindowManager?.GetWindow(GetSocialRoomWindowName(candidateKind))?.IsVisible == true;
                SocialRoomEmployeeBridgeHintCandidate candidate = new(candidateRuntime, candidateKind, score, isVisible);
                if (!bestCandidate.HasValue || IsBetterSocialRoomEmployeeBridgeHintCandidate(candidate, bestCandidate.Value, preferredKind))
                {
                    bestCandidate = candidate;
                }
            }

            if (!bestCandidate.HasValue)
            {
                return false;
            }

            runtime = bestCandidate.Value.Runtime;
            kind = bestCandidate.Value.Kind;
            return true;
        }

        private SocialRoomKind? ResolveEmployeeBridgeHintPreferredKind(SocialRoomEmployeePoolCodec.RoutingHint hint)
        {
            if (TryResolveSocialRoomKindFromMiniRoomType(hint.MiniRoomType, out SocialRoomKind packetHintKind))
            {
                return packetHintKind;
            }

            if (hint.EmployerId > 0
                && _packetOwnedEmployeePoolDispatcher.TryResolveKindHintForEmployer(hint.EmployerId, out SocialRoomKind employerHintKind))
            {
                return employerHintKind;
            }

            if (_packetOwnedEmployeePoolDispatcher.ActiveKind.HasValue)
            {
                return _packetOwnedEmployeePoolDispatcher.ActiveKind.Value;
            }

            if (_socialRoomEmployeeOfficialSessionBridge.PreferredKind.HasValue)
            {
                return _socialRoomEmployeeOfficialSessionBridge.PreferredKind.Value;
            }

            return null;
        }

        internal static bool IsBetterSocialRoomEmployeeBridgeHintCandidate(
            SocialRoomEmployeeBridgeHintCandidate candidate,
            SocialRoomEmployeeBridgeHintCandidate currentBest,
            SocialRoomKind? preferredKind)
        {
            if (candidate.Score != currentBest.Score)
            {
                return candidate.Score > currentBest.Score;
            }

            if (candidate.IsVisible != currentBest.IsVisible)
            {
                return candidate.IsVisible;
            }

            bool candidateMatchesPreferred = preferredKind.HasValue && candidate.Kind == preferredKind.Value;
            bool currentMatchesPreferred = preferredKind.HasValue && currentBest.Kind == preferredKind.Value;
            if (candidateMatchesPreferred != currentMatchesPreferred)
            {
                return candidateMatchesPreferred;
            }

            return candidate.Kind == SocialRoomKind.EntrustedShop
                && currentBest.Kind != SocialRoomKind.EntrustedShop;
        }

        internal readonly record struct SocialRoomEmployeeBridgeHintCandidate(
            SocialRoomRuntime Runtime,
            SocialRoomKind Kind,
            int Score,
            bool IsVisible);

        private static bool TryResolveSocialRoomKindFromMiniRoomType(byte miniRoomType, out SocialRoomKind kind)
        {
            switch (miniRoomType)
            {
                case 3:
                    kind = SocialRoomKind.PersonalShop;
                    return true;
                case 4:
                case 5:
                    kind = SocialRoomKind.EntrustedShop;
                    return true;
                default:
                    kind = SocialRoomKind.PersonalShop;
                    return false;
            }
        }
        private const int RemotePetPickupPredictedSlotCount = 3;

        internal static int BuildRemotePetPickupActorId(int ownerCharacterId, int slotIndex)
        {
            return -((ownerCharacterId * 10) + slotIndex + 1);
        }
        internal static bool TryDecodeRemotePetPickupActorId(int actorId, out int ownerCharacterId, out int slotIndex)
        {
            ownerCharacterId = 0;
            slotIndex = -1;

            if (actorId >= -1)
            {
                return false;
            }

            int encodedValue = -actorId - 1;
            int decodedOwnerId = encodedValue / 10;
            int decodedSlotIndex = encodedValue % 10;
            if (decodedOwnerId <= 0 || decodedSlotIndex < 0)
            {
                return false;
            }

            ownerCharacterId = decodedOwnerId;
            slotIndex = decodedSlotIndex;
            return true;
        }
        private static long BuildRemotePetPickupKey(int ownerCharacterId, int slotIndex)
        {
            return ((long)ownerCharacterId << 8) | (uint)(slotIndex + 1);
        }

        internal static bool TryResolveRemotePetPickupPosition(
            int actorId,
            RemoteUserActorPool remoteUserPool,
            out Vector2 position)
        {
            return TryResolveRemotePetPickupPosition(actorId, remoteUserPool, out position, null);
        }

        internal static bool TryResolveRemotePetPickupPosition(
            int actorId,
            RemoteUserActorPool remoteUserPool,
            IReadOnlyDictionary<int, Vector2> predictedPetActorPositions,
            out Vector2 position,
            Func<int, int, Vector2?> observedOwnerSlotPositionResolver)
        {
            if (TryResolveRemotePetPickupPosition(
                actorId,
                remoteUserPool,
                out position,
                observedOwnerSlotPositionResolver))
            {
                return true;
            }

            if (predictedPetActorPositions == null || actorId == 0)
            {
                position = default;
                return false;
            }

            if (predictedPetActorPositions.TryGetValue(actorId, out Vector2 exactPredictedPosition))
            {
                position = exactPredictedPosition;
                return true;
            }

            Vector2? ownerScopedPredictedPosition = ResolveObservedRemotePetPickupPosition(
                predictedPetActorPositions,
                actorId);
            if (ownerScopedPredictedPosition.HasValue)
            {
                position = ownerScopedPredictedPosition.Value;
                return true;
            }

            position = default;
            return false;
        }

        internal static bool TryResolveRemotePetPickupPosition(
            int actorId,
            RemoteUserActorPool remoteUserPool,
            out Vector2 position,
            Func<int, int, Vector2?> observedOwnerSlotPositionResolver)
        {
            position = default;

            if (remoteUserPool == null
                || !TryDecodeRemotePetPickupActorId(actorId, out int ownerCharacterId, out int slotIndex)
                || !remoteUserPool.TryGetActor(ownerCharacterId, out RemoteUserActor ownerActor)
                || ownerActor == null)
            {
                return false;
            }

            if (observedOwnerSlotPositionResolver?.Invoke(ownerCharacterId, slotIndex) is Vector2 observedPosition)
            {
                position = observedPosition;
                return true;
            }

            if (!TryResolveRemotePetPickupSlotIndexForPacketParity(
                    ownerActor.Build?.RemotePetItemIds,
                    slotIndex,
                    out int resolvedSlotIndex))
            {
                return false;
            }

            if (CanResolveRemotePetPickupSlot(ownerActor, resolvedSlotIndex))
            {
                position = ResolveRemotePetPickupPosition(ownerActor, resolvedSlotIndex);
                return true;
            }

            return TryResolveRemotePetPickupPositionFromOwnerState(
                ownerActor.Position,
                ownerActor.FacingRight,
                ownerActor.Build?.RemotePetItemIds,
                resolvedSlotIndex,
                out position);
        }

        internal static bool CanResolveRemotePetPickupSlot(RemoteUserActor ownerActor, int slotIndex)
        {
            return ownerActor?.Build?.RemotePetItemIds != null
                && slotIndex >= 0
                && slotIndex < ownerActor.Build.RemotePetItemIds.Count
                && ownerActor.Build.RemotePetItemIds[slotIndex] > 0;
        }

        internal static bool CanResolveRemotePetPickupSlotForPacketParity(
            IReadOnlyList<int> remotePetItemIds,
            int slotIndex)
        {
            return TryResolveRemotePetPickupSlotIndexForPacketParity(
                remotePetItemIds,
                slotIndex,
                out _);
        }

        internal static bool TryResolveRemotePetPickupSlotIndexForPacketParity(
            IReadOnlyList<int> remotePetItemIds,
            int slotIndex,
            out int resolvedSlotIndex)
        {
            resolvedSlotIndex = -1;
            if (slotIndex < 0)
            {
                return false;
            }

            if (remotePetItemIds == null || remotePetItemIds.Count == 0)
            {
                resolvedSlotIndex = slotIndex < RemotePetPickupPredictedSlotCount
                    ? slotIndex
                    : RemotePetPickupPredictedSlotCount - 1;
                return resolvedSlotIndex >= 0;
            }

            if (slotIndex < remotePetItemIds.Count
                && remotePetItemIds[slotIndex] > 0)
            {
                resolvedSlotIndex = slotIndex;
                return true;
            }

            int closestSlotIndex = -1;
            int closestSlotDelta = int.MaxValue;
            for (int candidateSlotIndex = 0; candidateSlotIndex < remotePetItemIds.Count; candidateSlotIndex++)
            {
                if (remotePetItemIds[candidateSlotIndex] <= 0)
                {
                    continue;
                }

                int candidateDelta = Math.Abs(candidateSlotIndex - slotIndex);
                if (candidateDelta > closestSlotDelta)
                {
                    continue;
                }

                if (candidateDelta == closestSlotDelta && closestSlotIndex >= 0 && candidateSlotIndex > closestSlotIndex)
                {
                    continue;
                }

                closestSlotDelta = candidateDelta;
                closestSlotIndex = candidateSlotIndex;
            }

            if (closestSlotIndex < 0)
            {
                resolvedSlotIndex = slotIndex < RemotePetPickupPredictedSlotCount
                    ? slotIndex
                    : RemotePetPickupPredictedSlotCount - 1;
                return resolvedSlotIndex >= 0;
            }

            resolvedSlotIndex = closestSlotIndex;
            return true;
        }

        internal static bool TryResolveRemotePetPickupPositionFromOwnerState(
            Vector2 ownerPosition,
            bool ownerFacingRight,
            IReadOnlyList<int> remotePetItemIds,
            int slotIndex,
            out Vector2 position)
        {
            position = default;
            if (!TryResolveRemotePetPickupSlotIndexForPacketParity(
                    remotePetItemIds,
                    slotIndex,
                    out int resolvedSlotIndex))
            {
                return false;
            }

            float direction = ownerFacingRight ? -1f : 1f;
            float offsetX = direction * (28f + resolvedSlotIndex * 18f);
            position = new Vector2(ownerPosition.X + offsetX, ownerPosition.Y);
            return true;
        }

        internal static Vector2 ResolveRemotePetPickupPosition(RemoteUserActor actor, int slotIndex)
        {
            float direction = actor.FacingRight ? -1f : 1f;
            float offsetX = direction * (28f + slotIndex * 18f);
            return new Vector2(actor.Position.X + offsetX, actor.Position.Y);
        }
        private static string ResolveRemotePetPickupName(int petItemId, int slotIndex)
        {
            string petName = ResolvePickupItemName(petItemId);
            return string.IsNullOrWhiteSpace(petName)
                ? $"Pet {slotIndex + 1}"
                : petName;
        }


        private void HandleDropPickedUp(DropItem drop, int pickerId, bool pickedByPet)
        {
            if (drop == null)
            {
                return;
            }


            PlayPickUpItemSE();

            _questRuntime.RecordDropPickup(drop);



            int currentTime = Environment.TickCount;
            string sourceName = ResolvePickupSourceName(pickerId, pickedByPet);
            PickupNoticeSource noticeSource = pickedByPet
                ? PickupNoticeSource.Pet
                : PickupNoticeSource.Player;


            if (drop.Type == Pools.DropType.Meso)

            {

                PickupNoticeSuccessMessages messages = PickupNoticeTextFormatter.FormatMesoPickup(
                    drop.MesoAmount,
                    pickedByPet,
                    sourceName);

                _pickupNoticeUI.AddFormattedNotice(
                    messages.ScreenMessage,
                    PickupMessageType.MesoPickup,
                    currentTime,
                    quantity: drop.MesoAmount);

                AddPickupChatMessage(messages.ChatMessage, currentTime, messages.ChatLogType);

                if (!string.IsNullOrWhiteSpace(messages.SecondaryScreenMessage))
                {
                    _pickupNoticeUI.AddFormattedNotice(
                        messages.SecondaryScreenMessage,
                        PickupMessageType.MesoPickup,
                        currentTime,
                        textColor: messages.SecondaryScreenColor);
                }
                AddMesoToInventoryWindow(drop.MesoAmount);
            }
            else if (drop.Type == Pools.DropType.Item || drop.Type == Pools.DropType.InstallItem)
            {
                int itemId = int.TryParse(drop.ItemId, out int parsedItemId) ? parsedItemId : 0;
                bool consumeOnPickupMonsterCard = _monsterBookManager.IsConsumeOnPickupCardItem(itemId);
                bool consumedOnPickupMetadata = !consumeOnPickupMonsterCard && InventoryItemMetadataResolver.IsConsumedOnPickup(itemId);
                bool runOnPickupMetadata = !consumeOnPickupMonsterCard && InventoryItemMetadataResolver.IsRunOnPickup(itemId);
                bool autoConsumePickedUpItem = !consumeOnPickupMonsterCard && ShouldAutoConsumePickedUpItem(itemId);
                bool autoRunConsumablePickedUpItem = !consumeOnPickupMonsterCard
                                                     && !autoConsumePickedUpItem
                                                     && ShouldAutoApplyRunOnPickupConsumableItem(itemId);
                bool autoRunPickedUpItem = !consumeOnPickupMonsterCard
                                           && !autoConsumePickedUpItem
                                           && !autoRunConsumablePickedUpItem
                                           && InventoryItemMetadataResolver.ShouldAutoRunOnPickupInteraction(itemId);
                bool autoHandlePickedUpItem = autoConsumePickedUpItem || autoRunConsumablePickedUpItem || autoRunPickedUpItem;
                // Monster Book card entries in Item/Consume/0238.img are authored as only=1 plus
                // consumeOnPickup=1, so a consumed card pickup advances one card copy even if a
                // simulator or packet-injected drop carried a larger stack quantity.
                int pickupQuantity = consumeOnPickupMonsterCard ? 1 : Math.Max(1, drop.Quantity);
                InventoryType inventoryType = itemId > 0
                    ? InventoryItemMetadataResolver.ResolveInventoryType(itemId)
                    : InventoryType.NONE;
                string itemName = itemId > 0 ? ResolvePickupNoticeItemName(itemId) : null;
                string itemTypeName = itemId > 0 ? ResolvePickupItemTypeName(itemId, inventoryType) : null;
                if (PickupNoticeTextFormatter.TryFormatItemPickup(itemName, itemTypeName, pickupQuantity, MeasurePickupNoticeTextWidth, out string screenMessage))
                {
                    Texture2D itemIcon = LoadInventoryItemIcon(itemId);
                    _pickupNoticeUI.AddFormattedNotice(
                        screenMessage,
                        PickupMessageType.ItemPickup,
                        currentTime,
                        itemIcon,
                        pickupQuantity,
                        drop.IsRare ? new Color(255, 200, 100) : Color.White);
                }

                if (consumeOnPickupMonsterCard)
                {
                    CharacterBuild activeBuild = _playerManager?.Player?.Build ?? _loginCharacterRoster.SelectedEntry?.Build;
                    int activeCharacterId = activeBuild?.Id ?? 0;
                    string activeCharacterName = activeBuild?.Name;
                    MonsterBookManager.CardPickupResult pickupResult = _monsterBookManager.RecordCardPickupWithResult(
                        activeBuild,
                        activeCharacterId,
                        activeCharacterName,
                        itemId,
                        1,
                        persistToDisk: false);
                    if (pickupResult.Changed)
                    {
                        QueuePacketOwnedMonsterBookOwnershipSaveApply(
                            activeBuild,
                            activeCharacterId,
                            activeCharacterName,
                            pickupResult.Snapshot,
                            "Consume-on-pickup Monster Card",
                            showFeedback: false);
                    }
                }
                else if (autoConsumePickedUpItem)
                {
                    int remainingQuantity = Math.Max(1, drop.Quantity);
                    while (remainingQuantity > 0 && TryApplyPickedUpConsumableRuntime(itemId))
                    {
                        remainingQuantity--;
                    }

                    if (remainingQuantity > 0)
                    {
                        AddItemToInventoryWindow(drop.ItemId, remainingQuantity);
                    }
                }
                else if (autoRunPickedUpItem)
                {
                    bool interactionOpened = TryApplyPickedUpItemRuntime(itemId, currentTime);
                    int remainderQuantity = ResolvePickupRunOnPickupInventoryRemainder(
                        Math.Max(1, drop.Quantity),
                        interactionOpened,
                        consumeOnUse: !InventoryItemMetadataResolver.IsNotConsumedOnUse(itemId));
                    if (remainderQuantity > 0)
                    {
                        AddItemToInventoryWindow(drop.ItemId, remainderQuantity);
                    }
                }
                else if (autoRunConsumablePickedUpItem)
                {
                    int pickedQuantity = Math.Max(1, drop.Quantity);
                    bool consumeOnUse = !InventoryItemMetadataResolver.IsNotConsumedOnUse(itemId);
                    int successfulUseCount = 0;
                    if (consumeOnUse)
                    {
                        while (successfulUseCount < pickedQuantity && TryApplyRunOnPickupConsumableRuntime(itemId))
                        {
                            successfulUseCount++;
                        }
                    }
                    else if (TryApplyRunOnPickupConsumableRuntime(itemId))
                    {
                        successfulUseCount = 1;
                    }

                    int remainderQuantity = ResolvePickupAutoUseRemainder(
                        pickedQuantity,
                        successfulUseCount,
                        consumeOnUse);
                    if (remainderQuantity > 0)
                    {
                        AddItemToInventoryWindow(drop.ItemId, remainderQuantity);
                    }
                }
                else if (ShouldBurnUnsupportedConsumeOnPickupRemainder(
                             consumedOnPickupMetadata,
                             autoConsumePickedUpItem,
                             autoRunPickedUpItem || autoRunConsumablePickedUpItem))
                {
                    // Keep consumeOnPickup rows pickup-owned even when the simulator does not
                    // model their authored effect family yet.
                }
                else if (ShouldBurnUnsupportedRunOnPickupRemainder(
                             runOnPickupMetadata,
                             autoRunConsumablePickedUpItem,
                             autoRunPickedUpItem))
                {
                    // Keep runOnPickup rows pickup-owned when they do not map to the current
                    // consumable or authored NPC/script interaction seams.
                }
                else if (!autoHandlePickedUpItem || !TryApplyPickedUpItemRuntime(itemId, currentTime))
                {
                    AddItemToInventoryWindow(drop.ItemId, drop.Quantity);
                }
            }
            else if (drop.Type == Pools.DropType.QuestItem)
            {
                int itemId = int.TryParse(drop.ItemId, out int parsedItemId) ? parsedItemId : 0;
                InventoryType inventoryType = itemId > 0
                    ? InventoryItemMetadataResolver.ResolveInventoryType(itemId)
                    : InventoryType.NONE;
                string itemName = itemId > 0 ? ResolvePickupNoticeItemName(itemId) : null;
                string itemTypeName = itemId > 0 ? ResolvePickupItemTypeName(itemId, inventoryType) : null;
                if (PickupNoticeTextFormatter.TryFormatQuestItemPickup(itemName, itemTypeName, MeasurePickupNoticeTextWidth, out string screenMessage))
                {
                    Texture2D itemIcon = LoadInventoryItemIcon(itemId);
                    _pickupNoticeUI.AddFormattedNotice(
                        screenMessage,
                        PickupMessageType.QuestItemPickup,
                        currentTime,
                        itemIcon);
                }

            }

        }



        private void HandlePickupAttemptFailed(Pools.DropPickupAttemptResult result)
        {
            HandlePickupAttemptFailed(result, 0, false);
        }

        private float MeasurePickupNoticeTextWidth(string text)
        {
            return ClientTextDrawing.Measure((GraphicsDevice)null, text, 1f, _fontChat).X;
        }


        private void HandlePickupAttemptFailed(Pools.DropPickupAttemptResult result, int pickerId, bool pickedByPet)
        {
            if (result == null)
            {
                return;
            }


            int currentTime = Environment.TickCount;
            string sourceName = ResolvePickupSourceName(pickerId, pickedByPet);
            DropItem contextDrop = result.ContextDrop;
            string itemName = ResolvePickupResultItemName(contextDrop);
            Pools.DropType dropType = contextDrop?.Type ?? Pools.DropType.Item;
            int quantity = contextDrop != null ? Math.Max(1, contextDrop.Quantity) : 1;
            int mesoAmount = contextDrop?.MesoAmount ?? 0;
            Pools.RecentPickupRecord recentPickup = result.RecentPickup;
            int localCharacterId = _playerManager?.Player?.Build?.Id ?? 0;
            if (result.FailureReason == Pools.DropPickupFailureReason.Unavailable
                && !ShouldTreatRecentPickupAsRemotePreemption(
                    recentPickup,
                    localCharacterId,
                    IsLocalPetRuntimeId,
                    AreDropActorsInSameParty))
            {
                recentPickup = null;
            }

            string recentActorName = ResolveRecentPickupActorName(recentPickup);
            PickupNoticeMessagePair messagePair = PickupNoticeTextFormatter.FormatFailure(
                result.FailureReason,
                itemName,
                dropType,
                quantity,
                mesoAmount,
                pickedByPet,
                sourceName,
                recentPickup,
                recentActorName,
                ResolvePickupNoticeItemName);


            if (!ShouldSurfacePickupFailure(result.FailureReason))
            {
                return;
            }

            if (result.FailureReason == Pools.DropPickupFailureReason.Unavailable
                && recentPickup != null)
            {
                int noticeDropId = recentPickup.DropId > 0
                    ? recentPickup.DropId
                    : contextDrop?.PoolId ?? result.Drop?.PoolId ?? 0;
                int fallbackOwnerId = ResolveRecentRemotePickupNoticeFallbackOwnerId(
                    recentPickup,
                    localCharacterId);
                if (!TryReserveRemotePickupNotice(
                        noticeDropId,
                        recentPickup.PickerId,
                        currentTime,
                        fallbackOwnerId))
                {
                    return;
                }
            }

            AddPickupFailureMessage(
                messagePair,
                currentTime,
                PickupNoticeTextFormatter.ResolveFailureScreenType(result.FailureReason));
        }

        internal static bool ShouldTreatRecentPickupAsRemotePreemption(
            Pools.RecentPickupRecord recentPickup,
            int localCharacterId,
            Func<int, bool> localPetRuntimeIdEvaluator,
            Func<int, int, bool> partyMembershipEvaluator)
        {
            if (recentPickup == null)
            {
                return false;
            }

            if (!ShouldSurfaceRecentPickupNotice(recentPickup, localCharacterId, partyMembershipEvaluator))
            {
                return false;
            }

            if (!IsRecentPickupActorAdmissibleForOwnershipWindow(
                    recentPickup,
                    localCharacterId,
                    localPetRuntimeIdEvaluator,
                    partyMembershipEvaluator))
            {
                return false;
            }

            return recentPickup.ActorKind switch
            {
                Pools.DropPickupActorKind.Player => localCharacterId <= 0 || recentPickup.PickerId != localCharacterId,
                Pools.DropPickupActorKind.Pet => recentPickup.PickerId > 0
                    && (localPetRuntimeIdEvaluator?.Invoke(recentPickup.PickerId) != true),
                Pools.DropPickupActorKind.Mob => true,
                Pools.DropPickupActorKind.Other => true,
                _ => true
            };
        }

        internal static bool IsRecentPickupActorAdmissibleForOwnershipWindow(
            Pools.RecentPickupRecord recentPickup,
            int localCharacterId,
            Func<int, bool> localPetRuntimeIdEvaluator,
            Func<int, int, bool> partyMembershipEvaluator)
        {
            if (recentPickup == null || !recentPickup.OwnershipWindowActive || recentPickup.OwnerId <= 0)
            {
                return true;
            }

            return recentPickup.ActorKind switch
            {
                Pools.DropPickupActorKind.Player => IsPlayerOwnershipWindowPickupAdmissible(
                    recentPickup.OwnerId,
                    recentPickup.OwnershipType,
                    recentPickup.PickerId,
                    partyMembershipEvaluator),
                Pools.DropPickupActorKind.Pet => IsPetOwnershipWindowPickupAdmissible(
                    recentPickup,
                    localCharacterId,
                    localPetRuntimeIdEvaluator,
                    partyMembershipEvaluator),
                _ => true
            };
        }

        private static bool IsPlayerOwnershipWindowPickupAdmissible(
            int ownerId,
            Pools.DropOwnershipType ownershipType,
            int pickerId,
            Func<int, int, bool> partyMembershipEvaluator)
        {
            if (pickerId <= 0)
            {
                return true;
            }

            return ownershipType switch
            {
                Pools.DropOwnershipType.Character => pickerId == ownerId,
                Pools.DropOwnershipType.Party => pickerId == ownerId
                    || partyMembershipEvaluator?.Invoke(ownerId, pickerId) == true,
                _ => true
            };
        }

        private static bool IsPetOwnershipWindowPickupAdmissible(
            Pools.RecentPickupRecord recentPickup,
            int localCharacterId,
            Func<int, bool> localPetRuntimeIdEvaluator,
            Func<int, int, bool> partyMembershipEvaluator)
        {
            int petOwnerId = ResolveRecentPetPickupOwnerCharacterId(
                recentPickup,
                localCharacterId,
                localPetRuntimeIdEvaluator);
            if (petOwnerId <= 0)
            {
                return true;
            }

            return recentPickup.OwnershipType switch
            {
                Pools.DropOwnershipType.Character => petOwnerId == recentPickup.OwnerId,
                Pools.DropOwnershipType.Party => petOwnerId == recentPickup.OwnerId
                    || partyMembershipEvaluator?.Invoke(recentPickup.OwnerId, petOwnerId) == true,
                _ => true
            };
        }

        private static int ResolveRecentPetPickupOwnerCharacterId(
            Pools.RecentPickupRecord recentPickup,
            int localCharacterId,
            Func<int, bool> localPetRuntimeIdEvaluator)
        {
            if (recentPickup == null || recentPickup.PickerId <= 0)
            {
                return 0;
            }

            if (localPetRuntimeIdEvaluator?.Invoke(recentPickup.PickerId) == true)
            {
                return localCharacterId > 0 ? localCharacterId : 0;
            }

            if (TryDecodeRemotePetPickupActorId(recentPickup.PickerId, out int ownerCharacterId, out _))
            {
                return ownerCharacterId;
            }

            return recentPickup.PickedByPet ? recentPickup.PickerId : 0;
        }

        private int ResolveRecentRemotePickupNoticeFallbackOwnerId(
            Pools.RecentPickupRecord recentPickup,
            int localCharacterId)
        {
            if (recentPickup?.PickerId <= 0)
            {
                return 0;
            }

            return recentPickup.ActorKind switch
            {
                Pools.DropPickupActorKind.Pet => ResolveRecentPetPickupOwnerCharacterId(
                    recentPickup,
                    localCharacterId,
                    IsLocalPetRuntimeId),
                Pools.DropPickupActorKind.Other => ResolveDropPartyActorOwnerId(recentPickup.PickerId),
                _ => 0
            };
        }


        private void HandleDropPickedUpByMob(DropItem drop, int mobId)
        {
            if (drop == null || !ShouldSurfaceMobPickupNotice(drop))
            {
                return;
            }

            int currentTime = Environment.TickCount;
            if (!TryReserveRemotePickupNotice(drop.PoolId, mobId, currentTime))
            {
                return;
            }

            string mobName = ResolveMobPickupSourceName(mobId);
            string itemName = ResolvePickupResultItemName(drop);
            PickupNoticeMessagePair messages = PickupNoticeTextFormatter.FormatMobPickup(
                drop.Type,
                mobName,
                itemName,
                drop.Quantity,
                drop.MesoAmount);
            AddPickupFailureMessage(messages, currentTime);
        }


