        private bool ShouldSurfaceMobPickupNotice(DropItem drop)
        {
            if (drop == null)
            {
                return false;
            }

            int localPlayerId = _playerManager?.Player?.Build?.Id ?? 0;
            return ShouldSurfacePickupNotice(
                drop.OwnershipType,
                drop.OwnerId,
                localPlayerId,
                AreDropActorsInSameParty);
        }



        private bool ShouldSurfaceRemotePickupNotice(DropItem drop)



        {



            return ShouldSurfaceMobPickupNotice(drop);



        }







        private static string ResolveMobPickupSourceName(int mobId)
        {
            string key = mobId.ToString("D7");
            return Program.InfoManager?.MobNameCache != null
                   && Program.InfoManager.MobNameCache.TryGetValue(key, out string mobName)
                   && !string.IsNullOrWhiteSpace(mobName)
                ? mobName
                : $"Monster {mobId}";
        }


        private static string ResolvePickupResultItemName(DropItem drop)
        {
            if (drop == null)
            {
                return null;
            }


            return drop.Type == Pools.DropType.Meso
                ? null
                : int.TryParse(drop.ItemId, out int itemId)
                    ? ResolvePickupNoticeItemName(itemId)
                    : null;
        }


        private string ResolveRecentPickupActorName(Pools.RecentPickupRecord recentPickup)
        {
            if (recentPickup == null)
            {
                return null;
            }
            if (!string.IsNullOrWhiteSpace(recentPickup.ActorName))
            {
                return recentPickup.ActorName;
            }


            return recentPickup.ActorKind switch

            {

                Pools.DropPickupActorKind.Player => recentPickup.PickerId == (_playerManager?.Player?.Build?.Id ?? 0)
                    ? ResolveLocalPlayerPickupActorName()
                    : ResolveRemotePickupActorName(Pools.DropPickupActorKind.Player, recentPickup.PickerId, null),

                Pools.DropPickupActorKind.Pet => ResolvePickupSourceName(recentPickup.PickerId, pickedByPet: true)
                    ?? ResolveRemotePickupActorName(Pools.DropPickupActorKind.Pet, recentPickup.PickerId, null),

                Pools.DropPickupActorKind.Mob => ResolveMobPickupSourceName(recentPickup.PickerId),



                Pools.DropPickupActorKind.Other => ResolveRemotePickupActorName(
                    Pools.DropPickupActorKind.Other,
                    recentPickup.PickerId,
                    recentPickup.ActorName),
                _ => null
            };
        }

        private bool IsLocalPetRuntimeId(int runtimeId)
        {
            if (runtimeId <= 0 || _playerManager?.Pets?.ActivePets == null)
            {
                return false;
            }

            foreach (PetRuntime pet in _playerManager.Pets.ActivePets)
            {
                if (pet?.RuntimeId == runtimeId)
                {
                    return true;
                }
            }

            return false;
        }

        private bool TrySurfaceRecentRemoteDropPickupNotice(
            int dropId,
            int currentTime,
            Pools.DropPickupActorKind actorKind,
            int actorId,
            string actorName,
            int fallbackOwnerId,
            Vector2? pickupTargetPosition = null)
        {
            Pools.RecentPickupRecord recentPickup = ResolveRecentRemoteDropPickupRecord(
                _dropPool,
                dropId,
                pickupTargetPosition,
                currentTime);
            if (recentPickup == null)
            {
                return false;
            }

            if (!ShouldSurfaceRecentPickupNotice(
                    recentPickup,
                    _playerManager?.Player?.Build?.Id ?? 0,
                    AreDropActorsInSameParty))
            {
                return true;
            }

            if (!ShouldTreatRecentPickupAsRemotePreemption(
                    recentPickup,
                    _playerManager?.Player?.Build?.Id ?? 0,
                    IsLocalPetRuntimeId,
                    AreDropActorsInSameParty))
            {
                return true;
            }

            int noticeDropId = recentPickup.DropId > 0 ? recentPickup.DropId : dropId;
            if (!TryReserveRemotePickupNotice(noticeDropId, actorId, currentTime, fallbackOwnerId))
            {
                return true;
            }

            string itemName = recentPickup.Type == Pools.DropType.Meso
                ? null
                : int.TryParse(recentPickup.ItemId, out int itemId)
                    ? ResolvePickupNoticeItemName(itemId)
                    : null;
            string resolvedActorName = ResolvePickupNoticeActorName(
                actorKind,
                actorId,
                !string.IsNullOrWhiteSpace(actorName) ? actorName : ResolveRecentPickupActorName(recentPickup),
                fallbackOwnerId);
            PickupNoticeMessagePair messages = PickupNoticeTextFormatter.FormatRemotePickup(
                actorKind,
                recentPickup.Type,
                resolvedActorName,
                itemName,
                recentPickup.Quantity,
                recentPickup.MesoAmount);
            AddPickupFailureMessage(messages, currentTime);
            return true;
        }

        internal static long BuildPickupRemoteNoticeKey(int dropId, int actorId)
        {
            return ((long)Math.Max(0, dropId) << 32) ^ (uint)Math.Max(0, actorId);
        }

        internal static bool ShouldSuppressRemotePickupNotice(int lastNoticeTime, int currentTime, int suppressionWindowMs)
        {
            if (suppressionWindowMs <= 0)
            {
                return false;
            }

            int elapsed = unchecked(currentTime - lastNoticeTime);
            return elapsed >= 0 && elapsed < suppressionWindowMs;
        }

        internal static int[] BuildPickupRemoteNoticeActorAliases(int actorId, int fallbackOwnerId = 0)
        {
            HashSet<int> aliases = new();

            void addAlias(int value)
            {
                if (value == 0)
                {
                    return;
                }

                aliases.Add(value);

                if (TryDecodeRemotePetPickupActorId(value, out int ownerCharacterId, out _)
                    && ownerCharacterId > 0)
                {
                    aliases.Add(ownerCharacterId);
                }
            }

            addAlias(actorId);
            addAlias(fallbackOwnerId);

            if (aliases.Count == 0)
            {
                aliases.Add(actorId);
            }

            int[] sortedAliases = aliases.ToArray();
            Array.Sort(sortedAliases);
            return sortedAliases;
        }

        private bool TryReserveRemotePickupNotice(int dropId, int actorId, int currentTime, int fallbackOwnerId = 0)
        {
            return TryReserveRemotePickupNotice(
                _recentPickupRemoteNoticeTimes,
                dropId,
                actorId,
                currentTime,
                PICKUP_REMOTE_NOTICE_SUPPRESSION_MS,
                fallbackOwnerId);
        }

        internal static bool TryReserveRemotePickupNotice(
            IDictionary<long, int> recentNoticeTimes,
            int dropId,
            int actorId,
            int currentTime,
            int suppressionWindowMs,
            int fallbackOwnerId = 0)
        {
            if (dropId <= 0 || recentNoticeTimes == null)
            {
                return true;
            }

            int[] actorAliases = BuildPickupRemoteNoticeActorAliases(actorId, fallbackOwnerId);
            for (int i = 0; i < actorAliases.Length; i++)
            {
                long aliasNoticeKey = BuildPickupRemoteNoticeKey(dropId, actorAliases[i]);
                if (recentNoticeTimes.TryGetValue(aliasNoticeKey, out int lastNoticeTime)
                    && ShouldSuppressRemotePickupNotice(
                        lastNoticeTime,
                        currentTime,
                        suppressionWindowMs))
                {
                    return false;
                }
            }

            for (int i = 0; i < actorAliases.Length; i++)
            {
                long aliasNoticeKey = BuildPickupRemoteNoticeKey(dropId, actorAliases[i]);
                recentNoticeTimes[aliasNoticeKey] = currentTime;
            }

            return true;
        }

        internal static Pools.RecentPickupRecord ResolveRecentRemoteDropPickupRecord(
            Pools.DropPool dropPool,
            int dropId,
            Vector2? pickupTargetPosition,
            int currentTime,
            float targetPositionFallbackRange = 48f)
        {
            if (dropPool == null)
            {
                return null;
            }

            Pools.RecentPickupRecord record = dropPool.FindRecentPickup(dropId, currentTime);
            if (record != null || !pickupTargetPosition.HasValue)
            {
                return record;
            }

            return dropPool.FindRecentPickupNear(
                pickupTargetPosition.Value.X,
                pickupTargetPosition.Value.Y,
                Math.Max(1f, targetPositionFallbackRange),
                currentTime);
        }

        private string ResolvePickupNoticeActorName(
            Pools.DropPickupActorKind actorKind,
            int actorId,
            string actorName,
            int fallbackOwnerId = 0)
        {
            return actorKind switch
            {
                Pools.DropPickupActorKind.Mob => !string.IsNullOrWhiteSpace(actorName)
                    ? actorName
                    : ResolveMobPickupSourceName(actorId),
                _ => ResolveRemotePickupActorName(actorKind, actorId, actorName, fallbackOwnerId)
            };
        }


        private void AddPickupFailureMessage(string screenMessage, string chatMessage, int currentTime)

        {

            _pickupNoticeUI.AddCantPickupMessage(screenMessage, currentTime);


            AddPickupChatMessage(chatMessage, currentTime);
        }


        internal static bool ShouldSurfacePickupFailure(Pools.DropPickupFailureReason reason)
        {
            return reason == Pools.DropPickupFailureReason.InventoryFull
                || reason == Pools.DropPickupFailureReason.OwnershipRestricted
                || reason == Pools.DropPickupFailureReason.PetPickupBlocked
                || reason == Pools.DropPickupFailureReason.FieldRestricted
                || reason == Pools.DropPickupFailureReason.Unavailable;
        }


        private void AddPickupFailureMessage(PickupNoticeMessagePair messagePair, int currentTime)
        {
            AddPickupFailureMessage(messagePair, currentTime, PickupMessageType.CantPickup);
        }

        private void AddPickupChatMessage(string message, int currentTime, int chatLogType = -1)
        {
            if (!string.IsNullOrWhiteSpace(message))
            {
                _chat?.AddMessage(message, new Color(255, 228, 151), currentTime, chatLogType);
            }
        }


        private void AddPickupFailureMessage(
            PickupNoticeMessagePair messagePair,
            int currentTime,
            PickupMessageType screenMessageType)
        {
            if (!string.IsNullOrWhiteSpace(messagePair.ScreenMessage))
            {
                _pickupNoticeUI.AddFormattedNotice(
                    messagePair.ScreenMessage,
                    screenMessageType,
                    currentTime);
            }

            AddPickupChatMessage(messagePair.ChatMessage, currentTime, messagePair.ChatLogType);
        }


        private Texture2D LoadInventoryItemIcon(int itemId)
        {
            WzSubProperty infoProperty = LoadInventoryItemInfoProperty(itemId);
            WzCanvasProperty iconCanvas = infoProperty?["iconRaw"] as WzCanvasProperty
                                          ?? infoProperty?["icon"] as WzCanvasProperty;
            return iconCanvas?.GetLinkedWzCanvasBitmap()?.ToTexture2DAndDispose(GraphicsDevice);
        }

        private IReadOnlyList<IDXObject> ResolvePacketItemDropVisuals(string itemId)
        {
            return int.TryParse(itemId, NumberStyles.Integer, CultureInfo.InvariantCulture, out int resolvedItemId)
                ? LoadInventoryItemDropFrames(resolvedItemId)
                : null;
        }

        private List<IDXObject> LoadInventoryItemDropFrames(int itemId)
        {
            WzSubProperty infoProperty = LoadInventoryItemInfoProperty(itemId);
            WzImageProperty dropProperty = infoProperty?["drop"];
            if (dropProperty == null || GraphicsDevice == null)
            {
                return null;
            }

            ConcurrentBag<WzObject> usedProps = new();
            List<IDXObject> frames = MapSimulatorLoader.LoadFrames(
                _texturePool,
                dropProperty,
                0,
                0,
                GraphicsDevice,
                usedProps);
            return frames.Count > 0 ? frames : null;
        }


