            public bool HasSupportedRecovery =>

                FlatHp > 0 || FlatMp > 0 || PercentHp > 0 || PercentMp > 0;

            public bool HasSupportedProgression =>
                DirectExperience > 0 ||
                CharismaExperience > 0 ||
                InsightExperience > 0 ||
                WillExperience > 0 ||
                CraftExperience > 0 ||
                SenseExperience > 0 ||
                CharmExperience > 0 ||
                EventPoint > 0;



