            public bool HasSupportedMorph =>



                DurationMs > 0 &&



                (MorphTemplateId > 0 ||



                 (RandomMorphTemplateIds != null && RandomMorphTemplateIds.Length > 0));



            public bool HasSupportedTemporaryBuff =>
                DurationMs > 0 &&
                (Booster != 0 ||
                 Pad != 0 ||
                 Mad != 0 ||
                 Pdd != 0 ||
                 Mdd != 0 ||
                 Strength != 0 ||
                 Dexterity != 0 ||
                 Intelligence != 0 ||
                 Luck != 0 ||
                 Accuracy != 0 ||
                 Avoidability != 0 ||
                 Speed != 0 ||
                 Jump != 0 ||
                 AllStat != 0 ||
                 IndieMaxHp != 0 ||
                 IndieMaxMp != 0 ||
                 MaxHpPercent != 0 ||
                 MaxMpPercent != 0 ||
                 AttackPercent != 0 ||
                 MagicAttackPercent != 0 ||
                 DefensePercent != 0 ||
                 MagicDefensePercent != 0 ||
                 AccuracyPercent != 0 ||
                 AvoidabilityPercent != 0 ||
                 SpeedPercent != 0 ||
                 AbnormalStatusResistance != 0 ||
                 ExperienceRate != 0 ||
                 DropRate != 0 ||
                 MesoRate != 0);

            public bool HasSupportedFieldProtection =>
                EnvironmentalDamageProtection > 0 &&
                DurationMs > 0;


            public bool HasSupportedCure =>
                CuresSeal ||
                CuresDarkness ||
                CuresWeakness ||
                CuresStun ||
                CuresPoison ||
                CuresSlow ||
                CuresFreeze ||
                CuresAwake ||
                CuresCurse ||
                CuresPainMark ||
                CuresDeathMark ||
                CuresAttract ||
                CuresReverseInput ||
                CuresUndead;

            public bool HasSupportedMobSkill =>
                MobSkillEffects != null && MobSkillEffects.Length > 0;
        }


        private readonly struct PetFoodItemEffect



        {



            public int FullnessIncrease { get; init; }



            public int[] SupportedPetItemIds { get; init; }







            public bool IsPetFood => FullnessIncrease > 0;



        }



        private int ResolveInventoryItemMaxStack(int itemId, InventoryType inventoryType)
        {
            WzSubProperty infoProperty = LoadInventoryItemInfoProperty(itemId);
            int? slotMax = infoProperty?["slotMax"] switch
            {
                WzIntProperty intProperty => intProperty.Value,
                WzShortProperty shortProperty => shortProperty.Value,
                _ => null
            };


            return InventoryItemMetadataResolver.ResolveMaxStack(inventoryType, slotMax);

        }



        private bool IsPetPickupBlocked(DropItem drop)
        {
            if (drop == null
                || drop.Type == Pools.DropType.Meso
                || string.IsNullOrWhiteSpace(drop.ItemId)
                || !int.TryParse(drop.ItemId, out int itemId))
            {
                return false;
            }


            return InventoryItemMetadataResolver.IsPetPickupBlocked(itemId);
        }

        private static bool IsClientPickupBlocked(DropItem drop)
        {
            if (drop == null
                || drop.Type == Pools.DropType.Meso
                || string.IsNullOrWhiteSpace(drop.ItemId)
                || !int.TryParse(drop.ItemId, out int itemId))
            {
                return false;
            }

            return InventoryItemMetadataResolver.IsPickupBlocked(itemId);
        }


        private bool TryUseConsumableInventoryItem(int itemId, InventoryType inventoryType, int currentTime, int? slotIndex = null)
        {
            if (itemId <= 0 ||
                _playerManager?.Player == null ||
                uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryWindow)
            {
                return false;
            }

            if (TryRejectOnlyPickupInventoryUse(itemId, inventoryType, currentTime))
            {
                return false;
            }

            if (slotIndex.HasValue)
            {
                IReadOnlyList<UI.InventorySlotData> slots = inventoryWindow.GetSlots(inventoryType);
                int lockedSlotIndex = slotIndex.Value;
                if (slots == null ||
                    lockedSlotIndex < 0 ||
                    lockedSlotIndex >= slots.Count)
                {
                    return false;
                }

                UI.InventorySlotData lockedSlot = slots[lockedSlotIndex];
                if (lockedSlot == null ||
                    lockedSlot.IsDisabled ||
                    lockedSlot.ItemId != itemId ||
                    Math.Max(0, lockedSlot.Quantity) <= 0)
                {
                    return false;
                }
            }

            string fieldItemRestrictionMessage = GetFieldItemUseRestrictionMessage(inventoryType, itemId, 1);
            if (!string.IsNullOrWhiteSpace(fieldItemRestrictionMessage))
            {
                ShowFieldRestrictionMessage(fieldItemRestrictionMessage);
                return false;
            }

            if (TryHandleSkillBookInventoryItem(
                itemId,
                inventoryType,
                inventoryWindow,
                currentTime,
                slotIndex,
                out bool skillBookUsed))
            {
                return skillBookUsed;
            }


            ConsumableItemEffect effect = ResolveConsumableItemEffect(itemId);

            bool supportsRecovery = effect.HasSupportedRecovery;
            bool supportsProgression = effect.HasSupportedProgression;

            bool supportsMovement = effect.HasSupportedMovement;



            bool supportsMorph = effect.HasSupportedMorph;
            bool supportsTemporaryBuff = effect.HasSupportedTemporaryBuff;
            bool supportsCure = effect.HasSupportedCure;
            bool supportsFieldProtection = effect.HasSupportedFieldProtection;
            bool supportsMobSkill = effect.HasSupportedMobSkill;
            if (!supportsRecovery && !supportsProgression && !supportsMovement && !supportsMorph && !supportsTemporaryBuff && !supportsCure && !supportsFieldProtection && !supportsMobSkill)
            {
                return false;
            }

            if (IsConsumableUseBlockedByMobStatus(effect))
            {
                ShowFieldRestrictionMessage("Consumables cannot be used while Potion Lock is active.");
                return false;
            }


            int availableCount = slotIndex.HasValue
                ? Math.Max(0, inventoryWindow.GetSlots(inventoryType)[slotIndex.Value]?.Quantity ?? 0)
                : inventoryWindow.GetItemCount(inventoryType, itemId);
            if (availableCount <= 0)
            {
                TryTriggerPetPotionFailureSpeech(effect, currentTime);
                return false;
            }


            PlayerCharacter player = _playerManager.Player;
            int hpGain = supportsRecovery
                ? ResolveConsumableRecoveryAmount(player.HP, player.MaxHP, effect.FlatHp, effect.PercentHp)
                : 0;
            int mpGain = supportsRecovery
                ? ResolveConsumableRecoveryAmount(player.MP, player.MaxMP, effect.FlatMp, effect.PercentMp)
                : 0;
            bool canApplyProgression = supportsProgression && player.Build != null;
            int targetMapId = supportsMovement
                ? ResolveConsumableMoveTargetMapId(effect.MoveToMapId)
                : 0;
            int morphTemplateId = supportsMorph


                ? ResolveConsumableMorphTemplateId(effect)



                : 0;



            bool canApplyTemporaryBuff = supportsTemporaryBuff && _playerManager?.Skills != null;
            bool canApplyFieldProtection = supportsFieldProtection;
            bool canApplyMobSkill = supportsMobSkill && _playerManager != null;



            bool canApplyMorph = supportsMorph



                && morphTemplateId > 0



                && player.CanApplyExternalAvatarTransform(itemId, actionName: null, morphTemplateId);
            bool canCureStatus = supportsCure && HasCurablePlayerMobStatus(effect);
            bool canQueueMovement = TryCanQueueConsumableMapTransfer(targetMapId, showFailureMessage: false);
            bool hasAnySupportedOutcome = hpGain > 0 || mpGain > 0 || canApplyProgression || canQueueMovement || canApplyMorph || canApplyTemporaryBuff || canCureStatus || canApplyFieldProtection || canApplyMobSkill;
            if (!hasAnySupportedOutcome)
            {
                return false;
            }


            if (!TryConsumeConsumableInventoryItem(inventoryWindow, inventoryType, itemId, slotIndex))
            {
                TryTriggerPetPotionFailureSpeech(effect, currentTime);
                return false;
            }


            ApplyConsumableRecovery(player, hpGain, mpGain);
            if (canApplyProgression)
            {
                ApplyConsumableProgressionToBuild(
                    player.Build,
                    effect.DirectExperience,
                    effect.CharismaExperience,
                    effect.InsightExperience,
                    effect.WillExperience,
                    effect.CraftExperience,
                    effect.SenseExperience,
                    effect.CharmExperience,
                    effect.EventPoint);
            }

            if (hpGain > 0)
            {
                _petHpPotionFailureSpeechCount = 0;
            }

            if (mpGain > 0)
            {
                _petMpPotionFailureSpeechCount = 0;
            }


            if (supportsCure)
            {
                ClearCurablePlayerMobStatuses(effect);
            }

            if (canApplyMorph)
            {
                player.ApplyExternalAvatarTransform(itemId, actionName: null, morphTemplateId, currentTime + effect.DurationMs);
            }


            if (canApplyTemporaryBuff)
            {
                SkillLevelData consumableBuffData = CreateConsumableBuffLevelData(effect);
                _playerManager.Skills.TryApplyConsumableBuff(
                    itemId,
                    ResolvePickupItemName(itemId),
                    ResolvePickupItemDescription(itemId),
                    consumableBuffData,
                    currentTime);
            }

            if (canApplyFieldProtection)
            {
                ApplyConsumableEnvironmentalDamageProtection(effect, currentTime);
            }

            if (canApplyMobSkill)
            {
                ApplyConsumableMobSkillEffects(effect.MobSkillEffects, currentTime);
            }


            if (!supportsMovement)

            {

                _fieldRuleRuntime?.RegisterSuccessfulItemUse(
                    ShouldTrackFieldConsumeItemCooldown(inventoryType, default, effect),
                    currentTime);
                return true;
            }

            if (canQueueMovement)
            {
                if (!TryQueueConsumableMapTransfer(targetMapId))
                {
                    return false;
                }

                _fieldRuleRuntime?.RegisterSuccessfulItemUse(
                    ShouldTrackFieldConsumeItemCooldown(inventoryType, default, effect),
                    currentTime);
                return true;
            }

            _fieldRuleRuntime?.RegisterSuccessfulItemUse(
                ShouldTrackFieldConsumeItemCooldown(inventoryType, default, effect),
                currentTime);
            return true;
        }

        internal static bool TryConsumeConsumableInventoryItem(
            UI.IInventoryRuntime inventoryWindow,
            InventoryType inventoryType,
            int itemId,
            int? slotIndex = null)
        {
            if (inventoryWindow == null || itemId <= 0)
            {
                return false;
            }

            return TryConsumeInventoryUseItem(inventoryWindow, inventoryType, itemId, 1, slotIndex);
        }

        private bool IsConsumableUseBlockedByMobStatus(ConsumableItemEffect effect)
        {
            return PlayerMobConsumableBlockEvaluator.IsStopPotionBlocked(
                _playerManager?.HasMobStatus(PlayerMobStatusEffect.StopPotion) == true,
                effect.HasSupportedRecovery,
                effect.HasSupportedCure,
                effect.HasSupportedMovement,
                effect.HasSupportedMorph,
                effect.HasSupportedTemporaryBuff);
        }

        private static void ApplyConsumableRecovery(PlayerCharacter player, int hpGain, int mpGain)
        {
            if (player == null || (hpGain <= 0 && mpGain <= 0))
            {
                return;
            }

            player.Recover(Math.Max(0, hpGain), Math.Max(0, mpGain));
        }

        internal static bool ApplyConsumableProgressionToBuild(
            CharacterBuild build,
            int directExperience,
            int charismaExperience,
            int insightExperience,
            int willExperience,
            int craftExperience,
            int senseExperience,
            int charmExperience,
            int eventPoint = 0)
        {
            if (build == null)
            {
                return false;
            }

            bool changed = false;
            long experienceGain = Math.Max(0, (long)directExperience);
            if (experienceGain > 0)
            {
                build.Exp = SaturatingAdd(build.Exp, experienceGain);
                changed = true;
            }

            int traitValue = build.TraitCharisma;
            changed |= TryApplyTraitExperience(ref traitValue, charismaExperience);
            build.TraitCharisma = traitValue;

            traitValue = build.TraitInsight;
            changed |= TryApplyTraitExperience(ref traitValue, insightExperience);
            build.TraitInsight = traitValue;

            traitValue = build.TraitWill;
            changed |= TryApplyTraitExperience(ref traitValue, willExperience);
            build.TraitWill = traitValue;

            traitValue = build.TraitCraft;
            changed |= TryApplyTraitExperience(ref traitValue, craftExperience);
            build.TraitCraft = traitValue;

            traitValue = build.TraitSense;
            changed |= TryApplyTraitExperience(ref traitValue, senseExperience);
            build.TraitSense = traitValue;

            traitValue = build.TraitCharm;
            changed |= TryApplyTraitExperience(ref traitValue, charmExperience);
            build.TraitCharm = traitValue;

            int cookieHousePoint = build.CookieHousePoint;
            changed |= TryApplyTraitExperience(ref cookieHousePoint, eventPoint);
            build.CookieHousePoint = cookieHousePoint;
            return changed;
        }

        private static bool TryApplyTraitExperience(ref int traitValue, int gain)
        {
            int normalizedGain = Math.Max(0, gain);
            if (normalizedGain <= 0)
            {
                return false;
            }

            traitValue = SaturatingAdd(traitValue, normalizedGain);
            return true;
        }

        private static long SaturatingAdd(long value, long gain)
        {
            if (gain <= 0)
            {
                return value;
            }

            return value >= long.MaxValue - gain
                ? long.MaxValue
                : value + gain;
        }

        private static int SaturatingAdd(int value, int gain)
        {
            if (gain <= 0)
            {
                return value;
            }

            return value >= int.MaxValue - gain
                ? int.MaxValue
                : value + gain;
        }


        private PetFoodItemEffect ResolvePetFoodItemEffect(int itemId)



        {



            WzSubProperty itemProperty = LoadInventoryItemProperty(itemId);



            WzSubProperty specProperty = itemProperty?["spec"] as WzSubProperty;



            if (specProperty == null)



            {



                return default;



            }







            int fullnessIncrease = Math.Max(0, GetWzIntValue(specProperty["inc"]));



            if (fullnessIncrease <= 0)



            {



                return default;



            }







            int[] supportedPetItemIds = specProperty.WzProperties



                .Where(property => int.TryParse(property.Name, out _))



                .Select(property => Math.Max(0, GetWzIntValue(property)))



                .Where(value => value > 0)



                .Distinct()



                .ToArray();







            return new PetFoodItemEffect



            {



                FullnessIncrease = fullnessIncrease,



                SupportedPetItemIds = supportedPetItemIds



            };



        }



        private ConsumableItemEffect ResolveConsumableItemEffect(int itemId)
        {
            WzSubProperty itemProperty = LoadInventoryItemProperty(itemId);
            WzSubProperty specProperty = itemProperty?["spec"] as WzSubProperty;
            WzSubProperty specExProperty = itemProperty?["specEx"] as WzSubProperty;
            if (specProperty == null && specExProperty == null)
            {
                return default;
            }


            return new ConsumableItemEffect
            {
                FlatHp = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "hp")),
                FlatMp = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "mp")),
                PercentHp = ResolveConsumablePercentValue(specProperty, specExProperty, "hpR", "hpRatio", "hpPer"),
                PercentMp = ResolveConsumablePercentValue(specProperty, specExProperty, "mpR", "mpRatio", "mpPer"),
                DirectExperience = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "expinc", "exp")),
                CharismaExperience = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "charismaEXP")),
                InsightExperience = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "insightEXP")),
                WillExperience = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "willEXP")),
                CraftExperience = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "craftEXP")),
                SenseExperience = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "senseEXP")),
                CharmExperience = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "charmEXP")),
                EventPoint = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "eventPoint")),
                MoveToMapId = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "moveTo")),
                Booster = ResolveConsumableIntValue(specProperty, specExProperty, "booster", "indieBooster"),
                Pad = ResolveConsumableIntValue(specProperty, specExProperty, "pad", "indiePad"),
                Mad = ResolveConsumableIntValue(specProperty, specExProperty, "mad", "indieMad"),
                Pdd = ResolveConsumableIntValue(specProperty, specExProperty, "pdd", "indiePdd"),
                Mdd = ResolveConsumableIntValue(specProperty, specExProperty, "mdd", "indieMdd"),
                Strength = ResolveConsumableIntValue(specProperty, specExProperty, "str", "indieSTR"),
                Dexterity = ResolveConsumableIntValue(specProperty, specExProperty, "dex", "indieDEX"),
                Intelligence = ResolveConsumableIntValue(specProperty, specExProperty, "int", "indieINT"),
                Luck = ResolveConsumableIntValue(specProperty, specExProperty, "luk", "indieLUK"),
                Accuracy = ResolveConsumableIntValue(specProperty, specExProperty, "acc"),
                Avoidability = ResolveConsumableIntValue(specProperty, specExProperty, "eva"),
                Speed = ResolveConsumableIntValue(specProperty, specExProperty, "speed", "indieSpeed"),
                Jump = ResolveConsumableIntValue(specProperty, specExProperty, "jump", "indieJump"),
                AllStat = ResolveConsumableIntValue(specProperty, specExProperty, "indieAllStat"),
                IndieMaxHp = ResolveConsumableIntValue(specProperty, specExProperty, "indieMhp"),
                IndieMaxMp = ResolveConsumableIntValue(specProperty, specExProperty, "indieMmp"),
                MaxHpPercent = ResolveConsumablePercentValue(specProperty, specExProperty, "mhpR", "mhpRRate"),
                MaxMpPercent = ResolveConsumablePercentValue(specProperty, specExProperty, "mmpR", "mmpRRate"),
                AttackPercent = ResolveConsumablePercentValue(specProperty, specExProperty, "padRate"),
                MagicAttackPercent = ResolveConsumablePercentValue(specProperty, specExProperty, "madRate"),
                DefensePercent = ResolveConsumablePercentValue(specProperty, specExProperty, "pddRate", "pddR"),
                MagicDefensePercent = ResolveConsumablePercentValue(specProperty, specExProperty, "mddRate", "mddR"),
                AccuracyPercent = ResolveConsumablePercentValue(specProperty, specExProperty, "accRate", "accR"),
                AvoidabilityPercent = ResolveConsumablePercentValue(specProperty, specExProperty, "evaRate", "evaR"),
                SpeedPercent = ResolveConsumablePercentValue(specProperty, specExProperty, "speedRate"),
                AbnormalStatusResistance = ResolveConsumablePercentValue(specProperty, specExProperty, "asrR", "indieAsrR"),
                ExperienceRate = ResolveConsumablePercentValue(specProperty, specExProperty, "expBuff", "expR", "plusExpRate"),
                DropRate = ResolveConsumablePercentValue(specProperty, specExProperty, "dropRate", "dropR"),
                MesoRate = ResolveConsumablePercentValue(specProperty, specExProperty, "mesoR"),
                EnvironmentalDamageProtection = ResolveConsumableEnvironmentalDamageProtection(specProperty?["thaw"], specExProperty?["thaw"]),
                ConsumeOnPickup = ResolveConsumableIntValue(specProperty, specExProperty, "consumeOnPickup") > 0,
                DurationMs = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "time")),


                MorphTemplateId = Math.Max(0, ResolveConsumableIntValue(specProperty, specExProperty, "morph")),



                RandomMorphTemplateIds = ResolveConsumableRandomMorphTemplateIds(
                    specProperty?["morphRandom"] as WzSubProperty,
                    specExProperty?["morphRandom"] as WzSubProperty),
                CuresSeal = ResolveConsumableIntValue(specProperty, specExProperty, "seal") > 0,
                CuresDarkness = ResolveConsumableIntValue(specProperty, specExProperty, "darkness") > 0,
                CuresWeakness = ResolveConsumableIntValue(specProperty, specExProperty, "weakness") > 0,
                CuresStun = ResolveConsumableIntValue(specProperty, specExProperty, "stun") > 0,
                CuresPoison = ResolveConsumableIntValue(specProperty, specExProperty, "poison") > 0,
                CuresSlow = ResolveConsumableIntValue(specProperty, specExProperty, "slow") > 0,
                CuresFreeze = ResolveConsumableIntValue(specProperty, specExProperty, "freeze") > 0,
                CuresAwake = ResolveConsumableIntValue(specProperty, specExProperty, "awake") > 0,
                CuresCurse = ResolveConsumableIntValue(specProperty, specExProperty, "curse") > 0,
                CuresPainMark = ResolveConsumableIntValue(specProperty, specExProperty, "painmark") > 0,
                CuresDeathMark = ResolveConsumableIntValue(specProperty, specExProperty, "deathmark") > 0,
                CuresAttract = ResolveConsumableIntValue(specProperty, specExProperty, "seduce", "attract") > 0,
                CuresReverseInput = ResolveConsumableIntValue(specProperty, specExProperty, "confusion", "reverseInput") > 0,
                CuresUndead = ResolveConsumableIntValue(specProperty, specExProperty, "undead", "zombie") > 0,
                MobSkillEffects = ResolveConsumableMobSkillEffects(specProperty, specExProperty)
            };
        }

        private bool ApplyConsumableMobSkillEffects(IReadOnlyList<ConsumableMobSkillEffect> effects, int currentTime)
        {
            if (_playerManager == null || effects == null || effects.Count == 0)
            {
                return false;
            }

            bool appliedAny = false;
            for (int i = 0; i < effects.Count; i++)
            {
                ConsumableMobSkillEffect effect = effects[i];
                int skillId = Math.Max(0, effect.SkillId);
                if (skillId <= 0)
                {
                    continue;
                }

                int skillLevel = Math.Max(1, effect.Level);
                MobSkillRuntimeData runtimeData = ResolveMobSkillRuntimeData(skillId, skillLevel);
                bool appliedStatus = _playerManager.TryApplyMobSkillStatus(skillId, runtimeData, currentTime);
                bool appliedBlocking = _playerManager.TryApplyMobSkillBlockingStatus(skillId, skillLevel, runtimeData, currentTime);
                if (!appliedStatus && !appliedBlocking)
                {
                    continue;
                }

                _playerManager.PlayMobSkillHitEffect(skillId, skillLevel, currentTime);
                appliedAny = true;
            }

            return appliedAny;
        }

        private static ConsumableMobSkillEffect[] ResolveConsumableMobSkillEffects(
            WzSubProperty specProperty,
            WzSubProperty specExProperty)
        {
            var effects = new List<ConsumableMobSkillEffect>();
            var seenEffects = new HashSet<(int SkillId, int Level, int Target)>();

            AppendConsumableMobSkillEffects(specProperty, effects, seenEffects);
            AppendConsumableMobSkillEffects(specExProperty, effects, seenEffects);

            return effects.Count == 0
                ? Array.Empty<ConsumableMobSkillEffect>()
                : effects.ToArray();
        }

        private static void AppendConsumableMobSkillEffects(
            WzSubProperty container,
            ICollection<ConsumableMobSkillEffect> effects,
            ISet<(int SkillId, int Level, int Target)> seenEffects)
        {
            if (container == null || effects == null || seenEffects == null)
            {
                return;
            }

            if (TryResolveConsumableMobSkillEffect(container, out ConsumableMobSkillEffect directEffect))
            {
                if (seenEffects.Add((directEffect.SkillId, directEffect.Level, directEffect.Target)))
                {
                    effects.Add(directEffect);
                }
            }

            IReadOnlyList<WzImageProperty> children = container.WzProperties;
            if (children == null || children.Count == 0)
            {
                return;
            }

            for (int i = 0; i < children.Count; i++)
            {
                if (children[i] is not WzSubProperty child)
                {
                    continue;
                }

                if (!TryResolveConsumableMobSkillEffect(child, out ConsumableMobSkillEffect childEffect))
                {
                    continue;
                }

                if (seenEffects.Add((childEffect.SkillId, childEffect.Level, childEffect.Target)))
                {
                    effects.Add(childEffect);
                }
            }
        }

        private static bool TryResolveConsumableMobSkillEffect(
            WzSubProperty property,
            out ConsumableMobSkillEffect effect)
        {
            effect = default;
            if (property == null)
            {
                return false;
            }

            int skillId = Math.Max(0, GetWzIntValue(property["mobSkill"]));
            if (skillId <= 0)
            {
                return false;
            }

            effect = new ConsumableMobSkillEffect
            {
                SkillId = skillId,
                Level = Math.Max(1, GetWzIntValue(property["level"])),
                Target = GetWzIntValue(property["target"])
            };
            return true;
        }

        internal static int ResolveConsumableMobSkillEffectCountForTests(
            WzSubProperty specProperty,
            WzSubProperty specExProperty)
        {
            return ResolveConsumableMobSkillEffects(specProperty, specExProperty).Length;
        }


        private bool HasCurablePlayerMobStatus(ConsumableItemEffect effect)
        {
            if (_playerManager?.Player == null)
            {
                return false;
            }


            foreach (PlayerMobStatusEffect status in EnumerateCurablePlayerMobStatuses(effect))
            {
                if (_playerManager.HasMobStatus(status))
                {
                    return true;
                }
            }


            return false;

        }



        private void ClearCurablePlayerMobStatuses(ConsumableItemEffect effect)
        {
            if (_playerManager == null)
            {
                return;
            }


            _playerManager.ClearMobStatuses(EnumerateCurablePlayerMobStatuses(effect));

        }



        private static IEnumerable<PlayerMobStatusEffect> EnumerateCurablePlayerMobStatuses(ConsumableItemEffect effect)
        {
            if (effect.CuresSeal)
            {
                yield return PlayerMobStatusEffect.Seal;
            }


            if (effect.CuresDarkness)
            {
                yield return PlayerMobStatusEffect.Darkness;
            }


            if (effect.CuresWeakness)
            {
                yield return PlayerMobStatusEffect.Weakness;
            }


            if (effect.CuresStun)
            {
                yield return PlayerMobStatusEffect.Stun;
            }


            if (effect.CuresPoison)
            {
                yield return PlayerMobStatusEffect.Poison;
            }


            if (effect.CuresSlow)
            {
                yield return PlayerMobStatusEffect.Slow;
            }


            if (effect.CuresFreeze)
            {
                yield return PlayerMobStatusEffect.Freeze;
            }

            if (effect.CuresAwake)
            {
                yield return PlayerMobStatusEffect.StopMotion;
            }


            if (effect.CuresCurse)
            {
                yield return PlayerMobStatusEffect.Curse;
            }


            if (effect.CuresPainMark)
            {
                yield return PlayerMobStatusEffect.PainMark;
            }

            if (effect.CuresDeathMark)
            {
                yield return PlayerMobStatusEffect.PainMark;
            }


            if (effect.CuresAttract)
            {
                yield return PlayerMobStatusEffect.Attract;
            }


            if (effect.CuresReverseInput)
            {
                yield return PlayerMobStatusEffect.ReverseInput;
            }


            if (effect.CuresUndead)
            {
                yield return PlayerMobStatusEffect.Undead;
            }
        }


        private static SkillLevelData CreateConsumableBuffLevelData(ConsumableItemEffect effect)
        {
            return new SkillLevelData
            {
                Level = 1,
                Time = Math.Max(1, effect.DurationMs / 1000),
                X = effect.Booster,
                PAD = effect.Pad,
                MAD = effect.Mad,
                PDD = effect.Pdd,
                MDD = effect.Mdd,
                STR = effect.Strength,
                DEX = effect.Dexterity,
                INT = effect.Intelligence,
                LUK = effect.Luck,
                ACC = effect.Accuracy,
                EVA = effect.Avoidability,
                Speed = effect.Speed,
                Jump = effect.Jump,
                AllStat = effect.AllStat,
                IndieMaxHP = effect.IndieMaxHp,
                IndieMaxMP = effect.IndieMaxMp,
                MaxHPPercent = effect.MaxHpPercent,
                MaxMPPercent = effect.MaxMpPercent,
                AttackPercent = effect.AttackPercent,
                MagicAttackPercent = effect.MagicAttackPercent,
                DefensePercent = effect.DefensePercent,
                MagicDefensePercent = effect.MagicDefensePercent,
                AccuracyPercent = effect.AccuracyPercent,
                AvoidabilityPercent = effect.AvoidabilityPercent,
                SpeedPercent = effect.SpeedPercent,
                AbnormalStatusResistance = effect.AbnormalStatusResistance,
                ExperienceRate = effect.ExperienceRate,
                DropRate = effect.DropRate,
                MesoRate = effect.MesoRate
            };
        }

        private void ApplyConsumableEnvironmentalDamageProtection(ConsumableItemEffect effect, int currentTime)
        {
            if (effect.EnvironmentalDamageProtection <= 0 || effect.DurationMs <= 0)
            {
                return;
            }

            _activeEnvironmentalDamageProtectionAmount = effect.EnvironmentalDamageProtection;
            _activeEnvironmentalDamageProtectionExpiresAt = currentTime + effect.DurationMs;
        }

        private int GetActiveEnvironmentalDamageProtectionAmount(int currentTime)
        {
            if (_activeEnvironmentalDamageProtectionAmount <= 0)
            {
                return 0;
            }

            if (currentTime >= _activeEnvironmentalDamageProtectionExpiresAt)
            {
                _activeEnvironmentalDamageProtectionAmount = 0;
                _activeEnvironmentalDamageProtectionExpiresAt = int.MinValue;
                return 0;
            }

            return _activeEnvironmentalDamageProtectionAmount;
        }

        private static int ResolveConsumableEnvironmentalDamageProtection(WzImageProperty property, WzImageProperty fallbackProperty = null)
        {
            int value = GetWzIntValue(property);
            if (value == 0 && fallbackProperty != null)
            {
                value = GetWzIntValue(fallbackProperty);
            }

            return Math.Abs(value);
        }

        private string ResolvePickupActorNameForHistory(Pools.DropPickupActorKind actorKind, int pickerId, bool pickedByPet)
        {
            if (pickerId <= 0)
            {
                return null;
            }

            return actorKind switch
            {
                Pools.DropPickupActorKind.Player => pickerId == (_playerManager?.Player?.Build?.Id ?? 0)
                    ? ResolveLocalPlayerPickupActorName()
                    : ResolveRemotePickupActorName(Pools.DropPickupActorKind.Player, pickerId, null),
                Pools.DropPickupActorKind.Pet => pickedByPet
                    ? ResolvePickupSourceName(pickerId, pickedByPet: true)
                    : ResolveRemotePickupActorName(Pools.DropPickupActorKind.Pet, pickerId, null),
                Pools.DropPickupActorKind.Mob => ResolveMobPickupSourceName(pickerId),
                Pools.DropPickupActorKind.Other => ResolveRemotePickupActorName(
                    Pools.DropPickupActorKind.Other,
                    pickerId,
                    null),
                _ => null
            };
        }

        private string ResolveLocalPlayerPickupActorName()
        {
            string playerName = _playerManager?.Player?.Build?.Name;
            if (!string.IsNullOrWhiteSpace(playerName))
            {
                return playerName;
            }

            return _loginCharacterRoster.SelectedEntry?.Build?.Name;
        }


        private bool TryQueueConsumableMapTransfer(int targetMapId)
        {
            string transferRestrictionMessage = GetCurrentMapTransferRestrictionMessage();
            if (!string.IsNullOrWhiteSpace(transferRestrictionMessage))
            {
                ShowFieldRestrictionMessage(transferRestrictionMessage);
                return false;
            }

            if (!CanQueueKnownCrossMapTransfer(targetMapId, showFailureMessage: true))
            {
                return false;
            }


            return QueueMapTransfer(targetMapId, null);

        }


        private bool TryCanQueueConsumableMapTransfer(int targetMapId, bool showFailureMessage)
        {
            if (targetMapId <= 0 || targetMapId == MapConstants.MaxMap)
            {
                return false;
            }


            if (_loadMapCallback == null)
            {
                if (showFailureMessage)
                {
                    PushFieldRuleMessage("Map loading is unavailable in this session.", currTickCount, false);
                }

                return false;
            }


            if (_gameState.PendingMapChange)
            {
                if (showFailureMessage)
                {
                    PushFieldRuleMessage("A map transfer is already in progress.", currTickCount, false);
                }

                return false;
            }

            if (!CanQueueKnownCrossMapTransfer(targetMapId, showFailureMessage))
            {
                return false;
            }


            return true;
        }



        private int ResolveConsumableMoveTargetMapId(int moveToMapId)
        {
            if (moveToMapId <= 0)
            {
                return 0;
            }


            return moveToMapId == 999999999
                ? ResolveNearestTownMapId()
                : moveToMapId;
        }


        private int ResolveNearestTownMapId()
        {
            if (_mapBoard?.MapInfo?.returnMap is int returnMapId &&
                returnMapId > 0 &&
                returnMapId != MapConstants.MaxMap)
            {
                return returnMapId;
            }


            if (_mapBoard?.MapInfo?.forcedReturn is int forcedReturnId &&
                forcedReturnId > 0 &&
                forcedReturnId != MapConstants.MaxMap)
            {
                return forcedReturnId;
            }


            return 0;

        }



        private static int[] ResolveConsumableRandomMorphTemplateIds(WzSubProperty morphRandomProperty)



        {



            if (morphRandomProperty == null)



            {



                return Array.Empty<int>();



            }







            List<int> weightedTemplateIds = new();



            foreach (WzSubProperty morphEntry in morphRandomProperty.WzProperties.OfType<WzSubProperty>())



            {



                int morphTemplateId = Math.Max(0, GetWzIntValue(morphEntry["morph"]));



                if (morphTemplateId <= 0)



                {



                    continue;



                }







                int weight = Math.Max(1, GetWzIntValue(morphEntry["prop"]));



                for (int i = 0; i < weight; i++)



                {



                    weightedTemplateIds.Add(morphTemplateId);



                }



            }







            return weightedTemplateIds.ToArray();



        }

        private static int[] ResolveConsumableRandomMorphTemplateIds(WzSubProperty morphRandomProperty, WzSubProperty fallbackMorphRandomProperty)
        {
            int[] primary = ResolveConsumableRandomMorphTemplateIds(morphRandomProperty);
            int[] fallback = ResolveConsumableRandomMorphTemplateIds(fallbackMorphRandomProperty);
            if (primary.Length == 0)
            {
                return fallback;
            }

            if (fallback.Length == 0)
            {
                return primary;
            }

            int[] merged = new int[primary.Length + fallback.Length];
            Array.Copy(primary, merged, primary.Length);
            Array.Copy(fallback, 0, merged, primary.Length, fallback.Length);
            return merged;
        }







        private static int ResolveConsumableMorphTemplateId(ConsumableItemEffect effect)



        {



            if (effect.MorphTemplateId > 0)



            {



                return effect.MorphTemplateId;



            }







            if (effect.RandomMorphTemplateIds == null || effect.RandomMorphTemplateIds.Length == 0)



            {



                return 0;



            }







            int randomIndex = Random.Shared.Next(effect.RandomMorphTemplateIds.Length);



            return effect.RandomMorphTemplateIds[randomIndex];



        }







        private static int ResolveConsumablePercentValue(WzSubProperty specProperty, params string[] propertyNames)
        {
            if (specProperty == null || propertyNames == null)
            {
                return 0;
            }


            for (int i = 0; i < propertyNames.Length; i++)
            {
                int value = Math.Max(0, GetWzIntValue(specProperty[propertyNames[i]]));
                if (value > 0)
                {
                    return value;
                }
            }


            return 0;
        }

        internal static int ResolveConsumablePercentValueForTests(
            WzSubProperty specProperty,
            WzSubProperty specExProperty,
            params string[] propertyNames)
        {
            return ResolveConsumablePercentValue(specProperty, specExProperty, propertyNames);
