        private void DrawPetSpeechBalloon(PetRuntime pet, in Managers.RenderContext renderContext)
        {
            if (pet == null ||
                !pet.HasActiveSpeech ||
                _fontChat == null ||
                _debugBoundaryTexture == null)
            {
                return;
            }


            IDXObject currentFrame = pet.GetCurrentFrame();
            int petTop = (int)pet.Y - (currentFrame?.Height ?? 40);
            Vector2 textSize = MeasureChatTextWithFallback(pet.ActiveSpeechText);
            int boxWidth = (int)Math.Ceiling(textSize.X) + 18;
            int boxHeight = (int)Math.Ceiling(textSize.Y) + 12;
            int boxX = (int)pet.X - renderContext.MapShiftX + renderContext.MapCenterX - (boxWidth / 2);
            int boxY = petTop - renderContext.MapShiftY + renderContext.MapCenterY - boxHeight - 24;


            if (boxX + boxWidth < 0 ||
                boxY + boxHeight < 0 ||
                boxX > renderContext.RenderParams.RenderWidth ||
                boxY > renderContext.RenderParams.RenderHeight)
            {
                return;
            }


            float remainingAlpha = MathHelper.Clamp((pet.ActiveSpeechExpiresAt - renderContext.TickCount) / 400f, 0f, 1f);
            Color backgroundColor = new Color(30, 31, 45) * (0.88f * remainingAlpha);
            Color borderColor = new Color(176, 223, 255) * remainingAlpha;
            Color textColor = new Color(242, 249, 255) * remainingAlpha;


            _spriteBatch.Draw(_debugBoundaryTexture, new Rectangle(boxX, boxY, boxWidth, boxHeight), backgroundColor);
            _spriteBatch.Draw(_debugBoundaryTexture, new Rectangle(boxX, boxY, boxWidth, 2), borderColor);
            _spriteBatch.Draw(_debugBoundaryTexture, new Rectangle(boxX, boxY + boxHeight - 2, boxWidth, 2), borderColor);
            _spriteBatch.Draw(_debugBoundaryTexture, new Rectangle(boxX, boxY, 2, boxHeight), borderColor);
            _spriteBatch.Draw(_debugBoundaryTexture, new Rectangle(boxX + boxWidth - 2, boxY, 2, boxHeight), borderColor);
            DrawChatTextWithFallback(pet.ActiveSpeechText, new Vector2(boxX + 9, boxY + 6), textColor);
        }


        private Vector2 MeasureChatTextWithFallback(string text)
        {
            if (_fontChat == null || string.IsNullOrEmpty(text))
            {
                return Vector2.Zero;
            }


            string normalizedText = NormalizeSpriteFontPunctuation(text);
            return ContainsUnsupportedChatGlyphs(normalizedText)
                ? MeasureFallbackChatText(normalizedText)
                : _fontChat.MeasureString(normalizedText);
        }


        private void DrawChatTextWithFallback(string text, Vector2 position, Color color)
        {
            DrawChatTextWithFallback(_spriteBatch, text, position, color);
        }

        private void DrawChatTextWithFallback(SpriteBatch spriteBatch, string text, Vector2 position, Color color)
        {
            if (spriteBatch == null || _fontChat == null || string.IsNullOrEmpty(text))
            {
                return;
            }


            string normalizedText = NormalizeSpriteFontPunctuation(text);
            if (!ContainsUnsupportedChatGlyphs(normalizedText))
            {
                spriteBatch.DrawString(_fontChat, normalizedText, position, color);
                return;
            }


            Texture2D texture = GetOrCreateChatFallbackTexture(normalizedText);
            if (texture != null)
            {
                spriteBatch.Draw(texture, position, color);
            }
        }


        private Texture2D GetOrCreateChatFallbackTexture(string text)
        {
            if (string.IsNullOrEmpty(text))
            {
                return null;
            }


            if (_chatFallbackTextureCache.TryGetValue(text, out Texture2D cachedTexture) &&
                cachedTexture != null &&
                !cachedTexture.IsDisposed)
            {
                return cachedTexture;
            }


            Vector2 size = MeasureFallbackChatText(text);

            int width = Math.Max(1, (int)Math.Ceiling(size.X));

            int height = Math.Max(1, Math.Max((int)Math.Ceiling(size.Y), (int)Math.Ceiling(_chatFallbackLineHeight)));



            using var bitmap = new SD.Bitmap(width, height);
            using SD.Graphics graphics = SD.Graphics.FromImage(bitmap);
            graphics.Clear(SD.Color.Transparent);
            graphics.TextRenderingHint = SDText.TextRenderingHint.AntiAliasGridFit;
            using var brush = new SD.SolidBrush(SD.Color.White);
            graphics.DrawString(text, _chatFallbackFont, brush, 0f, 0f, SD.StringFormat.GenericTypographic);


            Texture2D texture = bitmap.ToTexture2D(GraphicsDevice);
            _chatFallbackTextureCache[text] = texture;
            return texture;
        }


        private Vector2 MeasureFallbackChatText(string text)
        {
            if (string.IsNullOrEmpty(text))
            {
                return Vector2.Zero;
            }


            SD.SizeF size = _chatFallbackMeasureGraphics.MeasureString(text, _chatFallbackFont, SD.PointF.Empty, SD.StringFormat.GenericTypographic);
            if (size.Width <= 0f || size.Height <= 0f)
            {
                size = _chatFallbackMeasureGraphics.MeasureString(text, _chatFallbackFont);
            }


            return new Vector2((float)Math.Ceiling(size.Width), (float)Math.Ceiling(size.Height));

        }



        private bool ContainsUnsupportedChatGlyphs(string text)
        {
            if (_fontChat == null || string.IsNullOrEmpty(text))
            {
                return false;
            }


            IReadOnlyList<char> supportedCharacters = _fontChat.Characters;
            if (supportedCharacters == null)
            {
                return false;
            }


            for (int i = 0; i < text.Length; i++)
            {
                bool found = false;
                for (int j = 0; j < supportedCharacters.Count; j++)
                {
                    if (supportedCharacters[j] == text[i])
                    {
                        found = true;
                        break;
                    }
                }


                if (!found)
                {
                    return true;
                }
            }


            return false;

        }



        private static string NormalizeSpriteFontPunctuation(string text)
        {
            if (string.IsNullOrEmpty(text))
            {
                return text ?? string.Empty;
            }


            var builder = new StringBuilder(text.Length);
            for (int i = 0; i < text.Length; i++)
            {
                builder.Append(text[i] switch
                {
                    '\u2018' => '\'',
                    '\u2019' => '\'',
                    '\u201A' => '\'',
                    '\u201B' => '\'',
                    '\u201C' => '"',
                    '\u201D' => '"',
                    '\u201E' => '"',
                    '\u201F' => '"',
                    '\u2032' => '\'',
                    '\u2033' => '"',
                    '\u00B4' => '\'',
                    '\u0060' => '\'',
                    '\u2013' => '-',
                    '\u2014' => '-',
                    '\u2212' => '-',
                    '\u00A0' => ' ',
                    _ => text[i]
                });
            }


            return builder.ToString();

        }



        private Texture2D GetNpcQuestAlertTexture(NpcInteractionEntryKind? alertKind)
        {
            return alertKind switch
            {
                NpcInteractionEntryKind.AvailableQuest => _npcQuestAvailableIcon,
                NpcInteractionEntryKind.InProgressQuest => _npcQuestInProgressIcon,
                NpcInteractionEntryKind.CompletableQuest => _npcQuestCompletableIcon,
                _ => null
            };
        }

        private NpcInteractionEntryKind? ResolveCachedNpcQuestAlertKind(NpcItem npc)
        {
            CharacterBuild build = _playerManager?.Player?.Build;
            if (npc == null || _questRuntime == null || build == null)
            {
                return null;
            }


            if (_npcQuestAlertKindCacheStamp != _lastNpcClientActionSelectionContextStamp)
            {
                _npcQuestAlertKindCacheStamp = _lastNpcClientActionSelectionContextStamp;
                _npcQuestAlertKindCache.Clear();
            }


            if (!int.TryParse(npc.NpcInstance?.NpcInfo?.ID, out int npcId) || npcId <= 0)
            {
                return _questRuntime.GetNpcQuestAlertKind(npc, build);
            }


            if (_npcQuestAlertKindCache.TryGetValue(npcId, out NpcInteractionEntryKind? cachedKind))
            {
                return cachedKind;
            }


            NpcInteractionEntryKind? resolvedKind = _questRuntime.GetNpcQuestAlertKind(npc, build);
            _npcQuestAlertKindCache[npcId] = resolvedKind;
            return resolvedKind;
        }


        private MinimapUI.NpcMarkerType ResolveMinimapNpcMarkerType(NpcItem npc)
        {
            if (npc == null || _questRuntime == null || _playerManager?.Player?.Build == null)
            {
                return MinimapUI.NpcMarkerType.Default;
            }


            NpcInteractionEntryKind? alertKind = ResolveCachedNpcQuestAlertKind(npc);
            return alertKind switch
            {
                NpcInteractionEntryKind.AvailableQuest => MinimapUI.NpcMarkerType.QuestStart,
                NpcInteractionEntryKind.InProgressQuest => MinimapUI.NpcMarkerType.QuestEnd,
                NpcInteractionEntryKind.CompletableQuest => MinimapUI.NpcMarkerType.QuestEnd,
                _ => MinimapUI.NpcMarkerType.Default
            };
        }
        private void EnsureMinimapTooltipResources()
        {
            if (miniMapUi == null || _fontChat == null || GraphicsDevice == null)
            {
                return;
            }


            if (_minimapTooltipPixelTexture == null)
            {
                _minimapTooltipPixelTexture = new Texture2D(GraphicsDevice, 1, 1);
                _minimapTooltipPixelTexture.SetData(new[] { Color.White });
            }


            miniMapUi.SetTooltipResources(_fontChat, _minimapTooltipPixelTexture);

        }



        private string ResolveMinimapNpcTooltipText(NpcItem npc)
        {
            if (npc?.NpcInstance == null)
            {
                return null;
            }


            string npcName = npc.NpcInstance.NpcInfo?.StringName;
            if (string.IsNullOrWhiteSpace(npcName))
            {
                npcName = npc.NpcInstance.NpcInfo?.ID;
            }


            string questState = ResolveMinimapNpcQuestStateText(npc);

            return BuildMinimapTooltipText(npcName, questState);

        }



        private string ResolveMinimapPortalTooltipText(PortalItem portal)
        {
            PortalInstance instance = portal?.PortalInstance;
            if (instance == null || _mapBoard?.MapInfo == null)
            {
                return null;
            }

            return ResolveMinimapPortalTooltipTextForTesting(
                instance.pt,
                instance.hideTooltip,
                instance.tm,
                _mapBoard.MapInfo.id,
                instance.pn,
                TryResolveMinimapPortalTooltipTextFromWz,
                ResolveMinimapPortalFallbackMapText);

        }

        internal const int ClientMinimapPortalTooltipPathStringPoolId = 0x0EE3;
        internal const int ClientMinimapPortalMapStringKeyStringPoolId = 0x06EC;

        internal static string ResolveMinimapPortalTooltipTextForTesting(
            PortalType portalType,
            MapleBool hideTooltip,
            int targetMapId,
            int currentMapId,
            string portalName,
            Func<int, string, string> authoredTooltipResolver,
            Func<int, string> mapDisplayNameResolver)
        {
            if (hideTooltip == MapleBool.True
                || !IsClientMinimapTooltipPortalType(portalType)
                || targetMapId == -1)
            {
                return null;
            }

            if (!string.IsNullOrWhiteSpace(portalName))
            {
                string authoredTooltip = authoredTooltipResolver?.Invoke(currentMapId, portalName.Trim());
                if (!string.IsNullOrWhiteSpace(authoredTooltip))
                {
                    return authoredTooltip.Trim();
                }
            }

            string fallbackMapText = mapDisplayNameResolver?.Invoke(targetMapId);
            return string.IsNullOrWhiteSpace(fallbackMapText)
                ? null
                : fallbackMapText.Trim();
        }

        private string ResolveMinimapPortalFallbackMapText(int mapId)
        {
            string mapStringKey = MapleStoryStringPool.GetOrFallback(
                ClientMinimapPortalMapStringKeyStringPoolId,
                "streetName");
            if (TryResolveMapStringByClientKey(mapId, mapStringKey, out string mapString)
                && !string.IsNullOrWhiteSpace(mapString))
            {
                return mapString.Trim();
            }

            return ResolveMapTransferDisplayName(mapId);
        }

        private static bool TryResolveMapStringByClientKey(int mapId, string key, out string value)
        {
            value = null;
            if (!TryResolveMapNamePartsFromCache(mapId, out string mapName, out string streetName))
            {
                return false;
            }

            if (string.Equals(key, "streetName", StringComparison.OrdinalIgnoreCase))
            {
                value = streetName;
                return !string.IsNullOrWhiteSpace(value);
            }

            if (string.Equals(key, "mapName", StringComparison.OrdinalIgnoreCase))
            {
                value = mapName;
                return !string.IsNullOrWhiteSpace(value);
            }

            return false;
        }

        private static bool IsClientMinimapTooltipPortalType(PortalType portalType)
        {
            return portalType == PortalType.Visible || portalType == PortalType.TownPortalPoint;
        }

        private static string TryResolveMinimapPortalTooltipTextFromWz(int currentMapId, string portalName)
        {
            if (currentMapId <= 0 || string.IsNullOrWhiteSpace(portalName))
            {
                return null;
            }

            if (!TryGetToolTipHelpStringImage(out WzImage toolTipHelpImage))
            {
                return null;
            }

            string portalTooltipPathTemplate = MapleStoryStringPool.GetOrFallback(
                ClientMinimapPortalTooltipPathStringPoolId,
                "String/ToolTipHelp.img/PortalTooltip/%d");
            WzImageProperty portalTooltipRoot = ResolveWzPropertyPath(
                toolTipHelpImage,
                FormatClientWzPath(portalTooltipPathTemplate, currentMapId, "String/ToolTipHelp.img/"));
            WzImageProperty tooltipProperty = portalTooltipRoot?[portalName.Trim()];
            return ReadMinimapPortalTooltipString(tooltipProperty);
        }

        private static bool TryGetToolTipHelpStringImage(out WzImage toolTipHelpImage)
        {
            toolTipHelpImage = Program.DataSource?.GetImage("String", "ToolTipHelp.img");
            if (toolTipHelpImage == null && Program.WzManager != null)
            {
                toolTipHelpImage = Program.WzManager.FindWzImageByName("string", "ToolTipHelp.img") as WzImage;
            }

            if (toolTipHelpImage == null)
            {
                return false;
            }

            if (!toolTipHelpImage.Parsed)
            {
                toolTipHelpImage.ParseImage();
            }

            return true;
        }

        private static WzImageProperty ResolveWzPropertyPath(WzImage image, string relativePath)
        {
            if (image == null || string.IsNullOrWhiteSpace(relativePath))
            {
                return null;
            }

            WzImageProperty current = null;
            string[] segments = relativePath.Split(new[] { '/', '\\' }, StringSplitOptions.RemoveEmptyEntries);
            foreach (string segment in segments)
            {
                current = current == null ? image[segment] : current[segment];
                if (current == null)
                {
                    return null;
                }
            }

            return current;
        }

        private static string FormatClientWzPath(string pathTemplate, int mapId, string prefixToTrim)
        {
            string formattedPath = pathTemplate?.Replace("%d", mapId.ToString(CultureInfo.InvariantCulture))
                ?? string.Empty;
            if (!string.IsNullOrWhiteSpace(prefixToTrim)
                && formattedPath.StartsWith(prefixToTrim, StringComparison.OrdinalIgnoreCase))
            {
                return formattedPath[prefixToTrim.Length..];
            }

            return formattedPath;
        }

        private static string ReadMinimapPortalTooltipString(WzImageProperty tooltipProperty)
        {
            if (tooltipProperty is WzStringProperty stringProperty)
            {
                return stringProperty.GetString();
            }

            if (tooltipProperty is WzSubProperty subProperty)
            {
                if (subProperty["Title"] is WzStringProperty titleProperty)
                {
                    return titleProperty.GetString();
                }

                foreach (WzImageProperty childProperty in subProperty.WzProperties)
                {
                    if (childProperty is WzStringProperty nestedStringProperty
                        && !string.IsNullOrWhiteSpace(nestedStringProperty.GetString()))
                    {
                        return nestedStringProperty.GetString();
                    }
                }
            }

            return null;
        }



        private string ResolveMinimapNpcQuestStateText(NpcItem npc)
        {
            if (npc == null || _questRuntime == null || _playerManager?.Player?.Build == null)
            {
                return null;
            }


            NpcInteractionEntryKind? alertKind = ResolveCachedNpcQuestAlertKind(npc);
            return alertKind switch
            {
                NpcInteractionEntryKind.AvailableQuest => "Quest available",
                NpcInteractionEntryKind.InProgressQuest => "Quest in progress",
                NpcInteractionEntryKind.CompletableQuest => "Quest complete",
                _ => null
            };
        }


        private static string BuildMinimapTooltipText(params string[] lines)
        {
            if (lines == null || lines.Length == 0)
            {
                return null;
            }


            List<string> normalizedLines = new(lines.Length);
            foreach (string line in lines)

            {

                string normalized = NormalizeSpriteFontPunctuation(line)?.Trim();
                if (!string.IsNullOrWhiteSpace(normalized) && !normalizedLines.Contains(normalized, StringComparer.Ordinal))
                {
                    normalizedLines.Add(normalized);
                }
            }


            return normalizedLines.Count == 0 ? null : string.Join(Environment.NewLine, normalizedLines);

        }

        private static void MergeMinimapTooltipDetailLine(
            MinimapTrackedUserState state,
            string detailLine)
        {
            if (state == null || string.IsNullOrWhiteSpace(detailLine))
            {
                return;
            }

            string normalizedDetail = NormalizeSpriteFontPunctuation(detailLine)?.Trim();
            if (string.IsNullOrWhiteSpace(normalizedDetail))
            {
                return;
            }

            if (string.IsNullOrWhiteSpace(state.RoomDetailTooltipLine))
            {
                state.RoomDetailTooltipLine = normalizedDetail;
                return;
            }

            if (string.Equals(state.RoomDetailTooltipLine, normalizedDetail, StringComparison.Ordinal))
            {
                return;
            }

            state.RoomDetailTooltipLine = BuildMinimapTooltipText(state.RoomDetailTooltipLine, normalizedDetail);
        }



        private static string BuildMinimapTrackedUserTooltipText(MinimapTrackedUserState state)
        {
            if (state == null)
            {
                return null;
            }


            List<string> relationshipLines = new();
            if (state.IsTrader)
            {
                relationshipLines.Add(state.TraderTooltipLabel ?? "Trader");
            }
            if (state.IsMatchParticipant)
            {
                relationshipLines.Add(state.MatchTooltipLabel ?? "Match Cards participant");
            }
            if (state.IsPartyMember)
            {
                relationshipLines.Add(state.IsPartyLeader ? "Party leader" : "Party member");
            }
            if (state.IsGuildMember)
            {
                relationshipLines.Add(state.IsGuildLeader ? "Guild leader" : "Guild member");
            }
            if (state.IsFriend)
            {
                relationshipLines.Add("Friend");
            }
            if (state.IsCouplePartner)
            {
                relationshipLines.Add("Couple partner");
            }
            if (state.IsMarriedPartner)
            {
                relationshipLines.Add("Married partner");
            }
            if (state.IsStalkTarget)
            {
                relationshipLines.Add("Stalk target");
            }
            if (state.BattlefieldTeamId.HasValue)
            {
                relationshipLines.Add(FormatMinimapBattlefieldTeamText(state.BattlefieldTeamId.Value));
            }


            return BuildMinimapTooltipText(
                state.Name,
                relationshipLines.Count > 0 ? string.Join(", ", relationshipLines) : "Remote user",
                state.RoomDetailTooltipLine);

        }

        private static string FormatMinimapBattlefieldTeamText(int teamId)
        {
            return teamId switch
            {
                0 => "Battlefield team: Wolves",
                1 => "Battlefield team: Sheep",
                2 => "Battlefield team: Team 2",
                _ => $"Battlefield team: {teamId}"
            };
        }



        private IReadOnlyList<MinimapUI.EmployeeMarker> BuildMinimapEmployeeMarkers(PlayerCharacter player)

        {
            _minimapEmployeeMarkersCount = 0;

            SocialRoomFieldActorSnapshot snapshot = GetSocialRoomEmployeeFieldActorSnapshot();
            if (snapshot == null || player == null)
            {
                return Array.Empty<MinimapUI.EmployeeMarker>();
            }


            int worldX;
            int worldY;
            if (snapshot.HasWorldPosition && !snapshot.UseOwnerAnchor)
            {
                worldX = snapshot.WorldX;
                worldY = snapshot.WorldY;
            }
            else
            {
                int horizontalOffset = player.FacingRight ? snapshot.AnchorOffsetX : -snapshot.AnchorOffsetX;
                worldX = (int)Math.Round(player.Position.X) + horizontalOffset;
                worldY = (int)Math.Round(player.Position.Y) + snapshot.AnchorOffsetY;

            }



            string tooltipText = BuildMinimapTooltipText(snapshot.Headline, snapshot.Detail);
            if (string.IsNullOrWhiteSpace(tooltipText))
            {
                return Array.Empty<MinimapUI.EmployeeMarker>();
            }


            MinimapUI.EmployeeMarker marker = GetOrCreateMinimapEmployeeMarker(_minimapEmployeeMarkersCount++);
            marker.WorldX = worldX;
            marker.WorldY = worldY;
            marker.ShowDirectionOverlay = true;
            marker.PreferredMarkerType = ResolveMinimapEmployeeMarkerType(snapshot);
            marker.TooltipText = tooltipText;

            return _minimapEmployeeMarkersBuffer;
        }


        private static MinimapUI.HelperMarkerType? ResolveMinimapEmployeeMarkerType(SocialRoomFieldActorSnapshot snapshot)
        {
            if (snapshot == null)
            {
                return null;
            }


            return snapshot.Kind switch
            {
                SocialRoomKind.PersonalShop => MinimapUI.HelperMarkerType.UserTrader,
                SocialRoomKind.EntrustedShop => MinimapUI.HelperMarkerType.UserTrader,
                _ => null
            };
        }


        private void RefreshMinimapTrackedUserMarkers()
        {
            if (miniMapUi == null)
            {
                return;
            }


            miniMapUi.SetLocalPlayerHelperMarker(ResolveLocalPlayerMinimapHelperMarker());
            EnsureMinimapTooltipResources();
            miniMapUi.SetTrackedUserMarkers(BuildMinimapTrackedUserMarkers(), _minimapTrackedUserMarkersCount);
            miniMapUi.SetEmployeeMarkers(BuildMinimapEmployeeMarkers(_playerManager?.Player), _minimapEmployeeMarkersCount);

        }



        private IReadOnlyList<MinimapUI.TrackedUserMarker> BuildMinimapTrackedUserMarkers()
        {
            PlayerCharacter player = _playerManager?.Player;
            if (player == null)
            {
                return Array.Empty<MinimapUI.TrackedUserMarker>();
            }


            string currentLocationSummary = GetCurrentMapTransferDisplayName();
            _socialListRuntime.UpdateLocalContext(player.Build, currentLocationSummary, 1);
            _familyChartRuntime.UpdateLocalContext(player.Build, currentLocationSummary, 1);
            RefreshGuildSkillUiContext();


            IReadOnlyList<SocialTrackedEntrySnapshot> trackedEntries = _socialListRuntime.BuildTrackedEntriesSnapshot();
            int trackedEntryCount = _socialListRuntime.TrackedEntriesCount;
            Dictionary<string, MinimapTrackedUserState> trackedUsers = _minimapTrackedUsersBuffer;
            trackedUsers.Clear();
            for (int i = 0; i < trackedEntryCount; i++)
            {
                SocialTrackedEntrySnapshot entry = trackedEntries[i];
                if (entry == null || entry.IsLocalPlayer || !entry.IsOnline || !IsSameTrackedField(entry.LocationSummary, currentLocationSummary))
                {
                    continue;
                }


                if (!trackedUsers.TryGetValue(entry.Name, out MinimapTrackedUserState state))
                {
                    state = new MinimapTrackedUserState(entry.Name);
                    trackedUsers[entry.Name] = state;
                }


                switch (entry.Tab)
                {
                    case SocialListTab.Party:
                        state.IsPartyMember = true;
                        state.IsPartyLeader |= entry.IsLeader;
                        break;
                    case SocialListTab.Guild:
                        state.IsGuildMember = true;
                        state.IsGuildLeader |= entry.IsLeader;
                        break;
                    case SocialListTab.Friend:
                        state.IsFriend = true;
                        break;
                }
            }


            for (int i = 0; i < trackedEntryCount; i++)
            {
                SocialTrackedEntrySnapshot entry = trackedEntries[i];
                if (_remoteUserPool.TryGetPosition(entry.Name, out Vector2 remotePosition)
                    && trackedUsers.TryGetValue(entry.Name, out MinimapTrackedUserState trackedState))
                {
                    trackedState.HasPosition = true;
                    trackedState.Position = remotePosition;
                }
            }


            IReadOnlyList<FamilyTrackedMemberSnapshot> trackedMembers = _familyChartRuntime.BuildTrackedMembersSnapshot();
            int trackedMemberCount = _familyChartRuntime.TrackedMembersCount;
            for (int i = 0; i < trackedMemberCount; i++)
            {
                FamilyTrackedMemberSnapshot member = trackedMembers[i];
                if (member == null || member.IsLocalPlayer || !member.IsOnline || !IsSameTrackedField(member.LocationSummary, currentLocationSummary))
                {
                    continue;
                }


                if (!trackedUsers.TryGetValue(member.Name, out MinimapTrackedUserState state))
                {
                    state = new MinimapTrackedUserState(member.Name);
                    trackedUsers[member.Name] = state;
                }


                state.HasPosition = true;
                state.Position = member.SimulatedPosition;
            }
            AppendPacketOwnedFieldTrackedUserMarkers(trackedUsers);
            AppendPacketOwnedStalkTrackedUserMarkers(trackedUsers);
            AppendPacketOwnedRelationshipTrackedUserMarkers(trackedUsers);
            AppendMiniRoomTrackedUserMarkers(trackedUsers, player);
            AppendTraderTrackedUserMarkers(trackedUsers, player);


            if (trackedUsers.Count == 0 && _remoteUserPool.Count == 0)
            {
                return Array.Empty<MinimapUI.TrackedUserMarker>();
            }


            _minimapTrackedUserMarkersCount = 0;
            HashSet<string> packetOwnedHelperNames = new(StringComparer.OrdinalIgnoreCase);
            foreach (RemoteUserActor actor in _remoteUserPool.Actors)
            {
                if (actor == null
                    || string.IsNullOrWhiteSpace(actor.Name)
                    || !ShouldSuppressSyntheticTrackedUserMarkerForPacketHelperState(
                        actor.IsVisibleInWorld,
                        actor.HiddenLikeClient,
                        actor.HasPacketAuthoredHelperState))
                {
                    continue;
                }

                TryRecordPacketOwnedMinimapMarkerNameForSuppression(packetOwnedHelperNames, actor.Name);
            }

            IReadOnlyList<MinimapUI.TrackedUserMarker> remoteMarkers = _remoteUserPool.BuildHelperMarkers();
            for (int i = 0; i < _remoteUserPool.HelperMarkerCount; i++)
            {
                MinimapUI.TrackedUserMarker marker = GetOrCreateMinimapTrackedUserMarker(_minimapTrackedUserMarkersCount++);
                MinimapUI.TrackedUserMarker remoteMarker = remoteMarkers[i];
                marker.WorldX = remoteMarker.WorldX;
                marker.WorldY = remoteMarker.WorldY;
                marker.MarkerType = remoteMarker.MarkerType;
                marker.ShowDirectionOverlay = remoteMarker.ShowDirectionOverlay;
                string remoteMarkerName = remoteMarker.TooltipText;
                TryRecordPacketOwnedMinimapMarkerNameForSuppression(packetOwnedHelperNames, remoteMarkerName);
                marker.TooltipText = !string.IsNullOrWhiteSpace(remoteMarkerName)
                    && trackedUsers.TryGetValue(remoteMarkerName, out MinimapTrackedUserState trackedState)
                    ? BuildMinimapTrackedUserTooltipText(trackedState)
                    : remoteMarker.TooltipText;
            }

            _sortedMinimapTrackedUsersBuffer.Clear();
            foreach (MinimapTrackedUserState trackedUserState in trackedUsers.Values)
            {
                _sortedMinimapTrackedUsersBuffer.Add(trackedUserState);
            }

            if (_sortedMinimapTrackedUsersBuffer.Count > 1)
            {
                _sortedMinimapTrackedUsersBuffer.Sort(MinimapTrackedUserStateNameComparer);
            }

            int syntheticIndex = 0;
            for (int i = 0; i < _sortedMinimapTrackedUsersBuffer.Count; i++)
            {
                MinimapTrackedUserState state = _sortedMinimapTrackedUsersBuffer[i];
                if (packetOwnedHelperNames.Contains(state.Name))
                {
                    continue;
                }

                Vector2 position = state.HasPosition
                    ? state.Position
                    : ResolveSyntheticTrackedUserPosition(player.X, player.Y, syntheticIndex++);


                MinimapUI.TrackedUserMarker marker = GetOrCreateMinimapTrackedUserMarker(_minimapTrackedUserMarkersCount++);
                marker.WorldX = position.X;
                marker.WorldY = position.Y;
                marker.MarkerType = ResolveMinimapTrackedUserMarkerType(state);
                marker.ShowDirectionOverlay = true;
                marker.TooltipText = BuildMinimapTrackedUserTooltipText(state);
            }

            return _minimapTrackedUserMarkersBuffer;

        }



        private static bool IsSameTrackedField(string left, string right)
        {
            return string.Equals(NormalizeTrackedFieldLocation(left), NormalizeTrackedFieldLocation(right), StringComparison.OrdinalIgnoreCase);
        }

        private MinimapUI.TrackedUserMarker GetOrCreateMinimapTrackedUserMarker(int index)
        {
            while (_minimapTrackedUserMarkersBuffer.Count <= index)
            {
                _minimapTrackedUserMarkersBuffer.Add(new MinimapUI.TrackedUserMarker());
            }

            return _minimapTrackedUserMarkersBuffer[index];
        }

        private MinimapUI.EmployeeMarker GetOrCreateMinimapEmployeeMarker(int index)
        {
            while (_minimapEmployeeMarkersBuffer.Count <= index)
            {
                _minimapEmployeeMarkersBuffer.Add(new MinimapUI.EmployeeMarker());
            }

            return _minimapEmployeeMarkersBuffer[index];
        }


        private static string NormalizeTrackedFieldLocation(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return string.Empty;
            }


            int channelSeparatorIndex = value.IndexOf("  CH ", StringComparison.OrdinalIgnoreCase);
            string normalized = channelSeparatorIndex >= 0 ? value[..channelSeparatorIndex] : value;
            return normalized.Trim();
        }


        private static Vector2 ResolveSyntheticTrackedUserPosition(float playerX, float playerY, int index)
        {
            float radiusX = 84f + ((index % 3) * 18f);
            float radiusY = 32f + ((index % 2) * 10f);
            float angle = MathHelper.ToRadians(-30f + ((index % 6) * 50f));
            return new Vector2(
                playerX + (float)Math.Cos(angle) * radiusX,
                playerY + (float)Math.Sin(angle) * radiusY);
        }


        private static MinimapUI.HelperMarkerType ResolveMinimapTrackedUserMarkerType(MinimapTrackedUserState state)
        {
            return ResolveMinimapTrackedUserMarkerTypeCore(
                state.IsTrader,
                state.IsMatchParticipant,
                state.IsPartyMember,
                state.IsPartyLeader,
                state.IsGuildMember,
                state.IsGuildLeader,
                state.IsFriend,
                state.IsCouplePartner,
                state.IsMarriedPartner,
                state.IsStalkTarget,
                state.BattlefieldTeamId);
        }

        internal static MinimapUI.HelperMarkerType ResolveMinimapTrackedUserMarkerTypeCore(
            bool isTrader,
            bool isMatchParticipant,
            bool isPartyMember,
            bool isPartyLeader,
            bool isGuildMember,
            bool isGuildLeader,
            bool isFriend,
            bool isCouplePartner,
            bool isMarriedPartner,
            bool isStalkTarget,
            int? battlefieldTeamId)
        {
            if (battlefieldTeamId.HasValue)
            {
                return MinimapUI.HelperMarkerType.Match;
            }

            if (isTrader)
            {
                return MinimapUI.HelperMarkerType.AnotherTrader;
            }

            if (isMatchParticipant)
            {
                return MinimapUI.HelperMarkerType.Match;
            }

            if (isPartyMember)
            {
                return isPartyLeader ? MinimapUI.HelperMarkerType.PartyMaster : MinimapUI.HelperMarkerType.Party;
            }

            if (isGuildMember)
            {
                return isGuildLeader ? MinimapUI.HelperMarkerType.GuildMaster : MinimapUI.HelperMarkerType.Guild;
            }

            if (isFriend
                || isCouplePartner
                || isMarriedPartner
                || isStalkTarget)
            {
                return MinimapUI.HelperMarkerType.Friend;
            }

            return MinimapUI.HelperMarkerType.Another;
        }



        private sealed class MinimapTrackedUserState
        {
            public MinimapTrackedUserState(string name)
            {
                Name = string.IsNullOrWhiteSpace(name) ? "Player" : name.Trim();
            }


            public string Name { get; }
            public bool IsFriend { get; set; }
            public bool IsPartyMember { get; set; }
            public bool IsPartyLeader { get; set; }
            public bool IsGuildMember { get; set; }
            public bool IsGuildLeader { get; set; }
            public bool IsMatchParticipant { get; set; }
            public bool IsTrader { get; set; }
            public bool IsCouplePartner { get; set; }
            public bool IsMarriedPartner { get; set; }
            public bool IsStalkTarget { get; set; }
            public int? BattlefieldTeamId { get; set; }
            public bool HasPosition { get; set; }
            public Vector2 Position { get; set; }
            public string TraderTooltipLabel { get; set; }
            public string MatchTooltipLabel { get; set; }
            public string RoomDetailTooltipLine { get; set; }
        }

        private void AppendPacketOwnedFieldTrackedUserMarkers(
            Dictionary<string, MinimapTrackedUserState> trackedUsers)
        {
            if (trackedUsers == null || _remoteUserPool.Count == 0)
            {
                return;
            }

            foreach (RemoteUserActor actor in _remoteUserPool.Actors)
            {
                if (actor == null
                    || !actor.IsVisibleInWorld
                    || actor.HiddenLikeClient
                    || string.IsNullOrWhiteSpace(actor.Name))
                {
                    continue;
                }

                MinimapTrackedUserState state = GetOrCreateMinimapTrackedUserState(trackedUsers, actor.Name);
                state.BattlefieldTeamId ??= actor.BattlefieldTeamId;
                if (!state.HasPosition)
                {
                    state.HasPosition = true;
                    state.Position = actor.Position;
                }
            }
        }

        private void AppendPacketOwnedRelationshipTrackedUserMarkers(
            Dictionary<string, MinimapTrackedUserState> trackedUsers)
        {
            if (trackedUsers == null || _remoteUserPool.Count == 0)
            {
                return;
            }

            foreach (RemoteUserActor actor in _remoteUserPool.Actors)
            {
                if (!ShouldIncludePacketOwnedRelationshipMinimapMarker(
                        actor?.IsVisibleInWorld == true,
                        actor?.HiddenLikeClient == true,
                        actor?.Name,
                        actor?.RelationshipOverlays?.Count ?? 0))
                {
                    continue;
                }

                bool hasFriendshipOverlay = actor.RelationshipOverlays.ContainsKey(RemoteRelationshipOverlayType.Friendship);
                bool hasCoupleOverlay = actor.RelationshipOverlays.ContainsKey(RemoteRelationshipOverlayType.Couple);
                bool hasMarriageOverlay = actor.RelationshipOverlays.ContainsKey(RemoteRelationshipOverlayType.Marriage);
                bool hasNewYearCardOverlay = actor.RelationshipOverlays.ContainsKey(RemoteRelationshipOverlayType.NewYearCard);
                if (!hasFriendshipOverlay && !hasCoupleOverlay && !hasMarriageOverlay && !hasNewYearCardOverlay)
                {
                    continue;
                }

                MinimapTrackedUserState state = GetOrCreateMinimapTrackedUserState(trackedUsers, actor.Name);
                state.IsFriend |= hasFriendshipOverlay || hasCoupleOverlay || hasMarriageOverlay || hasNewYearCardOverlay;
                state.IsCouplePartner |= hasCoupleOverlay;
                state.IsMarriedPartner |= hasMarriageOverlay;
                if (!state.HasPosition)
                {
                    state.HasPosition = true;
                    state.Position = actor.Position;
                }
            }
        }

        internal static bool ShouldIncludePacketOwnedRelationshipMinimapMarker(
            bool isVisibleInWorld,
            bool hiddenLikeClient,
            string actorName,
            int relationshipOverlayCount)
        {
            return isVisibleInWorld
                && !hiddenLikeClient
                && !string.IsNullOrWhiteSpace(actorName)
                && relationshipOverlayCount > 0;
        }


        private MinimapUI.HelperMarkerType? ResolveLocalPlayerMinimapHelperMarker()

        {

            if (HasActiveTraderFieldActor(SocialRoomKind.PersonalShop)
                || HasActiveTraderFieldActor(SocialRoomKind.EntrustedShop))
            {
                return MinimapUI.HelperMarkerType.UserTrader;
            }
            return _specialFieldRuntime?.Minigames.MemoryGame?.IsVisible == true
                ? MinimapUI.HelperMarkerType.Match
                : null;

        }

        private void AppendMiniRoomTrackedUserMarkers(
            Dictionary<string, MinimapTrackedUserState> trackedUsers,
            PlayerCharacter player)

        {
            if (!TryGetSocialRoomRuntime(SocialRoomKind.MiniRoom, out SocialRoomRuntime runtime)
                || runtime == null
                || runtime.Kind != SocialRoomKind.MiniRoom
                || !string.Equals(runtime.ModeName, "Match Cards", StringComparison.OrdinalIgnoreCase))
            {
                return;
            }

            MemoryGameField memoryGame = _specialFieldRuntime?.Minigames.MemoryGame;
            if (memoryGame == null || !memoryGame.IsVisible)
            {
                return;
            }

            string localName = player?.Build?.Name;
            HashSet<string> seededNames = new(StringComparer.OrdinalIgnoreCase);
            foreach (string participantName in memoryGame.PlayerNames)

            {

                if (string.IsNullOrWhiteSpace(participantName)
                    || string.Equals(participantName, localName, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                SocialRoomOccupant occupant = runtime.Occupants.FirstOrDefault(candidate =>
                    candidate != null
                    && string.Equals(candidate.Name, participantName, StringComparison.OrdinalIgnoreCase));
                if (TryAppendMiniRoomTrackedUserMarker(trackedUsers, runtime, player, occupant, participantName))
                {
                    seededNames.Add(participantName.Trim());
                }
            }

            foreach (SocialRoomOccupant occupant in runtime.Occupants)
            {
                if (occupant == null
                    || string.IsNullOrWhiteSpace(occupant.Name)
                    || string.Equals(occupant.Name, localName, StringComparison.OrdinalIgnoreCase)
                    || seededNames.Contains(occupant.Name.Trim()))
                {
                    continue;
                }

                if (TryAppendMiniRoomTrackedUserMarker(trackedUsers, runtime, player, occupant, occupant.Name))
                {
                    seededNames.Add(occupant.Name.Trim());
                }
            }

        }

        internal static bool ShouldSuppressSyntheticTrackedUserMarkerForPacketHelperState(
            bool isVisibleInWorld,
            bool hiddenLikeClient,
            bool hasPacketAuthoredHelperState)
        {
            return isVisibleInWorld
                && !hiddenLikeClient
                && hasPacketAuthoredHelperState;
        }

        internal static bool TryRecordPacketOwnedMinimapMarkerNameForSuppression(
            ISet<string> packetOwnedMarkerNames,
            string markerName)
        {
            if (packetOwnedMarkerNames == null || string.IsNullOrWhiteSpace(markerName))
            {
                return false;
            }

            return packetOwnedMarkerNames.Add(markerName.Trim());
        }

        private bool TryAppendMiniRoomTrackedUserMarker(
            Dictionary<string, MinimapTrackedUserState> trackedUsers,
            SocialRoomRuntime runtime,
            PlayerCharacter player,
            SocialRoomOccupant occupant,
            string occupantName)
        {
            if (!ShouldSeedSyntheticMinimapOccupantMarker(
                    SocialRoomKind.MiniRoom,
                    runtime,
                    hasDedicatedFieldActorMarker: false,
                    occupant,
                    occupantName))
            {
                return false;
            }

            MinimapTrackedUserState state = GetOrCreateMinimapTrackedUserState(trackedUsers, occupantName);
            state.IsMatchParticipant = true;
            ApplyMinimapSocialRoomOccupantTooltip(
                state,
                SocialRoomKind.MiniRoom,
                occupant);
            TryAssignTrackedUserPosition(state, occupantName);
            TryAssignSocialRoomTrackedUserPosition(
                state,
                SocialRoomKind.MiniRoom,
                runtime,
                occupant,
                player);
            return true;
        }

        private void AppendTraderTrackedUserMarkers(
            Dictionary<string, MinimapTrackedUserState> trackedUsers,
            PlayerCharacter player)

        {

            AppendTraderTrackedUserMarkers(SocialRoomKind.PersonalShop, trackedUsers, player);
            AppendTraderTrackedUserMarkers(SocialRoomKind.EntrustedShop, trackedUsers, player);

        }

        private void AppendTraderTrackedUserMarkers(
            SocialRoomKind kind,
            Dictionary<string, MinimapTrackedUserState> trackedUsers,
            PlayerCharacter player)

        {
            if (!TryGetSocialRoomRuntime(kind, out SocialRoomRuntime runtime))
            {
                return;
            }

            SocialRoomFieldActorSnapshot fieldActorSnapshot = runtime?.GetFieldActorSnapshot(DateTime.UtcNow);
            if (runtime == null)
            {
                return;
            }

            bool hasDedicatedFieldActorMarker = fieldActorSnapshot != null;
            string localName = player?.Build?.Name;
            foreach (SocialRoomOccupant occupant in runtime.Occupants)

            {

                if (occupant == null
                    || string.IsNullOrWhiteSpace(occupant.Name)
                    || string.Equals(occupant.Name, localName, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (!ShouldSeedSyntheticMinimapOccupantMarker(
                        kind,
                        runtime,
                        hasDedicatedFieldActorMarker,
                        occupant,
                        occupant.Name))
                {
                    continue;
                }

                MinimapTrackedUserState state = GetOrCreateMinimapTrackedUserState(trackedUsers, occupant.Name);
                state.IsTrader = true;
                ApplyMinimapSocialRoomOccupantTooltip(state, kind, occupant);
                TryAssignTrackedUserPosition(state, occupant.Name);
                TryAssignSocialRoomTrackedUserPosition(
                    state,
                    kind,
                    runtime,
                    occupant,
                    player,
                    fieldActorSnapshot);
            }
        }

        private bool ShouldSeedSyntheticMinimapOccupantMarker(
            SocialRoomKind kind,
            SocialRoomRuntime runtime,
            bool hasDedicatedFieldActorMarker,
            SocialRoomOccupant occupant,
            string occupantName)
        {
            if (string.IsNullOrWhiteSpace(occupantName))
            {
                return false;
            }

            bool isRepresentedByDedicatedFieldActor = IsTraderOccupantRepresentedByFieldActor(kind, runtime, occupant);
            bool hasEligibleMiniRoomOccupantRole = kind is not SocialRoomKind.MiniRoom
                || IsMiniRoomOccupantRoleEligibleForSyntheticHelper(occupant?.Role);
            bool hasEligibleTraderOccupantRole = kind is not SocialRoomKind.PersonalShop
                && kind is not SocialRoomKind.EntrustedShop
                || isRepresentedByDedicatedFieldActor;

            return ShouldSeedSyntheticMinimapOccupantMarkerForTesting(
                kind,
                HasVisibleRemoteTrackedUserActor(occupantName),
                hasDedicatedFieldActorMarker,
                isRepresentedByDedicatedFieldActor,
                _remoteUserPool.TryGetPosition(occupantName, out _),
                occupant?.AvatarBuild != null,
                occupant != null,
                hasEligibleMiniRoomOccupantRole,
                hasEligibleTraderOccupantRole);
        }

        internal static bool ShouldSeedSyntheticMinimapOccupantMarkerForTesting(
            SocialRoomKind kind,
            bool hasVisibleRemoteTrackedUserActor,
            bool hasDedicatedFieldActorMarker,
            bool isRepresentedByDedicatedFieldActor,
            bool hasRemotePosition,
            bool hasAvatarBuild,
            bool hasOccupant,
            bool hasEligibleMiniRoomOccupantRole,
            bool hasEligibleTraderOccupantRole)
        {
            if (kind is not SocialRoomKind.MiniRoom
                && kind is not SocialRoomKind.PersonalShop
                && kind is not SocialRoomKind.EntrustedShop)
            {
                return false;
            }

            // Client minimap hover ownership resolves trader markers through CEmployeePool,
            // so simulator-side tracked-user helper synthesis stays disabled for trader rooms.
            if (kind is SocialRoomKind.PersonalShop or SocialRoomKind.EntrustedShop)
            {
                return false;
            }

            // Owner-window-only names without an active room occupant should not
            // be promoted into synthetic minimap helper markers.
            if (!hasOccupant)
            {
                return false;
            }

            if (kind == SocialRoomKind.MiniRoom
                && !hasEligibleMiniRoomOccupantRole)
            {
                return false;
            }

            if (kind == SocialRoomKind.MiniRoom
                && !hasVisibleRemoteTrackedUserActor
                && !hasRemotePosition)
            {
                // Keep synthetic minimap helper seeding tied to live world evidence
                // instead of owner-window occupant snapshots.
                return false;
            }

            if (hasDedicatedFieldActorMarker && isRepresentedByDedicatedFieldActor)
            {
                return false;
            }

            if (hasVisibleRemoteTrackedUserActor)
            {
                return true;
            }

            if (hasRemotePosition)
            {
                return true;
            }

            return false;
        }

        internal static bool IsMiniRoomOccupantRoleEligibleForSyntheticHelper(
            SocialRoomOccupantRole? role)
        {
            return role is SocialRoomOccupantRole.Owner
                or SocialRoomOccupantRole.Guest;
        }

        private bool HasVisibleRemoteTrackedUserActor(string occupantName)
        {
            return !string.IsNullOrWhiteSpace(occupantName)
                && _remoteUserPool.TryGetActorByName(occupantName, out RemoteUserActor actor)
                && actor != null
                && actor.IsVisibleInWorld
                && !actor.HiddenLikeClient;
        }

        private static bool IsTraderOccupantRepresentedByFieldActor(
            SocialRoomKind kind,
            SocialRoomRuntime runtime,
            SocialRoomOccupant occupant)
        {
            if (runtime == null || occupant == null)
            {
                return false;
            }

            bool matchesOwnerName = !string.IsNullOrWhiteSpace(runtime.OwnerName)
                && string.Equals(occupant.Name, runtime.OwnerName, StringComparison.OrdinalIgnoreCase);
            return kind switch
            {
                SocialRoomKind.PersonalShop => occupant.Role == SocialRoomOccupantRole.Owner || matchesOwnerName,
                SocialRoomKind.EntrustedShop => occupant.Role is SocialRoomOccupantRole.Owner or SocialRoomOccupantRole.Merchant || matchesOwnerName,
                _ => false
            };
        }

        private SocialRoomRuntime GetSocialRoomRuntimeIfAvailable(SocialRoomKind kind)
        {
            string windowName = GetSocialRoomWindowName(kind);
            return string.IsNullOrWhiteSpace(windowName)
                ? null
                : (uiWindowManager?.GetWindow(windowName) as SocialRoomWindow)?.Runtime;
        }
        private bool HasActiveTraderFieldActor(SocialRoomKind kind)
        {
            SocialRoomRuntime runtime = GetSocialRoomRuntimeIfAvailable(kind);
            return runtime?.GetFieldActorSnapshot(DateTime.UtcNow) != null;

        }

        private static MinimapTrackedUserState GetOrCreateMinimapTrackedUserState(
            IDictionary<string, MinimapTrackedUserState> trackedUsers,
            string name)
        {
            if (!trackedUsers.TryGetValue(name, out MinimapTrackedUserState state))
            {
                state = new MinimapTrackedUserState(name);
                trackedUsers[name] = state;
            }
            return state;
        }
        private void TryAssignTrackedUserPosition(MinimapTrackedUserState state, string trackedName)
        {
            if (state == null || string.IsNullOrWhiteSpace(trackedName) || state.HasPosition)
            {
                return;
            }
            if (_remoteUserPool.TryGetPosition(trackedName, out Vector2 remotePosition))
            {
                state.HasPosition = true;
                state.Position = remotePosition;

            }

        }

        private void TryAssignSocialRoomTrackedUserPosition(
            MinimapTrackedUserState state,
            SocialRoomKind kind,
            SocialRoomRuntime runtime,
            SocialRoomOccupant occupant,
            PlayerCharacter player,
            SocialRoomFieldActorSnapshot fieldActorSnapshot = null)
        {
            if (state == null
                || state.HasPosition
                || runtime == null
                || occupant == null
                || player == null)
            {
                return;
            }

            if (!TryResolveSocialRoomTrackedUserPosition(kind, runtime, occupant, player, fieldActorSnapshot, out Vector2 position))
            {
                return;
            }

            state.HasPosition = true;
            state.Position = position;
        }

        private static bool TryResolveSocialRoomTrackedUserPosition(
            SocialRoomKind kind,
            SocialRoomRuntime runtime,
            SocialRoomOccupant occupant,
            PlayerCharacter player,
            SocialRoomFieldActorSnapshot fieldActorSnapshot,
            out Vector2 position)
        {
            position = Vector2.Zero;
            if (runtime == null || occupant == null || player == null)
            {
                return false;
            }

            Vector2 anchor = ResolveSocialRoomTrackedUserAnchorPosition(player, fieldActorSnapshot);
            Vector2 offset = kind switch
            {
                SocialRoomKind.MiniRoom => ResolveMiniRoomTrackedUserOffset(runtime, occupant),
                SocialRoomKind.PersonalShop => ResolveTraderTrackedUserOffset(runtime, occupant, hasDedicatedFieldActorMarker: fieldActorSnapshot != null),
                SocialRoomKind.EntrustedShop => ResolveTraderTrackedUserOffset(runtime, occupant, hasDedicatedFieldActorMarker: fieldActorSnapshot != null),
                _ => Vector2.Zero
            };

            if (offset == Vector2.Zero
                && kind is not SocialRoomKind.MiniRoom
                && fieldActorSnapshot == null
                && occupant.Role is SocialRoomOccupantRole.Owner or SocialRoomOccupantRole.Merchant)
            {
                return false;
            }

            position = anchor + offset;
            return true;
        }

        private static Vector2 ResolveSocialRoomTrackedUserAnchorPosition(
            PlayerCharacter player,
            SocialRoomFieldActorSnapshot fieldActorSnapshot)
        {
            if (player == null)
            {
                return Vector2.Zero;
            }

            if (fieldActorSnapshot == null)
            {
                return player.Position;
            }

            if (fieldActorSnapshot.HasWorldPosition && !fieldActorSnapshot.UseOwnerAnchor)
            {
                return new Vector2(fieldActorSnapshot.WorldX, fieldActorSnapshot.WorldY);
            }

            int horizontalOffset = player.FacingRight ? fieldActorSnapshot.AnchorOffsetX : -fieldActorSnapshot.AnchorOffsetX;
            return new Vector2(
                (float)Math.Round(player.Position.X) + horizontalOffset,
                (float)Math.Round(player.Position.Y) + fieldActorSnapshot.AnchorOffsetY);
        }

        private static Vector2 ResolveMiniRoomTrackedUserOffset(SocialRoomRuntime runtime, SocialRoomOccupant occupant)
        {
            int seatIndex = GetSocialRoomOccupantSeatIndex(runtime, occupant);
            return occupant.Role switch
            {
                SocialRoomOccupantRole.Owner => ResolveMiniRoomSeatOffset(0),
                SocialRoomOccupantRole.Guest => ResolveMiniRoomSeatOffset(Math.Max(1, seatIndex)),
                SocialRoomOccupantRole.Visitor => ResolveMiniRoomSeatOffset(Math.Max(2, seatIndex)),
                _ => ResolveDeterministicOccupantOffset(occupant.Name, radiusX: 72f, radiusY: 28f, verticalBias: 14f)
            };
        }

        private static Vector2 ResolveTraderTrackedUserOffset(
            SocialRoomRuntime runtime,
            SocialRoomOccupant occupant,
            bool hasDedicatedFieldActorMarker)
        {
            int buyerOrdinal = GetSocialRoomOccupantRoleOrdinal(runtime, occupant, SocialRoomOccupantRole.Buyer);
            int visitorOrdinal = GetSocialRoomOccupantRoleOrdinal(runtime, occupant, SocialRoomOccupantRole.Visitor);
            return occupant.Role switch
            {
                SocialRoomOccupantRole.Owner when !hasDedicatedFieldActorMarker => new Vector2(-34f, -10f),
                SocialRoomOccupantRole.Merchant when !hasDedicatedFieldActorMarker => new Vector2(34f, -10f),
                SocialRoomOccupantRole.Buyer => ResolveTraderBuyerOffset(buyerOrdinal, hasDedicatedFieldActorMarker),
                SocialRoomOccupantRole.Visitor => ResolveTraderVisitorOffset(visitorOrdinal, hasDedicatedFieldActorMarker),
                _ => ResolveDeterministicOccupantOffset(occupant.Name, radiusX: 62f, radiusY: 22f, verticalBias: 12f)
            };
        }

        private static Vector2 ResolveMiniRoomSeatOffset(int seatIndex)
        {
            return seatIndex switch
            {
                <= 0 => new Vector2(-90f, -18f),
                1 => new Vector2(90f, -18f),
                2 => new Vector2(-54f, 28f),
                3 => new Vector2(0f, 40f),
                4 => new Vector2(54f, 28f),
                5 => new Vector2(-86f, 54f),
                6 => new Vector2(86f, 54f),
                _ => ResolveMiniRoomOverflowSeatOffset(seatIndex)
            };
        }

        private static Vector2 ResolveMiniRoomOverflowSeatOffset(int seatIndex)
        {
            int overflowIndex = Math.Max(0, seatIndex - 7);
            int side = (overflowIndex % 2 == 0) ? -1 : 1;
            int row = overflowIndex / 2;
            return new Vector2(
                side * (52f + (row * 28f)),
                68f + (row * 12f));
        }

        private static Vector2 ResolveTraderBuyerOffset(int ordinal, bool hasDedicatedFieldActorMarker)
        {
            int clampedOrdinal = Math.Max(0, ordinal);
            if (hasDedicatedFieldActorMarker)
            {
                return clampedOrdinal switch
                {
                    0 => new Vector2(56f, -16f),
                    1 => new Vector2(-56f, -16f),
                    2 => new Vector2(82f, 6f),
                    3 => new Vector2(-82f, 6f),
                    _ => new Vector2(56f + (clampedOrdinal * 12f), 20f + ((clampedOrdinal - 4) * 6f))
                };
            }

            return clampedOrdinal switch
            {
                0 => new Vector2(52f, -12f),
                1 => new Vector2(72f, 8f),
                2 => new Vector2(44f, 24f),
                _ => new Vector2(60f + (clampedOrdinal * 14f), 16f + ((clampedOrdinal - 2) * 6f))
            };
        }

        private static Vector2 ResolveTraderVisitorOffset(int ordinal, bool hasDedicatedFieldActorMarker)
        {
            int clampedOrdinal = Math.Max(0, ordinal);
            if (hasDedicatedFieldActorMarker)
            {
                return clampedOrdinal switch
                {
                    0 => new Vector2(-34f, 18f),
                    1 => new Vector2(34f, 18f),
                    2 => new Vector2(-66f, 34f),
                    3 => new Vector2(66f, 34f),
                    _ => ResolveAlternatingVisitorOffset(clampedOrdinal, verticalBias: 30f)
                };
            }

            return clampedOrdinal switch
            {
                0 => new Vector2(-26f, 20f),
                1 => new Vector2(26f, 20f),
                2 => new Vector2(-54f, 34f),
                3 => new Vector2(54f, 34f),
                _ => ResolveAlternatingVisitorOffset(clampedOrdinal, verticalBias: 26f)
            };
        }

        private static Vector2 ResolveAlternatingVisitorOffset(int ordinal, float verticalBias)
        {
            int clampedOrdinal = Math.Max(0, ordinal);
            int side = (clampedOrdinal % 2 == 0) ? -1 : 1;
            int spreadStep = clampedOrdinal / 2;
            return new Vector2(
                side * (46f + (spreadStep * 24f)),
                verticalBias + ((clampedOrdinal % 3) * 6f));
        }

        private static Vector2 ResolveDeterministicOccupantOffset(
            string occupantName,
            float radiusX,
            float radiusY,
            float verticalBias)
        {
            int hash = ComputeStableMinimapNameHash(occupantName);
            float angle = MathHelper.ToRadians(-40f + (hash % 7) * 18f);
            return new Vector2(
                (float)Math.Cos(angle) * radiusX,
                verticalBias + ((float)Math.Sin(angle) * radiusY));
        }

        private static int GetSocialRoomOccupantRoleOrdinal(
            SocialRoomRuntime runtime,
            SocialRoomOccupant occupant,
            SocialRoomOccupantRole role)
        {
            if (runtime?.Occupants == null || occupant == null)
            {
                return 0;
            }

            int ordinal = 0;
            foreach (SocialRoomOccupant candidate in runtime.Occupants)
            {
                if (candidate == null || candidate.Role != role)
                {
                    continue;
                }

                if (ReferenceEquals(candidate, occupant)
                    || string.Equals(candidate.Name, occupant.Name, StringComparison.OrdinalIgnoreCase))
                {
                    return ordinal;
                }

                ordinal++;
            }

            return ordinal;
        }

        private static int GetSocialRoomOccupantSeatIndex(
            SocialRoomRuntime runtime,
            SocialRoomOccupant occupant)
        {
            if (runtime?.Occupants == null || occupant == null)
            {
                return -1;
            }

            for (int i = 0; i < runtime.Occupants.Count; i++)
            {
                SocialRoomOccupant candidate = runtime.Occupants[i];
                if (candidate == null)
                {
                    continue;
                }

                if (ReferenceEquals(candidate, occupant)
                    || string.Equals(candidate.Name, occupant.Name, StringComparison.OrdinalIgnoreCase))
                {
                    return i;
                }
            }

            return -1;
        }

        private static int ComputeStableMinimapNameHash(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return 0;
            }

            unchecked
            {
                int hash = 17;
                string normalized = value.Trim();
                for (int i = 0; i < normalized.Length; i++)
                {
                    hash = (hash * 31) + normalized[i];
                }

                return Math.Abs(hash);
            }
        }



        [MethodImpl(MethodImplOptions.AggressiveInlining)]
        private NpcItem FindNpcById(int npcId)
        {
            if (npcId <= 0)
            {
                return null;
            }


            return _npcsById.TryGetValue(npcId, out NpcItem npc) ? npc : null;

        }



        [MethodImpl(MethodImplOptions.AggressiveInlining)]
        private NpcItem FindNpcAtMapPoint(int mapX, int mapY)
        {
            if (_npcsArray == null)
                return null;


            NpcItem[] npcsToCheck = _visibleNpcs ?? _npcsArray;
            int npcCount = _visibleNpcs != null ? _visibleNpcsCount : _npcsArray.Length;
            for (int i = 0; i < npcCount; i++)
            {
                NpcItem npc = npcsToCheck[i];
                if (npc != null && npc.ContainsMapPoint(mapX, mapY))
                    return npc;
            }


            return null;

        }



        [MethodImpl(MethodImplOptions.AggressiveInlining)]
        private bool CanTalkToNpc(NpcItem npc)
        {
            if (!_gameState.IsPlayerInputEnabled || npc == null || _playerManager?.Player == null)
                return false;


            float deltaX = Math.Abs(_playerManager.Player.X - npc.CurrentX);
            float deltaY = Math.Abs(_playerManager.Player.Y - npc.CurrentY);
            return deltaX <= 180f && deltaY <= 120f;
        }


        /// <summary>
        /// Handles double-click on portals for map teleportation.
        /// When a portal with a valid target map is double-clicked, sets the target map ID and exits.
        /// Also supports hidden/invisible portals that have valid map destinations.
        /// </summary>
        /// <param name="mouseState">Current mouse state</param>
        [MethodImpl(MethodImplOptions.AggressiveInlining)]
        private void HandlePortalDoubleClick(MouseState mouseState)
        {
            // Skip if player input is blocked or a map change is already pending
            if (!_gameState.IsPlayerInputEnabled || _gameState.PendingMapChange)
                return;

            // UI windows and scripted overlays own the click when the cursor is over them.
            // Do not let portal double-click detection fall through to the world underneath.
            if (uiWindowManager?.ContainsPoint(mouseState.X, mouseState.Y) == true ||
                _npcInteractionOverlay?.ContainsPoint(mouseState.X, mouseState.Y, _renderParams.RenderWidth, _renderParams.RenderHeight) == true)
            {
                return;
            }


            // Check for left mouse button click (transition from pressed to released)
            bool isLeftClick = mouseState.LeftButton == ButtonState.Released && _oldMouseState.LeftButton == ButtonState.Pressed;
            if (!isLeftClick)
                return;


            // Calculate mouse position relative to map coordinates

            int mouseMapX = mouseState.X + mapShiftX - _mapBoard.CenterPoint.X;

            int mouseMapY = mouseState.Y + mapShiftY - _mapBoard.CenterPoint.Y;



            const int PORTAL_HIT_PADDING = 15;

            const int HIDDEN_PORTAL_HIT_SIZE = 30; // Default hit area for hidden portals



            // Find which visible portal was clicked (if any)
            PortalItem clickedPortal = null;
            for (int i = 0; i < _portalsArray.Length; i++)
            {
                PortalItem portal = _portalsArray[i];
                PortalInstance instance = portal.PortalInstance;


                // Calculate portal bounds (portals are centered on their position)
                int portalLeft = instance.X - instance.Width / 2;
                int portalRight = instance.X + instance.Width / 2;
                int portalTop = instance.Y - instance.Height;
                int portalBottom = instance.Y;


                // Expand hit area slightly for easier clicking
                if (mouseMapX >= portalLeft - PORTAL_HIT_PADDING &&
                    mouseMapX <= portalRight + PORTAL_HIT_PADDING &&
                    mouseMapY >= portalTop - PORTAL_HIT_PADDING &&
                    mouseMapY <= portalBottom + PORTAL_HIT_PADDING)
                {
                    clickedPortal = portal;
                    break;
                }
            }


            // If visible portal found, handle it
            if (clickedPortal != null)
            {
                int currentTime = currTickCount;
                if (_lastClickedPortal == clickedPortal && (currentTime - _lastClickTime) <= DOUBLE_CLICK_TIME_MS)
                {
                    // Double-click detected! Check if portal has a valid destination
                    int targetMapId = clickedPortal.PortalInstance.tm;
                    if (targetMapId != MapConstants.MaxMap && targetMapId > 0)
                    {
                        if (!CanQueueKnownCrossMapTransfer(targetMapId, showFailureMessage: true))
                        {
                            return;
                        }

                        PlayPortalSE();
                        QueueMapTransfer(
                            targetMapId,
                            clickedPortal.PortalInstance.tn,
                            targetPortalIndex: -1);
                        return;
                    }
                }


                // Record this click for potential double-click detection
                _lastClickedPortal = clickedPortal;
                _lastClickedHiddenPortal = null;
                _lastClickTime = currentTime;
                return;
            }


            // No visible portal found - check hidden portals from _mapBoard.BoardItems.Portals
            PortalInstance clickedHiddenPortal = null;
            foreach (var portal in _mapBoard.BoardItems.Portals)
            {
                // Only consider hidden portals with valid map destinations
                if (portal.tm <= 0 || portal.tm == MapConstants.MaxMap)
                    continue;


                // Use portal's range if available, otherwise use default hit area

                int halfWidth = portal.hRange ?? HIDDEN_PORTAL_HIT_SIZE / 2;

                int halfHeight = portal.vRange ?? HIDDEN_PORTAL_HIT_SIZE / 2;



                if (mouseMapX >= portal.X - halfWidth &&
                    mouseMapX <= portal.X + halfWidth &&
                    mouseMapY >= portal.Y - halfHeight &&
                    mouseMapY <= portal.Y + halfHeight)
                {
                    clickedHiddenPortal = portal;
                    break;
                }
            }


            if (clickedHiddenPortal != null)
            {
                int currentTime = currTickCount;
                if (_lastClickedHiddenPortal == clickedHiddenPortal && (currentTime - _lastClickTime) <= DOUBLE_CLICK_TIME_MS)
                {
                    // Double-click detected on hidden portal
                    if (!CanQueueKnownCrossMapTransfer(clickedHiddenPortal.tm, showFailureMessage: true))
                    {
                        return;
                    }

                    PlayPortalSE();
                    QueueMapTransfer(
                        clickedHiddenPortal.tm,
                        clickedHiddenPortal.tn,
                        targetPortalIndex: -1);
                    return;
                }


                // Record this click for potential double-click detection
                _lastClickedHiddenPortal = clickedHiddenPortal;
                _lastClickedPortal = null;
                _lastClickTime = currentTime;
                return;
            }


            // Clicked outside any portal, reset tracking
            _lastClickedPortal = null;
            _lastClickedHiddenPortal = null;
        }


