        private ReactorFootholdPlacement? ResolveClosestReactorFootholdPlacement(int worldX, int worldY)
        {
            IReadOnlyList<FootholdLine> footholds = _mapBoard?.BoardItems?.FootholdLines;
            if (footholds == null || footholds.Count == 0)
            {
                return null;
            }

            FootholdLine closest = null;
            double closestDistanceSq = double.MaxValue;
            for (int i = 0; i < footholds.Count; i++)
            {
                FootholdLine foothold = footholds[i];
                if (foothold?.FirstDot == null || foothold.SecondDot == null)
                {
                    continue;
                }

                double distanceSq = GetDistanceSquaredToFoothold(foothold, worldX, worldY);
                if (distanceSq < closestDistanceSq)
                {
                    closestDistanceSq = distanceSq;
                    closest = foothold;
                }
            }

            return closest == null
                ? null
                : new ReactorFootholdPlacement(closest.LayerNumber, closest.PlatformNumber);
        }

        private static double GetDistanceSquaredToFoothold(FootholdLine foothold, int x, int y)
        {
            double x1 = foothold.FirstDot.X;
            double y1 = foothold.FirstDot.Y;
            double x2 = foothold.SecondDot.X;
            double y2 = foothold.SecondDot.Y;
            double dx = x2 - x1;
            double dy = y2 - y1;

            if (Math.Abs(dx) < double.Epsilon && Math.Abs(dy) < double.Epsilon)
            {
                return GetDistanceSquared(x, y, x1, y1);
            }

            double t = ((x - x1) * dx + (y - y1) * dy) / ((dx * dx) + (dy * dy));
            t = Math.Max(0d, Math.Min(1d, t));
            double closestX = x1 + (t * dx);
            double closestY = y1 + (t * dy);
            return GetDistanceSquared(x, y, closestX, closestY);
        }

        private static double GetDistanceSquared(double x1, double y1, double x2, double y2)
        {
            double dx = x1 - x2;
            double dy = y1 - y2;
            return (dx * dx) + (dy * dy);
        }



        /// <summary>
        /// Spawn reactors at hidden portal positions.
        /// Uses the PortalPool to find hidden portals and spawns reactors at their locations.
        /// </summary>
        /// <param name="reactorId">Reactor ID to spawn</param>
        /// <returns>Number of reactors spawned</returns>
        public int SpawnReactorsAtHiddenPortals(string reactorId)
        {
            if (_portalPool == null || _reactorPool == null)
                return 0;


            int currentTick = Environment.TickCount;



            // Get all hidden portal positions
            var positions = new List<(float x, float y)>();
            for (int i = 0; i < _portalPool.PortalCount; i++)
            {
                if (_portalPool.IsHiddenPortal(i))
                {
                    var portal = _portalPool.GetPortal(i);
                    if (portal?.PortalInstance != null)
                    {
                        positions.Add((portal.PortalInstance.X, portal.PortalInstance.Y));
                    }
                }
            }


            if (positions.Count == 0)

                return 0;



            var spawnedIndices = _reactorPool.SpawnReactorsAtPositions(reactorId, positions, currentTick);

            return spawnedIndices.Count;

        }



        /// <summary>
        /// Spawn a reactor at a specific portal's position.
        /// </summary>
        /// <param name="portalName">Portal name (pn)</param>
        /// <param name="reactorId">Reactor ID to spawn</param>
        /// <returns>True if reactor was spawned</returns>
        public bool SpawnReactorAtPortal(string portalName, string reactorId)
        {
            if (_portalPool == null || _reactorPool == null)
                return false;


            var portal = _portalPool.GetPortalByName(portalName);

            if (portal?.PortalInstance == null)

                return false;



            int currentTick = Environment.TickCount;
            var positions = new List<(float x, float y)>
            {
                (portal.PortalInstance.X, portal.PortalInstance.Y)
            };


            var spawnedIndices = _reactorPool.SpawnReactorsAtPositions(reactorId, positions, currentTick);

            return spawnedIndices.Count > 0;

        }

        private void SyncMonsterCarnivalGuardianReactors(int currentTick)
        {
            if (_reactorPool == null)
            {
                return;
            }

            MonsterCarnivalField carnivalField = _specialFieldRuntime?.Minigames?.MonsterCarnival;
            if (carnivalField?.IsVisible != true)
            {
                ClearMonsterCarnivalGuardianReactors(currentTick);
                return;
            }

            foreach (KeyValuePair<int, int> tracked in _monsterCarnivalGuardianSlotToReactorIndex.ToArray())
            {
                if (carnivalField.GuardianPlacements.ContainsKey(tracked.Key))
                {
                    continue;
                }

                RemoveMonsterCarnivalGuardianReactor(tracked.Key, tracked.Value, currentTick);
            }

            foreach (KeyValuePair<int, MonsterCarnivalGuardianPlacement> placementEntry in carnivalField.GuardianPlacements)
            {
                if (_monsterCarnivalGuardianSlotToReactorIndex.ContainsKey(placementEntry.Key))
                {
                    continue;
                }

                MonsterCarnivalGuardianPlacement placement = placementEntry.Value;
                if (placement?.Entry == null || placement.ReactorId <= 0)
                {
                    continue;
                }

                List<int> spawnedIndices = _reactorPool.SpawnReactorsAtPositions(
                    placement.ReactorId.ToString(CultureInfo.InvariantCulture),
                    new List<(float x, float y)> { (placement.SpawnPoint.X, placement.SpawnPoint.Y) },
                    currentTick,
                    ReactorActivationType.Hit,
                    canRespawn: false,
                    namePrefix: $"mc_guardian_{placementEntry.Key}");
                if (spawnedIndices.Count <= 0)
                {
                    continue;
                }

                int reactorIndex = spawnedIndices[0];
                _monsterCarnivalGuardianSlotToReactorIndex[placementEntry.Key] = reactorIndex;
                _monsterCarnivalGuardianReactorIndexToSlot[reactorIndex] = placementEntry.Key;
                ReactorRuntimeData runtimeData = _reactorPool.GetReactorData(reactorIndex);
                if (runtimeData != null)
                {
                    runtimeData.RequiredHits = Math.Max(1, placement.ReactorRequiredHits);
                    runtimeData.HitCount = Math.Clamp(placement.ReactorHitCount, 0, runtimeData.RequiredHits);
                }

                RegisterDynamicReactorForRendering(reactorIndex);
            }
        }

        private void ClearMonsterCarnivalGuardianReactors(int currentTick)
        {
            foreach (KeyValuePair<int, int> tracked in _monsterCarnivalGuardianSlotToReactorIndex.ToArray())
            {
                RemoveMonsterCarnivalGuardianReactor(tracked.Key, tracked.Value, currentTick);
            }
        }

        private void RemoveMonsterCarnivalGuardianReactor(int slotIndex, int reactorIndex, int currentTick)
        {
            _monsterCarnivalGuardianSlotToReactorIndex.Remove(slotIndex);
            _monsterCarnivalGuardianReactorIndexToSlot.Remove(reactorIndex);
            _reactorPool?.DestroyReactor(reactorIndex, playerId: 0, currentTick);
        }

        private void TryReconcileMonsterCarnivalGuardianFromSpawnedReactor(ReactorItem reactor, int currentTick)
        {
            MonsterCarnivalField carnivalField = _specialFieldRuntime?.Minigames?.MonsterCarnival;
            MonsterCarnivalFieldDefinition definition = carnivalField?.Definition;
            if (carnivalField?.IsVisible != true || definition == null)
            {
                return;
            }

            if (!TryResolveReactorTemplateId(reactor, out int reactorTemplateId))
            {
                return;
            }

            int reactorRed = Math.Max(0, definition.ReactorRed);
            int reactorBlue = Math.Max(0, definition.ReactorBlue);
            if (reactorTemplateId != reactorRed && reactorTemplateId != reactorBlue)
            {
                return;
            }

            if (TryFindMonsterCarnivalGuardianSlot(reactor, out _))
            {
                return;
            }

            if (!TryGetReactorPoolIndex(reactor, out int reactorIndex))
            {
                return;
            }

            ReactorRuntimeData runtimeData = _reactorPool?.GetReactorData(reactorIndex);
            int defaultRequiredHits = reactorTemplateId == reactorRed
                ? Math.Max(1, definition.ReactorRedRequiredHits)
                : Math.Max(1, definition.ReactorBlueRequiredHits);
            int requiredHits = Math.Max(1, runtimeData?.RequiredHits ?? defaultRequiredHits);
            int hitCount = Math.Clamp(runtimeData?.HitCount ?? 0, 0, requiredHits);

            if (!carnivalField.TryReconcileLiveGuardianPlacement(
                    reactorTemplateId,
                    reactor.ReactorInstance.X,
                    reactor.ReactorInstance.Y,
                    reactor.ReactorInstance.Flip,
                    hitCount,
                    requiredHits,
                    out int slotIndex,
                    out string reconcileMessage))
            {
                return;
            }

            _monsterCarnivalGuardianSlotToReactorIndex[slotIndex] = reactorIndex;
            _monsterCarnivalGuardianReactorIndexToSlot[reactorIndex] = slotIndex;
            if (runtimeData != null
                && carnivalField.GuardianPlacements.TryGetValue(slotIndex, out MonsterCarnivalGuardianPlacement placement)
                && placement?.Entry != null)
            {
                runtimeData.RequiredHits = Math.Max(1, placement.ReactorRequiredHits);
                runtimeData.HitCount = Math.Clamp(placement.ReactorHitCount, 0, runtimeData.RequiredHits);
            }

            if (!string.IsNullOrWhiteSpace(reconcileMessage))
            {
                _chat?.AddMessage(reconcileMessage, new Color(255, 228, 151), currentTick);
            }
        }

        private bool TryResolveReactorTemplateId(ReactorItem reactor, out int reactorTemplateId)
        {
            reactorTemplateId = 0;
            string templateIdText = reactor?.ReactorInstance?.ReactorInfo?.ID;
            return !string.IsNullOrWhiteSpace(templateIdText)
                   && int.TryParse(templateIdText, NumberStyles.Integer, CultureInfo.InvariantCulture, out reactorTemplateId)
                   && reactorTemplateId > 0;
        }

        private bool TryGetReactorPoolIndex(ReactorItem reactor, out int reactorIndex)
        {
            reactorIndex = -1;
            IReadOnlyList<ReactorItem> reactors = _reactorPool?.Reactors;
            if (reactor == null || reactors == null || reactors.Count == 0)
            {
                return false;
            }

            for (int i = 0; i < reactors.Count; i++)
            {
                if (!ReferenceEquals(reactors[i], reactor))
                {
                    continue;
                }

                reactorIndex = i;
                return true;
            }

            return false;
        }

        private bool TryFindMonsterCarnivalGuardianSlot(ReactorItem reactor, out int slotIndex)
        {
            slotIndex = -1;
            if (reactor?.ReactorInstance == null)
            {
                return false;
            }

            foreach (KeyValuePair<int, int> tracked in _monsterCarnivalGuardianSlotToReactorIndex)
            {
                ReactorItem trackedReactor = _reactorPool?.GetReactor(tracked.Value);
                if (!ReferenceEquals(trackedReactor, reactor))
                {
                    continue;
                }

                slotIndex = tracked.Key;
                _monsterCarnivalGuardianReactorIndexToSlot[tracked.Value] = tracked.Key;
                return true;
            }

            return false;
        }

        private void ResolveMonsterCarnivalGuardianHitProgress(
            MonsterCarnivalField carnivalField,
            int slotIndex,
            int reactorIndex,
            bool destroyingPlacement,
            out int hitCount,
            out int requiredHits)
        {
            hitCount = destroyingPlacement ? 1 : 0;
            requiredHits = 1;

            MonsterCarnivalGuardianPlacement placement = null;
            if (carnivalField?.GuardianPlacements != null)
            {
                carnivalField.GuardianPlacements.TryGetValue(slotIndex, out placement);
            }

            if (placement != null)
            {
                requiredHits = Math.Max(1, placement.ReactorRequiredHits);
                hitCount = destroyingPlacement
                    ? Math.Max(requiredHits, placement.ReactorHitCount)
                    : Math.Max(1, placement.ReactorHitCount + 1);
            }

            ReactorRuntimeData runtimeData = reactorIndex >= 0 ? _reactorPool?.GetReactorData(reactorIndex) : null;
            if (runtimeData != null)
            {
                requiredHits = Math.Max(requiredHits, runtimeData.RequiredHits);
                if (destroyingPlacement)
                {
                    hitCount = Math.Max(requiredHits, Math.Max(hitCount, runtimeData.HitCount));
                }
                else if (runtimeData.HitCount > 0)
                {
                    hitCount = runtimeData.HitCount;
                }
            }

            requiredHits = Math.Max(1, requiredHits);
            hitCount = Math.Clamp(hitCount, 1, requiredHits);
        }

        private bool TryUseConsumableInventoryItemAtSlot(int itemId, InventoryType inventoryType, int slotIndex, int currentTime)
        {
            if (itemId <= 0 ||
                slotIndex < 0 ||
                uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryWindow)
            {
                return false;
            }

            IReadOnlyList<UI.InventorySlotData> slots = inventoryWindow.GetSlots(inventoryType);
            if (slots == null || slotIndex >= slots.Count)
            {
                return false;
            }

            UI.InventorySlotData slot = slots[slotIndex];
            if (slot == null || slot.IsDisabled || slot.ItemId != itemId || Math.Max(0, slot.Quantity) <= 0)
            {
                return false;
            }

            return TryUseConsumableInventoryItem(itemId, inventoryType, currentTime, slotIndex);
        }

        private void RegisterDynamicReactorForRendering(int reactorIndex)
        {
            ReactorItem reactor = _reactorPool?.GetReactor(reactorIndex);
            if (reactor == null || mapObjects_Reactors.Contains(reactor))
            {
                return;
            }

            mapObjects_Reactors.Add(reactor);
            _reactorsArray = mapObjects_Reactors.Cast<ReactorItem>().ToArray();
            _reactorVisibilityBuffer = new bool[_reactorsArray.Length];

            if (_visibleReactors == null || _visibleReactors.Length != _reactorsArray.Length)
            {
                _visibleReactors = new ReactorItem[_reactorsArray.Length];
            }

            InitializeSpatialPartitioning();
            RefreshMobRenderArray();
        }



        /// <summary>
        /// Refreshes the client-owned local reactor touch set.
        /// The main update loop owns this poll, matching CUserLocal::CheckReactor_Collision.
        /// </summary>
        /// <param name="playerX">Player X position</param>
        /// <param name="playerY">Player Y position</param>
        /// <param name="playerId">Player ID</param>
        /// <returns>List of currently-entered touched reactors</returns>
        public List<ReactorItem> CheckReactorTouch(float playerX, float playerY, int playerId = 0, int currentTick = int.MinValue)
        {
            if (_reactorPool == null)
                return new List<ReactorItem>();

            _ = playerId;


            if (currentTick == int.MinValue)

                currentTick = Environment.TickCount;



            // Match CUserLocal::CheckReactor_Collision, which only refreshes
            // local touch-reactor overlap once per second.
            if (!ShouldPollReactorCollision(currentTick, _lastReactorCollisionCheckTick))
                return new List<ReactorItem>();


            _lastReactorCollisionCheckTick = currentTick;

            List<ReactorTouchStateChange> touchStateChanges = _reactorPool.RefreshTouchReactorsAroundLocalUser(
                playerX,
                playerY,
                currentTick: currentTick);
            DispatchReactorTouchStateChanges(touchStateChanges, currentTick);
            return touchStateChanges
                .Where(change => change.IsTouching)
                .Select(change => change.Reactor)
                .Where(static reactor => reactor != null)
                .ToList();

        }

        internal static bool ShouldPollReactorCollision(int currentTick, int lastCheckTick)
        {
            return unchecked(currentTick - lastCheckTick) >= ReactorCollisionCheckIntervalMs;
        }

        private void DispatchReactorTouchStateChanges(IReadOnlyList<ReactorTouchStateChange> touchStateChanges, int currentTick = int.MinValue)
        {
            if (touchStateChanges == null || touchStateChanges.Count == 0)
            {
                return;
            }

            foreach (ReactorTouchStateChange change in touchStateChanges)
            {
                if (!change.UsesPacketObjectId || change.ObjectId <= 0)
                {
                    continue;
                }

                DispatchReactorTouchStateChange(change, currentTick);
            }
        }

        private void DispatchReactorTouchStateChange(ReactorTouchStateChange change, int currentTick = int.MinValue)
        {
            if (!change.UsesPacketObjectId || change.ObjectId <= 0)
            {
                return;
            }

            if (_reactorPoolOfficialSessionBridge?.HasConnectedSession == true
                && _reactorPoolOfficialSessionBridge.TrySendTouchRequest(change.ObjectId, change.IsTouching, out _, currentTick))
            {
                return;
            }

            if (_reactorPoolOfficialSessionBridge.TryQueueTouchRequest(change.ObjectId, change.IsTouching, out _, currentTick))
            {
                return;
            }

            if (_reactorTouchPacketOutbox.TrySendTouchRequest(change.ObjectId, change.IsTouching, out _, currentTick))
            {
                return;
            }

            _reactorTouchPacketOutbox.TryQueueTouchRequest(change.ObjectId, change.IsTouching, out _, currentTick);
        }



        private void TriggerAttackReactors(Rectangle worldHitbox, int currentTick, int skillId, int damage)
        {
            if (worldHitbox.Width <= 0 || worldHitbox.Height <= 0)
                return;


            CoconutField coconut = _specialFieldRuntime?.Minigames?.Coconut;
            bool coconutRuntimeActive = coconut?.IsActive == true;
            bool coconutHandledBasicActionAttack = false;
            bool coconutOwnsBasicActionLane = coconutRuntimeActive
                && coconut.ResolveLocalBasicActionOwnerActive(currentTick);

            if (coconutRuntimeActive)
            {

                bool officialSessionBridgeHasOwnership = HasCoconutOfficialSessionBridgeOwnership(
                    _coconutOfficialSessionBridge.HasConnectedSession,
                    _coconutOfficialSessionBridge.HasAttachedClient,
                    _coconutOfficialSessionBridge.HasPassiveEstablishedSocketPair);
                bool allowLocalPreview = ShouldAllowLocalCoconutAttackPreview(
                    officialSessionBridgeHasOwnership,
                    _coconutPacketInbox.HasConnectedClients);
                coconutHandledBasicActionAttack = coconut.TryHandleNormalAttack(
                    worldHitbox,
                    currentTick,
                    skillId: skillId,
                    allowLocalPreview: allowLocalPreview);
                if (coconutHandledBasicActionAttack)
                {
                    FlushPendingCoconutAttackRequests();
                    coconutOwnsBasicActionLane = coconut.ResolveLocalBasicActionOwnerActive(currentTick);
                }
            }

            if (ShouldConsumeSharedReactorAttackAfterCoconutBasicAction(coconutRuntimeActive, coconutOwnsBasicActionLane))
            {
                return;
            }


            if (_reactorPool == null)

                return;



            _reactorPool.TriggerSkillReactorsInBounds(
                worldHitbox,
                playerId: 0,
                currentTick: currentTick,
                skillId: skillId,
                damage: damage);
        }

        private void HandleLocalAttackAreaResolved(SkillManager.LocalAttackAreaResolution resolution)
        {
            UpsertLocalOwnedAffectedAreaFromAttack(
                resolution.WorldHitbox,
                resolution.CurrentTime,
                resolution.SkillId,
                resolution.OwnerLane);
        }

        internal static bool HasCoconutOfficialSessionBridgeOwnership(
            bool officialSessionBridgeHasConnectedSession,
            bool officialSessionBridgeHasAttachedClient,
            bool officialSessionBridgeHasPassiveEstablishedSocketPair)
        {
            return officialSessionBridgeHasConnectedSession
                || officialSessionBridgeHasAttachedClient
                || officialSessionBridgeHasPassiveEstablishedSocketPair;
        }

        internal static bool ShouldAllowLocalCoconutAttackPreview(
            bool officialSessionBridgeHasOwnership,
            bool transportHasConnectedClients)
        {
            return !officialSessionBridgeHasOwnership && !transportHasConnectedClients;
        }

        internal static bool ShouldFallbackCoconutAttackTransport(
            bool officialSessionBridgeHasOwnership)
        {
            return !officialSessionBridgeHasOwnership;
        }

        internal static bool ShouldConsumeSharedReactorAttackAfterCoconutBasicAction(
            bool coconutRuntimeActive,
            bool coconutOwnsBasicActionLane)
        {
            return coconutRuntimeActive && coconutOwnsBasicActionLane;
        }

        private void UpsertLocalOwnedAffectedAreaFromAttack(
            Rectangle worldHitbox,
            int currentTime,
            int skillId,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            if (_affectedAreaPool == null
                || worldHitbox.Width <= 0
                || worldHitbox.Height <= 0
                || !TryResolveLocalOwnedAffectedAreaRuntime(skillId, ownerLane, out SkillData skill, out SkillLevelData levelData, out int skillLevel))
            {
                return;
            }

            LocalOwnedAffectedAreaCreateMetadata createMetadata = ResolveLocalOwnedAffectedAreaCreateMetadata(
                skill,
                levelData,
                ownerLane);
            int objectId = ResolveLocalOwnedAffectedAreaObjectId(skillId);
            int ownerId = Math.Max(1, _playerManager?.Player?.Build?.Id ?? 0);
            bool upserted = _affectedAreaPool.Upsert(
                new AffectedAreaCreateInfo(
                    objectId,
                    type: createMetadata.Type,
                    ownerId,
                    skillId,
                    skillLevel,
                    worldHitbox,
                    startDelayUnits: createMetadata.StartDelayUnits,
                    elementAttribute: createMetadata.ElementAttribute,
                    phase: createMetadata.Phase,
                    AffectedAreaSourceKind.PlayerSkill,
                    durationOverrideMs: createMetadata.DurationOverrideMs),
                currentTime);
            if (!upserted)
            {
                return;
            }

            if (createMetadata.DurationOverrideMs <= 0
                && ResolveLocalOwnedAffectedAreaDurationSeconds(skill, levelData, skillLevel, ownerLane) <= 0)
            {
                _affectedAreaPool.Remove(objectId, currentTime);
            }
        }

        private bool TryResolveLocalOwnedAffectedAreaRuntime(
            int skillId,
            SkillManager.LocalAttackAreaOwnerLane ownerLane,
            out SkillData skill,
            out SkillLevelData levelData,
            out int skillLevel)
        {
            skill = null;
            levelData = null;
            skillLevel = 0;

            if (skillId <= 0 || _playerManager?.SkillLoader == null || _playerManager?.Skills == null)
            {
                return false;
            }

            skill = _playerManager.SkillLoader.LoadSkill(skillId);
            if (skill == null)
            {
                return false;
            }

            skillLevel = Math.Max(1, _playerManager.Skills.GetSkillLevel(skillId));
            levelData = RemoteAffectedAreaSupportResolver.ResolveRemoteAffectedAreaSkillLevel(
                skill,
                skillLevel,
                preferPvpLevelData: false);
            if (levelData == null
                && IsLocalAttackAreaExplicitOwnerBranch(ownerLane, skill.SkillId))
            {
                // Keep explicit local owner families alive even when authored level data is absent.
                levelData = new SkillLevelData();
            }

            return IsLocalOwnedAffectedAreaCandidate(skill, levelData, ownerLane);
        }

        internal static bool IsLocalOwnedAffectedAreaCandidate(
            SkillData skill,
            SkillLevelData levelData,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            if (skill == null
                || !IsSupportedLocalAttackAreaOwnerLane(ownerLane)
                || skill.Type == SkillType.Summon
                || IsClientSummonInfoType(skill.ClientInfoType)
                || string.Equals(skill.ZoneType, "invincible", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (IsKnownNonOwnerLocalAttackAffectedAreaSkillId(skill.SkillId))
            {
                return false;
            }

            if (IsClientExplicitLocalAttackAreaOwnerLaneMismatch(ownerLane, skill.SkillId))
            {
                return false;
            }

            bool hasExplicitOwnerBranch = IsLocalAttackAreaExplicitOwnerBranch(ownerLane, skill.SkillId);

            if (ownerLane == SkillManager.LocalAttackAreaOwnerLane.DoActiveSkillMesoExplosion)
            {
                return skill.IsMesoExplosion
                       || hasExplicitOwnerBranch;
            }

            if (ownerLane == SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack)
            {
                return IsClientBodyLaneAreaCompatible(skill);
            }

            if (!hasExplicitOwnerBranch && levelData == null)
            {
                return false;
            }

            bool hasAreaMetadata = HasLocalOwnedAffectedAreaMetadata(skill, levelData)
                                   || hasExplicitOwnerBranch;
            if (!hasAreaMetadata)
            {
                return false;
            }

            if (!hasExplicitOwnerBranch && Math.Max(0, skill.ClientInfoType) <= 0)
            {
                return false;
            }

            if (!IsLocalAttackAreaOwnerLaneCompatibleWithSkill(ownerLane, skill))
            {
                return false;
            }

            return skill.Type == SkillType.Attack
                   || skill.Type == SkillType.Magic
                   || skill.Type == SkillType.Debuff
                   || skill.IsMesoExplosion;
        }

        internal static bool IsSupportedLocalAttackAreaOwnerLane(SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            return ownerLane == SkillManager.LocalAttackAreaOwnerLane.TryDoingMeleeAttack
                   || ownerLane == SkillManager.LocalAttackAreaOwnerLane.TryDoingShootAttack
                   || ownerLane == SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack
                   || ownerLane == SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack
                   || ownerLane == SkillManager.LocalAttackAreaOwnerLane.DoActiveSkillMesoExplosion;
        }

        internal readonly record struct LocalOwnedAffectedAreaCreateMetadata(
            int Type,
            short StartDelayUnits,
            int ElementAttribute,
            int Phase,
            int DurationOverrideMs);

        internal static LocalOwnedAffectedAreaCreateMetadata ResolveLocalOwnedAffectedAreaCreateMetadata(
            SkillData skill,
            SkillLevelData levelData,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            int type = ResolveLocalOwnedAffectedAreaType(skill, ownerLane);
            int phase = ResolveLocalOwnedAffectedAreaPhase(skill, ownerLane);
            int elementAttribute = ResolveLocalOwnedAffectedAreaElementAttribute(skill);
            short startDelayUnits = ResolveLocalOwnedAffectedAreaStartDelayUnits(skill, levelData, ownerLane);
            int durationOverrideMs = ResolveLocalOwnedAffectedAreaDurationOverrideMs(skill, levelData, ownerLane);
            return new LocalOwnedAffectedAreaCreateMetadata(
                type,
                startDelayUnits,
                ElementAttribute: elementAttribute,
                Phase: phase,
                DurationOverrideMs: durationOverrideMs);
        }

        internal static int ResolveLocalOwnedAffectedAreaType(
            SkillData skill,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            if (skill == null)
            {
                return 0;
            }

            int authoredType = Math.Max(0, skill.ClientInfoType);
            if (authoredType > 0)
            {
                return authoredType;
            }

            return ResolveClientExplicitLocalOwnedAffectedAreaTypeFallback(skill.SkillId, ownerLane);
        }

        internal static int ResolveLocalOwnedAffectedAreaPhase(
            SkillData skill,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            if (skill == null)
            {
                return 0;
            }

            if (skill?.IsMesoExplosion == true)
            {
                return 1;
            }

            if (IsLocalAttackAreaExplicitOwnerBranch(ownerLane, skill.SkillId))
            {
                return 1;
            }

            return 0;
        }

        internal static short ResolveLocalOwnedAffectedAreaStartDelayUnits(
            SkillData skill,
            SkillLevelData levelData,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            if (ownerLane == SkillManager.LocalAttackAreaOwnerLane.DoActiveSkillMesoExplosion)
            {
                return 0;
            }

            if (ownerLane == SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack)
            {
                return 0;
            }

            int delayMs = Math.Max(0, skill?.ClientDelayMs ?? 0);
            if (delayMs <= 0)
            {
                delayMs = ResolveClientExplicitLocalOwnedAffectedAreaStartDelayMs(
                    skill?.SkillId ?? 0,
                    ownerLane);
            }

            int units = (delayMs + 99) / 100;
            return (short)Math.Clamp(units, 0, short.MaxValue);
        }

        internal static int ResolveLocalOwnedAffectedAreaElementAttribute(SkillData skill)
        {
            if (skill == null)
            {
                return 0;
            }

            int resolvedMask = ResolveLocalOwnedElementMaskFromSources(
                new[] { skill.ElementAttributeToken },
                out bool hasElementAttributeTokens);
            if (resolvedMask <= 0 && hasElementAttributeTokens)
            {
                resolvedMask = ResolveLocalOwnedElementMaskFromSources(
                    new[]
                    {
                        skill.DotType,
                        skill.AffectedSkillEffect,
                        skill.DebuffMessageToken
                    },
                    out _);
            }

            if (resolvedMask <= 0 && !hasElementAttributeTokens)
            {
                resolvedMask = ResolveLocalOwnedElementMaskFromSources(
                    new[]
                    {
                        skill.DotType,
                        skill.AffectedSkillEffect,
                        skill.DebuffMessageToken
                    },
                    out bool hasFallbackTokens);
                if (!hasFallbackTokens)
                {
                    return 0;
                }
            }

            if (resolvedMask <= 0)
            {
                return 0;
            }

            return NormalizeLocalOwnedElementMask(resolvedMask);
        }

        private static int ResolveLocalOwnedElementMaskFromSources(
            IEnumerable<string> tokenSources,
            out bool hasAnyTokenSource)
        {
            hasAnyTokenSource = false;
            int resolvedMask = 0;

            if (tokenSources == null)
            {
                return 0;
            }

            foreach (string source in tokenSources)
            {
                if (string.IsNullOrWhiteSpace(source))
                {
                    continue;
                }

                hasAnyTokenSource = true;
                string[] parts = source.Split(
                    new[] { ',', '|', '&', ' ', '/', '\\', ';', ':', '+', '(', ')', '[', ']', '{', '}', '-', '_' },
                    StringSplitOptions.RemoveEmptyEntries);
                if (parts.Length == 0)
                {
                    parts = new[] { source };
                }

                for (int partIndex = 0; partIndex < parts.Length; partIndex++)
                {
                    string part = parts[partIndex]?.Trim();
                    if (string.IsNullOrWhiteSpace(part))
                    {
                        continue;
                    }

                    if (TryResolveLocalOwnedElementToken(part, out int partMask))
                    {
                        resolvedMask |= partMask;
                        continue;
                    }

                    if (TryResolveCompactLocalOwnedElementToken(part, out int compactMask))
                    {
                        resolvedMask |= compactMask;
                    }
                }
            }

            return resolvedMask;
        }

        private const int LocalOwnedAffectedAreaSupportedElementMask = 1 | 2 | 4 | 8 | 16 | 32;

        private static int NormalizeLocalOwnedElementMask(int mask)
        {
            if (mask <= 0)
            {
                return 0;
            }

            return mask & LocalOwnedAffectedAreaSupportedElementMask;
        }

        private static bool IsLocalAttackAreaOwnerLaneCompatibleWithSkill(
            SkillManager.LocalAttackAreaOwnerLane ownerLane,
            SkillData skill)
        {
            return ownerLane switch
            {
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMeleeAttack =>
                    IsClientMeleeLaneAreaCompatible(skill),
                SkillManager.LocalAttackAreaOwnerLane.TryDoingShootAttack =>
                    IsClientShootLaneAreaCompatible(skill),
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack =>
                    IsClientMagicLaneAreaCompatible(skill),
                SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack =>
                    IsClientBodyLaneAreaCompatible(skill),
                _ => true
            };
        }

        private static bool HasLocalOwnedAffectedAreaMetadata(SkillData skill, SkillLevelData levelData)
        {
            if (skill == null)
            {
                return false;
            }

            return skill.IsMesoExplosion
                   || skill.AreaAttack
                   || !string.IsNullOrWhiteSpace(skill.AffectedSkillEffect)
                   || !string.IsNullOrWhiteSpace(skill.DotType)
                   || ResolveLocalOwnedAffectedAreaMetadataDurationSeconds(levelData) > 0
                   || !string.IsNullOrWhiteSpace(skill.ZoneType)
                   || skill.ZoneAnimation != null;
        }

        private static int ResolveLocalOwnedAffectedAreaMetadataDurationSeconds(SkillLevelData levelData)
        {
            return levelData == null
                ? 0
                : Math.Max(0, Math.Max(levelData.Time, levelData.DotTime));
        }

        private static bool IsClientMeleeLaneAreaCompatible(SkillData skill)
        {
            if (skill == null)
            {
                return false;
            }

            if (ClientShootAttackFamilyResolver.UsesClientShootAttackLane(skill.SkillId))
            {
                return false;
            }

            return skill.Projectile == null
                   && !skill.UsesAffectedSkillBodyAttack
                   && !ContainsBodyAttackMetadata(skill.AffectedSkillEffect)
                   && skill.AttackType != SkillAttackType.Ranged
                   && skill.AttackType != SkillAttackType.Magic
                   && !skill.IsMagicDamageSkill
                   && !IsClientShootInfoType(skill.ClientInfoType)
                   && !IsClientMagicInfoType(skill.ClientInfoType);
        }

        private static bool IsClientShootLaneAreaCompatible(SkillData skill)
        {
            if (skill == null)
            {
                return false;
            }

            if (IsClientShootLaneExplicitAreaSkillId(skill.SkillId))
            {
                return true;
            }

            if (IsClientMagicInfoType(skill.ClientInfoType)
                || skill.AttackType == SkillAttackType.Magic
                || skill.IsMagicDamageSkill
                || skill.UsesAffectedSkillBodyAttack
                || ContainsBodyAttackMetadata(skill.AffectedSkillEffect)
                || IsClientBodyInfoType(skill.ClientInfoType))
            {
                return false;
            }

            if (ClientShootAttackFamilyResolver.UsesClientShootAttackLane(skill.SkillId))
            {
                return true;
            }

            return skill.Projectile != null
                   || skill.AttackType == SkillAttackType.Ranged
                   || IsClientShootInfoType(skill.ClientInfoType);
        }

        private static bool IsClientMagicLaneAreaCompatible(SkillData skill)
        {
            if (skill == null)
            {
                return false;
            }

            if (IsClientMagicLaneExplicitAreaSkillId(skill.SkillId))
            {
                return true;
            }

            if (IsClientMagicLaneKnownNonOwnerAreaSkillId(skill.SkillId))
            {
                return false;
            }

            if (ClientShootAttackFamilyResolver.UsesClientShootAttackLane(skill.SkillId)
                || skill.Projectile != null
                || skill.AttackType == SkillAttackType.Ranged
                || IsClientShootInfoType(skill.ClientInfoType)
                || skill.UsesAffectedSkillBodyAttack
                || ContainsBodyAttackMetadata(skill.AffectedSkillEffect)
                || IsClientBodyInfoType(skill.ClientInfoType))
            {
                return false;
            }

            return skill.AttackType == SkillAttackType.Magic
                   || skill.IsMagicDamageSkill
                   || IsClientMagicInfoType(skill.ClientInfoType)
                   || (skill.ClientInfoType == 32 && skill.IsMassSpell);
        }

        private static bool IsClientBodyLaneAreaCompatible(SkillData skill)
        {
            if (skill == null)
            {
                return false;
            }

            if (IsClientBodyLaneExplicitAreaSkillId(skill.SkillId))
            {
                return true;
            }

            if (ClientShootAttackFamilyResolver.UsesClientShootAttackLane(skill.SkillId)
                || skill.Projectile != null
                || skill.AttackType == SkillAttackType.Ranged
                || IsClientShootInfoType(skill.ClientInfoType)
                || skill.AttackType == SkillAttackType.Magic
                || skill.IsMagicDamageSkill
                || IsClientMagicInfoType(skill.ClientInfoType))
            {
                return false;
            }

            return skill.UsesAffectedSkillBodyAttack
                   || ContainsBodyAttackMetadata(skill.AffectedSkillEffect)
                   || (skill.AreaAttack && IsClientBodyInfoType(skill.ClientInfoType));
        }

        private static bool IsLocalAttackAreaExplicitOwnerBranch(
            SkillManager.LocalAttackAreaOwnerLane ownerLane,
            int skillId)
        {
            return ownerLane switch
            {
                SkillManager.LocalAttackAreaOwnerLane.TryDoingShootAttack =>
                    IsClientShootLaneExplicitAreaSkillId(skillId),
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack =>
                    IsClientMagicLaneExplicitAreaSkillId(skillId),
                SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack =>
                    IsClientBodyLaneExplicitAreaSkillId(skillId),
                SkillManager.LocalAttackAreaOwnerLane.DoActiveSkillMesoExplosion =>
                    IsClientMesoExplosionLaneExplicitAreaSkillId(skillId),
                _ => false
            };
        }

        private static bool IsKnownNonOwnerLocalAttackAffectedAreaSkillId(int skillId)
        {
            // WZ + IDA corroborated non-owner neighbors around the local attack-owned area branch family.
            return skillId == 12111004
                   || skillId == 1321007
                   || skillId == 2121006
                   || skillId == 2221006
                   || skillId == 2301002
                   || skillId == 4221006
                   || skillId == 32121006;
        }

        private static bool IsClientShootLaneExplicitAreaSkillId(int skillId)
        {
            // IDA: TryDoingShootAttack still has explicit area/foothold ownership branches.
            return skillId == 3111003;
        }

        private static bool IsClientMagicLaneExplicitAreaSkillId(int skillId)
        {
            // IDA: TryDoingMagicAttack still gates local area ownership through explicit skill-id branches.
            // Local affected-area ownership branch table recovered from TryDoingMagicAttack area-owner path.
            return skillId == 12111003
                   || skillId == 12111005
                   || skillId == 2121007
                   || skillId == 2221001
                   || skillId == 2221007
                   || skillId == 2321008
                   || skillId == 22161001
                   || skillId == 22181002
                   || skillId == 32121004;
        }

        private static bool IsClientMagicLaneExplicitAreaDurationFallbackSkillId(int skillId)
        {
            // IDA: TryDoingMagicAttack explicit area-owner duration fallback branch only keeps
            // 12111003/2121007/2221007/2321008/32121004 on the tDuration assignment path when
            // authored duration resolves to zero; neighboring explicit owners dispatch separate
            // presentation-only branches.
            return skillId == 12111003
                   || skillId == 2121007
                   || skillId == 2221007
                   || skillId == 2321008
                   || skillId == 32121004;
        }

        private static bool IsClientMagicLaneKnownNonOwnerAreaSkillId(int skillId)
        {
            // IDA: TryDoingMagicAttack references these in neighboring branch tables, but they are
            // outside the local affected-area owner branch family guarded by CAffectedAreaPool flow.
            return skillId == 2121006
                   || skillId == 2221006
                   || skillId == 2301002;
        }

        internal static int ResolveClientExplicitLocalOwnedAffectedAreaTypeFallback(
            int skillId,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            // WZ-first fallback for explicit owner-branch skills when runtime skill metadata is incomplete.
            return ownerLane switch
            {
                SkillManager.LocalAttackAreaOwnerLane.TryDoingShootAttack when skillId == 3111003 => 2,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack when skillId == 12111005 => 4,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack when IsClientMagicLaneExplicitAreaSkillId(skillId) => 1,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack when skillId == 32121003 => 11,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack when IsClientTeleportMasterySkillId(skillId) => 16,
                SkillManager.LocalAttackAreaOwnerLane.DoActiveSkillMesoExplosion when skillId == 4211006 => 1,
                _ => 0
            };
        }

        private static bool IsClientExplicitLocalAttackAreaOwnerLaneMismatch(
            SkillManager.LocalAttackAreaOwnerLane ownerLane,
            int skillId)
        {
            SkillManager.LocalAttackAreaOwnerLane explicitLane = ResolveClientExplicitLocalAttackAreaOwnerLane(skillId);
            return explicitLane != SkillManager.LocalAttackAreaOwnerLane.None
                   && explicitLane != ownerLane;
        }

        private static SkillManager.LocalAttackAreaOwnerLane ResolveClientExplicitLocalAttackAreaOwnerLane(int skillId)
        {
            if (IsClientShootLaneExplicitAreaSkillId(skillId))
            {
                return SkillManager.LocalAttackAreaOwnerLane.TryDoingShootAttack;
            }

            if (IsClientMagicLaneExplicitAreaSkillId(skillId))
            {
                return SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack;
            }

            if (IsClientBodyLaneExplicitAreaSkillId(skillId))
            {
                return SkillManager.LocalAttackAreaOwnerLane.TryDoingBodyAttack;
            }

            if (IsClientMesoExplosionLaneExplicitAreaSkillId(skillId))
            {
                return SkillManager.LocalAttackAreaOwnerLane.DoActiveSkillMesoExplosion;
            }

            return SkillManager.LocalAttackAreaOwnerLane.None;
        }

        private static bool IsClientBodyLaneExplicitAreaSkillId(int skillId)
        {
            // IDA coverage for TryDoingBodyAttack includes explicit 32121003 and
            // `is_teleport_mastery_skill` ownership in the same lane.
            return skillId == 32121003
                   || IsClientTeleportMasterySkillId(skillId);
        }

        private static bool IsClientMesoExplosionLaneExplicitAreaSkillId(int skillId)
        {
            // IDA: DoActiveSkill_MesoExplosion is still the local owner for meso area lifecycle.
            return skillId == 4211006;
        }

        private static bool IsClientTeleportMasterySkillId(int skillId)
        {
            return skillId == 2111007
                   || skillId == 2211007
                   || skillId == 2311007
                   || skillId == 32111010;
        }

        private static bool ContainsBodyAttackMetadata(string affectedSkillEffect)
        {
            return !string.IsNullOrWhiteSpace(affectedSkillEffect)
                   && affectedSkillEffect.IndexOf("bodyAttack", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private static bool IsClientShootInfoType(int infoType)
        {
            return infoType == 2 || infoType == 52;
        }

        private static bool IsClientMagicInfoType(int infoType)
        {
            return infoType == 10;
        }

        private static bool IsClientBodyInfoType(int infoType)
        {
            return infoType == 1;
        }

        private static bool IsClientSummonInfoType(int infoType)
        {
            return infoType == 33;
        }

        private static bool TryResolveLocalOwnedElementToken(string token, out int mask)
        {
            if (int.TryParse(token, out int numericMask) && numericMask >= 0)
            {
                mask = numericMask;
                return true;
            }

            string trimmed = token?.Trim();
            if (!string.IsNullOrWhiteSpace(trimmed)
                && trimmed.StartsWith("0x", StringComparison.OrdinalIgnoreCase)
                && int.TryParse(trimmed.AsSpan(2), NumberStyles.AllowHexSpecifier, CultureInfo.InvariantCulture, out int hexMask)
                && hexMask >= 0)
            {
                mask = hexMask;
                return true;
            }

            mask = trimmed?.ToLowerInvariant() switch
            {
                "f" => 1,
                "fire" => 1,
                "burn" => 1,
                "blaze" => 1,
                "i" => 2,
                "ice" => 2,
                "cold" => 2,
                "freeze" => 2,
                "frost" => 2,
                "frostbite" => 2,
                "l" => 4,
                "lightning" => 4,
                "thunder" => 4,
                "s" => 8,
                "poison" => 8,
                "venom" => 8,
                "paralyze" => 8,
                "paralysis" => 8,
                "h" => 16,
                "holy" => 16,
                "sacred" => 16,
                "d" => 32,
                "dark" => 32,
                "shadow" => 32,
                _ => 0
            };

            return mask != 0;
        }

        private static bool TryResolveCompactLocalOwnedElementToken(string token, out int mask)
        {
            mask = 0;
            string compact = token?.Trim();
            if (string.IsNullOrWhiteSpace(compact) || compact.Length > 6)
            {
                return false;
            }

            for (int i = 0; i < compact.Length; i++)
            {
                if (!TryResolveLocalOwnedElementToken(compact[i].ToString(), out int charMask))
                {
                    return false;
                }

                mask |= charMask;
            }

            return mask != 0;
        }

        private int ResolveLocalOwnedAffectedAreaDurationSeconds(
            SkillData skill,
            SkillLevelData levelData,
            int skillLevel,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            if (skill == null || levelData == null)
            {
                return 0;
            }

            SkillLoader skillLoader = _playerManager?.SkillLoader;
            Func<int, SkillData> loadLinkedSkill = skillLoader == null
                ? null
                : skillId => skillLoader.LoadSkill(skillId);
            Func<SkillData, int, SkillLevelData> resolveLevelData = (linkedSkill, linkedSkillLevel) =>
                RemoteAffectedAreaSupportResolver.ResolveRemoteAffectedAreaSkillLevel(
                    linkedSkill,
                    linkedSkillLevel,
                    preferPvpLevelData: false);
            AffectedAreaPool.PlayerSkillAreaMetadata metadata = AffectedAreaPool.ResolvePlayerSkillAreaMetadata(
                skill,
                levelData,
                loadLinkedSkill,
                affectedSkillId => skillLoader?.FindAffectedSkillParentIds(affectedSkillId) ?? Array.Empty<int>(),
                dummySkillId => skillLoader?.FindDummySkillParentIds(dummySkillId) ?? Array.Empty<int>(),
                resolveLevelData,
                skillLevel);
            if (metadata.DurationSeconds > 0)
            {
                return metadata.DurationSeconds;
            }

            return ResolveClientExplicitLocalOwnedAffectedAreaDurationSeconds(skill.SkillId, ownerLane);
        }

        internal static int ResolveClientExplicitLocalOwnedAffectedAreaDurationSeconds(
            int skillId,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            int fallbackDurationMs = ResolveClientExplicitLocalOwnedAffectedAreaDurationOverrideMs(skillId, ownerLane);
            return fallbackDurationMs <= 0
                ? 0
                : (fallbackDurationMs + 999) / 1000;
        }

        internal static int ResolveClientExplicitLocalOwnedAffectedAreaDurationOverrideMs(
            int skillId,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            // IDA: TryDoingMagicAttack explicit area-owner fallback keeps mixed constants
            // (`3000` and `2760`) across the recovered magic branch subset.
            return ownerLane switch
            {
                SkillManager.LocalAttackAreaOwnerLane.TryDoingShootAttack when skillId == 3111003 => 1000,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack when skillId == 12111003 => 3000,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack when skillId == 2121007 => 3000,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack when skillId == 2221007 => 2760,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack when skillId == 2321008 => 2760,
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack when skillId == 32121004 => 2760,
                _ => 0
            };
        }

        internal static int ResolveClientExplicitLocalOwnedAffectedAreaStartDelayMs(
            int skillId,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            // IDA: TryDoingMagicAttack explicit foothold registration keeps a fixed `180` start-delay
            // on the recovered explicit-duration fallback branch subset when authored delay is absent.
            return ownerLane switch
            {
                SkillManager.LocalAttackAreaOwnerLane.TryDoingMagicAttack
                    when IsClientMagicLaneExplicitAreaDurationFallbackSkillId(skillId) => 180,
                _ => 0
            };
        }

        internal static int ResolveLocalOwnedAffectedAreaDurationOverrideMs(
            SkillData skill,
            SkillLevelData levelData,
            SkillManager.LocalAttackAreaOwnerLane ownerLane)
        {
            if (skill == null || ResolveLocalOwnedAffectedAreaMetadataDurationSeconds(levelData) > 0)
            {
                return 0;
            }

            return ResolveClientExplicitLocalOwnedAffectedAreaDurationOverrideMs(
                skill.SkillId,
                ownerLane);
        }

        private int ResolveLocalOwnedAffectedAreaObjectId(int skillId)
        {
            if (skillId <= 0)
            {
                return 0;
            }

            if (_localOwnedAffectedAreaObjectIdsBySkillId.TryGetValue(skillId, out int existingObjectId))
            {
                return existingObjectId;
            }

            if (_nextLocalOwnedAffectedAreaObjectId < LocalPlayerAffectedAreaObjectIdBase
                || _nextLocalOwnedAffectedAreaObjectId > LocalPlayerAffectedAreaObjectIdMax)
            {
                _nextLocalOwnedAffectedAreaObjectId = LocalPlayerAffectedAreaObjectIdBase;
            }

            int allocatedObjectId = _nextLocalOwnedAffectedAreaObjectId++;
            _localOwnedAffectedAreaObjectIdsBySkillId[skillId] = allocatedObjectId;
            return allocatedObjectId;
        }

        private void RemoveLocalOwnedAffectedAreasByCancelRequest(int requestedSkillId, int currentTime)
        {
            if (requestedSkillId <= 0
                || _affectedAreaPool == null
                || _localOwnedAffectedAreaObjectIdsBySkillId.Count == 0)
            {
                return;
            }

            SkillLoader skillLoader = _playerManager?.SkillLoader;
            IReadOnlyList<SkillData> skillCatalog = _playerManager?.Skills?.GetAllSkills()?.ToArray()
                ?? Array.Empty<SkillData>();
            List<int> removedSkillIds = null;

            foreach ((int activeSkillId, int objectId) in _localOwnedAffectedAreaObjectIdsBySkillId)
            {
                bool matchesCancelRequest = ClientSkillCancelResolver.DoesClientCancelMatchSkillId(
                    activeSkillId,
                    requestedSkillId,
                    skillId => skillLoader?.LoadSkill(skillId),
                    skillCatalog);
                if (!matchesCancelRequest)
                {
                    continue;
                }

                _affectedAreaPool.Remove(objectId, currentTime);
                removedSkillIds ??= new List<int>();
                removedSkillIds.Add(activeSkillId);
            }

            if (removedSkillIds == null)
            {
                return;
            }

            for (int i = 0; i < removedSkillIds.Count; i++)
            {
                _localOwnedAffectedAreaObjectIdsBySkillId.Remove(removedSkillIds[i]);
            }
        }


        private void UpdateReactorRuntime(int currentTick, float deltaSeconds)
        {
            if (_reactorPool == null)
                return;


            SyncMonsterCarnivalGuardianReactors(currentTick);
            _reactorPool.RefreshQuestReactors(currentTick);
            _reactorPool.Update(currentTick, deltaSeconds);

            if (_reactorsArray == null || _reactorsArray.Length == 0)
                return;


            if (_reactorVisibilityBuffer == null || _reactorVisibilityBuffer.Length != _reactorsArray.Length)
            {
                _reactorVisibilityBuffer = new bool[_reactorsArray.Length];
            }


            Array.Clear(_reactorVisibilityBuffer, 0, _reactorsArray.Length);
            foreach (var (reactor, index, alpha) in _reactorPool.GetRenderableReactors())
            {
                if (reactor == null || index < 0 || index >= _reactorsArray.Length)
                    continue;


                reactor.LayerAlpha = alpha;
                _reactorVisibilityBuffer[index] = true;



                var (state, _) = _reactorPool.GetReactorAnimationState(index);

                reactor.SetAnimationState(state, currentTick);

            }



            for (int i = 0; i < _reactorsArray.Length; i++)
            {
                ReactorItem reactor = _reactorsArray[i];
                if (reactor != null)
                {
                    reactor.SetVisible(_reactorVisibilityBuffer[i]);
                }
            }
        }


        /// <summary>
        /// Check for hidden portals near player and reveal them.
        /// </summary>
        /// <param name="playerX">Player X position</param>
        /// <param name="playerY">Player Y position</param>
        /// <returns>List of revealed hidden portals</returns>
        public List<PortalItem> CheckHiddenPortals(float playerX, float playerY)
        {
            if (_portalPool == null)
                return new List<PortalItem>();


            var hiddenPortals = _portalPool.FindPortal_Hidden(playerX, playerY);

            int currentTick = Environment.TickCount;



            foreach (var (portal, index) in hiddenPortals)
            {
                if (!_portalPool.IsHiddenPortalRevealed(index))
                {
                    _portalPool.SetHiddenPortal(index, false, currentTick); // Reveal
                }
            }


            return hiddenPortals.Select(t => t.portal).ToList();

        }



