        private void HandleSkillMacroClientForwardedFunctionKeyStateChanged(int functionKeyIndex, bool keyDown)
        {
            if (functionKeyIndex < 0 || functionKeyIndex >= SkillManager.FUNCTION_SLOT_COUNT)
            {
                return;
            }

            SkillManager skills = _playerManager?.Skills;
            if (skills == null)
            {
                return;
            }

            int hotkeySlot = SkillManager.FUNCTION_SLOT_OFFSET + functionKeyIndex;
            if (keyDown)
            {
                skills.TryCastHotkey(hotkeySlot, currTickCount);
            }
            else
            {
                skills.ReleaseHotkeyIfActive(hotkeySlot, currTickCount);
            }
        }

        private void HandleSkillMacroClientForwardedNonFunctionHotkeyStateChanged(int hotkeySlot, bool keyDown)
        {
            if (hotkeySlot < 0 || hotkeySlot >= SkillManager.TOTAL_SLOT_COUNT)
            {
                return;
            }

            SkillManager skills = _playerManager?.Skills;
            if (skills == null)
            {
                return;
            }

            if (keyDown)
            {
                skills.TryCastHotkey(hotkeySlot, currTickCount);
            }
            else
            {
                skills.ReleaseHotkeyIfActive(hotkeySlot, currTickCount);
            }
        }

        private void HandleSkillMacroClientForwardedNonFunctionPhysicalKeyStateChanged(
            Keys key,
            bool keyDown,
            bool controlHeld,
            bool shiftHeld,
            bool imeCompositionActive,
            bool imeCandidateWindowActive)
        {
            Func<InputAction, KeyBinding> bindingResolver = _playerManager?.Input != null
                ? _playerManager.Input.GetBinding
                : null;
            bool suppressImeOwnedForwarding = ShouldSuppressSkillMacroImeOwnedForwardedPhysicalKeyActionsForTesting(
                key,
                imeCompositionActive,
                imeCandidateWindowActive);
            HandleSkillMacroClientForwardedConfiguredNonFunctionHotkeyState(
                key,
                keyDown,
                controlHeld,
                suppressImeOwnedForwarding,
                bindingResolver);
            if (!keyDown)
            {
                return;
            }

            if (suppressImeOwnedForwarding)
            {
                return;
            }

            if (!TryResolveSkillMacroForwardedUtilityFunctionIdForTesting(
                    key,
                    bindingResolver,
                    out int clientFunctionId))
            {
                return;
            }

            TryDispatchPacketOwnedRawFunctionEntry(clientFunctionId, currTickCount);
        }

        private void HandleSkillMacroClientForwardedConfiguredNonFunctionHotkeyState(
            Keys key,
            bool keyDown,
            bool controlHeld,
            bool suppressImeOwnedForwarding,
            Func<InputAction, KeyBinding> bindingResolver)
        {
            if (key == Keys.None
                || SkillMacroOwnerKeyHandler.IsClientForwardedNonFunctionHotkeyPhysicalKey(key))
            {
                return;
            }

            if (keyDown)
            {
                if (suppressImeOwnedForwarding)
                {
                    _skillMacroImeSuppressedConfiguredHotkeyPhysicalKeys.Add(key);
                    return;
                }

                _skillMacroImeSuppressedConfiguredHotkeyPhysicalKeys.Remove(key);
                if (!TryResolveSkillMacroForwardedNonFunctionHotkeySlotForTesting(
                        key,
                        controlHeld,
                        bindingResolver,
                        out int hotkeySlot))
                {
                    return;
                }

                _skillMacroForwardedConfiguredHotkeySlotsByPhysicalKey[key] = hotkeySlot;
                HandleSkillMacroClientForwardedNonFunctionHotkeyStateChanged(hotkeySlot, keyDown: true);
                return;
            }

            if (_skillMacroImeSuppressedConfiguredHotkeyPhysicalKeys.Remove(key))
            {
                _skillMacroForwardedConfiguredHotkeySlotsByPhysicalKey.Remove(key);
                return;
            }

            if (_skillMacroForwardedConfiguredHotkeySlotsByPhysicalKey.TryGetValue(key, out int releasedHotkeySlot))
            {
                _skillMacroForwardedConfiguredHotkeySlotsByPhysicalKey.Remove(key);
                HandleSkillMacroClientForwardedNonFunctionHotkeyStateChanged(releasedHotkeySlot, keyDown: false);
                return;
            }

            if (TryResolveSkillMacroForwardedNonFunctionHotkeySlotForTesting(
                    key,
                    controlHeld,
                    bindingResolver,
                    out int fallbackHotkeySlot))
            {
                HandleSkillMacroClientForwardedNonFunctionHotkeyStateChanged(fallbackHotkeySlot, keyDown: false);
            }
        }

        internal static bool ShouldSuppressSkillMacroImeOwnedForwardedPhysicalKeyActionsForTesting(
            Keys key,
            bool imeCompositionActive,
            bool imeCandidateWindowActive)
        {
            return SkillMacroOwnerKeyHandler.ShouldSuppressConfiguredNonFunctionHotkeyForwarding(
                key,
                imeCompositionActive,
                imeCandidateWindowActive);
        }

        internal static bool TryResolveSkillMacroForwardedUtilityFunctionIdForTesting(
            Keys key,
            Func<InputAction, KeyBinding> bindingResolver,
            out int clientFunctionId)
        {
            clientFunctionId = -1;
            if (key == Keys.None || bindingResolver == null)
            {
                return false;
            }

            for (int i = 0; i < PacketOwnedKnownFunctionBindings.Length; i++)
            {
                (int candidateClientFunctionId, InputAction action) = PacketOwnedKnownFunctionBindings[i];
                if (ResolvePacketOwnedRawFunctionOwner(candidateClientFunctionId) == PacketOwnedRawFunctionOwner.None
                    && ResolvePacketOwnedRawChatOwner(candidateClientFunctionId) == PacketOwnedRawChatOwner.None)
                {
                    continue;
                }

                KeyBinding binding = bindingResolver(action);
                if (binding == null)
                {
                    continue;
                }

                if (binding.PrimaryKey == key || binding.SecondaryKey == key)
                {
                    clientFunctionId = candidateClientFunctionId;
                    return true;
                }
            }

            return false;
        }

        internal static bool TryResolveSkillMacroForwardedNonFunctionHotkeySlotForTesting(
            Keys key,
            bool controlHeld,
            Func<InputAction, KeyBinding> bindingResolver,
            out int hotkeySlot)
        {
            if (key == Keys.None)
            {
                hotkeySlot = -1;
                return false;
            }

            if (controlHeld
                && TryResolveSkillMacroForwardedConfiguredSlot(
                    key,
                    bindingResolver,
                    InputAction.CtrlSlot1,
                    SkillMacroOwnerKeyHandler.ClientForwardedCtrlSlotKeyCount,
                    SkillManager.CTRL_SLOT_OFFSET,
                    out hotkeySlot))
            {
                return true;
            }

            if (TryResolveSkillMacroForwardedConfiguredSlot(
                    key,
                    bindingResolver,
                    InputAction.Skill1,
                    SkillMacroOwnerKeyHandler.ClientForwardedPrimarySlotKeyCount,
                    slotOffset: 0,
                    out hotkeySlot))
            {
                return true;
            }

            return SkillMacroOwnerKeyHandler.TryResolveClientForwardedNonFunctionHotkeySlot(key, controlHeld, out hotkeySlot);
        }

        private static bool TryResolveSkillMacroForwardedConfiguredSlot(
            Keys key,
            Func<InputAction, KeyBinding> bindingResolver,
            InputAction startAction,
            int actionCount,
            int slotOffset,
            out int hotkeySlot)
        {
            hotkeySlot = -1;
            if (bindingResolver == null)
            {
                return false;
            }

            for (int i = 0; i < actionCount; i++)
            {
                InputAction action = startAction + i;
                KeyBinding binding = bindingResolver(action);
                if (binding == null)
                {
                    continue;
                }

                if (binding.PrimaryKey == key || binding.SecondaryKey == key)
                {
                    hotkeySlot = slotOffset + i;
                    return true;
                }
            }

            return false;
        }

