            return _mesoAnimFrames[DropPool.GetMoneyIconTypeForAmount(amount)];

        }

        private static void ApplyMinimapSocialRoomOccupantTooltip(
            MinimapTrackedUserState state,
            SocialRoomKind kind,
            SocialRoomOccupant occupant)
        {
            if (state == null || occupant == null)
            {
                return;
            }

            switch (kind)
            {
                case SocialRoomKind.MiniRoom:
                    state.MatchTooltipLabel = occupant.Role switch
                    {
                        SocialRoomOccupantRole.Owner => "Match Cards host",
                        SocialRoomOccupantRole.Guest => "Match Cards guest",
                        SocialRoomOccupantRole.Visitor => "Match Cards visitor",
                        _ => "Match Cards participant"
                    };
                    break;
                case SocialRoomKind.PersonalShop:
                    state.TraderTooltipLabel = occupant.Role switch
                    {
                        SocialRoomOccupantRole.Owner => "Personal shop owner",
                        SocialRoomOccupantRole.Buyer => "Personal shop buyer",
                        SocialRoomOccupantRole.Visitor => "Personal shop visitor",
                        _ => "Personal shop trader"
                    };
                    break;
                case SocialRoomKind.EntrustedShop:
                    state.TraderTooltipLabel = occupant.Role switch
                    {
                        SocialRoomOccupantRole.Merchant => "Entrusted shop merchant",
                        SocialRoomOccupantRole.Owner => "Entrusted shop owner",
                        SocialRoomOccupantRole.Buyer => "Entrusted shop buyer",
                        SocialRoomOccupantRole.Visitor => "Entrusted shop visitor",
                        _ => "Entrusted shop trader"
                    };
                    break;
            }

            if (!string.IsNullOrWhiteSpace(occupant.Detail))
            {
                MergeMinimapTooltipDetailLine(state, occupant.Detail);
            }
        }

        private void ApplyMesoAnimationsToDropPool()
        {
            if (_dropPool == null || _mesoAnimFrames == null)
            {
                return;
            }

            for (int i = 0; i < _mesoAnimFrames.Length; i++)
            {
                _dropPool.SetMesoAnimationFrames(i, _mesoAnimFrames[i]);
            }
        }



        private void SpawnMobDeathRewards(MobItem mob, int currentTick)
        {
            if (mob?.MovementInfo == null || _dropPool == null)
            {
                return;
            }

            if (!ShouldSpawnSimulatorOwnedMobDeathDrops(_mapBoard?.MapInfo))
            {
                return;
            }

            float mobX = mob.MovementInfo.X;

            float mobY = mob.MovementInfo.Y;

            bool isBoss = mob.AI?.IsBoss ?? false;



            int mesoMin = isBoss ? 1000 : 10;

            int mesoMaxExclusive = isBoss ? 10000 : 500;

            int mesoAmount = Random.Shared.Next(mesoMin, mesoMaxExclusive);
            int supportDropRatePercent = _playerManager?.Skills?.GetActiveDropRatePercent(currentTick) ?? 0;
            int supportMesoRatePercent = _playerManager?.Skills?.GetActiveMesoRatePercent(currentTick) ?? 0;
            mesoAmount = MobStatusRewardParity.ResolveMesoAmount(mob, mesoAmount, supportMesoRatePercent);


            DropItem mesoDrop = _dropPool.SpawnMesoDrop(mobX, mobY, mesoAmount, currentTick);
            if (mesoDrop == null)
            {
                return;
            }

            int killedMobId = 0;
            if (mob?.MobInstance?.MobInfo != null)
            {
                int.TryParse(mob.MobInstance.MobInfo.ID, out killedMobId);
            }

            int monsterCardItemId = 0;
            if (killedMobId > 0
                && _monsterBookManager.TryResolveRewardItemIds(killedMobId, out IReadOnlyList<int> rewardItemIds))
            {
                int rewardIdentitySeed = mob?.PoolId > 0
                    ? mob.PoolId
                    : killedMobId;
                int rewardItemId = MobStatusRewardParity.ResolveStableAuthoredRewardItemId(
                    rewardIdentitySeed,
                    rewardItemIds);
                if (rewardItemId > 0)
                {
                    int rewardQuantity = MobStatusRewardParity.ResolveDropItemQuantity(mob, rewardItemId, 1, supportDropRatePercent);
                    _dropPool.SpawnItemDrop(
                        mobX - 18f,
                        mobY,
                        rewardItemId.ToString(CultureInfo.InvariantCulture),
                        rewardQuantity,
                        currentTick,
                        isRare: true);
                }
            }

            if (killedMobId > 0
                && _monsterBookManager.TryResolveCardItemId(killedMobId, out monsterCardItemId))
            {
                int recentPacketDropAgeMs = ResolvePacketDropEnterAgeMs(currentTick, _dropPool?.LastPacketEnterAppliedTime ?? int.MinValue);
                if (ShouldSuppressSimulatorOwnedMonsterCardDropFallback(
                    recentPacketDropAgeMs,
                    _dropPool?.ActiveDrops,
                    monsterCardItemId))
                {
                    return;
                }

                if (_monsterBookManager.TryResolveCardDropProbabilityPercent(killedMobId, out int probabilityPercent)
                    && !ShouldSpawnSimulatorOwnedMonsterCardDropFromCatalogProb(probabilityPercent))
                {
                    return;
                }

                // Item/Consume/0238.img card entries are only=1 consume-on-pickup records, so keep
                // simulator-authored Monster Card drops single-count as the fallback path while packet-
                // owned drop enters keep ownership when they are active.
                const int cardQuantity = 1;
                _dropPool.SpawnItemDrop(
                    mobX + 18f,
                    mobY,
                    monsterCardItemId.ToString(CultureInfo.InvariantCulture),
                    cardQuantity,
                    currentTick,
                    isRare: true);
            }

        }

        internal static bool ShouldSpawnSimulatorOwnedMobDeathDrops(MapInfo mapInfo)
        {
            return FieldInteractionRestrictionEvaluator.CanSpawnDrops(mapInfo?.fieldLimit ?? 0);
        }

        internal static int ResolvePacketDropEnterAgeMs(int currentTick, int lastPacketEnterTick)
        {
            if (lastPacketEnterTick == int.MinValue)
            {
                return -1;
            }

            int elapsed = unchecked(currentTick - lastPacketEnterTick);
            return elapsed < 0 ? -1 : elapsed;
        }

        internal static bool ShouldSuppressSimulatorOwnedMonsterCardDropFallback(int recentPacketDropAgeMs)
        {
            const int packetDropSuppressionWindowMs = 2200;
            return recentPacketDropAgeMs >= 0
                && recentPacketDropAgeMs <= packetDropSuppressionWindowMs;
        }

        internal static bool HasActivePacketOwnedMonsterCardDrop(
            IReadOnlyList<DropItem> activeDrops,
            int cardItemId)
        {
            if (activeDrops == null
                || activeDrops.Count <= 0
                || cardItemId <= 0)
            {
                return false;
            }

            for (int i = 0; i < activeDrops.Count; i++)
            {
                DropItem drop = activeDrops[i];
                if (drop == null
                    || !drop.IsPacketControlled
                    || drop.Type != DropType.Item
                    || !IsSameMonsterCardItemId(drop.ItemId, cardItemId)
                    || drop.State == DropState.Expired
                    || drop.State == DropState.Removed)
                {
                    continue;
                }

                return true;
            }

            return false;
        }

        private static bool IsSameMonsterCardItemId(string dropItemId, int cardItemId)
        {
            if (cardItemId <= 0 || string.IsNullOrWhiteSpace(dropItemId))
            {
                return false;
            }

            string normalizedDropItemId = dropItemId.Trim();
            if (int.TryParse(normalizedDropItemId, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedItemId))
            {
                return parsedItemId == cardItemId;
            }

            return string.Equals(normalizedDropItemId, cardItemId.ToString(CultureInfo.InvariantCulture), StringComparison.Ordinal)
                || string.Equals(normalizedDropItemId, cardItemId.ToString("D8", CultureInfo.InvariantCulture), StringComparison.Ordinal);
        }

        internal readonly struct CharacterInfoSocialRoomPresenceSnapshot
        {
            public CharacterInfoSocialRoomPresenceSnapshot(
                SocialRoomKind kind,
                bool isVisible,
                string ownerName,
                IReadOnlyList<string> occupantNames,
                string modeName)
            {
                Kind = kind;
                IsVisible = isVisible;
                OwnerName = ownerName ?? string.Empty;
                OccupantNames = occupantNames ?? Array.Empty<string>();
                ModeName = modeName ?? string.Empty;
            }

            public SocialRoomKind Kind { get; }
            public bool IsVisible { get; }
            public string OwnerName { get; }
            public IReadOnlyList<string> OccupantNames { get; }
            public string ModeName { get; }
        }

        private IReadOnlyList<CharacterInfoSocialRoomPresenceSnapshot> BuildCharacterInfoActiveSocialRoomPresenceSnapshots()
        {
            List<CharacterInfoSocialRoomPresenceSnapshot> snapshots = new(4);
            SocialRoomKind[] kinds =
            {
                SocialRoomKind.MiniRoom,
                SocialRoomKind.TradingRoom,
                SocialRoomKind.PersonalShop,
                SocialRoomKind.EntrustedShop
            };

            foreach (SocialRoomKind kind in kinds)
            {
                if (!TryGetSocialRoomRuntime(kind, out SocialRoomRuntime runtime) || runtime == null)
                {
                    continue;
                }

                string windowName = GetSocialRoomWindowName(kind);
                bool isVisible = !string.IsNullOrWhiteSpace(windowName)
                    && uiWindowManager?.GetWindow(windowName)?.IsVisible == true;
                IReadOnlyList<string> occupantNames = runtime.Occupants
                    .Where(occupant => occupant != null && !string.IsNullOrWhiteSpace(occupant.Name))
                    .Select(occupant => occupant.Name.Trim())
                    .ToArray();
                snapshots.Add(new CharacterInfoSocialRoomPresenceSnapshot(
                    kind,
                    isVisible,
                    runtime.OwnerName,
                    occupantNames,
                    runtime.ModeName));
            }

            return snapshots;
        }

        internal static bool TryResolveCharacterInfoPresenceFromSocialRoomSnapshots(
            string characterName,
            IReadOnlyList<CharacterInfoSocialRoomPresenceSnapshot> snapshots,
            string currentMapDisplayName,
            int currentChannel,
            out string locationSummary,
            out int channel)
        {
            locationSummary = string.IsNullOrWhiteSpace(currentMapDisplayName)
                ? "Location unknown"
                : currentMapDisplayName.Trim();
            channel = currentChannel > 0 ? currentChannel : 1;
            if (snapshots == null || snapshots.Count <= 0 || string.IsNullOrWhiteSpace(characterName))
            {
                return false;
            }

            string resolvedName = characterName.Trim();
            for (int i = 0; i < snapshots.Count; i++)
            {
                CharacterInfoSocialRoomPresenceSnapshot snapshot = snapshots[i];
                if (!snapshot.IsVisible || !HasCharacterInfoSocialRoomNameMatch(snapshot, resolvedName))
                {
                    continue;
                }

                locationSummary = BuildCharacterInfoSocialRoomPresenceLocation(
                    currentMapDisplayName,
                    snapshot.Kind,
                    snapshot.ModeName);
                return true;
            }

            return false;
        }

        private static bool HasCharacterInfoSocialRoomNameMatch(CharacterInfoSocialRoomPresenceSnapshot snapshot, string resolvedName)
        {
            if (string.IsNullOrWhiteSpace(resolvedName))
            {
                return false;
            }

            if (string.Equals(snapshot.OwnerName?.Trim(), resolvedName, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            IReadOnlyList<string> occupantNames = snapshot.OccupantNames;
            if (occupantNames == null || occupantNames.Count <= 0)
            {
                return false;
            }

            for (int i = 0; i < occupantNames.Count; i++)
            {
                if (string.Equals(occupantNames[i]?.Trim(), resolvedName, StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }
            }

            return false;
        }

        internal static string BuildCharacterInfoSocialRoomPresenceLocation(
            string currentMapDisplayName,
            SocialRoomKind kind,
            string modeName)
        {
            string roomLabel = kind switch
            {
                SocialRoomKind.MiniRoom when !string.IsNullOrWhiteSpace(modeName) => $"{modeName.Trim()} room",
                SocialRoomKind.MiniRoom => "Mini-room",
                SocialRoomKind.PersonalShop => "Personal shop",
                SocialRoomKind.EntrustedShop => "Entrusted shop",
                SocialRoomKind.TradingRoom => "Trading room",
                _ => "Social room"
            };

            string mapLabel = string.IsNullOrWhiteSpace(currentMapDisplayName)
                ? "Location unknown"
                : currentMapDisplayName.Trim();
            return $"{mapLabel} ({roomLabel})";
        }

        internal static bool ShouldSuppressSimulatorOwnedMonsterCardDropFallback(
            int recentPacketDropAgeMs,
            IReadOnlyList<DropItem> activeDrops,
            int cardItemId)
        {
            return HasActivePacketOwnedMonsterCardDrop(activeDrops, cardItemId)
                || ShouldSuppressSimulatorOwnedMonsterCardDropFallback(recentPacketDropAgeMs);
        }

