        private void AwardMobKillExperience(MobItem mob)
        {
            var build = _playerManager?.Player?.Build;
            if (build == null)
            {
                return;
            }

            int currentTime = Environment.TickCount;
            int supportExperienceRatePercent = _playerManager?.Skills?.GetActiveExperienceRatePercent(currentTime) ?? 0;
            int expReward = MobStatusRewardParity.ResolveKillExperience(mob, supportExperienceRatePercent);
            expReward = _playerManager.AdjustMobAffectedExperienceReward(expReward, currentTime);
            if (expReward <= 0)
            {
                return;
            }

            build.Exp += expReward;
        }



        /// <summary>
        /// Loads tombstone animation from Effect.wz/Tomb.img
        /// fall/0..19 - falling animation
        /// land/0 - final resting frame (UOL to fall/19)
        /// </summary>
        private void LoadTombstoneAnimation()
        {
            _tombFallFrames = new List<IDXObject>();
            _tombLandFrame = null;


            var tombImage = Program.FindImage("Effect", "Tomb.img");
            if (tombImage == null)
            {
                System.Diagnostics.Debug.WriteLine("[LoadTombstoneAnimation] Effect.wz/Tomb.img not found");
                return;
            }


            // Load fall animation frames (0..19)
            var fallProperty = tombImage["fall"] as WzSubProperty;
            if (fallProperty != null)
            {
                for (int i = 0; i < 20; i++)
                {
                    WzObject frameProperty = fallProperty[i.ToString()];
                    if (frameProperty == null) break;


                    // Resolve UOL if necessary
                    if (frameProperty is WzUOLProperty uol)
                    {
                        frameProperty = uol.LinkValue;
                    }


                    if (frameProperty is WzCanvasProperty canvas)
                    {
                        var bitmap = canvas.GetLinkedWzCanvasBitmap();
                        if (bitmap != null)
                        {
                            var texture = bitmap.ToTexture2D(GraphicsDevice);
                            if (texture != null)
                            {
                                var origin = canvas["origin"] as WzVectorProperty;
                                int ox = origin?.X?.Value ?? texture.Width / 2;
                                int oy = origin?.Y?.Value ?? texture.Height;
                                int delay = (canvas["delay"] as WzIntProperty)?.Value ?? 100;


                                _tombFallFrames.Add(new DXObject(-ox, -oy, texture, delay));
                            }
                        }
                    }
                }
            }


            // Load land frame (0 - typically UOL to fall/19)
            var landProperty = tombImage["land"] as WzSubProperty;
            if (landProperty != null)
            {
                WzObject landFrame = landProperty["0"];
                if (landFrame != null)
                {
                    // Resolve UOL if necessary
                    if (landFrame is WzUOLProperty uol)
                    {
                        landFrame = uol.LinkValue;
                    }


                    if (landFrame is WzCanvasProperty canvas)
                    {
                        var bitmap = canvas.GetLinkedWzCanvasBitmap();
                        if (bitmap != null)
                        {
                            var texture = bitmap.ToTexture2D(GraphicsDevice);
                            if (texture != null)
                            {
                                var origin = canvas["origin"] as WzVectorProperty;
                                int ox = origin?.X?.Value ?? texture.Width / 2;
                                int oy = origin?.Y?.Value ?? texture.Height;
                                int delay = 0; // Static frame


                                _tombLandFrame = new DXObject(-ox, -oy, texture, delay);
                            }
                        }
                    }
                }
            }


            // Fallback: if land frame not loaded but we have fall frames, use last fall frame
            if (_tombLandFrame == null && _tombFallFrames.Count > 0)
            {
                _tombLandFrame = _tombFallFrames[_tombFallFrames.Count - 1];
            }


            System.Diagnostics.Debug.WriteLine($"[LoadTombstoneAnimation] Loaded {_tombFallFrames.Count} fall frames, land frame: {(_tombLandFrame != null ? "yes" : "no")}");

        }



        /// <summary>
        /// Handles UP key press near portals for map teleportation.
        /// When the player presses UP while standing near a portal with a valid target map,
        /// triggers teleportation the same way as double-clicking the portal.
        /// </summary>
        [MethodImpl(MethodImplOptions.AggressiveInlining)]
        private void HandlePortalUpInteract(int currentTime)
        {
            if (ShouldCancelPassiveTransferFieldRequestFromHorizontalKeyDown())
            {
                ClearPassiveTransferRequest();
            }

            PassiveTransferFieldReadinessEvaluator.QueuedRetryDecision queuedRetryDecision =
                EvaluatePassiveTransferFieldQueuedRetryDecision(currentTime);

            if (queuedRetryDecision == PassiveTransferFieldReadinessEvaluator.QueuedRetryDecision.ReplayHandleUpKeyDown)
            {
                PassiveTransferFieldReplayState replayState = ResolvePassiveTransferFieldReplayState(currentTime);
                bool canAttemptHandleUpKeyDownReplay =
                    PassiveTransferFieldReadinessEvaluator.CanAttemptHandleUpKeyDownReplay(replayState);
                bool canReplayHandleUpKeyDown =
                    PassiveTransferFieldReadinessEvaluator.CanReplayHandleUpKeyDown(replayState);

                if (PassiveTransferFieldReadinessEvaluator.ShouldStopSkillMacroForQueuedReplay(canAttemptHandleUpKeyDownReplay))
                {
                    StopSkillMacroForHandleUpKeyDown();
                }

                if (canReplayHandleUpKeyDown)
                {
                    TryHandlePortalInteractCore(currentTime);
                }

                ClearPassiveTransferRequest();
                return;
            }

            if (queuedRetryDecision == PassiveTransferFieldReadinessEvaluator.QueuedRetryDecision.Clear)
            {
                ClearPassiveTransferRequest();
            }

            if (!CanAttemptPortalInteract(currentTime))
            {
                return;
            }


            bool interactPressed = _playerManager.IsInteractPressedForWorldInput();

            if (!interactPressed)

                return;

            if (!PassiveTransferFieldReadinessEvaluator.CanHandleFreshUpKeyDown(_localFollowRuntime.HasAttachedDriver))
            {
                return;
            }

            StopSkillMacroForHandleUpKeyDown();

            if (ShouldHandleFreshUpKeyDownAsChairGetUp(_playerManager?.Player))
            {
                if (PassiveTransferFieldReadinessEvaluator.ShouldClearQueuedRetryOnChairGetUp(
                        _passiveTransferRequestPending,
                        consumedChairGetUpBranch: true))
                {
                    ClearPassiveTransferRequest();
                }

                _playerManager?.Player?.ApplyPacketOwnedChairStandCorrection();
                return;
            }


            if (CanReplayPassiveTransferFieldUpKeyPath(currentTime) && _playerManager.Player?.CanMove == true)
            {
                if (TryHandlePortalInteractCore(currentTime))
                {
                    ClearPassiveTransferRequest();
                }


                return;

            }



            if (!ShouldQueuePassiveTransferFieldRequest())
            {
                return;
            }

            _passiveTransferRequestPending = true;
        }

        private void StopSkillMacroForHandleUpKeyDown()
        {
            _playerManager?.Skills?.ClearSkillQueue();
        }



        private bool CanAttemptPortalInteract(int currentTime)
        {
            return !_gameState.PendingMapChange
                   && !_sameMapTeleportPending
                   && !IsPacketOwnedTeleportRegistrationCoolingDown(currentTime)
                   && _gameState.IsPlayerInputEnabled
                   && _playerManager != null
                   && _playerManager.IsPlayerActive;
        }


        private void ClearPassiveTransferRequest()
        {
            _passiveTransferRequestPending = false;
        }

        private void ConsumePassiveTransferRequestFromTransferLifecycle()
        {
            if (!_passiveTransferRequestPending)
            {
                return;
            }

            ClearPassiveTransferRequest();
        }

        private bool ShouldCancelPassiveTransferFieldRequestFromHorizontalKeyDown()
        {
            PlayerInput input = _playerManager?.Input;
            if (input == null)
            {
                return false;
            }

            return ShouldCancelPassiveTransferFieldRequestFromHorizontalKeyDown(
                input,
                _passiveTransferRequestPending);
        }

        internal static bool ShouldCancelPassiveTransferFieldRequestFromHorizontalKeyDown(
            PlayerInput input,
            bool hasPendingRequest)
        {
            if (input == null)
            {
                return false;
            }

            return PassiveTransferFieldReadinessEvaluator.ShouldCancelQueuedRetryOnHorizontalKeyDown(
                hasPendingRequest,
                input.IsPressed(InputAction.MoveLeft),
                input.IsPressed(InputAction.MoveRight));
        }

        internal static bool ShouldHandleFreshUpKeyDownAsChairGetUp(PlayerCharacter player)
        {
            return player?.State == PlayerState.Sitting;
        }

        private PassiveTransferFieldReadinessEvaluator.QueuedRetryDecision EvaluatePassiveTransferFieldQueuedRetryDecision(int currentTime)
        {
            PlayerCharacter player = _playerManager?.Player;
            bool hasActiveOneTimeAction = HasActivePassiveTransferFieldOneTimeAction(player);
            bool hasLiveFieldInterface = HasPassiveTransferFieldInterface();
            PassiveTransferFieldInterfaceGateState interfaceGateState =
                ResolvePassiveTransferFieldInterfaceGateState(currentTime, hasLiveFieldInterface);
            bool hasCollidingTransferPortal = HasPassiveTransferFieldPortalCollision();
            return PassiveTransferFieldReadinessEvaluator.EvaluateQueuedRetryDecision(
                new PassiveTransferFieldQueuedRetryDecisionState(
                    HasPendingRequest: _passiveTransferRequestPending,
                    HasOneTimeActionCompleted: !hasActiveOneTimeAction,
                    HasReadyFieldInterface: !hasActiveOneTimeAction
                                            && ResolvePassiveTransferFieldQueuedRetryInterfaceGateState(interfaceGateState),
                    HasCollidingTransferPortal: hasCollidingTransferPortal,
                    HasLiveFieldInterface: hasLiveFieldInterface,
                    HasPendingMapChange: _gameState.PendingMapChange,
                    HasBoundPlayer: player != null,
                    IsPlayerActive: _playerManager?.IsPlayerActive == true));
        }

        private bool ResolvePassiveTransferFieldQueuedRetryInterfaceGateState(PassiveTransferFieldInterfaceGateState interfaceGateState)
        {
            return PassiveTransferFieldReadinessEvaluator.CanAdmitQueuedRetryInterfaceGate(interfaceGateState);
        }

        private bool ResolvePassiveTransferFieldReadyState(int currentTime, bool requirePortalCollision = true)
        {
            bool hasLiveFieldInterface = HasPassiveTransferFieldInterface();
            return PassiveTransferFieldReadinessEvaluator.CanRetryFromLiveFieldInterface(
                new PassiveTransferFieldInterfaceState(
                    HasLiveFieldInterface: hasLiveFieldInterface,
                    HasCollidingTransferPortal: !requirePortalCollision || HasPassiveTransferFieldPortalCollision(),
                    HasActiveVectorControl: _playerManager?.IsPlayerActive == true,
                    HasPendingMapChange: _gameState.PendingMapChange,
                    HasPlayerInputControl: _gameState.IsPlayerInputEnabled,
                    HasStandAloneControlOwner: _gameState.StandAloneModeActive,
                    AllowsTransferField: ResolvePassiveTransferFieldRuntimeTransferAllowance(),
                    HasPendingSpecialTransfer: _specialFieldRuntime.HasPendingTransfer,
                    HasPendingPacketOwnedTransfer: HasPendingPassiveTransferFieldPacketTransferOwnership(),
                    HasPacketOwnedTeleportRegistrationCoolingDown: IsPacketOwnedTeleportRegistrationCoolingDown(currentTime),
                    HasPendingExclusiveTransferRequest: HasPendingExclusiveTransferRequest(currentTime),
                    HasAttachedPacketOwnedDriver: _localFollowRuntime.HasAttachedDriver,
                    HasPendingSameMapTransfer: _sameMapTeleportPending,
                    HasBlockingScriptedSequence: _specialFieldRuntime.HasBlockingScriptedSequence));
        }

        private PassiveTransferFieldInterfaceGateState ResolvePassiveTransferFieldInterfaceGateState(
            int currentTime,
            bool? hasLiveFieldInterfaceOverride = null)
        {
            return new PassiveTransferFieldInterfaceGateState(
                HasLiveFieldInterface: hasLiveFieldInterfaceOverride ?? HasPassiveTransferFieldInterface(),
                HasPendingMapChange: _gameState.PendingMapChange,
                HasPlayerInputControl: _gameState.IsPlayerInputEnabled,
                HasStandAloneControlOwner: _gameState.StandAloneModeActive,
                AllowsTransferField: ResolvePassiveTransferFieldRuntimeTransferAllowance(),
                HasPendingSpecialTransfer: _specialFieldRuntime.HasPendingTransfer,
                HasPendingPacketOwnedTransfer: HasPendingPassiveTransferFieldPacketTransferOwnership(),
                HasPacketOwnedTeleportRegistrationCoolingDown: IsPacketOwnedTeleportRegistrationCoolingDown(currentTime),
                HasPendingExclusiveTransferRequest: HasPendingExclusiveTransferRequest(currentTime),
                HasAttachedPacketOwnedDriver: _localFollowRuntime.HasAttachedDriver,
                HasPendingSameMapTransfer: _sameMapTeleportPending,
                HasBlockingScriptedSequence: _specialFieldRuntime.HasBlockingScriptedSequence);
        }

