        }

        private bool HasPassiveTransferFieldPortalCollision()
        {
            PortalCollisionResult? collision = ResolvePortalCollisionAtLocalUserPosition();
            PortalInstance portal = collision?.Portal?.PortalInstance;
            if (portal == null)
            {
                return false;
            }

            if (!IsPassiveTransferFieldPortalType(portal.pt))
            {
                return false;
            }

            return IsPassiveTransferFieldPortalCandidate(portal.tm);
        }

        private static bool IsPassiveTransferFieldPortalType(PortalType portalType)
        {
            return portalType != PortalType.CollisionScript
                   && portalType != PortalType.CollisionVerticalJump
                   && portalType != PortalType.CollisionCustomImpact;
        }

        internal static bool IsPassiveTransferFieldPortalCandidate(int targetMapId)
        {
            return targetMapId > 0
                   && targetMapId != MapConstants.MaxMap;
        }

        private static bool IsChangeablePortalType(PortalType portalType)
        {
            return portalType == PortalType.Changeable
                   || portalType == PortalType.ChangeableInvisible;
        }

        internal static bool ShouldSendTransferFieldRequestForPortal(
            int targetMapId,
            int currentMapId,
            PortalType portalType)
        {
            return targetMapId > 0
                   && targetMapId != MapConstants.MaxMap
                   && (targetMapId != currentMapId || IsChangeablePortalType(portalType));
        }

        internal static bool ShouldPlayTransferFieldPortalSound(PortalType portalType)
        {
            return !IsChangeablePortalType(portalType);
        }


        private bool TryHandlePortalInteractCore(int currentTime)
        {
            // Central local owner for portal collision parity. This mirrors
            // the client seam where `CUserLocal::CheckPortal_Collision`
            // resolves the colliding portal first and then branches by portal type.
            // Get player position
            var playerPos = _playerManager.GetPlayerPosition();
            float playerX = playerPos.X;
            float playerY = playerPos.Y;
            long fieldLimit = _mapBoard?.MapInfo?.fieldLimit ?? 0;


            if (_gameState.IsPortalOnCooldown(currentTime))

                return false;



            if (_temporaryPortalField != null
                && _temporaryPortalField.TryUseLinkedPortal(_mapBoard.MapInfo.id, playerX, playerY, out var temporaryPortalDestination))
            {
                string temporaryTargetPortalName = null;
                string temporaryTargetResolutionSummary = "temporary portal destination coordinates";
                string[] temporaryTargetPortalNameCandidates = Array.Empty<string>();
                int temporaryTargetPortalIndex = -1;
                if (temporaryPortalDestination.MapId == _mapBoard.MapInfo.id)
                {
                    if (TryResolvePacketOwnedTeleportPortalByPosition(
                        temporaryPortalDestination.X,
                        temporaryPortalDestination.Y,
                        out int resolvedTemporarySameMapTargetPortalIndex,
                        out PortalInstance resolvedTemporaryTargetPortal))
                    {
                        temporaryTargetPortalName = resolvedTemporaryTargetPortal.pn;
                        temporaryTargetPortalIndex = resolvedTemporarySameMapTargetPortalIndex;
                        temporaryTargetResolutionSummary = $"current-field portal '{temporaryTargetPortalName}'";
                    }
                }
                else if (TryResolvePacketOwnedTargetPortalMetadata(
                    temporaryPortalDestination.MapId,
                    temporaryPortalDestination.X,
                    temporaryPortalDestination.Y,
                    _mapBoard.MapInfo.id,
                    null,
                    out string resolvedTemporaryCrossMapTargetPortalName,
                    out string resolvedTemporaryCrossMapTargetSummary,
                    out string[] resolvedTemporaryCrossMapTargetCandidates,
                    out int resolvedTemporaryCrossMapTargetPortalIndex))
                {
                    temporaryTargetPortalName = resolvedTemporaryCrossMapTargetPortalName;
                    temporaryTargetResolutionSummary = resolvedTemporaryCrossMapTargetSummary;
                    temporaryTargetPortalNameCandidates = resolvedTemporaryCrossMapTargetCandidates;
                    temporaryTargetPortalIndex = resolvedTemporaryCrossMapTargetPortalIndex;
                }

                TryResolvePacketOwnedTemporarySourcePortal(
                    temporaryPortalDestination.MapId,
                    temporaryPortalDestination.SourceX,
                    temporaryPortalDestination.SourceY,
                    temporaryPortalDestination.X,
                    temporaryPortalDestination.Y,
                    temporaryTargetPortalName,
                    temporaryTargetPortalNameCandidates,
                    out PortalInstance temporarySourcePortal,
                    out string temporarySourcePortalName,
                    out string[] temporarySourcePortalNameCandidates);

                IEnumerable<PortalInstance> temporaryTargetFieldPortals = temporaryPortalDestination.MapId == _mapBoard.MapInfo.id
                    ? _mapBoard?.BoardItems?.Portals
                    : _loadMapCallback?.Invoke(temporaryPortalDestination.MapId)?.Item1?.BoardItems?.Portals;
                if (string.IsNullOrWhiteSpace(temporaryTargetPortalName)
                    && temporarySourcePortalNameCandidates.Length > 0
                    && TryResolvePacketOwnedTargetPortalMetadataFromSourcePortalCandidates(
                        _mapBoard?.BoardItems?.Portals,
                        temporaryTargetFieldPortals,
                        _mapBoard.MapInfo.id,
                        temporaryPortalDestination.MapId,
                        temporarySourcePortalNameCandidates,
                        temporaryPortalDestination.X,
                        temporaryPortalDestination.Y,
                        out string recoveredTemporaryTargetPortalName,
                        out string[] recoveredTemporaryTargetPortalCandidates,
                        out string recoveredTemporaryTargetSummary))
                {
                    if (temporaryTargetPortalNameCandidates.Length > 0
                        && recoveredTemporaryTargetPortalCandidates.Length > 0
                        && TryIntersectPacketOwnedCandidateSets(
                            temporaryTargetPortalNameCandidates,
                            recoveredTemporaryTargetPortalCandidates,
                            out string[] intersectedTemporaryTargetPortalCandidates))
                    {
                        temporaryTargetPortalNameCandidates = intersectedTemporaryTargetPortalCandidates;
                        if (TryResolvePacketOwnedTeleportUniqueCandidatePortalName(
                            intersectedTemporaryTargetPortalCandidates,
                            out string uniqueIntersectedTemporaryTargetPortalName))
                        {
                            temporaryTargetPortalName = uniqueIntersectedTemporaryTargetPortalName;
                        }
                    }
                    else
                    {
                        temporaryTargetPortalName = recoveredTemporaryTargetPortalName;
                        temporaryTargetPortalNameCandidates = recoveredTemporaryTargetPortalCandidates;
                    }

                    temporaryTargetResolutionSummary = recoveredTemporaryTargetSummary;
                    if (!string.IsNullOrWhiteSpace(temporaryTargetPortalName) && temporaryTargetFieldPortals != null)
                    {
                        temporaryTargetPortalIndex = GetPacketOwnedPortalListIndex(temporaryTargetFieldPortals, temporaryTargetPortalName);
                    }
                }

                if (temporaryPortalDestination.MapId == _mapBoard.MapInfo.id
                    && string.IsNullOrWhiteSpace(temporaryTargetPortalName)
                    && TryResolvePacketOwnedTargetPortalNameFromSourcePortal(
                        temporarySourcePortal,
                        temporaryPortalDestination.MapId,
                        out string directTemporarySameMapTargetPortalName,
                        out int directTemporarySameMapTargetPortalIndex))
                {
                    temporaryTargetPortalName = directTemporarySameMapTargetPortalName;
                    temporaryTargetPortalIndex = directTemporarySameMapTargetPortalIndex;
                    temporaryTargetPortalNameCandidates = new[] { directTemporarySameMapTargetPortalName };
                    temporaryTargetResolutionSummary = $"current-field portal '{directTemporarySameMapTargetPortalName}' from source portal '{temporarySourcePortal?.pn}'";
                }

                if (temporaryPortalDestination.MapId != _mapBoard.MapInfo.id
                    && !string.IsNullOrWhiteSpace(temporarySourcePortalName)
                    && TryResolvePacketOwnedTargetPortalMetadata(
                        temporaryPortalDestination.MapId,
                        temporaryPortalDestination.X,
                        temporaryPortalDestination.Y,
                        _mapBoard.MapInfo.id,
                        temporarySourcePortalName,
                        out string refreshedTemporaryTargetPortalName,
                        out string refreshedTemporaryTargetSummary,
                        out string[] refreshedTemporaryTargetCandidates,
                        out int refreshedTemporaryTargetPortalIndex))
                {
                    temporaryTargetPortalName = refreshedTemporaryTargetPortalName;
                    temporaryTargetResolutionSummary = refreshedTemporaryTargetSummary;
                    temporaryTargetPortalNameCandidates = refreshedTemporaryTargetCandidates;
                    temporaryTargetPortalIndex = refreshedTemporaryTargetPortalIndex;
                }

                if (temporaryPortalDestination.MapId != _mapBoard.MapInfo.id
                    && string.IsNullOrWhiteSpace(temporaryTargetPortalName)
                    && TryResolvePacketOwnedTargetPortalNameFromSourcePortal(
                        temporarySourcePortal,
                        temporaryPortalDestination.MapId,
                        out string directTemporaryCrossMapTargetPortalName,
                        out int directTemporaryCrossMapTargetPortalIndex))
                {
                    temporaryTargetPortalName = directTemporaryCrossMapTargetPortalName;
                    temporaryTargetPortalIndex = directTemporaryCrossMapTargetPortalIndex;
                    temporaryTargetPortalNameCandidates = new[] { directTemporaryCrossMapTargetPortalName };
                    temporaryTargetResolutionSummary = $"target-map portal '{directTemporaryCrossMapTargetPortalName}' from source portal '{temporarySourcePortal?.pn}'";
                }

                bool temporaryCrossMapTransfer = temporaryPortalDestination.MapId != _mapBoard.MapInfo.id;
                if (temporaryCrossMapTransfer)
                {
                    if (!CanSendTransferFieldRequest(currentTime))
                    {
                        return true;
                    }

                    string transferRestrictionMessage = FieldInteractionRestrictionEvaluator.GetTransferRestrictionMessage(fieldLimit);
                    if (!string.IsNullOrWhiteSpace(transferRestrictionMessage))
                    {
                        ShowFieldRestrictionMessage(transferRestrictionMessage);
                        return true;
                    }

                    if (!CanQueueKnownCrossMapTransfer(temporaryPortalDestination.MapId, showFailureMessage: true))
                    {
                        return true;
                    }

                    SetTransferFieldExclusiveRequestSent(currentTime);
                }

                RecordPacketOwnedTeleportPortalRequest(
                    temporaryPortalDestination.MapId,
                    temporarySourcePortalName,
                    temporaryPortalDestination.SourceX,
                    temporaryPortalDestination.SourceY,
                    temporaryPortalDestination.X,
                    temporaryPortalDestination.Y,
                    temporaryTargetPortalName,
                    temporaryTargetPortalNameCandidates,
                    temporaryTargetResolutionSummary);


                PlayPortalSE();

                _playerManager?.ForceStand();



                if (temporaryPortalDestination.MapId == _mapBoard.MapInfo.id)
                {
                    if (TryResolvePacketOwnedTeleportPortalByPosition(
                        temporaryPortalDestination.X,
                        temporaryPortalDestination.Y,
                        out int resolvedTemporaryPortalIndex,
                        out _))
                    {
                        temporaryTargetPortalIndex = resolvedTemporaryPortalIndex;
                    }

                    StartSameMapTeleport(
                        temporaryPortalDestination.X,
                        temporaryPortalDestination.Y,
                        temporaryPortalDestination.DelayMs,
                        currentTime,
                        temporaryTargetPortalIndex,
                        temporarySourcePortalName,
                        temporaryTargetPortalName,
                        temporaryTargetPortalNameCandidates,
                        usePacketOwnedApply: true);
                }
                else
                {
                    StagePendingCrossMapTeleport(
                        temporaryPortalDestination.MapId,
                        sourcePortalName: temporarySourcePortalName,
                        targetPortalName: temporaryTargetPortalName,
                        targetPortalIndex: temporaryTargetPortalIndex,
                        fallbackX: temporaryPortalDestination.X,
                        fallbackY: temporaryPortalDestination.Y,
                        targetPortalNameCandidates: temporaryTargetPortalNameCandidates);
                    SetPendingMapSpawnTarget(temporaryPortalDestination.X, temporaryPortalDestination.Y);
                    QueueMapTransfer(
                        temporaryPortalDestination.MapId,
                        temporaryTargetPortalName,
                        temporaryTargetPortalIndex,
                        temporaryTargetPortalNameCandidates);
                }


                return true;

            }



            PortalCollisionResult? collision = ResolvePortalCollisionAtLocalUserPosition();
            if (!collision.HasValue || collision.Value.Portal?.PortalInstance == null)
            {
                return false;
            }

            return TryHandlePortalCollisionByType(
                collision.Value.Portal.PortalInstance,
                collision.Value.PortalIndex,
                currentTime,
                fieldLimit);

        }

        private PortalCollisionResult? ResolvePortalCollisionAtLocalUserPosition()
        {
            if (_portalPool == null)
            {
                return null;
            }

            PlayerCharacter player = _playerManager?.Player;
            if (player?.Physics == null)
            {
                return null;
            }

            Vector2 position = player.Physics.GetPosition();
            return _portalPool.FindPortalCollision(position.X, position.Y);
        }

        private bool TryHandlePortalCollisionByType(
            PortalInstance portal,
            int portalIndex,
            int currentTime,
            long fieldLimit)
        {
            if (portal == null)
            {
                return false;
            }

            return portal.pt switch
            {
                PortalType.CollisionScript => TryHandleCollisionScriptPortal(portal, portalIndex, currentTime),
                PortalType.CollisionVerticalJump => TryHandleVerticalJumpPortal(portal, currentTime),
                PortalType.CollisionCustomImpact => TryHandleCustomImpactPortal(portal),
                _ => TryHandleTransferPortalCollision(portal, portalIndex, currentTime, fieldLimit)
            };
        }

        private bool TryHandleCollisionScriptPortal(
            PortalInstance portal,
            int portalIndex,
            int currentTime)
        {
            if (!CanSendCollisionScriptPortalRequest(portal, portalIndex, currentTime))
            {
                return true;
            }

            PlayerCharacter player = _playerManager?.Player;
            if (player?.Physics == null)
            {
                return false;
            }

            Vector2 position = player.Physics.GetPosition();
            return TryDispatchCollisionScriptPortalRequest(portal, portalIndex, position.X, position.Y, currentTime);
        }

        private bool CanSendCollisionScriptPortalRequest(PortalInstance portal, int portalIndex, int currentTime)
        {
            RefreshCollisionScriptExclusiveRequestState(currentTime);
            if (portal == null
                || !CanSendExclRequestLike(
                    _collisionScriptExclusiveRequestSent,
                    _collisionScriptExclusiveRequestSentTick,
                    currentTime,
                    timeIntervalMs: 0,
                    ignoreDeadState: false,
                    isLocalCharacterAlive: IsLocalCharacterAliveForExclusiveRequest(_playerManager?.Player))
                || ShouldBlockCollisionScriptPortalSendFromTransferExclusiveRequest(
                    _transferFieldExclusiveRequestSent,
                    _transferFieldExclusiveRequestSentTick,
                    currentTime,
                    TRANSFER_FIELD_REQUEST_EXCLUSIVE_COOLDOWN_MS,
                    IsLocalCharacterAliveForExclusiveRequest(_playerManager?.Player)))
            {
                return false;
            }

            int delayMs = ResolveCollisionScriptRequestCooldownMs(
                portal.delay ?? 0,
                _collisionScriptExclusiveRequestDelayMs,
                _collisionScriptExclusiveRequestSentTick);
            if (_collisionScriptExclusiveRequestSentTick != int.MinValue
                && unchecked(currentTime - _collisionScriptExclusiveRequestSentTick) < delayMs)
            {
                return false;
            }

            return portal.onlyOnce != MapleBool.True || portalIndex != _lastPortalCollisionSourcePortalIndex;
        }

        private bool TryDispatchCollisionScriptPortalRequest(
            PortalInstance portal,
            int portalIndex,
            float playerX,
            float playerY,
            int currentTime)
        {
            byte fieldKey = ResolveCollisionScriptPortalFieldKey();
            if (portal == null
                || !PortalCollisionScriptRequestCodec.TryBuildPayload(
                    fieldKey,
                    portal.pn,
                    playerX,
                    playerY,
                    out byte[] payload))
            {
                _lastCollisionScriptOutboundOpcode = -1;
                _lastCollisionScriptOutboundPayload = Array.Empty<byte>();
                _lastCollisionScriptOutboundSummary = "CollisionScript portal request was not dispatched because the portal name was empty.";
                return false;
            }

            _lastCollisionScriptOutboundOpcode = PortalCollisionScriptRequestCodec.Opcode;
            _lastCollisionScriptOutboundPayload = payload;
            _lastCollisionScriptOutboundSummary = DispatchCollisionScriptPortalRequest(payload, portal.pn, playerX, playerY, fieldKey);
            SetCollisionScriptExclusiveRequestSent(currentTime, portalIndex, portal.delay ?? 0);
            RegisterPortalCollisionRequestSource(portalIndex);
            return true;
        }

        internal static int ResolveCollisionScriptRequestCooldownMs(
            int portalDelayMs,
            int requestDelayMs,
            int requestSentTick)
        {
            int normalizedPortalDelayMs = Math.Max(0, portalDelayMs);
            if (requestSentTick == int.MinValue)
            {
                return normalizedPortalDelayMs;
            }

            return Math.Max(normalizedPortalDelayMs, Math.Max(0, requestDelayMs));
        }

        private byte[] TryEncodePortalOwnedMovePathSnapshot(
            CVecCtrl physics,
            int currentTime,
            bool hasDynamicFoothold,
            bool includeClientRandomCounts,
            out bool encoded)
        {
            encoded = false;
            if (physics == null)
            {
                return Array.Empty<byte>();
            }

            List<MovePathElement> path = physics.GetMovePathPacketSnapshot(currentTime);
            IReadOnlyList<MovePathElement> normalizedPath =
                CMovePathClientPacketCodec.NormalizeForPortalOwnedClientMakeMovePath(path);
            bool isTimeForFlush = physics.IsTimeForFlush(
                currentTime,
                isFlying: physics.IsFlying,
                hasDynamicFoothold: hasDynamicFoothold);
            int thresholdMs = hasDynamicFoothold ? 200 : 500;
            bool flushAdmitted = ShouldAdmitPortalOwnedMovePathFlushCadence(
                isTimeForFlush,
                currentTime,
                _lastPortalOwnedMovePathFlushAdmissionTick,
                thresholdMs);
            IReadOnlyList<MovePathElement> cadenceShapedPath =
                CMovePathClientPacketCodec.ApplyPortalOwnedFlushCadenceHint(
                    normalizedPath,
                    flushAdmitted);
            cadenceShapedPath = CMovePathClientPacketCodec.ApplyPortalOwnedPostFlushCarryHint(
                cadenceShapedPath,
                !flushAdmitted ? _portalOwnedMovePathPostFlushCarry : Array.Empty<MovePathElement>(),
                out bool consumedPostFlushCarry);
            if (consumedPostFlushCarry)
            {
                _portalOwnedMovePathPostFlushCarry.Clear();
            }
            if (!CMovePathClientPacketCodec.TryEncode(
                    cadenceShapedPath,
                    out byte[] payload,
                    out _,
                    includeClientRandomCounts))
            {
                return Array.Empty<byte>();
            }

            if (flushAdmitted)
            {
                _lastPortalOwnedMovePathFlushAdmissionTick = currentTime;
                _portalOwnedMovePathPostFlushCarry.Clear();
                IReadOnlyList<MovePathElement> carryPath =
                    CMovePathClientPacketCodec.CapturePortalOwnedPostFlushCarryHint(cadenceShapedPath);
                for (int i = 0; i < carryPath.Count; i++)
                {
                    _portalOwnedMovePathPostFlushCarry.Add(carryPath[i]);
                }
            }

            encoded = true;
            return payload ?? Array.Empty<byte>();
        }

        internal static bool ShouldAdmitPortalOwnedMovePathFlushCadence(
            bool isTimeForFlush,
            int currentTime,
            int lastFlushAdmissionTick,
            int thresholdMs)
        {
            if (!isTimeForFlush)
            {
                return false;
            }

            if (lastFlushAdmissionTick == int.MinValue)
            {
                return true;
            }

            int normalizedThresholdMs = Math.Max(1, thresholdMs);
            return unchecked(currentTime - lastFlushAdmissionTick) >= normalizedThresholdMs;
        }

        private byte ResolveCollisionScriptPortalFieldKey()
        {
            int mapId = _mapBoard?.MapInfo?.id ?? 0;
            return _packetStageTransitionRuntime.TryGetAuthoritativeFieldKey(mapId, out byte fieldKey)
                ? fieldKey
                : PortalCollisionScriptRequestCodec.SyntheticFieldKey;
        }

        private string DispatchCollisionScriptPortalRequest(byte[] payload, string portalName, float playerX, float playerY, byte fieldKey)
        {
            payload ??= Array.Empty<byte>();
            string summary =
                $"Recorded CUserLocal::CheckPortal_Collision opcode {PortalCollisionScriptRequestCodec.Opcode} " +
                $"for CollisionScript portal '{portalName?.Trim()}' at ({(int)MathF.Round(playerX)}, {(int)MathF.Round(playerY)}) " +
                $"with field key {fieldKey}.";

            if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(
                PortalCollisionScriptRequestCodec.Opcode,
                payload,
                out string bridgeStatus))
            {
                return $"{summary} Dispatched it through the live official-session bridge. {bridgeStatus}";
            }

            if (_localUtilityPacketOutbox.TrySendOutboundPacket(
                PortalCollisionScriptRequestCodec.Opcode,
                payload,
                out string outboxStatus))
            {
                return $"{summary} Dispatched it through the generic packet outbox after the live bridge path was unavailable. Bridge: {bridgeStatus} Outbox: {outboxStatus}";
            }

            if (_localUtilityOfficialSessionBridge.IsRunning
                && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(
                    PortalCollisionScriptRequestCodec.Opcode,
                    payload,
                    out string queuedBridgeStatus))
            {
                return $"{summary} Queued it for deferred official-session injection after the live bridge path was unavailable. Bridge: {bridgeStatus} Outbox: {outboxStatus} Deferred bridge: {queuedBridgeStatus}";
            }

            if (_localUtilityPacketOutbox.TryQueueOutboundPacket(
                PortalCollisionScriptRequestCodec.Opcode,
                payload,
                out string queuedOutboxStatus))
            {
                return $"{summary} Queued it for deferred generic packet outbox delivery after the live bridge path was unavailable. Bridge: {bridgeStatus} Outbox: {outboxStatus} Deferred outbox: {queuedOutboxStatus}";
            }

            return $"{summary} The request remained simulator-owned because neither the live bridge nor the packet outbox accepted opcode {PortalCollisionScriptRequestCodec.Opcode}. Bridge: {bridgeStatus} Outbox: {outboxStatus}";
        }

        private void SetCollisionScriptExclusiveRequestSent(int currentTime, int portalIndex, int portalDelayMs)
        {
            _collisionScriptExclusiveRequestSent = true;
            _collisionScriptExclusiveRequestSentTick = currentTime;
            _collisionScriptExclusiveRequestPortalIndex = portalIndex;
            _collisionScriptExclusiveRequestDelayMs = Math.Max(0, portalDelayMs);
        }

        private void ClearCollisionScriptExclusiveRequestSent(bool preserveCooldown = true)
        {
            ApplyCollisionScriptExclusiveRequestClear(
                preserveCooldown,
                ref _collisionScriptExclusiveRequestSent,
                ref _collisionScriptExclusiveRequestSentTick,
                ref _collisionScriptExclusiveRequestPortalIndex,
                ref _collisionScriptExclusiveRequestDelayMs);
        }

        internal static void ApplyCollisionScriptExclusiveRequestClear(
            bool preserveCooldown,
            ref bool exclusiveRequestSent,
            ref int exclusiveRequestSentTick,
            ref int exclusiveRequestPortalIndex,
            ref int exclusiveRequestDelayMs,
            bool stampResetTick = false,
            int resetTick = int.MinValue)
        {
            exclusiveRequestSent = false;
            if (preserveCooldown)
            {
                return;
            }

            exclusiveRequestSentTick = stampResetTick ? resetTick : int.MinValue;
            exclusiveRequestPortalIndex = -1;
            exclusiveRequestDelayMs = 0;
        }

        private void ConsumeCollisionScriptExclusiveRequestFromTransferLifecycle()
        {
            if (!_collisionScriptExclusiveRequestSent
                && _collisionScriptExclusiveRequestSentTick == int.MinValue
                && _collisionScriptExclusiveRequestPortalIndex < 0
                && _collisionScriptExclusiveRequestDelayMs <= 0)
            {
                return;
            }

            // CStage/CField transfer handoff teardown consumes pending portal collision-script requests.
            ClearCollisionScriptExclusiveRequestSent(preserveCooldown: false);
            TryConsumePacketOwnedQuestResultStartQuestLatchFromSharedExclusiveReset();
        }

        private void RefreshCollisionScriptExclusiveRequestState(int currentTime)
        {
            if (!_collisionScriptExclusiveRequestSent)
            {
                return;
            }

            PortalCollisionResult? collision = ResolvePortalCollisionAtLocalUserPosition();
            PortalType? collisionPortalType = collision?.Portal?.PortalInstance?.pt;
            int collisionPortalIndex = collision?.PortalIndex ?? -1;
            if (!ShouldClearCollisionScriptExclusiveRequest(
                    _collisionScriptExclusiveRequestSent,
                    _collisionScriptExclusiveRequestPortalIndex,
                    collisionPortalType,
                    collisionPortalIndex,
                    _collisionScriptExclusiveRequestSentTick,
                    _collisionScriptExclusiveRequestDelayMs,
                    _packetOwnedTeleportRequestActive,
                    currentTime))
            {
                return;
            }

            ClearCollisionScriptExclusiveRequestSent();
        }

        internal static bool ShouldClearCollisionScriptExclusiveRequest(
            bool exclusiveRequestSent,
            int requestPortalIndex,
            PortalType? collidingPortalType,
            int collidingPortalIndex,
            int requestSentTick,
            int requestDelayMs,
            bool packetOwnedTeleportRequestActive,
            int currentTime)
        {
            if (!exclusiveRequestSent || packetOwnedTeleportRequestActive)
            {
                return false;
            }

            bool sameCollisionScriptPortal = collidingPortalType == PortalType.CollisionScript
                && collidingPortalIndex == requestPortalIndex
                && requestPortalIndex >= 0;
            if (!sameCollisionScriptPortal)
            {
                return true;
            }

            if (requestSentTick == int.MinValue)
            {
                return true;
            }

            return unchecked(currentTime - requestSentTick) >= Math.Max(0, requestDelayMs);
        }

        private bool TryHandleVerticalJumpPortal(PortalInstance portal, int currentTime)
        {
            PlayerCharacter player = _playerManager?.Player;
            if (player?.Physics == null
                || !CanHandleCollisionVerticalJumpFromLiveInterface(
                    hasLiveFieldInterface: HasPassiveTransferFieldInterface(),
                    hasActiveVectorControl: _playerManager?.IsPlayerActive == true,
                    hasPlayerInputControl: _gameState.IsPlayerInputEnabled,
                    hasPendingMapChange: _gameState.PendingMapChange,
                    hasAttachedDriver: _localFollowRuntime.HasAttachedDriver))
            {
                return false;
            }

            double horizontalImpact = ResolveCollisionVerticalJumpHorizontalImpact(player.HorizontalInputDirection, player.FacingRight);
            player.Physics.SetMovePathAttribute(CollisionVerticalJumpMovePathAttribute);
            player.Physics.SetImpactNext(horizontalImpact, CollisionVerticalJumpVelocityY);
            _lastCollisionVerticalJumpMovePathAttribute = CollisionVerticalJumpMovePathAttribute;
            bool hasDynamicFoothold = IsPortalOwnedMovePathDynamicFootholdBranch(_mapBoard?.MapInfo?.fieldType);
            _lastCollisionVerticalJumpMovePathPayload = TryEncodePortalOwnedMovePathSnapshot(
                player.Physics,
                currentTime,
                hasDynamicFoothold,
                _packetOwnedMovePathRandomCounterOptionEnabled,
                out _);
            TryRegisterCollisionVerticalJumpEffect(currentTime);
            _ = ClearPacketOwnedTeleportPassengerLink();
            return true;
        }

        internal const string CollisionVerticalJumpEffectUol = "Effect/BasicEff.img/VerticalJump";
        internal const int CollisionVerticalJumpMovePathAttribute = 24;
        internal const double CollisionVerticalJumpVelocityY = -2300d;

        internal static bool CanHandleCollisionVerticalJumpFromLiveInterface(
            bool hasLiveFieldInterface,
            bool hasActiveVectorControl,
            bool hasPlayerInputControl,
            bool hasPendingMapChange,
            bool hasAttachedDriver)
        {
            return hasLiveFieldInterface
                   && hasActiveVectorControl
                   && hasPlayerInputControl
                   && !hasPendingMapChange
                   && !hasAttachedDriver;
        }

        internal static double ResolveCollisionVerticalJumpHorizontalImpact(int inputDirection, bool facingRight)
        {
            int clampedInputDirection = Math.Clamp(inputDirection, -1, 1);
            return (clampedInputDirection * 100) + (facingRight ? 200 : -200);
        }

        private bool TryHandleCustomImpactPortal(PortalInstance portal)
        {
            if (portal == null)
            {
                return false;
            }

            if (!IsCollisionCustomImpactPortalField(_mapBoard?.MapInfo?.fieldType, _mapBoard?.MapInfo?.id ?? 0))
            {
                return false;
            }

            if (!CanApplyCustomImpactPortalFromReactor(portal))
            {
                return true;
            }

            if (!string.IsNullOrWhiteSpace(portal.sessionValueKey)
                && TryApplyPortalSessionValueImpact(portal))
            {
                _ = ClearPacketOwnedTeleportPassengerLink();
                return true;
            }

            PlayerCharacter player = _playerManager?.Player;
            if (player?.Physics == null)
            {
                return false;
            }

            if (!TryApplyCollisionCustomImpactToPlayer(
                    player,
                    portal.horizontalImpact ?? 0,
                    -(portal.verticalImpact ?? 0),
                    currTickCount))
            {
                return false;
            }

            _ = ClearPacketOwnedTeleportPassengerLink();
            return true;
        }

        private bool TryApplyCollisionCustomImpactToPlayer(
            PlayerCharacter player,
            double velocityX,
            double velocityY,
            int currentTime)
        {
            if (player?.Physics == null
                || !CanHandleCollisionCustomImpactFromLiveInterface(
                    hasLiveFieldInterface: HasPassiveTransferFieldInterface(),
                    hasActiveVectorControl: _playerManager?.IsPlayerActive == true,
                    hasPendingMapChange: _gameState.PendingMapChange,
                    hasAttachedDriver: _localFollowRuntime.HasAttachedDriver))
            {
                return false;
            }

            player.Physics.SetMovePathAttribute(CollisionCustomImpactMovePathAttribute);
            player.Physics.SetImpactNext(velocityX, velocityY);
            _lastCollisionCustomImpactMovePathAttribute = CollisionCustomImpactMovePathAttribute;
            bool hasDynamicFoothold = IsPortalOwnedMovePathDynamicFootholdBranch(_mapBoard?.MapInfo?.fieldType);
            _lastCollisionCustomImpactMovePathPayload = TryEncodePortalOwnedMovePathSnapshot(
                player.Physics,
                currentTime,
                hasDynamicFoothold,
                _packetOwnedMovePathRandomCounterOptionEnabled,
                out _);
            TryRegisterCollisionCustomImpactEffect(currentTime, velocityX);
            return true;
        }

        internal const int CollisionCustomImpactMovePathAttribute = 25;

        internal static bool IsPortalOwnedMovePathDynamicFootholdBranch(FieldType? fieldType)
        {
            return fieldType == FieldType.FIELDTYPE_DYNAMICFOOTHOLD;
        }

        internal static bool CanHandleCollisionCustomImpactFromLiveInterface(
            bool hasLiveFieldInterface,
            bool hasActiveVectorControl,
            bool hasPendingMapChange,
            bool hasAttachedDriver)
        {
            return hasLiveFieldInterface
                   && hasActiveVectorControl
                   && !hasPendingMapChange
                   && !hasAttachedDriver;
        }

        private bool CanApplyCustomImpactPortalFromReactor(PortalInstance portal)
        {
            if (portal == null
                || string.IsNullOrWhiteSpace(portal.reactorName)
                || _reactorPool == null)
            {
                return true;
            }

            if (!_reactorPool.TryGetReactorStatesByName(portal.reactorName, out int state, out int visualState))
            {
                return true;
            }

            return state == (int)ReactorState.Activated
                && visualState != 1
                && visualState != 2;
        }

        private bool TryApplyPortalSessionValueImpact(PortalInstance portal)
        {
            PlayerCharacter player = _playerManager?.Player;
            if (player?.Physics == null)
            {
                return false;
            }

            string sessionValue = string.IsNullOrWhiteSpace(portal.sessionValue) ? "0" : portal.sessionValue;
            if (TryResolveStructuredPortalSessionValueImpactOwner(
                    portal.sessionValueKey,
                    sessionValue,
                    out PortalSessionValueImpactOwnerKind ownerKind))
            {
                QueuePendingPortalSessionValueImpact(new PendingPortalSessionValueImpact(
                    _mapBoard?.MapInfo?.id ?? -1,
                    ownerKind,
                    portal.sessionValueKey,
                    sessionValue,
                    currTickCount,
                    portal.horizontalImpact ?? 0,
                    -(portal.verticalImpact ?? 0)));
                TryDispatchPortalSessionValueRequest(portal.sessionValueKey, currTickCount);
                return true;
            }

            return false;
        }

        private bool TryResolveStructuredPortalSessionValueImpactOwner(
            string key,
            string value,
            out PortalSessionValueImpactOwnerKind ownerKind)
        {
            return TryResolveStructuredPortalSessionValueImpactOwner(
                _mapBoard?.MapInfo,
                _specialFieldRuntime?.PartyRaid.IsActive == true,
                key,
                value,
                out ownerKind);
        }

        internal static bool TryResolveStructuredPortalSessionValueImpactOwner(
            MapInfo mapInfo,
            bool partyRaidRuntimeActive,
            string key,
            string value,
            out PortalSessionValueImpactOwnerKind ownerKind)
        {
            ownerKind = PortalSessionValueImpactOwnerKind.None;
            if (string.IsNullOrWhiteSpace(key))
            {
                return false;
            }

            if (IsChaosZakumPortalSessionWrapperMap(mapInfo)
                && IsChaosZakumPortalSessionKey(key))
            {
                ownerKind = PortalSessionValueImpactOwnerKind.ChaosZakum;
                return true;
            }

            if (mapInfo?.fieldType == MapleLib.WzLib.WzStructure.Data.FieldType.FIELDTYPE_HUNTINGADBALLOON
                && string.Equals(key?.Trim(), "balloon_Team", StringComparison.Ordinal)
                && (string.Equals(value, "redTeam", StringComparison.Ordinal)
                    || string.Equals(value, "blueTeam", StringComparison.Ordinal)))
            {
                ownerKind = PortalSessionValueImpactOwnerKind.HuntingAdBalloon;
                return true;
            }

            if (partyRaidRuntimeActive
                && Fields.PartyRaidField.IsPartyRaidMap(mapInfo))
            {
                ownerKind = PortalSessionValueImpactOwnerKind.PartyRaid;
                return true;
            }

            return false;
        }

        internal static bool IsCollisionCustomImpactPortalField(MapleLib.WzLib.WzStructure.Data.FieldType? fieldType, int mapId)
        {
            return mapId == ChaosZakumPortalSessionFallbackFieldId
                || fieldType is MapleLib.WzLib.WzStructure.Data.FieldType.FIELDTYPE_PARTYRAID
                or MapleLib.WzLib.WzStructure.Data.FieldType.FIELDTYPE_PARTYRAID_BOSS
                or MapleLib.WzLib.WzStructure.Data.FieldType.FIELDTYPE_CHAOSZAKUM
                or MapleLib.WzLib.WzStructure.Data.FieldType.FIELDTYPE_WAITINGPARTYQUEST
                or MapleLib.WzLib.WzStructure.Data.FieldType.FIELDTYPE_HUNTINGADBALLOON;
        }

        private bool TryHandleTransferPortalCollision(
            PortalInstance portal,
            int portalIndex,
            int currentTime,
            long fieldLimit)
        {
            if (portal == null || portal.tm <= 0 || portal.tm == MapConstants.MaxMap)
            {
                return false;
            }

            if (ShouldSendTransferFieldRequestForPortal(portal.tm, _mapBoard?.MapInfo?.id ?? -1, portal.pt))
            {
                if (!CanSendTransferFieldRequest(currentTime))
                {
                    return true;
                }

                string transferRestrictionMessage =
                    FieldInteractionRestrictionEvaluator.GetTransferRestrictionMessage(fieldLimit);
                if (!string.IsNullOrWhiteSpace(transferRestrictionMessage))
                {
                    ShowFieldRestrictionMessage(transferRestrictionMessage);
                    return true;
                }

                if (!CanQueueKnownCrossMapTransfer(portal.tm, showFailureMessage: true))
                {
                    return true;
                }

                SetTransferFieldExclusiveRequestSent(currentTime);
            }

            _playerManager?.ForceStand();
            PublishDynamicObjectTagStatesForPortal(portal, currentTime);
            RecordPacketOwnedTeleportPortalRequest(portal);

            if (TryStartPacketOwnedPortalTeleport(portal, currentTime))
            {
                RegisterPortalCollisionRequestSource(portalIndex);
                if (ShouldPlayTransferFieldPortalSound(portal.pt))
                {
                    PlayPortalSE();
                }

                return true;
            }

            TryResolvePacketOwnedPendingCrossMapPortalNames(
                portal,
                out string targetPortalName,
                out string[] targetPortalNameCandidates,
                out int targetPortalIndex);
            StagePendingCrossMapTeleport(
                portal.tm,
                sourcePortalName: portal.pn,
                targetPortalName: targetPortalName,
                targetPortalIndex: targetPortalIndex,
                targetPortalNameCandidates: targetPortalNameCandidates);
            QueueMapTransfer(
                portal.tm,
                targetPortalName,
                targetPortalIndex,
                targetPortalNameCandidates);
            RegisterPortalCollisionRequestSource(portalIndex);
            if (ShouldPlayTransferFieldPortalSound(portal.pt))
            {
                PlayPortalSE();
            }

            return true;
        }

        private bool CanSendTransferFieldRequest(int currentTime)
        {
            return CanSendExclRequestLike(
                _transferFieldExclusiveRequestSent,
                _transferFieldExclusiveRequestSentTick,
                currentTime,
                TRANSFER_FIELD_REQUEST_EXCLUSIVE_COOLDOWN_MS,
                ignoreDeadState: false,
                isLocalCharacterAlive: IsLocalCharacterAliveForExclusiveRequest(_playerManager?.Player));
        }

        private bool IsTransferFieldExclusiveRequestInFlight(int currentTime)
        {
            return PassiveTransferFieldReadinessEvaluator.IsExclusiveTransferRequestInFlight(
                _transferFieldExclusiveRequestSent,
                _transferFieldExclusiveRequestSentTick,
                currentTime,
                TRANSFER_FIELD_REQUEST_EXCLUSIVE_COOLDOWN_MS);
        }

        internal static bool ShouldBlockCollisionScriptPortalSendFromTransferExclusiveRequest(
            bool transferExclusiveRequestSent,
            int transferExclusiveRequestSentTick,
            int currentTime,
            int cooldownMs,
            bool isLocalCharacterAlive)
        {
            return !CanSendExclRequestLike(
                transferExclusiveRequestSent,
                transferExclusiveRequestSentTick,
                currentTime,
                cooldownMs,
                ignoreDeadState: false,
                isLocalCharacterAlive);
        }

        internal static bool CanSendExclRequestLike(
            bool exclusiveRequestSent,
            int exclusiveRequestSentTick,
            int currentTime,
            int timeIntervalMs,
            bool ignoreDeadState,
            bool isLocalCharacterAlive)
        {
            if (exclusiveRequestSent)
            {
                return false;
            }

            if (!ignoreDeadState && !isLocalCharacterAlive)
            {
                return false;
            }

            if (exclusiveRequestSentTick == int.MinValue)
            {
                return true;
            }

            return unchecked(currentTime - exclusiveRequestSentTick) >= Math.Max(0, timeIntervalMs);
        }

        internal static bool IsLocalCharacterAliveForExclusiveRequest(PlayerCharacter player)
        {
            return player?.Build?.HP > 0;
        }

        private void SetTransferFieldExclusiveRequestSent(int currentTime)
        {
            _transferFieldExclusiveRequestSent = true;
            _transferFieldExclusiveRequestSentTick = currentTime;
        }

        private void ClearTransferFieldExclusiveRequestSent(bool preserveCooldown = true)
        {
            ApplyTransferFieldExclusiveRequestClear(
                preserveCooldown,
                ref _transferFieldExclusiveRequestSent,
                ref _transferFieldExclusiveRequestSentTick);
        }

        internal static void ApplyTransferFieldExclusiveRequestClear(
            bool preserveCooldown,
            ref bool exclusiveRequestSent,
            ref int exclusiveRequestSentTick,
            bool stampResetTick = false,
            int resetTick = int.MinValue)
        {
            exclusiveRequestSent = false;
            if (preserveCooldown)
            {
                return;
            }

            exclusiveRequestSentTick = stampResetTick ? resetTick : int.MinValue;
        }

        private void ConsumeSharedExclusiveRequestStateFromTransferResponseLifecycle()
        {
            // CWvsContext transfer/portal handoff responses consume both shared exclusive-request owners.
            ClearCollisionScriptExclusiveRequestSent(preserveCooldown: false);
            ClearTransferFieldExclusiveRequestSent(preserveCooldown: false);
            ConsumePassiveTransferRequestFromTransferLifecycle();
            TryConsumePacketOwnedQuestResultStartQuestLatchFromSharedExclusiveReset();
        }

