        }



        private void HandleSpecialFieldAttackHitbox(PlayerCharacter player, Rectangle attackHitbox, int currentTime)
        {
            GuildBossField guildBoss = _specialFieldRuntime?.SpecialEffects?.GuildBoss;
            if (guildBoss?.IsActive != true
                || _gameState.PendingMapChange
                || _sameMapTeleportPending
                || !_gameState.IsPlayerInputEnabled
                || _playerManager?.IsPlayerActive != true
                || player != _playerManager.Player)
            {
                return;
            }


            bool officialSessionBridgeHoldsOwnership = HoldsGuildBossOfficialSessionBridgeOwnership();
            bool hasHitReactor = _reactorPool?.FindHitReactorsInBounds(attackHitbox, currentTick: currentTime).Count > 0;
            bool allowLocalPreview = ShouldAllowLocalGuildBossPulleyPreview(
                officialSessionBridgeHoldsOwnership,
                _guildBossTransport.HasConnectedClients);
            if (!guildBoss.TryHandleLocalPulleyAttack(attackHitbox, currentTime, allowLocalPreview, hasHitReactor, out string message))
            {
                return;
            }


            if (!allowLocalPreview && guildBoss.TryConsumePulleyPacketRequest(out GuildBossField.PulleyPacketRequest request))
            {
                string transportStatus = "Guild Boss pulley transport is unavailable.";
                if (officialSessionBridgeHoldsOwnership)
                {
                    if (_guildBossOfficialSessionBridge.TrySendOrQueuePulleyRequest(request, out bool queued, out string sessionStatus))
                    {
                        message = queued
                            ? $"{message} Queued for live session."
                            : $"{message} Waiting for live session reply.";
                    }
                    else
                    {
                        message = sessionStatus;
                    }
                }
                else if (ShouldFallbackGuildBossPulleyTransport(officialSessionBridgeHoldsOwnership)
                    && _guildBossTransport.TrySendPulleyRequest(request, out string sendTransportStatus))
                {
                    transportStatus = sendTransportStatus;
                    message = $"{message} Waiting for transport reply.";
                }
                else
                {
                    message = transportStatus;
                }
            }


            if (!string.IsNullOrWhiteSpace(message))
            {
                _chat.AddMessage(message, new Color(151, 221, 255), currentTime);
            }
        }


        private bool TryStartPacketOwnedPortalTeleport(PortalInstance sourcePortal, int currentTime)
        {
            if (sourcePortal == null
                || _mapBoard?.MapInfo == null
                || sourcePortal.tm != _mapBoard.MapInfo.id
                || ShouldSendTransferFieldRequestForPortal(sourcePortal.tm, _mapBoard.MapInfo.id, sourcePortal.pt)
                || _portalPool == null
                || string.IsNullOrWhiteSpace(sourcePortal.tn))
            {
                return false;
            }

            int targetPortalIndex = _portalPool.GetPortalIndexByName(sourcePortal.tn);
            PortalItem targetPortal = _portalPool.GetPortal(targetPortalIndex);
            if (targetPortal?.PortalInstance == null)
            {
                return false;
            }

            StartSameMapTeleport(
                targetPortal.PortalInstance.X,
                targetPortal.PortalInstance.Y,
                sourcePortal.delay ?? 120,
                currentTime,
                targetPortalIndex,
                sourcePortal.pn,
                sourcePortal.tn,
                usePacketOwnedApply: true);
            return true;
        }

        private void StagePendingCrossMapTeleport(
            int targetMapId,
            int sourceMapId = -1,
            string sourcePortalName = null,
            string targetPortalName = null,
            int targetPortalIndex = -1,
            float? fallbackX = null,
            float? fallbackY = null,
            string[] targetPortalNameCandidates = null)
        {
            _pendingCrossMapTeleportTarget = targetMapId > 0
                ? new PendingCrossMapTeleportTarget(targetMapId, sourceMapId, sourcePortalName, targetPortalName, targetPortalIndex, fallbackX, fallbackY, targetPortalNameCandidates)
                : null;
            _packetOwnedTeleportRequestActive = _pendingCrossMapTeleportTarget != null;
        }


        private void StartSameMapTeleport(
            float targetX,
            float targetY,
            int delayMs,
            int currentTime,
            int portalIndex = -1,
            string sourcePortalName = null,
            string targetPortalName = null,
            string[] targetPortalNameCandidates = null,
            bool usePacketOwnedApply = false)
        {
            _sameMapTeleportPending = true;
            _sameMapTeleportStartTime = currentTime;
            _sameMapTeleportDelay = Math.Max(0, delayMs);
            _sameMapTeleportTarget = new SameMapTeleportTarget(
                targetX,
                portalIndex >= 0 ? targetY : targetY - SAME_MAP_TELEPORT_Y_OFFSET,
                portalIndex,
                sourcePortalName,
                targetPortalName,
                targetPortalNameCandidates,
                usePacketOwnedApply);
            _pendingCrossMapTeleportTarget = null;
            _packetOwnedTeleportRequestActive = usePacketOwnedApply;
            if (usePacketOwnedApply)
            {
                _lastPacketOwnedTeleportPortalIndex = portalIndex >= 0 ? portalIndex : -1;
                _lastPacketOwnedTeleportSourcePortalName = sourcePortalName;
                _lastPacketOwnedTeleportTargetPortalName = targetPortalName;
            }
        }


        private void SetPendingMapSpawnTarget(float x, float y)
        {
            _pendingMapSpawnTarget = new PendingMapSpawnTarget(x, y);
        }


        private bool TryConsumePendingMapSpawnTarget(out float spawnX, out float spawnY)
        {
            if (_pendingMapSpawnTarget == null)
            {
                spawnX = 0f;
                spawnY = 0f;
                return false;
            }


            spawnX = _pendingMapSpawnTarget.X;
            spawnY = _pendingMapSpawnTarget.Y;
            _pendingMapSpawnTarget = null;
            return true;
        }


        private void ResolveSpawnPosition(out float spawnX, out float spawnY)
        {
            bool spawnPositionSet = false;
            spawnX = _vrFieldBoundary.Center.X;
            spawnY = _vrFieldBoundary.Center.Y;


            if (!spawnPositionSet && (!string.IsNullOrEmpty(_spawnPortalName) || (_spawnPortalNameCandidates?.Length ?? 0) > 0))
            {
                PortalInstance targetPortal = ResolvePortalByNameCandidatesOrIndex(
                    _mapBoard.BoardItems.Portals,
                    _spawnPortalName,
                    _spawnPortalNameCandidates,
                    portalIndex: -1);
                if (targetPortal != null)
                {
                    mapShiftX = targetPortal.X;
                    mapShiftY = targetPortal.Y;
                    spawnX = targetPortal.X;
                    spawnY = targetPortal.Y;
                    spawnPositionSet = true;
                }
            }

            if (!spawnPositionSet && TryConsumePendingMapSpawnTarget(out float pendingSpawnX, out float pendingSpawnY))
            {
                mapShiftX = (int)MathF.Round(pendingSpawnX);
                mapShiftY = (int)MathF.Round(pendingSpawnY);
                spawnX = pendingSpawnX;
                spawnY = pendingSpawnY;
                spawnPositionSet = true;
            }

            if (!spawnPositionSet && _spawnPortalIndex >= 0)
            {
                PortalInstance indexedPortal = ResolvePortalByNameOrIndex(_mapBoard.BoardItems.Portals, null, _spawnPortalIndex);
                if (indexedPortal != null)
                {
                    mapShiftX = indexedPortal.X;
                    mapShiftY = indexedPortal.Y;
                    spawnX = indexedPortal.X;
                    spawnY = indexedPortal.Y;
                    spawnPositionSet = true;
                }
            }


            if (!spawnPositionSet)
            {
                List<PortalInstance> startPortals = _mapBoard.BoardItems.Portals
                    .Where(portal => portal.pt == PortalType.StartPoint)
                    .ToList();
                if (startPortals.Count > 0)
                {
                    Random random = new Random();
                    PortalInstance randomStartPortal = startPortals[random.Next(startPortals.Count)];
                    mapShiftX = randomStartPortal.X;
                    mapShiftY = randomStartPortal.Y;
                    spawnX = randomStartPortal.X;
                    spawnY = randomStartPortal.Y;
                }
            }
        }


        private void UpdateDirectionModeState(int currentTime)
        {
            _scriptedDirectionModeWindows.TrackOwner(
                NpcInteractionDirectionModeOwnerName,
                () => _npcInteractionOverlay?.IsVisible == true);
            _scriptedDirectionModeWindows.TrackOwner(
                WeddingDirectionModeOwnerName,
                () => _specialFieldRuntime.SpecialEffects.Wedding.HasActiveScriptedDialog);
            _scriptedDirectionModeWindows.TrackOwner(
                CakePieItemInfoDirectionModeOwnerName,
                () => _specialFieldRuntime.SpecialEffects.CakePie.IsItemInfoVisible);
            _scriptedDirectionModeWindows.TrackOwner(
                MemoryGameDirectionModeOwnerName,
                () => _specialFieldRuntime.Minigames.MemoryGame.IsVisible);
            _scriptedDirectionModeWindows.TrackOwner(
                TournamentMatchTableDirectionModeOwnerName,
                () => _specialFieldRuntime.Minigames.Tournament.MatchTableDialog.IsVisible);
            _scriptedDirectionModeWindows.TrackOwner(
                RockPaperScissorsDirectionModeOwnerName,
                () => _specialFieldRuntime.Minigames.RockPaperScissors.IsVisible);
            _scriptedDirectionModeWindows.TrackOwner(
                InitialQuizDirectionModeOwnerName,
                () => _initialQuizTimerRuntime.IsActive(currentTime));
            _scriptedDirectionModeWindows.TrackOwner(
                SpeedQuizDirectionModeOwnerName,
                () => _speedQuizOwnerRuntime.IsActive(currentTime));
            _scriptedDirectionModeWindows.TrackOwner(
                PacketScriptDedicatedOwnerDirectionModeOwnerName,
                () => _packetScriptDedicatedOwnerRuntime.IsActive);


            bool scriptedOwnerActive = _scriptedDirectionModeWindows.HasVisibleOwnedWindow(IsWindowVisible);



            if (scriptedOwnerActive)
            {
                _gameState.EnterDirectionMode();
            }
            else if (_scriptedDirectionModeOwnerActive)
            {
                _gameState.RequestLeaveDirectionMode(currentTime, DIRECTION_MODE_RELEASE_DELAY_MS);
            }


            _scriptedDirectionModeOwnerActive = scriptedOwnerActive;

            _gameState.UpdateDirectionMode(currentTime);

        }



