        private void RefreshQuestUiState()
        {
            RefreshNpcClientActionSelectionIfNeeded();

            if (_activeQuestDetailQuestId != 0 && uiWindowManager.QuestDetailWindow?.IsVisible == true)
            {
                UpdateQuestDetailWindow();
            }
        }

        private void RefreshNpcClientActionSelectionIfNeeded()
        {
            if (_npcsArray == null || _npcsArray.Length == 0 || _mapBoard?.BoardItems?.NPCs == null)
            {
                _lastNpcClientActionSelectionContextStamp = _questRuntime?.GetNpcClientActionSelectionContextStamp(_playerManager?.Player?.Build?.Gender) ?? int.MinValue;
                return;
            }

            int currentStamp = _questRuntime?.GetNpcClientActionSelectionContextStamp(_playerManager?.Player?.Build?.Gender) ?? int.MinValue;
            if (currentStamp == _lastNpcClientActionSelectionContextStamp)
            {
                return;
            }

            RebuildNpcClientActionSelections();
            _lastNpcClientActionSelectionContextStamp = currentStamp;
        }

        private void RebuildNpcClientActionSelections()
        {
            if (_mapBoard?.BoardItems?.NPCs == null || _texturePool == null || GraphicsDevice == null)
            {
                return;
            }

            Dictionary<int, NpcItem> previousNpcsById = _npcsById.Count > 0
                ? new Dictionary<int, NpcItem>(_npcsById)
                : null;
            var rebuiltNpcs = new List<NpcItem>(_mapBoard.BoardItems.NPCs.Count);
            var usedProps = new ConcurrentBag<WzObject>();

            foreach (NpcInstance npc in _mapBoard.BoardItems.NPCs)
            {
                if (npc == null || npc.Hide)
                {
                    continue;
                }

                NpcItem rebuiltNpc = MapSimulatorLoader.CreateNpcFromProperty(
                    _texturePool,
                    npc,
                    UserScreenScaleFactor,
                    GraphicsDevice,
                    usedProps,
                    _playerManager?.Player?.Build?.Gender,
                    _questRuntime.HasNpcClientActionSelectionContext(),
                    _questRuntime.GetCurrentState,
                    questId => _questRuntime.TryGetQuestRecordValue(questId, out string value) ? value : string.Empty);
                if (rebuiltNpc == null)
                {
                    continue;
                }

                if (int.TryParse(rebuiltNpc.NpcInstance?.NpcInfo?.ID, out int npcId) &&
                    previousNpcsById != null &&
                    previousNpcsById.TryGetValue(npcId, out NpcItem previousNpc) &&
                    previousNpc != null)
                {
                    rebuiltNpc.IdleActionCyclingEnabled = previousNpc.IdleActionCyclingEnabled;
                    string previousAction = previousNpc.CurrentAction;
                    if (!string.IsNullOrWhiteSpace(previousAction) && rebuiltNpc.HasAction(previousAction))
                    {
                        rebuiltNpc.SetAction(previousAction);
                    }
                }

                rebuiltNpcs.Add(rebuiltNpc);
            }

            _npcsArray = rebuiltNpcs.ToArray();
            _npcsById.Clear();
            for (int i = 0; i < _npcsArray.Length; i++)
            {
                NpcItem npc = _npcsArray[i];
                if (npc?.NpcInstance?.NpcInfo == null || !int.TryParse(npc.NpcInstance.NpcInfo.ID, out int npcId))
                {
                    continue;
                }

                _npcsById[npcId] = npc;
            }

            if (_activeNpcInteractionNpcId > 0)
            {
                _activeNpcInteractionNpc = FindNpcById(_activeNpcInteractionNpcId);
            }

            miniMapUi?.SetNpcMarkers(_npcsArray);

            if (_npcQuestFeedback.ActiveNpcId > 0)
            {
                ApplyNpcQuestFeedbackAnimation(currTickCount);
            }
        }


        private void OpenQuestDetailWindow(int questId)
        {
            if (questId <= 0 || uiWindowManager?.QuestDetailWindow == null)
            {
                return;
            }

            if (_activeQuestDetailQuestId != questId)
            {
                ResetQuestDetailInlineItemSelection();
            }

            _activeQuestDetailQuestId = questId;
            UpdateQuestDetailWindow();
            uiWindowManager.QuestDetailWindow.Show();
            uiWindowManager.BringToFront(uiWindowManager.QuestDetailWindow);
        }


        private void OpenQuestFromAlarmWindow(int questId)
        {
            if (questId <= 0 || uiWindowManager == null)
            {
                return;
            }

            if (_activeQuestDetailQuestId == questId && uiWindowManager.QuestDetailWindow?.IsVisible == true)
            {
                _activeQuestDetailQuestId = 0;
                ResetQuestDetailInlineItemSelection();
                uiWindowManager.QuestDetailWindow.SetDetailState(null, -1, 0);
                uiWindowManager.QuestDetailWindow.Hide();
                return;
            }


            uiWindowManager.ShowWindow(MapSimulatorWindowNames.Quest);
            SelectQuestInActiveWindow(questId);
            OpenQuestDetailWindow(questId);
        }


        private void OpenQuestLogFromAlarmWindow(int questId, bool focusSelectedQuest)
        {
            if (uiWindowManager == null)
            {
                return;
            }


            if (focusSelectedQuest)
            {
                // Recovered `CUIQuestAlarm::OnButtonClicked(BtQ)` alert branch closes then reopens Quest.
                if (uiWindowManager.GetWindow(MapSimulatorWindowNames.Quest)?.IsVisible == true)
                {
                    uiWindowManager.HideWindow(MapSimulatorWindowNames.Quest);
                }

                uiWindowManager.ShowWindow(MapSimulatorWindowNames.Quest);
                if (questId > 0)
                {
                    SelectQuestInActiveWindow(questId);
                    OpenQuestDetailWindow(questId);
                }


                return;

            }



            UIWindowBase questWindow = uiWindowManager.GetWindow(MapSimulatorWindowNames.Quest);
            if (questWindow?.IsVisible == true)
            {
                uiWindowManager.HideWindow(MapSimulatorWindowNames.Quest);
                return;
            }


            uiWindowManager.ShowWindow(MapSimulatorWindowNames.Quest);
            if (questId > 0)
            {
                SelectQuestInActiveWindow(questId);
            }
        }

        private void ResetQuestDetailFromQuestAlarmMutation()
        {
            _activeQuestDetailQuestId = 0;
            ResetQuestDetailInlineItemSelection();
            uiWindowManager?.QuestDetailWindow?.SetDetailState(null, -1, 0);
        }


        private void UpdateQuestDetailWindow()
        {
            if (_activeQuestDetailQuestId <= 0 || uiWindowManager?.QuestDetailWindow == null)
            {
                return;
            }


            IReadOnlyList<int> questIds = GetVisibleQuestIdsForCurrentTab();
            if (questIds.Count == 0)
            {
                uiWindowManager.QuestDetailWindow.SetDetailState(null, -1, 0);
                return;
            }


            int navigationIndex = -1;
            for (int i = 0; i < questIds.Count; i++)
            {
                if (questIds[i] == _activeQuestDetailQuestId)
                {
                    navigationIndex = i;
                    break;
                }
            }


            if (navigationIndex < 0)
            {
                if (_activeQuestDetailQuestId != questIds[0])
                {
                    ResetQuestDetailInlineItemSelection();
                }
                _activeQuestDetailQuestId = questIds[0];
                navigationIndex = 0;
                SelectQuestInActiveWindow(_activeQuestDetailQuestId);
            }


            QuestWindowDetailState state = GetQuestWindowDetailStateWithPacketState(_activeQuestDetailQuestId);
            state = ApplyQuestDetailWindowButtonParity(state);
            _questRuntime.RecordQuestDetailViewed(_activeQuestDetailQuestId);
            uiWindowManager.QuestDetailWindow.SetDetailState(state, navigationIndex, questIds.Count);
        }



        private IReadOnlyList<int> GetVisibleQuestIdsForCurrentTab()
        {
            return uiWindowManager?.QuestWindow is QuestUI questWindow
                ? questWindow.GetCurrentTabQuestIds()
                : Array.Empty<int>();
        }


        private void SelectQuestInActiveWindow(int questId)
        {
            if (uiWindowManager?.QuestWindow is QuestUI questWindow)
            {
                questWindow.SelectQuestById(questId);
            }
        }


        private void NavigateQuestDetail(int direction)
        {
            IReadOnlyList<int> questIds = GetVisibleQuestIdsForCurrentTab();
            if (questIds.Count <= 1)
            {
                return;
            }


            int currentIndex = -1;
            for (int i = 0; i < questIds.Count; i++)
            {
                if (questIds[i] == _activeQuestDetailQuestId)
                {
                    currentIndex = i;
                    break;
                }
            }
            if (currentIndex < 0)
            {
                currentIndex = 0;
            }


            int nextIndex = Math.Max(0, Math.Min(questIds.Count - 1, currentIndex + direction));
            if (nextIndex == currentIndex)
            {
                return;
            }


            _activeQuestDetailQuestId = questIds[nextIndex];
            ResetQuestDetailInlineItemSelection();
            SelectQuestInActiveWindow(_activeQuestDetailQuestId);
            UpdateQuestDetailWindow();
        }


        private void HandleQuestDetailAction(QuestWindowActionKind action)
        {
            if (_activeQuestDetailQuestId <= 0)
            {
                return;
            }


            QuestWindowActionResult result = action switch
            {
                QuestWindowActionKind.Accept => _questRuntime.TryAcceptFromQuestWindow(_activeQuestDetailQuestId, _playerManager?.Player?.Build),
                QuestWindowActionKind.GiveUp => _questRuntime.TryGiveUpFromQuestWindow(_activeQuestDetailQuestId),
                QuestWindowActionKind.Complete => _questRuntime.TryCompleteFromQuestWindow(_activeQuestDetailQuestId, _playerManager?.Player?.Build),
                QuestWindowActionKind.Track => TrackQuestInAlarmWindow(_activeQuestDetailQuestId),
                QuestWindowActionKind.LocateNpc => LocateQuestNpcFromDetailWindow(_activeQuestDetailQuestId),
                QuestWindowActionKind.LocateMob => LocateQuestMobFromDetailWindow(_activeQuestDetailQuestId),
                QuestWindowActionKind.QuestGuide => LocateQuestMobFromDetailWindow(_activeQuestDetailQuestId),
                QuestWindowActionKind.QuestDeliveryAccept => HandleQuestDetailDeliveryAction(_activeQuestDetailQuestId, false),
                QuestWindowActionKind.QuestDeliveryComplete => HandleQuestDetailDeliveryAction(_activeQuestDetailQuestId, true),
                _ => null
            };
            HandleQuestWindowActionResult(result);

        }

        private void HandleQuestDetailInlineReference(QuestDetailInlineReference reference)
        {
            if (reference.Kind == QuestDetailInlineReferenceKind.Item)
            {
                RememberQuestDetailInlineItemSelection(_activeQuestDetailQuestId, reference.TargetId);
            }

            QuestWindowActionResult result = OpenQuestDetailInlineReferenceWorldMap(reference);
            HandleQuestWindowActionResult(result);
        }

        private static bool ShouldRouteInlineReferenceToDemandDeliveryHandoff(QuestDetailInlineReference reference)
        {
            if (reference.Kind != QuestDetailInlineReferenceKind.Item)
            {
                return false;
            }

            return reference.Source is QuestDetailInlineReferenceSource.RequirementText
                or QuestDetailInlineReferenceSource.RequirementLine
                or QuestDetailInlineReferenceSource.HintText
                or QuestDetailInlineReferenceSource.Unknown;
        }

        internal static bool ShouldRouteInlineReferenceToDemandDeliveryHandoffForTesting(QuestDetailInlineReference reference)
        {
            return ShouldRouteInlineReferenceToDemandDeliveryHandoff(reference);
        }

        private QuestWindowActionResult OpenQuestDetailInlineReferenceWorldMap(QuestDetailInlineReference reference)
        {
            if (reference.TargetId <= 0)
            {
                return new QuestWindowActionResult
                {
                    QuestId = _activeQuestDetailQuestId,
                    Messages = new[] { "This quest-detail reference does not expose a usable world-map target." }
                };
            }

            QuestDemandItemQueryState detailItemQueryState = null;
            bool hasDetailItemQuery = reference.Kind == QuestDetailInlineReferenceKind.Item &&
                                      _activeQuestDetailQuestId > 0 &&
                                      _questRuntime.TryBuildQuestDemandItemQuery(_activeQuestDetailQuestId, out detailItemQueryState) &&
                                      detailItemQueryState != null;

            if (reference.Kind == QuestDetailInlineReferenceKind.Item &&
                _activeQuestDetailQuestId > 0)
            {
                QuestWindowDetailState detailState = GetQuestWindowDetailStateWithPacketState(_activeQuestDetailQuestId);
                bool routesToDeliveryHandoff = detailState != null &&
                                               ShouldRouteInlineReferenceToDemandDeliveryHandoff(reference) &&
                                               detailState.DeliveryType != QuestDetailDeliveryType.None &&
                                               (detailState.TargetItemId == reference.TargetId ||
                                                IsQuestDetailDeliveryRequirementItem(
                                                    _activeQuestDetailQuestId,
                                                    reference.TargetId,
                                                    detailState.DeliveryType));
                if (routesToDeliveryHandoff)
                {
                    bool completionPhase = detailState.DeliveryType == QuestDetailDeliveryType.Complete;
                    int inlineTargetItemId = reference.TargetId > 0
                        ? reference.TargetId
                        : detailState.TargetItemId.GetValueOrDefault();
                    return HandleQuestDeliveryLocalHandoff(
                        _activeQuestDetailQuestId,
                        completionPhase,
                        sourceContext: $"quest-detail inline demand-item {(completionPhase ? "completion" : "accept")} handoff",
                        localHandoff: () => ApplyDeliveryQuestLaunch(
                            _activeQuestDetailQuestId,
                            inlineTargetItemId,
                            Array.Empty<int>(),
                            detailState.DeliveryType),
                        targetItemIdOverride: inlineTargetItemId);
                }

                if (hasDetailItemQuery &&
                    detailItemQueryState.VisibleItemIds != null &&
                    detailItemQueryState.VisibleItemIds.Contains(reference.TargetId))
                {
                    return new QuestWindowActionResult
                    {
                        QuestId = _activeQuestDetailQuestId,
                        Messages = new[] { LaunchQuestDemandItemQuery(detailItemQueryState, reference.TargetId) }
                    };
                }
            }

            int currentMapId = _mapBoard?.MapInfo?.id ?? 0;
            IReadOnlyList<int> mapIds;
            WorldMapUI.SearchResultKind resultKind;
            string label;

            switch (reference.Kind)
            {
                case QuestDetailInlineReferenceKind.Npc:
                    mapIds = ResolveQuestNpcMapIds(reference.TargetId);
                    resultKind = WorldMapUI.SearchResultKind.Npc;
                    label = ResolveQuestDetailInlineNpcName(reference);
                    break;
                case QuestDetailInlineReferenceKind.Mob:
                    mapIds = ResolveQuestMobMapIds(reference.TargetId);
                    resultKind = WorldMapUI.SearchResultKind.Mob;
                    label = ResolveQuestDetailInlineMobName(reference);
                    break;
                case QuestDetailInlineReferenceKind.Map:
                    mapIds = new[] { reference.TargetId };
                    resultKind = WorldMapUI.SearchResultKind.Field;
                    label = ResolveQuestDetailInlineMapName(reference);
                    break;
                case QuestDetailInlineReferenceKind.Item:
                    mapIds = ResolveQuestDemandQueryMapIds(reference.TargetId, fallbackMapId: 0);
                    if ((mapIds == null || mapIds.Count == 0) &&
                        hasDetailItemQuery &&
                        detailItemQueryState.VisibleItemMapIds != null &&
                        detailItemQueryState.VisibleItemMapIds.TryGetValue(reference.TargetId, out IReadOnlyList<int> runtimeMapIds) &&
                        runtimeMapIds != null &&
                        runtimeMapIds.Count > 0)
                    {
                        mapIds = runtimeMapIds;
                    }

                    if ((mapIds == null || mapIds.Count == 0) &&
                        _activeQuestDetailQuestId > 0 &&
                        _questRuntime.TryGetQuestWorldMapTarget(_activeQuestDetailQuestId, _playerManager?.Player?.Build, out QuestWorldMapTarget inlineTarget) &&
                        inlineTarget?.Kind == QuestWorldMapTargetKind.Item &&
                        inlineTarget.EntityId == reference.TargetId)
                    {
                        mapIds = inlineTarget.MapIds?.Count > 0
                            ? inlineTarget.MapIds
                            : (inlineTarget.MapId > 0 ? new[] { inlineTarget.MapId } : Array.Empty<int>());
                    }

                    resultKind = WorldMapUI.SearchResultKind.Item;
                    label = ResolveQuestDetailInlineItemName(reference);
                    if ((mapIds == null || mapIds.Count == 0) &&
                        hasDetailItemQuery &&
                        detailItemQueryState.HiddenItemCount > 0 &&
                        !string.IsNullOrWhiteSpace(detailItemQueryState.FallbackNpcName))
                    {
                        resultKind = WorldMapUI.SearchResultKind.Npc;
                        label = detailItemQueryState.FallbackNpcName;
                    }
                    break;
                default:
                    return new QuestWindowActionResult
                    {
                        QuestId = _activeQuestDetailQuestId,
                        Messages = new[] { "This quest-detail reference kind is not modeled by the world-map owner." }
                    };
            }

            if (mapIds == null || mapIds.Count == 0)
            {
                mapIds = currentMapId > 0 ? new[] { currentMapId } : Array.Empty<int>();
            }

            int focusMapId = mapIds.Count > 0 ? mapIds[0] : currentMapId;
            _lastQuestDetailInlineWorldMapReference = reference;
            _lastQuestDetailInlineWorldMapIds = mapIds.Where(mapId => mapId > 0).Distinct().OrderBy(mapId => mapId).ToArray();

            RefreshWorldMapWindow(focusMapId);
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.WorldMap) is not WorldMapUI worldMapWindow)
            {
                return new QuestWindowActionResult
                {
                    QuestId = _activeQuestDetailQuestId,
                    Messages = new[] { "World map window is not available in this UI build." }
                };
            }

            bool focused = worldMapWindow.FocusSearchResult(resultKind, label, focusMapId);
            uiWindowManager.ShowWindow(MapSimulatorWindowNames.WorldMap);
            uiWindowManager.BringToFront(worldMapWindow);

            string mapSuffix = _lastQuestDetailInlineWorldMapIds.Count > 1
                ? $" across {_lastQuestDetailInlineWorldMapIds.Count} WZ-indexed map result(s)"
                : string.Empty;
            return new QuestWindowActionResult
            {
                QuestId = _activeQuestDetailQuestId,
                Messages = focused
                    ? new[] { $"Opened the world map for quest-detail {reference.Kind.ToString().ToLowerInvariant()} reference {label}{mapSuffix}." }
                    : new[] { $"Opened the world map, but quest-detail reference {label} could not be focused in the search owner{mapSuffix}." }
            };
        }

        private void HandleQuestWindowActionResult(QuestWindowActionResult result)
        {
            if (result?.PendingRewardChoicePrompt != null)
            {
                OpenQuestRewardChoicePrompt(result.PendingRewardChoicePrompt, QuestRewardRaiseSourceKind.QuestWindow);
                return;
            }

            if (result?.Messages != null)
            {
                for (int i = 0; i < result.Messages.Count; i++)
                {
                    if (!string.IsNullOrWhiteSpace(result.Messages[i]))
                    {
                        _chat.AddMessage(result.Messages[i], new Color(255, 228, 151), currTickCount);
                    }
                }
            }

            if (result?.StateChanged == true)
            {
                RefreshQuestUiState();
                SelectQuestInActiveWindow(_activeQuestDetailQuestId);
                UpdateQuestDetailWindow();
                bool publishedViaPublications =
                    PublishDynamicObjectTagStatesForScriptPublications(result.PublishedScriptPublications, currTickCount);
                if (!publishedViaPublications)
                {
                    PublishDynamicObjectTagStatesForScriptNames(result.PublishedScriptNames, currTickCount);
                }
            }
        }

        private void HandleNpcOverlayQuestActionResult(QuestActionResult result, int questId)
        {
            if (result?.PendingRewardChoicePrompt != null)
            {
                OpenQuestRewardChoicePrompt(result.PendingRewardChoicePrompt, QuestRewardRaiseSourceKind.NpcOverlay);
                return;
            }

            if (result?.Messages != null)
            {
                for (int i = 0; i < result.Messages.Count; i++)
                {
                    if (!string.IsNullOrWhiteSpace(result.Messages[i]))
                    {
                        _chat.AddMessage(result.Messages[i], new Color(255, 228, 151), currTickCount);
                    }
                }
            }

            if (result?.StateChanged == true)
            {
                RefreshQuestUiState();
                SelectQuestInActiveWindow(result.PreferredQuestId ?? questId);
                UpdateQuestDetailWindow();

                bool publishedViaPublications =
                    PublishDynamicObjectTagStatesForScriptPublications(result.PublishedScriptPublications, currTickCount);
                if (!publishedViaPublications)
                {
                    PublishDynamicObjectTagStatesForScriptNames(result.PublishedScriptNames, currTickCount);
                }
                ShowNpcQuestFeedback(result, currTickCount);

                if (_activeNpcInteractionNpc != null)
                {
                    OpenNpcInteraction(_activeNpcInteractionNpc, result.PreferredQuestId ?? questId);
                }
                else
                {
                    _npcInteractionOverlay?.Close();
                }
            }
        }



        private QuestWindowActionResult TrackQuestInAlarmWindow(int questId)

        {

            string fieldRestrictionMessage = GetFieldWindowRestrictionMessage(MapSimulatorWindowNames.QuestAlarm);
            if (!string.IsNullOrWhiteSpace(fieldRestrictionMessage))
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[] { fieldRestrictionMessage }
                };
            }
            if (questId <= 0 || uiWindowManager?.GetWindow(MapSimulatorWindowNames.QuestAlarm) is not QuestAlarmWindow questAlarmWindow)
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[] { "Quest alarm window is not available in this UI build." }
                };
            }


            bool wasTracked = questAlarmWindow.IsQuestTracked(questId);
            bool registered = questAlarmWindow.TrackQuest(questId);

            questAlarmWindow.Show();

            uiWindowManager.BringToFront(questAlarmWindow);



            return new QuestWindowActionResult
            {
                QuestId = questId,
                Messages = new[]
                {
                    registered || wasTracked
                        ? "Tracking quest in the quest alarm window."
                        : "This quest cannot be registered in the quest alarm."
                }
            };
        }

        private QuestWindowDetailState ApplyQuestDetailWindowButtonParity(QuestWindowDetailState state)
        {
            if (state == null ||
                state.PrimaryAction != QuestWindowActionKind.Track ||
                uiWindowManager?.GetWindow(MapSimulatorWindowNames.QuestAlarm) is not QuestAlarmWindow questAlarmWindow)
            {
                return state;
            }

            bool isTracked = questAlarmWindow.IsQuestTracked(state.QuestId);
            bool canTrack = questAlarmWindow.CanTrackQuest(state.QuestId);
            if (!isTracked && canTrack)
            {
                return state;
            }

            return new QuestWindowDetailState
            {
                QuestId = state.QuestId,
                Title = state.Title,
                HeaderNoteText = state.HeaderNoteText,
                State = state.State,
                SummaryText = state.SummaryText,
                RequirementText = state.RequirementText,
                RewardText = state.RewardText,
                HintText = state.HintText,
                NpcText = state.NpcText,
                RequirementLines = state.RequirementLines,
                RewardLines = state.RewardLines,
                CurrentProgress = state.CurrentProgress,
                TotalProgress = state.TotalProgress,
                PrimaryAction = state.PrimaryAction,
                PrimaryActionEnabled = false,
                PrimaryActionSelected = isTracked,
                PrimaryActionLabel = isTracked ? "Tracked" : state.PrimaryActionLabel,
                SecondaryAction = state.SecondaryAction,
                SecondaryActionEnabled = state.SecondaryActionEnabled,
                SecondaryActionLabel = state.SecondaryActionLabel,
                TertiaryAction = state.TertiaryAction,
                TertiaryActionEnabled = state.TertiaryActionEnabled,
                TertiaryActionLabel = state.TertiaryActionLabel,
                QuaternaryAction = state.QuaternaryAction,
                QuaternaryActionEnabled = state.QuaternaryActionEnabled,
                QuaternaryActionLabel = state.QuaternaryActionLabel,
                TargetNpcId = state.TargetNpcId,
                TargetNpcName = state.TargetNpcName,
                TargetMobId = state.TargetMobId,
                TargetMobName = state.TargetMobName,
                TargetItemId = state.TargetItemId,
                TargetItemName = state.TargetItemName,
                HasDetailInset = state.HasDetailInset,
                TimeLimitSeconds = state.TimeLimitSeconds,
                RemainingTimeSeconds = state.RemainingTimeSeconds,
                TimerUiKey = state.TimerUiKey,
                DeliveryType = state.DeliveryType,
                DeliveryActionEnabled = state.DeliveryActionEnabled,
                DeliveryCashItemId = state.DeliveryCashItemId,
                DeliveryCashItemName = state.DeliveryCashItemName,
                NpcButtonStyle = state.NpcButtonStyle
            };
        }


        private QuestWindowActionResult LocateQuestNpcFromDetailWindow(int questId)
        {
            if (!_questRuntime.TryGetQuestWorldMapTarget(questId, _playerManager?.Player?.Build, out QuestWorldMapTarget target)
                || target == null)
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[] { "This quest does not expose a world-map target in the loaded data." }
                };
            }


            return OpenQuestWorldMapTargetFromDetailWindow(questId, target, preferPacketGuideMapsForMobs: false);
        }


        private QuestWindowActionResult LocateQuestMobFromDetailWindow(int questId)
        {
            if (!_questRuntime.TryGetQuestWorldMapTarget(questId, _playerManager?.Player?.Build, out QuestWorldMapTarget target)
                || target == null)
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[] { "This quest does not expose a quest-guide target in the loaded data." }
                };
            }

            return OpenQuestWorldMapTargetFromDetailWindow(questId, target, preferPacketGuideMapsForMobs: true);
        }

        private QuestWindowActionResult OpenQuestWorldMapTargetFromDetailWindow(
            int questId,
            QuestWorldMapTarget target,
            bool preferPacketGuideMapsForMobs)
        {
            if (target == null)
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[] { "This quest does not expose a world-map target in the loaded data." }
                };
            }

            RefreshWorldMapWindow(_mapBoard?.MapInfo?.id ?? 0);
            if (uiWindowManager?.GetWindow(MapSimulatorWindowNames.WorldMap) is not WorldMapUI worldMapWindow)
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[] { "World map window is not available in this UI build." }
                };
            }


            int targetMapId = target.MapId > 0 ? target.MapId : (_mapBoard?.MapInfo?.id ?? 0);
            bool focused = false;
            string successMessage;
            string failureMessage;

            switch (target.Kind)
            {
                case QuestWorldMapTargetKind.Mob:
                    IReadOnlyList<int> packetGuideMapIds = Array.Empty<int>();
                    bool hasPacketGuideMaps = preferPacketGuideMapsForMobs &&
                                              target.EntityId is int targetMobId &&
                                              TryGetPacketQuestGuideMapIds(targetMobId, out packetGuideMapIds) &&
                                              packetGuideMapIds.Count > 0;
                    if (hasPacketGuideMaps)
                    {
                        targetMapId = packetGuideMapIds[0];
                    }

                    focused = worldMapWindow.FocusSearchResult(WorldMapUI.SearchResultKind.Mob, target.Label, targetMapId);
                    successMessage = hasPacketGuideMaps
                        ? $"Opened the world map search for {target.Label} using packet-authored quest-guide maps."
                        : $"Opened the world map search for quest mob {target.Label}.";
                    failureMessage = hasPacketGuideMaps
                        ? $"Opened the world map, but {target.Label} could not be focused even with packet-authored quest-guide maps."
                        : $"Opened the world map, but {target.Label} is not in the current field search results.";
                    break;
                case QuestWorldMapTargetKind.Item:
                    if (_questRuntime.TryBuildQuestDemandItemQuery(questId, out QuestDemandItemQueryState itemQueryState)
                        && itemQueryState != null)
                    {
                        int preferredVisibleItemId = ResolveQuestDetailInlineSelectedItemId(questId);
                        if (preferredVisibleItemId <= 0 && target.EntityId.GetValueOrDefault() > 0)
                        {
                            preferredVisibleItemId = target.EntityId.Value;
                        }

                        return new QuestWindowActionResult
                        {
                            QuestId = questId,
                            Messages = new[] { LaunchQuestDemandItemQuery(itemQueryState, preferredVisibleItemId) }
                        };
                    }

                    if (!string.IsNullOrWhiteSpace(target.FallbackNpcName))
                    {
                        focused = worldMapWindow.FocusSearchResult(WorldMapUI.SearchResultKind.Npc, target.FallbackNpcName, targetMapId);
                        successMessage = $"Opened the world map for {target.FallbackNpcName}; {target.Label} still needs to be delivered.";
                        failureMessage = $"Opened the world map, but neither {target.FallbackNpcName} nor {target.Label} could be resolved in the current field search results.";
                    }
                    else
                    {
                        QuestDetailDeliveryType detailDeliveryType =
                            GetQuestWindowDetailStateWithPacketState(questId)?.DeliveryType
                            ?? QuestDetailDeliveryType.None;

                        int itemTargetId = target.EntityId.GetValueOrDefault();
                        if (detailDeliveryType is QuestDetailDeliveryType.Accept or QuestDetailDeliveryType.Complete &&
                            itemTargetId > 0 &&
                            IsQuestDetailDeliveryRequirementItem(questId, itemTargetId, detailDeliveryType))
                        {
                            bool completionPhase = detailDeliveryType == QuestDetailDeliveryType.Complete;
                            return HandleQuestDeliveryLocalHandoff(
                                questId,
                                completionPhase,
                                sourceContext: $"quest-detail guide item {(completionPhase ? "completion" : "accept")} handoff",
                                localHandoff: () => ApplyDeliveryQuestLaunch(
                                    questId,
                                    itemTargetId,
                                    Array.Empty<int>(),
                                    detailDeliveryType),
                                targetItemIdOverride: itemTargetId);
                        }

                        string deliveryMessage = ApplyDeliveryQuestLaunch(
                            questId,
                            itemTargetId,
                            Array.Empty<int>(),
                            detailDeliveryType);
                        return new QuestWindowActionResult
                        {
                            QuestId = questId,
                            Messages = new[] { deliveryMessage }
                        };
                    }

                    break;
                default:
                    focused = worldMapWindow.FocusSearchResult(WorldMapUI.SearchResultKind.Npc, target.Label, targetMapId);
                    successMessage = $"Opened the world map search for {target.Label}.";
                    failureMessage = $"Opened the world map, but {target.Label} is not in the current field search results.";
                    break;
            }

            uiWindowManager.ShowWindow(MapSimulatorWindowNames.WorldMap);
            uiWindowManager.BringToFront(worldMapWindow);

            return new QuestWindowActionResult
            {
                QuestId = questId,
                Messages = focused
                    ? new[] { successMessage }
                    : new[] { failureMessage }
            };
        }

        private QuestWindowActionResult HandleQuestDetailDeliveryAction(int questId, bool completionPhase)
        {
            QuestWindowDetailState detailState = GetQuestWindowDetailStateWithPacketState(questId);
            int detailTargetItemId = detailState?.TargetItemId ?? 0;
            QuestDetailDeliveryType detailDeliveryType = detailState?.DeliveryType ?? QuestDetailDeliveryType.None;
            int targetItemOverride = ResolveQuestDetailInlineSelectedItemId(questId);
            if (targetItemOverride <= 0)
            {
                targetItemOverride = detailTargetItemId;
            }

            return HandleQuestDeliveryLocalHandoff(
                questId,
                completionPhase,
                sourceContext: $"quest-detail {(completionPhase ? "completion" : "accept")} button",
                localHandoff: () => ApplyDeliveryQuestLaunch(
                    questId,
                    targetItemOverride,
                    Array.Empty<int>(),
                    detailDeliveryType),
                targetItemIdOverride: targetItemOverride);
        }

        private void RememberQuestDetailInlineItemSelection(int questId, int itemId)
        {
            if (questId <= 0 || itemId <= 0)
            {
                return;
            }

            _lastQuestDetailInlineItemQuestId = questId;
            _lastQuestDetailInlineItemId = itemId;
        }

        private int ResolveQuestDetailInlineSelectedItemId(int questId)
        {
            return _lastQuestDetailInlineItemQuestId == questId
                ? Math.Max(0, _lastQuestDetailInlineItemId)
                : 0;
        }

        private void ResetQuestDetailInlineItemSelection()
        {
            _lastQuestDetailInlineItemQuestId = 0;
            _lastQuestDetailInlineItemId = 0;
        }

        private bool IsQuestDetailDeliveryRequirementItem(int questId, int itemId, QuestDetailDeliveryType deliveryType)
        {
            if (_questRuntime.IsQuestDeliveryRequirementItem(questId, itemId, deliveryType))
            {
                return true;
            }

            if (questId <= 0 || itemId <= 0 || deliveryType == QuestDetailDeliveryType.None)
            {
                return false;
            }

            QuestDetailDeliveryType packetOwnedHint = ResolvePacketOwnedQuestDeliveryTypeHint(questId);
            if (packetOwnedHint != deliveryType)
            {
                return false;
            }

            return _questRuntime.IsQuestDeliveryRequirementItemIgnoringQuestState(
                questId,
                itemId,
                deliveryType);
        }

        private QuestWindowActionResult HandleQuestDeliveryLocalHandoff(
            int questId,
            bool completionPhase,
            string sourceContext,
            Func<string> localHandoff,
            int targetItemIdOverride = 0,
            MapleLib.WzLib.WzStructure.Data.ItemStructure.InventoryType resolvedInventoryType = MapleLib.WzLib.WzStructure.Data.ItemStructure.InventoryType.NONE,
            int resolvedRuntimeSlotIndex = -1,
            int resolvedClientSlotIndex = 0)
        {
            if (IsPacketOwnedDeliveryQuestBlocked(questId))
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[]
                    {
                        $"{sourceContext} is currently blocked by the packet-owned disallowed-delivery quest list for quest #{questId}."
                    }
                };
            }

            QuestWindowDetailState state = GetQuestWindowDetailStateWithPacketState(questId);
            int targetItemId = 0;
            if (targetItemIdOverride > 0 &&
                state?.DeliveryType is QuestDetailDeliveryType.Accept or QuestDetailDeliveryType.Complete &&
                IsQuestDetailDeliveryRequirementItem(questId, targetItemIdOverride, state.DeliveryType))
            {
                targetItemId = targetItemIdOverride;
            }

            if (targetItemId <= 0)
            {
                targetItemId = state?.TargetItemId ?? 0;
            }

            if (targetItemId <= 0)
            {
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[] { "This quest does not expose an item-backed delivery target in the loaded data." }
                };
            }

            int cashItemId = state.DeliveryCashItemId ?? 0;
            string targetItemName = state.TargetItemId == targetItemId && !string.IsNullOrWhiteSpace(state.TargetItemName)
                ? state.TargetItemName
                : ResolvePickupItemName(targetItemId);
            if (string.IsNullOrWhiteSpace(targetItemName))
            {
                targetItemName = $"Item {targetItemId}";
            }
            string cashItemName = string.IsNullOrWhiteSpace(state.DeliveryCashItemName) ? $"Cash item {cashItemId}" : state.DeliveryCashItemName;
            MapleLib.WzLib.WzStructure.Data.ItemStructure.InventoryType deliveryInventoryType = resolvedInventoryType;
            int deliveryRuntimeSlotIndex = resolvedRuntimeSlotIndex;
            int deliveryClientSlotIndex = resolvedClientSlotIndex;
            bool resolvedCashSlot = deliveryInventoryType != MapleLib.WzLib.WzStructure.Data.ItemStructure.InventoryType.NONE
                && deliveryRuntimeSlotIndex >= 0
                && deliveryClientSlotIndex > 0;
            if (!resolvedCashSlot)
            {
                resolvedCashSlot = TryResolveQuestDeliveryCashItemSlot(
                    cashItemId,
                    out deliveryInventoryType,
                    out deliveryRuntimeSlotIndex,
                    out deliveryClientSlotIndex);
            }

            if (cashItemId <= 0)
            {
                string deliveryMessage = localHandoff?.Invoke() ?? "Opened the local quest-delivery handoff.";
                RegisterPendingQuestDeliveryQuestResult(
                    questId,
                    completionPhase,
                    cashItemId: 0,
                    commoditySn: 0,
                    sourceContext);
                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[]
                    {
                        $"{deliveryMessage} Routed from the {sourceContext}, and the loaded quest data did not require a delivery cash item for {targetItemName}."
                    }
                };
            }

            if (cashItemId > 0 && HasInventoryItem(cashItemId))
            {
                bool consumedCashItem = resolvedCashSlot
                    && uiWindowManager?.InventoryWindow is IInventoryRuntime inventoryWindow
                    && inventoryWindow.TryConsumeItemAtSlot(deliveryInventoryType, deliveryRuntimeSlotIndex, cashItemId, 1);
                if (consumedCashItem)
                {
                    QuestDeliveryCashItemUseRequest request = QuestDeliveryCashItemUseRequest.Create(
                        completionPhase
                            ? QuestDeliveryCashItemUseRequestKind.CompleteDelivery
                            : QuestDeliveryCashItemUseRequestKind.AcceptDelivery,
                        updateTime: currTickCount,
                        cashItemSlotPosition: deliveryClientSlotIndex,
                        cashItemId: cashItemId);
                    string consumeRequestDispatch = BuildQuestDeliveryConsumeCashItemUseRequestDispatchLabel(
                        request,
                        sourceContext);
                    RegisterPendingQuestDeliveryQuestResult(
                        questId,
                        completionPhase,
                        cashItemId,
                        commoditySn: 0,
                        sourceContext);
                    string deliveryMessage = localHandoff?.Invoke() ?? "Opened the local quest-delivery handoff.";
                    return new QuestWindowActionResult
                    {
                        QuestId = questId,
                        Messages = new[]
                        {
                            $"{deliveryMessage} Consumed {cashItemName} from {deliveryInventoryType} slot #{deliveryClientSlotIndex} through the client-shaped delivery-item seam and routed the {sourceContext} for {targetItemName} into the packet-owned delivery handoff. {consumeRequestDispatch}"
                        }
                    };
                }

                return new QuestWindowActionResult
                {
                    QuestId = questId,
                    Messages = new[]
                    {
                        resolvedCashSlot
                            ? $"{sourceContext} could not consume {cashItemName} from {deliveryInventoryType} slot #{deliveryClientSlotIndex}, so the packet-owned delivery handoff stayed blocked before the created-NPC interaction could open for {targetItemName}."
                            : $"{sourceContext} could not resolve a live inventory slot for {cashItemName}, so the packet-owned delivery handoff stayed blocked before the created-NPC interaction could open for {targetItemName}."
                    }
                };
            }

            int fallbackCommoditySn = completionPhase ? 50200219 : 50200218;
            long fallbackCommodityPrice = 0L;
            int resolvedCommoditySn = 0;
            long resolvedCommodityPrice = 0L;
            bool resolvedCommodityFromWz = cashItemId > 0
                && AdminShopDialogUI.TryResolveBestCommoditySerialNumberForItem(cashItemId, out resolvedCommoditySn, out resolvedCommodityPrice);
            if (resolvedCommodityFromWz)
            {
                fallbackCommoditySn = resolvedCommoditySn;
                fallbackCommodityPrice = resolvedCommodityPrice;
            }

            RegisterPendingQuestDeliveryQuestResult(
                questId,
                completionPhase,
                cashItemId,
                fallbackCommoditySn,
                sourceContext);
            string shopMessage = ApplyPacketOwnedGoToCommoditySn(fallbackCommoditySn);
            return new QuestWindowActionResult
            {
                QuestId = questId,
                Messages = new[]
                {
                    resolvedCommodityFromWz
                        ? $"{sourceContext} requested {cashItemName} through the packet-shaped Cash Shop seam by resolving item {cashItemId} to commodity SN {fallbackCommoditySn} in `Etc/Commodity.img` ({fallbackCommodityPrice.ToString("N0", CultureInfo.InvariantCulture)} NX). {shopMessage}"
                        : $"{sourceContext} could not use {cashItemName} locally, so it fell back to the packet-shaped Cash Shop seam at client commodity SN {fallbackCommoditySn}. {shopMessage}"
                }
            };
        }

        private string BuildQuestDeliveryConsumeCashItemUseRequestDispatchLabel(
            QuestDeliveryCashItemUseRequest request,
            string sourceContext)
        {
            if (request?.Payload == null)
            {
                return "Quest-detail delivery consume request remained simulator-local because the request payload was unavailable.";
            }

            byte[] payload = request.Payload.Count > 0
                ? request.Payload.ToArray()
                : Array.Empty<byte>();
            int opcode = request.Opcode;
            string payloadHex = payload.Length > 0 ? Convert.ToHexString(payload) : "<empty>";
            string contextLabel = string.IsNullOrWhiteSpace(sourceContext) ? "quest-detail delivery" : sourceContext;
            string dispatchStatus = "live bridge unavailable";
            string outboxStatus = "packet outbox unavailable";

            if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(opcode, payload, out dispatchStatus))
            {
                return $"{contextLabel} mirrored CWvsContext::SendConsumeCashItemUseRequest opcode {opcode} [{payloadHex}] through the live local-utility bridge. {dispatchStatus}";
            }

            if (_localUtilityPacketOutbox.TrySendOutboundPacket(opcode, payload, out outboxStatus))
            {
                return $"{contextLabel} mirrored CWvsContext::SendConsumeCashItemUseRequest opcode {opcode} [{payloadHex}] through the generic local-utility outbox after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
            }

            if (_localUtilityOfficialSessionBridge.IsRunning
                && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(opcode, payload, out string queuedBridgeStatus))
            {
                return $"{contextLabel} queued CWvsContext::SendConsumeCashItemUseRequest opcode {opcode} [{payloadHex}] for deferred official-session injection after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred bridge: {queuedBridgeStatus}";
            }

            if (_localUtilityPacketOutbox.TryQueueOutboundPacket(opcode, payload, out string queuedOutboxStatus))
            {
                return $"{contextLabel} queued CWvsContext::SendConsumeCashItemUseRequest opcode {opcode} [{payloadHex}] for deferred generic local-utility outbox delivery after the live bridge path was unavailable. Bridge: {dispatchStatus} Outbox: {outboxStatus} Deferred outbox: {queuedOutboxStatus}";
            }

            return $"{contextLabel} kept CWvsContext::SendConsumeCashItemUseRequest opcode {opcode} [{payloadHex}] simulator-local because neither the live bridge nor the generic outbox nor either deferred queue accepted the delivery owner request. Bridge: {dispatchStatus} Outbox: {outboxStatus}";
        }
        private bool TryHandleSkillUiLevelUp(SkillDisplayData skill)
        {
            if (skill == null || _playerManager?.Skills == null)
                return false;


            int playerLevel = _playerManager.Player?.Level ?? 1;

            if (skill.RequiredCharacterLevel > 0 && playerLevel < skill.RequiredCharacterLevel)

                return false;



            if (skill.RequiredSkillId > 0)
            {
                int requiredLevel = Math.Max(1, skill.RequiredSkillLevel);
                if (_playerManager.Skills.GetSkillLevel(skill.RequiredSkillId) < requiredLevel)
                    return false;
            }


            int currentLevel = _playerManager.Skills.GetSkillLevel(skill.SkillId);
            int targetLevel = Math.Min(skill.MaxLevel, Math.Max(currentLevel, skill.CurrentLevel) + 1);
            if (targetLevel <= currentLevel)
                return false;


            _playerManager.Skills.SetSkillLevel(skill.SkillId, targetLevel);

            return true;

        }



        private void HandlePlayerSkillCast(SkillCastInfo castInfo)

        {
            if (!TryRegisterLocalSkillCastThroughClientShowSkillEffectDirectPath(castInfo))
            {
                TryRegisterAnimationDisplayerSkillUse(castInfo);
            }

            _fieldRuleRuntime?.RegisterSuccessfulSkillUse(castInfo?.SkillData);



            int currentMapId = _mapBoard?.MapInfo?.id ?? -1;

            if (currentMapId < 0)

                return;



            if (IsMysticDoorSkill(castInfo)
                && TryResolveMysticDoorReturnTarget(out int returnMapId, out float returnX, out float returnY))
            {
                _temporaryPortalField?.TryCreateMysticDoor(castInfo, currentMapId, returnMapId, returnX, returnY);
            }


            _temporaryPortalField?.TryCreateOpenGate(castInfo, currentMapId);

        }

        private bool TryRegisterLocalSkillCastThroughClientShowSkillEffectDirectPath(SkillCastInfo castInfo)
        {
            if (!ShouldRegisterLocalSkillCastThroughClientShowSkillEffectDirectPathForTesting(castInfo))
            {
                return false;
            }

            return TryRegisterAnimationDisplayerSkillUse(castInfo);
        }



