        private static LoginAvatarLook ResolveLoginRosterAvatarLook(
            CharacterBuild sourceBuild,
            byte[] avatarLookPacket,
            out byte[] resolvedAvatarLookPacket)
        {
            resolvedAvatarLookPacket = null;

            if (avatarLookPacket?.Length > 0 &&
                LoginAvatarLookCodec.TryDecode(avatarLookPacket, out LoginAvatarLook packetAvatarLook, out _))
            {
                resolvedAvatarLookPacket = (byte[])avatarLookPacket.Clone();
                return packetAvatarLook;
            }

            return sourceBuild != null ? LoginAvatarLookCodec.CreateLook(sourceBuild) : null;
        }

        private bool ShouldShowOffBarSkillCooldownNotification(int skillId)
        {
            return skillId > 0 && !IsSkillRepresentedOnDirectHotkeyBar(skillId);
        }

        private bool HasBlockingStatusNoticeOwnerForSkillCooldownNotice(int currentTime, int incomingSkillId)
        {
            // Client parity seam:
            // CUIStatusBar::SetItemMsg blocks new item/float notice creation while quizPanel,
            // floatNotice, or itemMsg layer owners are alive.
            // Keep owner admission in one typed list so cooldown notice gating can mirror
            // cross-layer owner identity more closely than a flat boolean probe.
            IReadOnlyList<SkillCooldownNoticeUI.StatusBarNoticeOwnerState> owners =
                ResolveStatusBarNoticeOwnersForClientParity(currentTime);
            return SkillCooldownNoticeUI.HasBlockingStatusNoticeOwnerForClientParity(owners, incomingSkillId);
        }

        private IReadOnlyList<SkillCooldownNoticeUI.StatusBarNoticeOwnerState> ResolveStatusBarNoticeOwnersForClientParity(int currentTime)
        {
            _statusBarNoticeOwnerBuffer.Clear();

            if (_initialQuizTimerRuntime?.IsActive(currentTime) == true)
            {
                int remainingMs = Math.Max(0, _initialQuizTimerRuntime.GetRemainingMs(currentTime));
                _statusBarNoticeOwnerBuffer.Add(new SkillCooldownNoticeUI.StatusBarNoticeOwnerState(
                    StatusBarNoticeOwnerKind.QuizPanel,
                    OwnerIdentity: _initialQuizTimerRuntime.BoundCharacterId,
                    OwnerExpiresAtTick: currentTime + remainingMs,
                    OwnerSourceKind: WeatherMessageOwnerSourceKind.Unknown,
                    OwnerSkillId: 0,
                    IsPresent: true,
                    IsExpired: false));
            }

            if (_speedQuizOwnerRuntime?.IsActive(currentTime) == true)
            {
                int remainingMs = Math.Max(0, _speedQuizOwnerRuntime.GetRemainingMs(currentTime));
                _statusBarNoticeOwnerBuffer.Add(new SkillCooldownNoticeUI.StatusBarNoticeOwnerState(
                    StatusBarNoticeOwnerKind.QuizPanel,
                    OwnerIdentity: int.MaxValue,
                    OwnerExpiresAtTick: currentTime + remainingMs,
                    OwnerSourceKind: WeatherMessageOwnerSourceKind.Unknown,
                    OwnerSkillId: 0,
                    IsPresent: true,
                    IsExpired: false));
            }

            if (_localOverlayRuntime?.HasDamageMeterTimer(currentTime) == true)
            {
                _statusBarNoticeOwnerBuffer.Add(new SkillCooldownNoticeUI.StatusBarNoticeOwnerState(
                    StatusBarNoticeOwnerKind.FloatNotice,
                    OwnerIdentity: 1,
                    OwnerExpiresAtTick: _localOverlayRuntime.DamageMeterExpiresAt,
                    OwnerSourceKind: WeatherMessageOwnerSourceKind.Unknown,
                    OwnerSkillId: 0,
                    IsPresent: true,
                    IsExpired: false));
            }

            if (_localOverlayRuntime?.HasActiveFieldHazardNotice(currentTime) == true)
            {
                _statusBarNoticeOwnerBuffer.Add(new SkillCooldownNoticeUI.StatusBarNoticeOwnerState(
                    StatusBarNoticeOwnerKind.FloatNotice,
                    OwnerIdentity: 2,
                    OwnerExpiresAtTick: _localOverlayRuntime.LastFieldHazardNoticeExpiresAt,
                    OwnerSourceKind: WeatherMessageOwnerSourceKind.Unknown,
                    OwnerSkillId: 0,
                    IsPresent: true,
                    IsExpired: false));
            }

            IReadOnlyList<WeatherMessageInfo> weatherMessages = _fieldEffects?.WeatherMessages;
            if (weatherMessages != null)
            {
                for (int i = 0; i < weatherMessages.Count; i++)
                {
                    if (SkillCooldownNoticeUI.TryCreateStatusBarItemMsgOwnerForClientParity(
                        weatherMessages[i],
                        currentTime,
                        out SkillCooldownNoticeUI.StatusBarNoticeOwnerState itemMsgOwner))
                    {
                        _statusBarNoticeOwnerBuffer.Add(itemMsgOwner);
                    }
                }
            }

            return _statusBarNoticeOwnerBuffer;
        }


        private void LoadSkillCooldownNoticeUiFrame()
        {
            WzImage basicUiImage = Program.FindImage("UI", "Basic.img");
            WzSubProperty noticeSource = ResolveSkillCooldownNoticeFrameSource(basicUiImage);
            if (noticeSource == null)
            {
                return;
            }


            Texture2D top = LoadUiCanvasTexture(noticeSource["t"] as WzCanvasProperty);

            Texture2D center = LoadUiCanvasTexture(noticeSource["c"] as WzCanvasProperty);

            Texture2D bottom = LoadUiCanvasTexture(noticeSource["s"] as WzCanvasProperty);

            _skillCooldownNoticeUI.SetFrameTextures(top, center, bottom);
        }

        private static WzSubProperty ResolveSkillCooldownNoticeFrameSource(WzImage basicUiImage)
        {
            if (basicUiImage == null)
            {
                return null;
            }

            const string fallbackNoticeFamily = "Notice3";
            string[] candidateNames = { "Notice2", "Notice3", "Notice4", "Notice5", "Notice6" };
            List<SkillCooldownNoticeUI.NoticeFrameCandidate> candidates = new(candidateNames.Length);
            for (int i = 0; i < candidateNames.Length; i++)
            {
                string name = candidateNames[i];
                if (basicUiImage[name] is not WzSubProperty noticeFamily)
                {
                    continue;
                }

                candidates.Add(CreateSkillCooldownNoticeFrameCandidate(name, noticeFamily));
            }

            string resolvedFamilyName = SkillCooldownNoticeUI.ResolveNoticeFrameFamilyForClientParity(candidates);
            if (!string.IsNullOrWhiteSpace(resolvedFamilyName)
                && basicUiImage[resolvedFamilyName] is WzSubProperty resolvedFamily)
            {
                return resolvedFamily;
            }

            return basicUiImage[fallbackNoticeFamily] as WzSubProperty;
        }

        private static SkillCooldownNoticeUI.NoticeFrameCandidate CreateSkillCooldownNoticeFrameCandidate(
            string name,
            WzSubProperty noticeFamily)
        {
            WzCanvasProperty top = noticeFamily?["t"] as WzCanvasProperty;
            WzCanvasProperty center = noticeFamily?["c"] as WzCanvasProperty;
            WzCanvasProperty bottom = noticeFamily?["s"] as WzCanvasProperty;

            return new SkillCooldownNoticeUI.NoticeFrameCandidate(
                name,
                top != null,
                center != null,
                bottom != null,
                top?.PngProperty?.Width ?? 0,
                top?.PngProperty?.Height ?? 0,
                center?.PngProperty?.Width ?? 0,
                center?.PngProperty?.Height ?? 0,
                bottom?.PngProperty?.Width ?? 0,
                bottom?.PngProperty?.Height ?? 0,
                CountSkillCooldownNoticeExtraParts(noticeFamily));
        }

        private static int CountSkillCooldownNoticeExtraParts(WzSubProperty noticeFamily)
        {
            if (noticeFamily == null)
            {
                return 0;
            }

            int extraPartCount = 0;
            foreach (WzImageProperty child in noticeFamily.WzProperties)
            {
                if (child == null)
                {
                    continue;
                }

                string name = child.Name;
                if (!string.Equals(name, "t", StringComparison.OrdinalIgnoreCase)
                    && !string.Equals(name, "c", StringComparison.OrdinalIgnoreCase)
                    && !string.Equals(name, "s", StringComparison.OrdinalIgnoreCase))
                {
                    extraPartCount++;
                }
            }

            return extraPartCount;
        }

        private void LoadPacketOwnedHudNoticeUiFrame()
        {
            WzImage basicUiImage = Program.FindImage("UI", "Basic.img");
            WzImage statusBarUiImage = Program.FindImage("UI", "StatusBar2.img");

            WzSubProperty damageMeterSource = basicUiImage?["Notice3"] as WzSubProperty;
            WzSubProperty fieldHazardSource = basicUiImage?["Notice2"] as WzSubProperty ?? damageMeterSource;

            _packetOwnedHudNoticeUI.SetDamageMeterFrameTextures(
                LoadUiCanvasTexture(damageMeterSource?["t"] as WzCanvasProperty),
                LoadUiCanvasTexture(damageMeterSource?["c"] as WzCanvasProperty),
                LoadUiCanvasTexture(damageMeterSource?["s"] as WzCanvasProperty));

            _packetOwnedHudNoticeUI.SetFieldHazardFrameTextures(
                LoadUiCanvasTexture(fieldHazardSource?["t"] as WzCanvasProperty),
                LoadUiCanvasTexture(fieldHazardSource?["c"] as WzCanvasProperty),
                LoadUiCanvasTexture(fieldHazardSource?["s"] as WzCanvasProperty));

            _packetFieldUtilityStatusNoticeIcon = LoadUiCanvasTexture(statusBarUiImage?["mainBar"]?["notice"] as WzCanvasProperty);
            _packetOwnedHudNoticeUI.SetNoticeIcon(_packetFieldUtilityStatusNoticeIcon);
        }

        private Texture2D LoadUiCanvasTexture(WzCanvasProperty canvasProperty)
        {
            if (canvasProperty == null)
            {
                return null;
            }

            string textureKey = ResolveUiCanvasTextureCacheKey(canvasProperty);
            if (!string.IsNullOrEmpty(textureKey))
            {
                if (_failedUiCanvasTextureKeys.Contains(textureKey))
                {
                    return null;
                }

                Texture2D cachedTexture = _texturePool?.GetTexture(textureKey);
                if (cachedTexture != null && !cachedTexture.IsDisposed)
                {
                    return cachedTexture;
                }
            }

            System.Drawing.Bitmap bitmap = null;
            try
            {
                bitmap = canvasProperty.GetLinkedWzCanvasBitmap();
            }
            catch (Exception ex)
            {
                if (!string.IsNullOrEmpty(textureKey))
                {
                    _failedUiCanvasTextureKeys.Add(textureKey);
                }

                System.Diagnostics.Debug.WriteLine($"[MapSimulator] UI canvas texture load failed for {textureKey ?? canvasProperty.FullPath}: {ex.Message}");
                return null;
            }

            if (bitmap == null)
            {
                if (!string.IsNullOrEmpty(textureKey))
                {
                    _failedUiCanvasTextureKeys.Add(textureKey);
                }

                return null;
            }

            Texture2D texture = bitmap.ToTexture2DAndDispose(GraphicsDevice);
            if (texture != null && !texture.IsDisposed && !string.IsNullOrEmpty(textureKey))
            {
                _texturePool?.AddTextureToPool(textureKey, texture);
            }

            return texture;
        }

        private static string ResolveUiCanvasTextureCacheKey(WzCanvasProperty canvasProperty)
        {
            if (canvasProperty == null)
            {
                return null;
            }

            WzImageProperty linkedProperty = canvasProperty.GetLinkedWzImageProperty();
            if (linkedProperty != null)
            {
                return linkedProperty.FullPath;
            }

            return canvasProperty.FullPath;
        }



        private void InitializeFieldRuleRuntime(int currentTime, bool includeFirstUserEnterScript)

        {

            _fieldRuleRuntime = new FieldRuleRuntime(
                _mapBoard?.MapInfo,
                HasInventoryItem,
                GetActiveEnvironmentalDamageProtectionAmount,
                includeFirstUserEnterScript);

            ApplyAmbientFieldWeather(currentTime);
            ApplyFieldRuntimeInteractionRestrictions();
            ApplyFieldRuntimeMinimapRestrictions();



            if (_fieldRuleRuntime == null || !_fieldRuleRuntime.IsActive)
            {
                _fieldRuleRuntime = null;
                return;
            }


            IReadOnlyList<string> entryMessages = _fieldRuleRuntime.Reset(currentTime);
            for (int i = 0; i < entryMessages.Count; i++)
            {
                PushFieldRuleMessage(entryMessages[i], currentTime, false);
            }
        }


        private void UpdateFieldRuleRuntime(int currentTime)
        {
            if (_fieldRuleRuntime == null)
                return;


            FieldRuleUpdateResult updateResult = _fieldRuleRuntime.Update(
                currentTime,
                _playerManager?.Player?.IsAlive == true,
                _gameState.PendingMapChange);


            if (updateResult == null)

                return;



            for (int i = 0; i < updateResult.Messages.Count; i++)
            {
                PushFieldRuleMessage(updateResult.Messages[i], currentTime, false, true);
            }


            for (int i = 0; i < updateResult.OverlayMessages.Count; i++)
            {
                PushFieldRuleMessage(updateResult.OverlayMessages[i], currentTime, true, false);
            }


            if (updateResult.EnvironmentalDamage > 0 && _playerManager?.Player?.IsAlive == true)
            {
                _playerManager.Player.TakeDamage(updateResult.EnvironmentalDamage, 0f, 0f);
                if (updateResult.TriggerDamageMist)
                {
                    _fieldEffects.TriggerDamageMist(0.45f, FIELD_RULE_DAMAGE_MIST_DURATION_MS, currentTime);
                }
            }


            FieldRuleEffectApplier.ApplyRecovery(_playerManager?.Player, updateResult);
            if (updateResult.TransferMapId > 0)
            {
                QueueFieldTransfer(updateResult.TransferMapId);
            }
        }


        private bool ShouldRunOnFirstUserEnterForCurrentMap()
        {
            int mapId = _mapBoard?.MapInfo?.id ?? 0;
            if (mapId <= 0 || string.IsNullOrWhiteSpace(_mapBoard?.MapInfo?.onFirstUserEnter))
            {
                return false;
            }


            return _consumedFirstUserEnterMaps.Add(mapId);

        }



        private void PushFieldRuleMessage(string message, int currentTime, bool showOverlay, bool addChat = true)
        {
            if (string.IsNullOrWhiteSpace(message))
                return;


            if (addChat)
            {
                _chat.AddMessage(message, new Color(255, 228, 151), currentTime);
            }
            if (showOverlay)
            {
                _fieldEffects.AddWeatherMessage(
                    message,
                    WeatherEffectType.None,
                    currentTime,
                    WeatherMessageOwnerKind.StatusBarItemMsg,
                    ownerSourceKind: WeatherMessageOwnerSourceKind.FieldRuleMessage);
            }
        }


        private bool QueueFieldTransfer(int targetMapId, string targetPortalName = null)
        {
            if (!CanQueueKnownCrossMapTransfer(targetMapId, showFailureMessage: true))
            {
                return false;
            }

            return QueueMapTransfer(targetMapId, targetPortalName);
        }


        private void ApplyAmbientFieldWeather(int currentTime)
        {
            if (TryApplyPacketOwnedFieldUtilityWeatherOverride(currentTime))
            {
                return;
            }

            WeatherType ambientWeather = FieldEnvironmentEffectEvaluator.ResolveAmbientWeather(_mapBoard?.MapInfo);
            ToggleWeather(ambientWeather);


            if (ambientWeather == WeatherType.None)
            {
                _fieldEffects.StopWeather();
                return;
            }


            _fieldEffects.OnBlowWeather(
                ConvertToFieldWeatherEffect(ambientWeather),
                null,
                null,
                1f,
                -1,
                currentTime);
        }


        private static WeatherEffectType ConvertToFieldWeatherEffect(WeatherType weather)
        {
            return weather switch
            {
                WeatherType.Rain => WeatherEffectType.Rain,
                WeatherType.Snow => WeatherEffectType.Snow,
                WeatherType.Leaves => WeatherEffectType.Leaves,
                _ => WeatherEffectType.None
            };
        }


        private bool TryResolveMysticDoorReturnTarget(out int returnMapId, out float returnX, out float returnY)
        {
            returnMapId = -1;
            returnX = 0f;
            returnY = 0f;


            if (_mapBoard?.MapInfo == null || _loadMapCallback == null)

                return false;



            return TryResolveMysticDoorReturnTargetForMap(_mapBoard.MapInfo.id, out returnMapId, out returnX, out returnY);
        }
        private static bool TryResolveMysticDoorReturnTargetForMap(int sourceMapId, out int returnMapId, out float returnX, out float returnY)
        {
            returnMapId = -1;
            returnX = 0f;
            returnY = 0f;
            if (sourceMapId <= 0)
                return false;
            WzImage mapImage = TryGetMapImageForMetadataLookup(sourceMapId);
            if (mapImage == null)
                return false;
            bool shouldUnparse = !mapImage.Parsed;
            try
            {
                if (!mapImage.Parsed)
                {
                    mapImage.ParseImage();
                }
                string mapIdKey = sourceMapId.ToString().PadLeft(9, '0');
                if (Program.InfoManager?.MapsCache == null
                    || !Program.InfoManager.MapsCache.TryGetValue(mapIdKey, out Tuple<WzImage, string, string, string, MapleLib.WzLib.WzStructure.MapInfo> cachedMap)
                    || cachedMap?.Item5 == null)
                {
                    return false;
                }
                MapleLib.WzLib.WzStructure.MapInfo mapInfo = cachedMap.Item5;
                int configuredReturnMap = mapInfo.returnMap;
                if (configuredReturnMap <= 0 || configuredReturnMap == MapConstants.MaxMap)
                {
                    configuredReturnMap = mapInfo.forcedReturn;
                }


                if (configuredReturnMap <= 0 || configuredReturnMap == MapConstants.MaxMap)

                    return false;



                if (!TryResolveReturnMapPortalPosition(configuredReturnMap, out returnX, out returnY))

                    return false;



                returnMapId = configuredReturnMap;

                return true;
            }
            finally
            {
                if (shouldUnparse)
                {
                    mapImage.UnparseImage();
                }
            }
        }



        private static bool TryResolveReturnMapPortalPosition(int mapId, out float portalX, out float portalY)
        {
            portalX = 0f;
            portalY = 0f;


            WzImage mapImage = TryGetMapImageForMetadataLookup(mapId);
            if (mapImage == null)
            {
                return false;
            }


            bool shouldUnparse = !mapImage.Parsed;



            try
            {
                if (!mapImage.Parsed)
                {
                    mapImage.ParseImage();
                }


                if (TryResolvePortalPosition(mapImage, PortalType.TownPortalPoint, PortalType.TownPortalPoint.ToCode(), out portalX, out portalY) ||
                    TryResolvePortalPosition(mapImage, PortalType.StartPoint, null, out portalX, out portalY))
                {
                    return true;
                }
            }
            finally
            {
                if (shouldUnparse)
                {
                    mapImage.UnparseImage();
                }
            }


            return false;

        }



        private static WzImage TryGetMapImageForMetadataLookup(int mapId)
        {
            string mapIdKey = mapId.ToString().PadLeft(9, '0');
            if (Program.InfoManager?.MapsCache != null &&
                Program.InfoManager.MapsCache.TryGetValue(mapIdKey, out Tuple<WzImage, string, string, string, MapleLib.WzLib.WzStructure.MapInfo> cachedMap) &&
                cachedMap?.Item1 != null)
            {
                return cachedMap.Item1;
            }


            if (Program.DataSource == null)
            {
                return null;
            }


            string folderNum = mapIdKey[0].ToString();
            return Program.DataSource.GetImageByPath($"Map/Map/Map{folderNum}/{mapIdKey}.img")
                   ?? Program.DataSource.GetImage("Map", $"Map/Map{folderNum}/{mapIdKey}.img");
        }


        private static bool TryResolvePortalPosition(
            WzImage mapImage,
            PortalType preferredPortalType,
            string preferredPortalName,
            out float portalX,
            out float portalY)
        {
            portalX = 0f;
            portalY = 0f;


            if (mapImage?["portal"] is not WzSubProperty portalParent)
            {
                return false;
            }


            WzSubProperty fallbackPortal = null;
            foreach (WzImageProperty property in portalParent.WzProperties)
            {
                if (property is not WzSubProperty portal)
                {
                    continue;
                }


                int? portalTypeId = InfoTool.GetOptionalInt(portal["pt"]);
                PortalType? portalType = null;
                if (portalTypeId.HasValue &&
                    Program.InfoManager?.PortalEditor_TypeById != null &&
                    portalTypeId.Value >= 0 &&
                    portalTypeId.Value < Program.InfoManager.PortalEditor_TypeById.Count)
                {
                    portalType = Program.InfoManager.PortalEditor_TypeById[portalTypeId.Value];
                }


                string portalName = InfoTool.GetOptionalString(portal["pn"]);
                bool matchesType = portalType == preferredPortalType;
                bool matchesName = !string.IsNullOrWhiteSpace(preferredPortalName) &&
                                   string.Equals(portalName, preferredPortalName, StringComparison.OrdinalIgnoreCase);
                if (!matchesType && !matchesName)
                {
                    continue;
                }


                portalX = InfoTool.GetInt(portal["x"]);
                portalY = InfoTool.GetInt(portal["y"]);
                return true;
            }


            if (preferredPortalType == PortalType.StartPoint)
            {
                fallbackPortal = portalParent.WzProperties.OfType<WzSubProperty>().FirstOrDefault();
            }


            if (fallbackPortal == null)
            {
                return false;
            }


            portalX = InfoTool.GetInt(fallbackPortal["x"]);
            portalY = InfoTool.GetInt(fallbackPortal["y"]);
            return true;
        }


        private static bool IsMysticDoorSkill(SkillCastInfo castInfo)
        {
            return castInfo?.SkillData != null
                   && string.Equals(castInfo.SkillData.Name, "Mystic Door", StringComparison.OrdinalIgnoreCase);
        }


        private bool HasInventoryItem(int itemId)
        {
            if (itemId <= 0 || uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventory)
            {
                return false;
            }


            InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(itemId);
            if (inventoryType != InventoryType.NONE)
            {
                return inventory.GetItemCount(inventoryType, itemId) > 0;
            }


            return inventory.GetItemCount(InventoryType.EQUIP, itemId) > 0
                   || inventory.GetItemCount(InventoryType.USE, itemId) > 0
                   || inventory.GetItemCount(InventoryType.SETUP, itemId) > 0
                   || inventory.GetItemCount(InventoryType.ETC, itemId) > 0
                   || inventory.GetItemCount(InventoryType.CASH, itemId) > 0;
        }


        private string GetFieldItemUseRestrictionMessage(InventoryType inventoryType, int itemId, int quantity)
        {
            if (itemId <= 0)
            {
                return null;
            }


            string battlefieldRestriction = GetBattlefieldItemRestrictionMessage(itemId);
            if (!string.IsNullOrWhiteSpace(battlefieldRestriction))
            {
                return battlefieldRestriction;
            }
            InventoryItemMetadataResolver.TryResolveItemName(itemId, out string itemName);
            InventoryItemMetadataResolver.TryResolveItemDescription(itemId, out string itemDescription);

            ConsumableItemEffect consumableEffect = ResolveConsumableItemEffect(itemId);
            PetFoodItemEffect petFoodEffect = ResolvePetFoodItemEffect(itemId);
            string fieldLimitRestriction = FieldInteractionRestrictionEvaluator.GetItemUseRestrictionMessage(
                _mapBoard?.MapInfo?.fieldLimit ?? 0,
                inventoryType,
                itemId,
                itemName,
                itemDescription,
                FieldInteractionRestrictionEvaluator.IsStatChangeConsumable(
                    consumableEffect.HasSupportedRecovery,
                    consumableEffect.HasSupportedTemporaryBuff,
                    consumableEffect.HasSupportedMorph,
                    consumableEffect.HasSupportedCure,
                    consumableEffect.HasSupportedFieldProtection));
            if (!string.IsNullOrWhiteSpace(fieldLimitRestriction))
            {
                return fieldLimitRestriction;
            }



            return _fieldRuleRuntime?.GetItemUseRestrictionMessage(
                inventoryType,
                itemId,
                currTickCount,
                ShouldTrackFieldConsumeItemCooldown(inventoryType, petFoodEffect, consumableEffect));

        }

        private bool HandleLocalInventoryDropRequestWithClientCancelIngress(
            InventoryType sourceInventoryType,
            int sourceSlotIndex,
            InventorySlotData draggedSlotData,
            int requestedQuantity)
        {
            ReleaseActiveKeydownSkillForClientCancelIngress(currTickCount);
            return HandleLocalInventoryDropRequest(
                sourceInventoryType,
                sourceSlotIndex,
                draggedSlotData,
                requestedQuantity);
        }

        private bool HandleLocalInventoryDropRequest(
            InventoryType sourceInventoryType,
            int sourceSlotIndex,
            InventorySlotData draggedSlotData,
            int requestedQuantity)
        {
            if (!FieldDropRequestEvaluator.TryResolveLocalItemDropRequest(
                    _mapBoard?.MapInfo?.fieldLimit ?? 0,
                    sourceInventoryType,
                    sourceSlotIndex,
                    draggedSlotData,
                    requestedQuantity,
                    out LocalFieldItemDropRequest request,
                    out string restrictionMessage))
            {
                if (!string.IsNullOrWhiteSpace(restrictionMessage))
                {
                    ShowFieldRestrictionMessage(restrictionMessage);
                }

                return false;
            }

            if (_dropPool == null || _playerManager?.Player == null)
            {
                return false;
            }

            return TryQueuePendingLocalItemDropRequest(request, draggedSlotData);
        }

        private bool HandleLocalMesoDropRequestWithClientCancelIngress(long requestedAmount)
        {
            ReleaseActiveKeydownSkillForClientCancelIngress(currTickCount);
            return HandleLocalMesoDropRequest(requestedAmount, out _);
        }

        private bool HandleLocalMesoDropRequest(long requestedAmount, out string message)
        {
            message = null;
            IInventoryRuntime inventoryRuntime = uiWindowManager?.InventoryWindow as IInventoryRuntime;
            long currentMeso = inventoryRuntime?.GetMesoCount() ?? 0L;

            if (!FieldDropRequestEvaluator.TryResolveLocalMesoDropRequest(
                    _mapBoard?.MapInfo?.fieldLimit ?? 0,
                    currentMeso,
                    requestedAmount,
                    out LocalFieldMesoDropRequest request,
                    out string restrictionMessage))
            {
                message = restrictionMessage ?? "The meso drop request is invalid.";
                if (!string.IsNullOrWhiteSpace(message))
                {
                    ShowFieldRestrictionMessage(message);
                }

                return false;
            }

            if (_dropPool == null || _playerManager?.Player == null || inventoryRuntime == null)
            {
                message = "Meso drops are unavailable right now.";
                return false;
            }

            if (!inventoryRuntime.TryConsumeMeso(request.Amount))
            {
                message = "You do not have enough mesos to drop that amount.";
                ShowFieldRestrictionMessage(message);
                return false;
            }

            MirrorClientMesoDropRequestEcho(request.Amount);

            int ownerId = _playerManager.Player.Build?.Id ?? 0;
            _dropPool.SpawnMesoDrop(
                _playerManager.Player.X,
                _playerManager.Player.Y,
                request.Amount,
                currTickCount,
                ownerId);
            PlayDropItemSE();
            message = $"Dropped {request.Amount.ToString("N0", CultureInfo.InvariantCulture)} mesos.";
            return true;
        }

        private void MirrorClientMesoDropRequestEcho(int amount)
        {
            if (amount <= 0)
            {
                return;
            }

            byte[] payload = FieldDropRequestEvaluator.BuildClientMesoDropRequestPayload(Environment.TickCount, amount);
            TrySendOrQueueLocalUtilityPacket(
                FieldDropRequestEvaluator.ClientDropMoneyRequestOpcode,
                payload);
        }

        private bool MirrorClientItemDropRequestEcho(LocalFieldItemDropRequest request)
        {
            if (request.ItemId <= 0 || request.Quantity <= 0)
            {
                return false;
            }

            byte[] payload = FieldDropRequestEvaluator.BuildClientItemDropRequestPayload(
                Environment.TickCount,
                request.InventoryType,
                request.SlotIndex,
                request.Quantity);
            return TrySendOrQueueLocalUtilityPacket(
                FieldDropRequestEvaluator.ClientChangeSlotPositionRequestOpcode,
                payload);
        }

        private bool TrySendOrQueueLocalUtilityPacket(int opcode, byte[] payload)
        {
            StampPacketOwnedUtilityRequestState();
            if (_localUtilityOfficialSessionBridge.TrySendOutboundPacket(
                opcode,
                payload,
                out _))
            {
                return true;
            }

            if (_localUtilityPacketOutbox.TrySendOutboundPacket(
                opcode,
                payload,
                out _))
            {
                return true;
            }

            if (_localUtilityOfficialSessionBridgeEnabled
                && _localUtilityOfficialSessionBridge.TryQueueOutboundPacket(
                    opcode,
                    payload,
                    out _))
            {
                return true;
            }

            return _localUtilityPacketOutbox.TryQueueOutboundPacket(
                opcode,
                payload,
                out _);
        }

        private static bool ShouldTrackFieldConsumeItemCooldown(
            InventoryType inventoryType,
            PetFoodItemEffect petFoodEffect,
            ConsumableItemEffect consumableEffect)
        {
            if (inventoryType == InventoryType.USE)
            {
                return true;
            }

            if (inventoryType != InventoryType.CASH)
            {
                return false;
            }

            return petFoodEffect.IsPetFood
                   || consumableEffect.HasSupportedRecovery
                   || consumableEffect.HasSupportedProgression
                   || consumableEffect.HasSupportedMovement
                   || consumableEffect.HasSupportedMorph
                   || consumableEffect.HasSupportedTemporaryBuff
                   || consumableEffect.HasSupportedCure
                   || consumableEffect.HasSupportedFieldProtection;
        }



        private string GetBattlefieldEquipRestrictionMessage(int itemId)
        {
            return GetBattlefieldItemRestrictionMessage(itemId);
        }


        private string GetBattlefieldItemRestrictionMessage(int itemId)
        {
            BattlefieldField battlefield = _specialFieldRuntime?.SpecialEffects?.Battlefield;
            if (itemId <= 0
                || battlefield?.IsActive != true
                || !battlefield.IsItemBlockedForLocalTeam(itemId))
            {
                return null;
            }


            string teamText = battlefield.LocalTeamId switch
            {
                0 => "wolves",
                1 => "sheep",
                2 => "team 2",
                int numericTeam => $"team {numericTeam}",
                _ => "current team"
            };
            return $"Battlefield {teamText} restrictions block item {itemId}.";
        }


        private float ApplyBattlefieldMoveSpeedCap(float speed)
        {
            BattlefieldField battlefield = _specialFieldRuntime?.SpecialEffects?.Battlefield;
            if (battlefield?.IsActive != true)
            {
                return speed;
            }


            return battlefield.ApplyLocalMoveSpeedCap(speed);

        }



        private string GetPendingMapEntryRestrictionMessage(Board targetBoard)
        {
            if (targetBoard?.MapInfo == null)
            {
                return null;
            }


            return FieldEntryRestrictionEvaluator.GetRestrictionMessage(
                targetBoard.MapInfo,
                BuildFieldEntryRestrictionContext());
        }

        private string GetKnownCrossMapTransferEntryRestrictionMessage(int targetMapId)
        {
            if (targetMapId <= 0 || targetMapId == MapConstants.MaxMap)
            {
                return null;
            }

            return GetMapTransferEntryRestrictionMessage(
                targetMapId,
                ResolveMapTransferDestinationMapInfo(targetMapId));
        }

        private bool CanQueueKnownCrossMapTransfer(int targetMapId, bool showFailureMessage)
        {
            string restrictionMessage = GetKnownCrossMapTransferEntryRestrictionMessage(targetMapId);
            if (string.IsNullOrWhiteSpace(restrictionMessage))
            {
                return true;
            }

            if (showFailureMessage)
            {
                ShowFieldRestrictionMessage(restrictionMessage);
            }

            return false;
        }

        private FieldEntryRestrictionContext BuildFieldEntryRestrictionContext()
        {
            bool hasPartyContext = _socialListRuntime?.HasPartyAdmissionContext() == true;
            bool hasExpeditionContext = _socialListRuntime?.HasExpeditionAdmissionContext() == true;
            bool usesPacketOwnedPartyContext = _socialListRuntime?.UsesPacketOwnedPartyAdmissionContext() == true;
            bool hasPacketOwnedPartyContext = _socialListRuntime?.HasPacketOwnedPartyAdmissionContext() == true;
            bool usesPacketOwnedExpeditionContext = _socialListRuntime?.UsesPacketOwnedExpeditionAdmissionContext() == true;
            bool hasPacketOwnedExpeditionContext = _socialListRuntime?.HasPacketOwnedExpeditionAdmissionContext() == true;

            return new FieldEntryRestrictionContext(
                _playerManager?.Player?.Level ?? 1,
                hasPartyContext,
                hasExpeditionContext,
                usesPacketOwnedPartyContext,
                hasPacketOwnedPartyContext,
                usesPacketOwnedExpeditionContext,
                hasPacketOwnedExpeditionContext);
        }


        private bool TryTogglePortableChair(int itemId, out string message)

        {

            message = string.Empty;



            if (_playerManager?.Player == null || _playerManager.Loader == null)
            {
                message = "Player runtime is not available.";
                return false;
            }


            if (itemId <= 0)
            {
                message = $"Invalid chair item ID: {itemId}";
                return false;
            }


            if (InventoryItemMetadataResolver.ResolveInventoryType(itemId) != InventoryType.SETUP)
            {
                message = "Portable chairs must be setup/install items.";
                return false;
            }


            string fieldItemRestrictionMessage = GetFieldItemUseRestrictionMessage(InventoryType.SETUP, itemId, 1);
            if (!string.IsNullOrWhiteSpace(fieldItemRestrictionMessage))
            {
                message = fieldItemRestrictionMessage;
                ShowFieldRestrictionMessage(message);
                return false;
            }


            if (!HasInventoryItem(itemId))
            {
                message = $"Setup item {itemId} is not in the current inventory.";
                return false;
            }


            PortableChair activeChair = _playerManager.Player.Build?.ActivePortableChair;
            if (activeChair?.ItemId == itemId)
            {
                _playerManager.Player.ClearPortableChair();
                _remoteUserPool?.ClearLocalPortableChairPairPreference();
                message = "Portable chair cleared.";
                return true;
            }


            PortableChair chair = _playerManager.Loader.LoadPortableChair(itemId);
            if (chair == null)
            {
                message = $"Unable to load portable chair data for item {itemId}.";
                return false;
            }

            if (chair.TamingMobItemId is int tamingMobItemId && tamingMobItemId > 0)
            {
                string tamingMobRestrictionMessage = FieldInteractionRestrictionEvaluator.GetTamingMobRestrictionMessage(_mapBoard?.MapInfo?.fieldLimit ?? 0);
                if (!string.IsNullOrWhiteSpace(tamingMobRestrictionMessage))
                {
                    message = tamingMobRestrictionMessage;
                    ShowFieldRestrictionMessage(message);
                    return false;
                }
            }

            if (TryGetPortableChairCooldownMessage(itemId, out string cooldownMessage))
            {
                message = cooldownMessage;
                return false;
            }

            string activationRestrictionMessage = _playerManager.Player.GetPortableChairActivationRestrictionMessage(chair);
            if (!string.IsNullOrWhiteSpace(activationRestrictionMessage))
            {
                message = activationRestrictionMessage;
                return false;
            }

            if (!TryConsumePortableChairAuthoredRequirement(itemId, out string requirementMessage))
            {
                message = requirementMessage;
                return false;
            }

            if (!_playerManager.Player.TryActivatePortableChair(chair))
            {
                message = string.IsNullOrWhiteSpace(activationRestrictionMessage)
                    ? "Portable chairs can only be activated while standing on a foothold."
                    : activationRestrictionMessage;
                return false;
            }

            RegisterPortableChairCooldown(itemId);
            if (!chair.IsCoupleChair)
            {
                _remoteUserPool?.ClearLocalPortableChairPairPreference();
            }


            string ridingChairNote = chair.TamingMobItemId is int ridingChairMountItemId && ridingChairMountItemId > 0
                ? $" Riding-chair mount applied: {ridingChairMountItemId}."
                : string.Empty;
            message = $"Activated chair {chair.Name} ({itemId}).{ridingChairNote}";
            return true;
        }

        private bool TryGetPortableChairCooldownMessage(int itemId, out string message)
        {
            message = null;

            int cooldownSeconds = InventoryItemMetadataResolver.ResolveItemCooldownSeconds(itemId);
            if (cooldownSeconds <= 0
                || !_portableChairCooldowns.TryGetValue(itemId, out int nextAvailableAt))
            {
                return false;
            }

            int remainingMs = nextAvailableAt - currTickCount;
            if (remainingMs <= 0)
            {
                _portableChairCooldowns.Remove(itemId);
                return false;
            }

            int remainingSeconds = Math.Max(1, (int)Math.Ceiling(remainingMs / 1000d));
            string chairLabel = ResolvePickupItemName(itemId);
            message = string.IsNullOrWhiteSpace(chairLabel)
                ? $"That chair is on cooldown for {remainingSeconds.ToString(CultureInfo.InvariantCulture)} seconds."
                : $"{chairLabel} is on cooldown for {remainingSeconds.ToString(CultureInfo.InvariantCulture)} seconds.";
            return true;
        }

        private void RegisterPortableChairCooldown(int itemId)
        {
            int cooldownSeconds = InventoryItemMetadataResolver.ResolveItemCooldownSeconds(itemId);
            if (cooldownSeconds <= 0)
            {
                _portableChairCooldowns.Remove(itemId);
                return;
            }

            _portableChairCooldowns[itemId] = currTickCount + (cooldownSeconds * 1000);
        }

        private bool TryConsumePortableChairAuthoredRequirement(int chairItemId, out string message)
        {
            message = null;

            IReadOnlyList<ConsumeItemRequirementMetadata> requirements =
                InventoryItemMetadataResolver.ResolveConsumeItemRequirements(chairItemId);
            if (requirements.Count == 0)
            {
                return true;
            }

            if (uiWindowManager?.InventoryWindow is not UI.IInventoryRuntime inventoryWindow)
            {
                message = "Inventory runtime is not available.";
                return false;
            }

            int totalEligibleRate = 0;
            for (int i = 0; i < requirements.Count; i++)
            {
                ConsumeItemRequirementMetadata requirement = requirements[i];
                InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(requirement.ItemId);
                if (inventoryType == InventoryType.NONE
                    || inventoryWindow.GetItemCount(inventoryType, requirement.ItemId) < requirement.Count)
                {
                    continue;
                }

                if (requirement.Rate > 0)
                {
                    totalEligibleRate += requirement.Rate;
                }
            }

            int weightedRoll = totalEligibleRate > 0
                ? _setupConsumeItemRandom.Next(1, totalEligibleRate + 1)
                : 1;
            if (InventoryItemMetadataResolver.TrySelectConsumeItemRequirement(
                    requirements,
                    itemId =>
                    {
                        InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(itemId);
                        return inventoryType == InventoryType.NONE
                            ? 0
                            : inventoryWindow.GetItemCount(inventoryType, itemId);
                    },
                    weightedRoll,
                    out ConsumeItemRequirementMetadata selectedRequirement))
            {
                InventoryType selectedType = InventoryItemMetadataResolver.ResolveInventoryType(selectedRequirement.ItemId);
                if (selectedType != InventoryType.NONE
                    && inventoryWindow.TryConsumeItem(selectedType, selectedRequirement.ItemId, selectedRequirement.Count))
                {
                    return true;
                }
            }

            for (int i = 0; i < requirements.Count; i++)
            {
                ConsumeItemRequirementMetadata requirement = requirements[i];
                InventoryType inventoryType = InventoryItemMetadataResolver.ResolveInventoryType(requirement.ItemId);
                if (inventoryType == InventoryType.NONE
                    || inventoryWindow.GetItemCount(inventoryType, requirement.ItemId) < requirement.Count)
                {
                    continue;
                }

                if (inventoryWindow.TryConsumeItem(inventoryType, requirement.ItemId, requirement.Count))
                {
                    return true;
                }
            }

            List<string> requirementLabels = new();
            for (int i = 0; i < requirements.Count; i++)
            {
                ConsumeItemRequirementMetadata requirement = requirements[i];
                string itemLabel = ResolvePickupItemName(requirement.ItemId);
                if (string.IsNullOrWhiteSpace(itemLabel))
                {
                    itemLabel = requirement.ItemId.ToString(CultureInfo.InvariantCulture);
                }

                requirementLabels.Add(requirement.Count > 1
                    ? $"{itemLabel} x{requirement.Count.ToString(CultureInfo.InvariantCulture)}"
                    : itemLabel);
            }

            string requirementText = requirementLabels.Count > 0
                ? string.Join(", ", requirementLabels)
                : "the authored consume-item requirement";
            message = $"That chair requires one of the following items before it can be used: {requirementText}.";
            return false;
        }


        private bool TrySetPlayerJob(int jobId)
        {
            var build = _playerManager?.Player?.Build;
            if (build == null)
                return false;


            build.Job = jobId;

            build.JobName = SkillDataLoader.GetJobName(jobId);



            if (_playerManager?.Skills != null)
            {
                _playerManager.Skills.LoadSkillsForJob(jobId);
                _playerManager.Skills.LearnAllNonHiddenSkills();
            }


            RefreshSkillWindowForJob(jobId);

            return true;

        }



        private void RefreshSkillWindowForJob(int jobId)
        {
            if (uiWindowManager?.SkillWindow is SkillUIBigBang skillWindow)
            {
                UIWindowLoader.LoadSkillsForJob(
                    skillWindow,
                    jobId,
                    GraphicsDevice,
                    _playerManager?.Skills?.GetLearnedSkillRecordIds(),
                    _playerManager?.Player?.Build?.SubJob ?? 0);
            }
            else if (uiWindowManager?.SkillWindow is SkillUI legacySkillWindow)
            {
                UIWindowLoader.LoadSkillsForJob(
                    legacySkillWindow,
                    jobId,
                    GraphicsDevice,
                    _playerManager?.Skills?.GetLearnedSkillRecordIds(),
                    _playerManager?.Player?.Build?.SubJob ?? 0);
            }
            else
            {
                return;
            }

            ConfigureSkillUIBindings();

        }



        /// <summary>
        /// Gets character stats data for display on the status bar.
        /// Uses player character data when available, or provides defaults.
        /// </summary>
        /// <returns>CharacterStatsData with current player stats</returns>
        private CharacterStatsData GetCharacterStatsData()
        {
            if (_playerManager?.Player == null)
            {
                return new CharacterStatsData(); // Default values
            }


            var player = _playerManager.Player;
            return new CharacterStatsData
            {
                HP = player.HP,
                MaxHP = player.MaxHP,
                MP = player.MP,
                MaxMP = player.MaxMP,
                Level = player.Level,
                Name = player.Build?.Name ?? "Player",
                Job = player.Build?.JobName ?? "Beginner",
                EXP = player.Build?.Exp ?? 0,
                MaxEXP = player.Build?.ExpToNextLevel ?? 100
            };
        }


        private IReadOnlyList<StatusBarBuffRenderData> GetStatusBarBuffData(int currentTime)
        {
            if (_statusBarBuffRenderCacheTime == currentTime)
            {
                return _statusBarBuffRenderCache;
            }


            _statusBarBuffRenderCacheTime = currentTime;
            if (_playerManager?.Skills == null)
            {
                _statusBarBuffRenderCache.Clear();
                return Array.Empty<StatusBarBuffRenderData>();
            }


            IReadOnlyList<StatusBarBuffEntry> buffEntries = _playerManager.Skills.GetStatusBarBuffEntries(currentTime);
            if (buffEntries.Count == 0)
            {
                _statusBarBuffRenderCache.Clear();
                return Array.Empty<StatusBarBuffRenderData>();
            }


            for (int i = 0; i < buffEntries.Count; i++)
            {
                StatusBarBuffEntry buffEntry = buffEntries[i];
                StatusBarBuffRenderData renderData = i < _statusBarBuffRenderCache.Count
                    ? _statusBarBuffRenderCache[i]
                    : CreateAndAppendStatusBarBuffRenderData(_statusBarBuffRenderCache);
                ApplyStatusBarBuffRenderData(renderData, buffEntry);
            }


            TrimReusableList(_statusBarBuffRenderCache, buffEntries.Count);

            return _statusBarBuffRenderCache;

        }



        private StatusBarChatUI.StatusBarPointNotificationState GetStatusBarPointNotificationState()
        {
            bool hasAbilityPoints = _playerManager?.Player?.Build?.AP > 0;
            bool hasSkillPoints = uiWindowManager?.SkillWindow is SkillUIBigBang skillWindow && skillWindow.HasAvailableSkillPoints();


            if (!hasAbilityPoints && !hasSkillPoints)
            {
                return null;
            }


            return new StatusBarChatUI.StatusBarPointNotificationState
            {
                ShowAbilityPointNotification = hasAbilityPoints,
                ShowSkillPointNotification = hasSkillPoints
            };
        }


        private IReadOnlyList<StatusBarCooldownRenderData> GetStatusBarCooldownData(int currentTime)
        {
            if (!ShouldRefreshStatusBarShortcutCooldownUiForClientParity(
                currentTime,
                _statusBarCooldownRenderCacheTime))
            {
                return _statusBarCooldownRenderCache;
            }


            _statusBarCooldownRenderCacheTime = currentTime;
            if (_playerManager?.Skills == null || _playerManager.SkillLoader == null)
            {
                _statusBarCooldownSortBuffer.Clear();
                _statusBarCooldownRenderCache.Clear();
                return Array.Empty<StatusBarCooldownRenderData>();
            }


            Dictionary<int, int> hotkeys = _playerManager.Skills.GetAllHotkeys();
            if (hotkeys.Count == 0)
            {
                _statusBarCooldownSortBuffer.Clear();
                _statusBarCooldownRenderCache.Clear();
                return Array.Empty<StatusBarCooldownRenderData>();
            }


            _statusBarCooldownSortBuffer.Clear();
            _statusBarProcessedCooldownSkills.Clear();
            int renderIndex = 0;
            foreach (KeyValuePair<int, int> hotkey in hotkeys)
            {
                int skillId = hotkey.Value;
                if (skillId <= 0 || !_statusBarProcessedCooldownSkills.Add(skillId))
                {
                    continue;
                }


                SkillData skill = _playerManager.SkillLoader.LoadSkill(skillId);
                bool hasCooldownState = _playerManager.Skills.TryGetCooldownUiState(
                    skillId,
                    currentTime,
                    SkillManager.CooldownMaskSurface.StatusBarShortcutTray,
                    out var cooldownState);
                if (!ShouldAdmitStatusBarShortcutCooldownForClientParity(hasCooldownState, cooldownState))
                {
                    continue;
                }


                _playerManager.Skills.TryGetCooldownStartTime(skillId, out int cooldownStartTime);



                StatusBarCooldownRenderData renderData = renderIndex < _statusBarCooldownRenderCache.Count
                    ? _statusBarCooldownRenderCache[renderIndex]
                    : CreateAndAppendStatusBarCooldownRenderData(_statusBarCooldownRenderCache);
                SkillLevelData levelData = skill?.GetLevel(_playerManager.Skills.GetSkillLevel(skillId));
                renderData.SkillId = skillId;
                renderData.SkillName = skill?.Name;
                renderData.Description = skill?.Description;
                renderData.IconTexture = skill?.IconTexture;
                renderData.RemainingMs = cooldownState.RemainingMs;
                renderData.DurationMs = cooldownState.DurationMs;
                bool hasVisualState = SkillManager.TryResolveCooldownMaskVisualState(
                    cooldownState,
                    out int maskFrameIndex,
                    out string counterText,
                    includeCounterText: true,
                    maskSurface: SkillManager.CooldownMaskSurface.StatusBarShortcutTray);
                renderData.MaskFrameIndex = maskFrameIndex;
                renderData.MaskSurface = SkillManager.CooldownMaskSurface.StatusBarShortcutTray;
                renderData.UseQuickSlotMaskSurface = true;
                renderData.CounterText = SkillManager.ResolveCooldownCounterTextForSurface(
                    hasVisualState,
                    counterText,
                    cooldownState);
                renderData.TooltipStateText = cooldownState.TooltipStateText;
                renderData.TooltipCostLineMarkup = SkillCooldownTooltipText.BuildSkillTooltipMarkup(
                    levelData,
                    hasCooldownState: true,
                    cooldownState.RemainingMs,
                    cooldownState.TooltipStateText).SecondaryLineMarkup;
                renderData.SuppressProgressOverlay = cooldownState.SuppressProgressOverlay;
                renderData.SuppressCounterText = cooldownState.SuppressCounterText;
                _statusBarCooldownSortBuffer.Add((renderData, cooldownStartTime, hotkey.Key));
                renderIndex++;
            }


            _statusBarCooldownSortBuffer.Sort(static (left, right) =>
            {
                int cooldownComparison = right.CooldownStartTime.CompareTo(left.CooldownStartTime);
                return cooldownComparison != 0 ? cooldownComparison : left.SortKey.CompareTo(right.SortKey);
            });


            for (int i = 0; i < _statusBarCooldownSortBuffer.Count; i++)
            {
                _statusBarCooldownRenderCache[i] = _statusBarCooldownSortBuffer[i].RenderData;
            }


            TrimReusableList(_statusBarCooldownRenderCache, _statusBarCooldownSortBuffer.Count);

            return _statusBarCooldownRenderCache;

        }

        internal static bool ShouldAdmitStatusBarShortcutCooldownForClientParity(
            bool hasCooldownState,
            SkillManager.CooldownUiState cooldownState)
        {
            // Keep shortcut-tray intake on surface-owned cooldown UI state admission
            // so packet/server-owned cooldown rows can render without a separate timer gate.
            return hasCooldownState && cooldownState.DisplayInCooldownUi;
        }

        internal static bool ShouldRefreshStatusBarShortcutCooldownUiForClientParity(
            int currentTime,
            int lastRefreshTime)
        {
            // Client evidence: CUIStatusBar::Update triggers CQuickSlot::DrawSkillCooltime
            // only when `timeGetTime() - m_tLastUpdateSkillCooltime > 1000`.
            if (lastRefreshTime == int.MinValue)
            {
                return true;
            }

            if (currentTime < lastRefreshTime)
            {
                return true;
            }

            return currentTime - lastRefreshTime > 1000;
        }



        private IReadOnlyList<StatusBarCooldownRenderData> GetStatusBarOffBarCooldownData(int currentTime)
        {
            if (!ShouldRefreshStatusBarOffBarCooldownUiForClientParity(
                currentTime,
                _statusBarOffBarCooldownRenderCacheTime))
            {
                return _statusBarOffBarCooldownRenderCache;
            }


            _statusBarOffBarCooldownRenderCacheTime = currentTime;
            if (_playerManager?.Skills == null)
            {
                _statusBarOffBarCooldownSortBuffer.Clear();
                _statusBarOffBarCooldownRenderCache.Clear();
                return Array.Empty<StatusBarCooldownRenderData>();
            }


            IReadOnlyList<int> activeCooldownSkillIds = _playerManager.Skills.GetActiveCooldownUiSkillIdsForSurface(
                currentTime,
                SkillManager.CooldownMaskSurface.StatusBarOffBarTray);
            if (activeCooldownSkillIds.Count == 0)
            {
                _statusBarOffBarCooldownSortBuffer.Clear();
                _statusBarOffBarCooldownRenderCache.Clear();
                return Array.Empty<StatusBarCooldownRenderData>();
            }


            _statusBarOffBarCooldownSortBuffer.Clear();
            int renderIndex = 0;
            foreach (int skillId in activeCooldownSkillIds)
            {
                if (_playerManager.Skills.IsSkillAssignedToDirectHotkey(skillId))
                {
                    continue;
                }


                SkillData skill = _playerManager.Skills.GetSkillData(skillId);
                if (!_playerManager.Skills.TryGetCooldownUiState(
                        skillId,
                        currentTime,
                        SkillManager.CooldownMaskSurface.StatusBarOffBarTray,
                        out var cooldownState)
                    || !cooldownState.DisplayInCooldownUi)
                {
                    continue;
                }


                if (!_playerManager.Skills.TryGetCooldownStartTime(skillId, out int cooldownStartTime)
                    && _playerManager.Skills.TryGetPassiveVehicleTemporaryStatStateForParity(
                        skillId,
                        out SkillManager.PassiveVehicleTemporaryStatState passiveState))
                {
                    cooldownStartTime = passiveState.StartTime;
                }
                StatusBarCooldownRenderData renderData = renderIndex < _statusBarOffBarCooldownRenderCache.Count
                    ? _statusBarOffBarCooldownRenderCache[renderIndex]
                    : CreateAndAppendStatusBarCooldownRenderData(_statusBarOffBarCooldownRenderCache);
                SkillLevelData levelData = skill?.GetLevel(_playerManager.Skills.GetSkillLevel(skillId));
                renderData.SkillId = skillId;
                renderData.SkillName = skill?.Name ?? $"Skill {skillId}";
                renderData.Description = skill?.Description ?? string.Empty;
                renderData.IconTexture = skill?.IconTexture ?? skill?.Icon?.Texture;
                renderData.RemainingMs = cooldownState.RemainingMs;
                renderData.DurationMs = cooldownState.DurationMs;
                bool hasVisualState = SkillManager.TryResolveCooldownMaskVisualState(
                    cooldownState,
                    out int maskFrameIndex,
                    out string counterText,
                    includeCounterText: true,
                    maskSurface: SkillManager.CooldownMaskSurface.StatusBarOffBarTray);
                renderData.MaskFrameIndex = maskFrameIndex;
                renderData.MaskSurface = SkillManager.CooldownMaskSurface.StatusBarOffBarTray;
                renderData.UseQuickSlotMaskSurface = false;
                renderData.CounterText = SkillManager.ResolveCooldownCounterTextForSurface(
                    hasVisualState,
                    counterText,
                    cooldownState);
                renderData.TooltipStateText = cooldownState.TooltipStateText;
                renderData.TooltipCostLineMarkup = SkillCooldownTooltipText.BuildSkillTooltipMarkup(
                    levelData,
                    hasCooldownState: true,
                    cooldownState.RemainingMs,
                    cooldownState.TooltipStateText).SecondaryLineMarkup;
                renderData.SuppressProgressOverlay = cooldownState.SuppressProgressOverlay;
                renderData.SuppressCounterText = cooldownState.SuppressCounterText;
                _statusBarOffBarCooldownSortBuffer.Add((renderData, cooldownStartTime, skillId));
                renderIndex++;
            }


            _statusBarOffBarCooldownSortBuffer.Sort(static (left, right) =>
            {
                int cooldownComparison = right.CooldownStartTime.CompareTo(left.CooldownStartTime);
                return cooldownComparison != 0 ? cooldownComparison : left.SortKey.CompareTo(right.SortKey);
            });


            for (int i = 0; i < _statusBarOffBarCooldownSortBuffer.Count; i++)
            {
                _statusBarOffBarCooldownRenderCache[i] = _statusBarOffBarCooldownSortBuffer[i].RenderData;
            }


            TrimReusableList(_statusBarOffBarCooldownRenderCache, _statusBarOffBarCooldownSortBuffer.Count);

            return _statusBarOffBarCooldownRenderCache;

        }

        internal static bool ShouldRefreshStatusBarOffBarCooldownUiForClientParity(
            int currentTime,
            int lastRefreshTime)
        {
            // Keep off-bar cooldown rows on the same recovered status-bar cooltime cadence
            // used by shortcut tray updates.
            return ShouldRefreshStatusBarShortcutCooldownUiForClientParity(
                currentTime,
                lastRefreshTime);
        }



        private StatusBarPreparedSkillRenderData GetPreparedSkillBarData(int currentTime, PreparedSkillHudSurface surface)
        {
            if (surface == PreparedSkillHudSurface.StatusBar && _preparedSkillStatusBarCacheTime == currentTime)
            {
                return _preparedSkillStatusBarCache.SkillId == 0 ? null : _preparedSkillStatusBarCache;
            }


            if (surface == PreparedSkillHudSurface.World && _preparedSkillWorldCacheTime == currentTime)
            {
                return _preparedSkillWorldCache.SkillId == 0 ? null : _preparedSkillWorldCache;
            }


            var preparedSkill = _playerManager?.Skills?.GetPreparedSkill();
            if (preparedSkill == null)
            {
                ClearPreparedSkillBarCache(surface, currentTime);
                return null;
            }


            if (!preparedSkill.ShowHudBar || preparedSkill.HudSurface != surface)
            {
                ClearPreparedSkillBarCache(surface, currentTime);
                return null;
            }


            StatusBarPreparedSkillRenderData renderData = surface == PreparedSkillHudSurface.World
                ? _preparedSkillWorldCache
                : _preparedSkillStatusBarCache;
            renderData.SkillId = preparedSkill.SkillId;
            renderData.SkillName = PreparedSkillHudRules.ResolveDisplayName(
                preparedSkill.SkillId,
                preparedSkill.SkillData?.Name);
            renderData.SkinKey = preparedSkill.HudSkinKey;
            renderData.Surface = preparedSkill.HudSurface;
            renderData.RemainingMs = Math.Max(0, preparedSkill.Duration - preparedSkill.Elapsed(currentTime));
            renderData.DurationMs = preparedSkill.Duration;
            renderData.GaugeDurationMs = preparedSkill.HudGaugeDurationMs;
            renderData.Progress = preparedSkill.Progress(currentTime);
            renderData.IsKeydownSkill = preparedSkill.IsKeydownSkill;
            renderData.IsPreparingPhase = preparedSkill.IsKeydownSkill
                && !preparedSkill.IsHolding
                && preparedSkill.Duration > 0
                && preparedSkill.Elapsed(currentTime) < preparedSkill.Duration;
            renderData.IsHolding = preparedSkill.IsHolding;
            renderData.PrepareRemainingMs = renderData.IsPreparingPhase
                ? renderData.RemainingMs
                : 0;
            renderData.HoldElapsedMs = preparedSkill.HoldElapsed(currentTime);
            renderData.MaxHoldDurationMs = preparedSkill.MaxHoldDurationMs;
            renderData.TextVariant = preparedSkill.HudTextVariant;
            renderData.ShowText = preparedSkill.ShowHudText;
            Vector2 worldAnchor = Vector2.Zero;
            if (surface == PreparedSkillHudSurface.World
                && !TryResolvePreparedSkillWorldAnchor(preparedSkill, currentTime, out worldAnchor))
            {
                ClearPreparedSkillBarCache(surface, currentTime);
                return null;
            }


            renderData.WorldAnchor = surface == PreparedSkillHudSurface.World

                ? worldAnchor

                : Vector2.Zero;



            if (surface == PreparedSkillHudSurface.World)
            {
                _preparedSkillWorldCacheTime = currentTime;
            }
            else
            {
                _preparedSkillStatusBarCacheTime = currentTime;
            }


            return renderData;

        }



        private static StatusBarBuffRenderData CreateAndAppendStatusBarBuffRenderData(List<StatusBarBuffRenderData> cache)
        {
            StatusBarBuffRenderData renderData = new StatusBarBuffRenderData();
            cache.Add(renderData);
            return renderData;
        }


        private static StatusBarCooldownRenderData CreateAndAppendStatusBarCooldownRenderData(List<StatusBarCooldownRenderData> cache)
        {
            StatusBarCooldownRenderData renderData = new StatusBarCooldownRenderData();
            cache.Add(renderData);
            return renderData;
        }


        private void ClearPreparedSkillBarCache(PreparedSkillHudSurface surface, int currentTime)
        {
            StatusBarPreparedSkillRenderData renderData = surface == PreparedSkillHudSurface.World
                ? _preparedSkillWorldCache
                : _preparedSkillStatusBarCache;
            renderData.SkillId = 0;
            renderData.SkillName = null;
            renderData.SkinKey = "KeyDownBar";
            renderData.Surface = surface;
            renderData.RemainingMs = 0;
            renderData.DurationMs = 0;
            renderData.GaugeDurationMs = 0;
            renderData.Progress = 0f;
            renderData.IsKeydownSkill = false;
            renderData.IsPreparingPhase = false;
            renderData.IsHolding = false;
            renderData.PrepareRemainingMs = 0;
            renderData.HoldElapsedMs = 0;
            renderData.MaxHoldDurationMs = 0;
            renderData.TextVariant = PreparedSkillHudTextVariant.Default;
            renderData.ShowText = true;
            renderData.WorldAnchor = Vector2.Zero;


            if (surface == PreparedSkillHudSurface.World)
            {
                _preparedSkillWorldCacheTime = currentTime;
            }
            else
            {
                _preparedSkillStatusBarCacheTime = currentTime;
            }
        }


        private static void TrimReusableList<T>(List<T> items, int count)
        {
            if (items.Count > count)
            {
                items.RemoveRange(count, items.Count - count);
            }
        }


        private bool TryResolvePreparedSkillWorldAnchor(PreparedSkill preparedSkill, int currentTime, out Vector2 anchor)

        {

            anchor = Vector2.Zero;



            if (preparedSkill?.HudSurface != PreparedSkillHudSurface.World || _playerManager?.Player == null)
            {
                return false;
            }


            if (IsDragonPreparedSkill(preparedSkill.SkillId)
                && _playerManager.Dragon != null
                && _playerManager.Dragon.TryGetCurrentKeyDownBarAnchor(currentTime, out Vector2 dragonTop))
            {
                anchor = dragonTop;
                return true;
            }


            if (IsDragonPreparedSkill(preparedSkill.SkillId))
            {
                return false;
            }


            PlayerCharacter player = _playerManager.Player;
            Point? bodyOrigin = player.TryGetCurrentBodyOrigin(currentTime);
            Rectangle? frameBounds = player.TryGetCurrentFrameBounds(currentTime);
            if (bodyOrigin.HasValue && frameBounds.HasValue)
            {
                float topY = bodyOrigin.Value.Y + frameBounds.Value.Top;
                anchor = new Vector2(player.X, topY - 18f);
                return true;
            }


            anchor = new Vector2(player.X, player.Y - 80f);

            return true;

        }



        private static bool IsDragonPreparedSkill(int skillId)
        {
            return skillId is 22121000 or 22151001;
        }


        private static string GetPreparedSkillBarSkin(PreparedSkill preparedSkill)
        {
            return preparedSkill?.HudSkinKey ?? "KeyDownBar";
        }


