        private void DrainCoconutPacketInbox(int currentTickCount)
        {
            while (_coconutOfficialSessionBridge.TryDequeue(out CoconutPacketInboxMessage bridgeMessage))
            {
                _coconutPacketInbox.EnqueueProxy(bridgeMessage);
            }

            while (_coconutPacketInbox.TryDequeue(out CoconutPacketInboxMessage message))
            {
                if (TryApplyCoconutInboxLocalTeamUpdate(message, _specialFieldRuntime?.Minigames?.Coconut, out string localTeamMessage))
                {
                    ApplyClientOwnedFieldWrappers();
                    _coconutPacketInbox.RecordDispatchResult(
                        message.Source,
                        message.PacketType,
                        success: true,
                        localTeamMessage);
                    continue;
                }

                bool applied = TryApplyCoconutWrapperPacket(message.PacketType, message.Payload, currentTickCount, out string errorMessage);
                _coconutPacketInbox.RecordDispatchResult(
                    message.Source,
                    message.PacketType,
                    applied,
                    errorMessage);
            }
        }

        private bool TryApplyCoconutWrapperPacket(int packetType, byte[] payload, int currentTickCount, out string message)
        {
            CoconutField field = _specialFieldRuntime?.Minigames?.Coconut;
            int previousLocalTeam = field?.LocalTeam ?? 0;
            CoconutField.LocalTeamSelectionSource previousSelectionSource =
                field?.TeamSelectionSource ?? CoconutField.LocalTeamSelectionSource.Default;

            bool applied = TryDispatchCurrentWrapperPacketIngress(packetType, payload, currentTickCount, out message);
            if (applied)
            {
                ApplyClientOwnedFieldWrappersIfCoconutTeamSelectionChanged(field, previousLocalTeam, previousSelectionSource);
            }

            return applied;
        }

        private void ApplyClientOwnedFieldWrappersIfCoconutTeamSelectionChanged(
            CoconutField field,
            int previousLocalTeam,
            CoconutField.LocalTeamSelectionSource previousSelectionSource)
        {
            if (field?.IsActive != true)
            {
                return;
            }

            if (field.LocalTeam != previousLocalTeam || field.TeamSelectionSource != previousSelectionSource)
            {
                ApplyClientOwnedFieldWrappers();
            }
        }

        internal static bool TryApplyCoconutInboxLocalTeamUpdate(
            CoconutPacketInboxMessage message,
            CoconutField field,
            out string statusMessage)
        {
            statusMessage = null;
            if (message?.IsLocalTeamUpdate != true || field?.IsActive != true)
            {
                return false;
            }

            field.SetLocalTeam(
                message.LocalTeam.GetValueOrDefault(),
                CoconutField.LocalTeamSelectionSource.TransportControlLine);
            statusMessage = $"localTeam={(field.LocalTeam == 1 ? "Story" : "Maple")}";
            return true;
        }


        private void DrainSnowBallPacketInbox(int currentTickCount)
        {
            while (_snowBallPacketInbox.TryDequeue(out SnowBallPacketInboxMessage message))
            {
                bool applied = TryDispatchCurrentWrapperPacketIngress(message.PacketType, message.Payload, currentTickCount, out string errorMessage);
                _snowBallPacketInbox.RecordDispatchResult(
                    message.Source,
                    message.PacketType,
                    applied,
                    errorMessage);
            }

            while (_snowBallOfficialSessionBridge.TryDequeue(out SnowBallPacketInboxMessage bridgeMessage))
            {
                bool applied = TryDispatchCurrentWrapperPacketIngress(bridgeMessage.PacketType, bridgeMessage.Payload, currentTickCount, out string bridgeErrorMessage);
                _snowBallOfficialSessionBridge.RecordDispatchResult(
                    bridgeMessage.Source,
                    bridgeMessage.PacketType,
                    applied,
                    bridgeErrorMessage);
            }
        }


        private void FlushPendingSnowBallTouchRequests()
        {
            SnowBallField field = _specialFieldRuntime?.Minigames?.SnowBall;
            if (field == null
                || (!_snowBallPacketInbox.HasConnectedClients
                    && !_snowBallOfficialSessionBridge.HasConnectedSession
                    && !field.TryPeekTouchPacketRequest(out _)))
            {
                return;
            }

            while (field.TryConsumeTouchPacketRequest(out SnowBallField.TouchPacketRequest request))
            {
                if (_snowBallOfficialSessionBridge.HasConnectedSession)
                {
                    if (!_snowBallOfficialSessionBridge.TrySendTouchRequest(request, out _))
                    {
                        break;
                    }
                }
                else if (_snowBallPacketInbox.HasConnectedClients)
                {
                    if (!_snowBallPacketInbox.TrySendTouchRequest(request, out _))
                    {
                        break;
                    }
                }
                else
                {
                    break;
                }
            }
        }


        private void FlushPendingCoconutAttackRequests()
        {
            CoconutField field = _specialFieldRuntime?.Minigames?.Coconut;
            if (field?.IsActive != true)
            {
                return;
            }


            bool officialSessionBridgeHasOwnership = HasCoconutOfficialSessionBridgeOwnership(
                _coconutOfficialSessionBridge.HasConnectedSession,
                _coconutOfficialSessionBridge.HasAttachedClient,
                _coconutOfficialSessionBridge.HasPassiveEstablishedSocketPair);
            bool allowTransportFallback = ShouldFallbackCoconutAttackTransport(officialSessionBridgeHasOwnership);

            while (field.TryGetNextUndispatchedAttackPacketRequest(out CoconutField.AttackPacketRequest request))
            {
                if (_coconutOfficialSessionBridge.HasConnectedSession)
                {
                    if (!_coconutOfficialSessionBridge.TrySendAttackRequest(request, out _))
                    {
                        break;
                    }
                }
                else if (allowTransportFallback && _coconutPacketInbox.HasConnectedClients)
                {
                    if (!_coconutPacketInbox.TrySendAttackRequest(request, out _))
                    {
                        break;
                    }
                }
                else
                {
                    break;
                }


                field.MarkAttackPacketRequestTransportDispatched(request);

            }

        }



        private void DrainMemoryGamePacketInbox(int currentTickCount)
        {
            MemoryGameField field = _specialFieldRuntime.Minigames.MemoryGame;
            field.SetOfficialClientRelayEnabled(_memoryGameOfficialSessionBridge.IsRunning || _memoryGameOfficialSessionBridge.HasConnectedSession);
            while (_memoryGamePacketInbox.TryDequeue(out MemoryGamePacketInboxMessage message))
            {
                if (message == null)
                {
                    continue;
                }


                bool applyClientMirror = !string.IsNullOrWhiteSpace(message.RawText)
                    && message.RawText.StartsWith("packetclientraw", StringComparison.OrdinalIgnoreCase);
                bool applied = applyClientMirror
                    ? field.TryDispatchOfficialClientPacket(message.Payload, currentTickCount, out string resultMessage, enforcePromptFlow: true, relayOutboundTransport: true)
                    : field.TryDispatchMiniRoomPacket(message.Payload, currentTickCount, out resultMessage);
                _memoryGamePacketInbox.RecordDispatchResult(
                    message.Source,
                    applied,
                    applied ? field.DescribeStatus() : resultMessage);


                if (applied)
                {
                    ShowMiniRoomWindow();
                }
            }
            while (_memoryGameOfficialSessionBridge.TryDequeue(out MemoryGamePacketInboxMessage bridgeMessage))
            {
                if (bridgeMessage == null)
                {
                    continue;
                }


                bool applyClientMirror = !string.IsNullOrWhiteSpace(bridgeMessage.RawText)
                    && bridgeMessage.RawText.StartsWith("packetclientraw", StringComparison.OrdinalIgnoreCase);
                string bridgeResultMessage;
                bool applied = applyClientMirror
                    ? field.TryDispatchOfficialClientPacket(bridgeMessage.Payload, currentTickCount, out bridgeResultMessage, enforcePromptFlow: true, relayOutboundTransport: false)
                    : field.TryDispatchMiniRoomPacket(bridgeMessage.Payload, currentTickCount, out bridgeResultMessage);
                _memoryGameOfficialSessionBridge.RecordDispatchResult(
                    bridgeMessage.Source,
                    applied,
                    applied ? field.DescribeStatus() : bridgeResultMessage);


                if (applied)
                {
                    ShowMiniRoomWindow();
                }
            }

            while (field.TryDequeuePendingOfficialClientRequest(out byte[] outboundPayload))
            {
                _memoryGameOfficialSessionBridge.TrySendOrQueueClientMiniRoomRequest(outboundPayload, out _, out _);
            }
        }

