        private bool TryApplyTransportInboxMessage(TransportationPacketInboxMessage message, out string resultMessage)
        {
            resultMessage = _transportField.DescribeStatus();
            if (message == null)
            {
                resultMessage = "Transport inbox message is missing.";
                return false;
            }


            byte[] payload = message.Payload ?? Array.Empty<byte>();
            switch (message.PacketType)
            {
                case TransportationPacketInboxManager.PacketTypeContiMove:
                    if (payload.Length < 2)
                    {
                        resultMessage = "Transport OnContiMove payload must contain subtype and value bytes.";
                        return false;
                    }


                    return payload[0] switch
                    {
                        TransportationPacketInboxManager.ContiMoveStartShip => _transportField.TryApplyStartShipMovePacket(payload[1], out resultMessage),
                        TransportationPacketInboxManager.ContiMoveMoveField => _transportField.TryApplyMoveFieldPacket(payload[1], out resultMessage),
                        TransportationPacketInboxManager.ContiMoveEndShip => _transportField.TryApplyEndShipMovePacket(payload[1], out resultMessage),
                        _ => FailTransportMessage(
                            $"Ignored OnContiMove subtype {payload[0]}; client only handles 8, 10, and 12.",
                            out resultMessage)
                    };
                case TransportationPacketInboxManager.PacketTypeContiState:
                    if (payload.Length < 2)
                    {
                        resultMessage = "Transport OnContiState payload must contain state and value bytes.";
                        return false;
                    }


                    return _transportField.TryApplyContiState(payload[0], payload[1], out resultMessage);
                default:
                    resultMessage = $"Unsupported transport packet opcode: {message.PacketType}";
                    return false;
            }
        }
        private static bool FailTransportMessage(string message, out string resultMessage)
        {
            resultMessage = message;
            return false;
        }


        private bool TryApplyDojoInboxMessage(DojoField field, DojoPacketInboxMessage message, int currentTickCount, out string resultMessage)
        {
            resultMessage = field?.DescribeStatus() ?? "Mu Lung Dojo HUD inactive";
            if (field == null || message == null)
            {
                resultMessage = "Dojo inbox message is missing.";
                return false;
            }


            switch (message.Kind)
            {
                case DojoPacketMessageKind.Energy:
                    field.SetEnergy(message.Value);
                    return true;


                case DojoPacketMessageKind.Clock:

                    field.OnClock(2, message.Value, currentTickCount);

                    return true;



                case DojoPacketMessageKind.Stage:

                    field.SetStage(message.Value, currentTickCount);

                    return true;



                case DojoPacketMessageKind.Clear:
                    if (string.Equals(message.Option, "none", StringComparison.OrdinalIgnoreCase))
                    {
                        field.ShowClearResult(currentTickCount, -1);
                        return true;
                    }


                    if (string.Equals(message.Option, "auto", StringComparison.OrdinalIgnoreCase) || string.IsNullOrWhiteSpace(message.Option))
                    {
                        field.ShowClearResultForNextFloor(currentTickCount);
                        return true;
                    }

                    if (!DojoField.TryParseTransferTargetOption(message.Option, out int clearMapId, out string clearPortalName, out string clearError))
                    {
                        resultMessage = clearError;
                        return false;
                    }

                    field.ShowClearResult(currentTickCount, clearMapId, clearPortalName);

                    return true;



                case DojoPacketMessageKind.TimeOver:

                    field.ShowTimeOverResult(currentTickCount, message.Value);

                    return true;



                case DojoPacketMessageKind.RawPacket:
                    return TryDispatchCurrentWrapperPacketIngress(message.PacketType, message.Payload, currentTickCount, out resultMessage);

                case DojoPacketMessageKind.RawClientPacket:
                    if (!_dojoOfficialSessionBridge.TryMapInboundPacket(message.Payload, message.Source, out DojoPacketInboxMessage decodedMessage))
                    {
                        resultMessage = "Dojo opcode-framed packet did not decode into a supported Mu Lung Dojo packet.";
                        return false;
                    }

                    return TryApplyDojoInboxMessage(field, decodedMessage, currentTickCount, out resultMessage);



                default:
                    resultMessage = $"Unsupported Dojo inbox action: {message.Kind}";
                    return false;
            }
        }


        private void DrainPartyRaidPacketInbox(int currentTickCount)
        {
            PartyRaidField field = _specialFieldRuntime.PartyRaid;
            while (_partyRaidOfficialSessionBridge.TryDequeue(out PartyRaidPacketInboxMessage bridgeMessage))
            {
                _partyRaidPacketInbox.EnqueueProxy(bridgeMessage);
            }

            while (_partyRaidPacketInbox.TryDequeue(out PartyRaidPacketInboxMessage message))
            {
                if (!field.IsActive)
                {
                    _partyRaidPacketInbox.RecordDispatchResult(
                        message.Source,
                        message.Scope,
                        message.Key,
                        success: false,
                        message: "runtime inactive");
                    continue;
                }


                string dispatchMessage = null;
                bool applied = message.Scope switch
                {
                    PartyRaidPacketScope.Field => field.OnFieldSetVariable(message.Key, message.Value),
                    PartyRaidPacketScope.Party => field.OnPartyValue(message.Key, message.Value),
                    PartyRaidPacketScope.Session => field.OnSessionValue(message.Key, message.Value),
                    PartyRaidPacketScope.Clock => TryApplyPartyRaidClockInbox(field, message, currentTickCount),
                    PartyRaidPacketScope.Packet => TryApplyPartyRaidWrapperPacket(message.PacketType, message.Payload, currentTickCount, out dispatchMessage),
                    _ => false
                };

                if (applied)
                {
                    if (message.Scope == PartyRaidPacketScope.Session)
                    {
                        TryApplyPendingPortalSessionValueImpact(
                            message.Key,
                            message.Value,
                            PartyRaidField.ClientSessionValuePacketType,
                            PacketFieldSpecificDataOwnerHint.Session);
                    }
                    else if (message.Scope == PartyRaidPacketScope.Packet)
                    {
                        TryApplyPendingPortalSessionValueImpactFromPacket(message.PacketType, message.Payload);
                    }
                }


                _partyRaidPacketInbox.RecordDispatchResult(
                    message.Source,
                    message.Scope,
                    message.Scope == PartyRaidPacketScope.Packet ? message.PacketType.ToString() : message.Key,
                    applied,
                    applied
                        ? field.DescribeStatus()
                        : dispatchMessage ?? $"key not accepted ({message.Key}={message.Value})");
            }
        }

        private bool TryApplyPartyRaidWrapperPacket(int packetType, byte[] payload, int currentTickCount, out string message)
        {
            return TryDispatchCurrentWrapperPacketIngress(packetType, payload, currentTickCount, out message);
        }

        private bool TryDispatchCurrentWrapperPacketIngress(int packetType, byte[] payload, int currentTickCount, out string message)
        {
            if (packetType == SpecialFieldRuntimeCoordinator.CurrentWrapperRelayOpcode)
            {
                return _specialFieldRuntime.TryDispatchCurrentWrapperRelayPayload(payload, currentTickCount, out message);
            }

            return _specialFieldRuntime.TryDispatchCurrentWrapperPacketRelay(packetType, payload, currentTickCount, out message);
        }

        private void DrainTournamentPacketInbox(int currentTickCount)
        {
            while (_tournamentPacketInbox.TryDequeue(out TournamentPacketInboxMessage message))
            {
                bool applied = TryDispatchCurrentWrapperPacketIngress(message.PacketType, message.Payload, currentTickCount, out string errorMessage);
                _tournamentPacketInbox.RecordDispatchResult(
                    message.Source,
                    message.PacketType,
                    applied,
                    errorMessage);
            }

            while (_tournamentOfficialSessionBridge.TryDequeue(out TournamentPacketInboxMessage bridgeMessage))
            {
                bool bridgeApplied = TryDispatchCurrentWrapperPacketIngress(bridgeMessage.PacketType, bridgeMessage.Payload, currentTickCount, out string bridgeErrorMessage);
                _tournamentOfficialSessionBridge.RecordDispatchResult(
                    bridgeMessage.Source,
                    bridgeMessage.PacketType,
                    bridgeApplied,
                    bridgeErrorMessage);
            }
        }


        private static bool TryApplyPartyRaidClockInbox(PartyRaidField field, PartyRaidPacketInboxMessage message, int currentTickCount)
        {
            if (field == null || message == null)
            {
                return false;
            }


            if (string.Equals(message.Key, "clear", StringComparison.OrdinalIgnoreCase))
            {
                field.ClearClock();
                return true;
            }


            string clockValue = string.IsNullOrWhiteSpace(message.Value)
                ? message.Key
                : message.Value;
            if (!int.TryParse(clockValue, out int seconds))
            {
                return false;
            }


            field.OnClock(2, seconds, currentTickCount);

            return true;

        }



        private void DrainGuildBossTransport(int currentTickCount)
        {
            while (_guildBossOfficialSessionBridge.TryDequeue(out GuildBossPacketInboxMessage bridgeMessage))
            {
                bool bridgeApplied = TryDispatchCurrentWrapperPacketIngress(bridgeMessage.PacketType, bridgeMessage.Payload, currentTickCount, out string bridgeErrorMessage);
                _guildBossOfficialSessionBridge.RecordDispatchResult(
                    bridgeMessage.Source,
                    bridgeMessage.PacketType,
                    bridgeApplied,
                    bridgeErrorMessage);
            }
            while (_guildBossTransport.TryDequeue(out GuildBossPacketInboxMessage message))
            {
                bool applied = TryDispatchCurrentWrapperPacketIngress(message.PacketType, message.Payload, currentTickCount, out string errorMessage);
                _guildBossTransport.RecordDispatchResult(
                    message.Source,
                    message.PacketType,
                    applied,
                    errorMessage);
            }
        }


